INSERT INTO `products` (`id`, `name`, `slug`, `sku`, `content`, `short_desc`, `price`, `discount`, `quantity`, `status`, `type`, `thumbnail`, `category_id`, `brand_id`, `created_at`, `updated_at`) VALUES
(1, 'Mặt bích thép', 'm-t-b-ch-th-p', NULL, '\n<h1>Mặt bích thép<strong> </strong></h1>\n<h1><strong>thường được sản xuất theo tiêu chuẩn: JIS 10K, BS PN10, BS PN16, ANSI class 150, DIN PN10, DIN PN16. Được dùng để kết nối các đường ống thép, kết nối với van và các thiết bị khác trong hệ thống chuyền dẫn chất lỏng, khí, gas…</strong></h1>\n<div class=\"wp-caption aligncenter\" id=\"attachment_362\" style=\"width: 510px\"><img alt=\"Mặt bích thép tiêu chuẩn: JIS, BS, ANSI, DIN\" aria-describedby=\"caption-attachment-362\" class=\"wp-image-362\" height=\"292\" loading=\"lazy\" sizes=\"(max-width: 500px) 100vw, 500px\" src=\"https://vanphukien.com/wp-content/uploads/2018/11/mat-bich-thep-1.jpg\" srcset=\"https://vanphukien.com/wp-content/uploads/2018/11/mat-bich-thep-1.jpg 1200w, https://vanphukien.com/wp-content/uploads/2018/11/mat-bich-thep-1-300x175.jpg 300w, https://vanphukien.com/wp-content/uploads/2018/11/mat-bich-thep-1-768x448.jpg 768w, https://vanphukien.com/wp-content/uploads/2018/11/mat-bich-thep-1-1024x597.jpg 1024w, https://vanphukien.com/wp-content/uploads/2018/11/mat-bich-thep-1-170x100.jpg 170w, https://vanphukien.com/wp-content/uploads/2018/11/mat-bich-thep-1-600x350.jpg 600w\" title=\"Mặt bích thép tiêu chuẩn: JIS, BS, ANSI, DIN\" width=\"500\"/>\n<p class=\"wp-caption-text\" id=\"caption-attachment-362\"><em>Tiêu chuẩn: JIS, BS, ANSI, DIN (Ảnh: Internet)</em></p></div>\n<p><strong>Mặt bích thép</strong> được sản xuất theo các tiêu chuẩn thông dụng và được chấp nhận trên toàn thế giới. Đó là tiêu chuẩn: JIS, BS, ANSI và DIN.<strong> </strong>thường được mạ kẽm nhúng nóng hoặc mạ kẽm điện phân. Mục đích bảo vệ bích sắt trước tác động của trường cũng như môi chất trong hệ thống. Bích thép mạ kẽm có độ bền cao, chịu được ăn mòn và oxi hóa.</p>\n<p>Có hai loại mặt bích thép thông dụng đó là rỗng và đặc</p>\n<p>Bích thép rỗng có tâm là lỗ rỗng để kết nối đường ống và van, cũng như các phụ kiện khác trong hệ thống.</p>\n<div class=\"wp-caption aligncenter\" id=\"attachment_363\" style=\"width: 510px\"><img alt=\"Bích thép rỗng tiêu chuẩn: JIS 10K, ANSI class 150, BS PN10, BS PN16\" aria-describedby=\"caption-attachment-363\" class=\"wp-image-363 size-full\" height=\"413\" loading=\"lazy\" sizes=\"(max-width: 500px) 100vw, 500px\" src=\"https://vanphukien.com/wp-content/uploads/2018/11/bich-thep-rong.jpg\" srcset=\"https://vanphukien.com/wp-content/uploads/2018/11/bich-thep-rong.jpg 500w, https://vanphukien.com/wp-content/uploads/2018/11/bich-thep-rong-300x248.jpg 300w\" title=\"Bích thép rỗng tiêu chuẩn: JIS 10K, ANSI class 150, BS PN10, BS PN16\" width=\"500\"/>\n<p class=\"wp-caption-text\" id=\"caption-attachment-363\"><em>Bích thép rỗng tiêu chuẩn: JIS 10K, ANSI class 150, BS PN10, BS PN16 (Ảnh: Internet)</em></p></div>\n<p>Đường kính lỗ rỗng phụ thuộc vào từng loại ống thép kết nối. Thông thường chúng chỉ được sản xuất theo các thông số: DN15, DN20, DN25, DN32, DN40, DN50, DN65, DN80, DN100, DN125, DN150, DN200, DN250, DN300, DN350, DN400, DN450, DN500, DN550, DN600, DN650, DN700, DN750, DN800…</p>\n<p>Bích thép đặc không có lỗ thoát ở giữa tâm, loại bích này được dùng để bịt các đường ống dẫn, chúng còn có tên gọi khác là<strong> </strong>bích mù</p>\n<p>Bích mù thường được lắp đặt ở các đầu đường ống chờ, có thể tháo lắp dễ dàng, kết nối thêm đường ống, van hay các thiết bị khác.</p>\n<div class=\"wp-caption aligncenter\" id=\"attachment_364\" style=\"width: 510px\"><img alt=\"Mặt bích thép đặc tiêu chuẩn: JIS, BS, ANSI, DIN\" aria-describedby=\"caption-attachment-364\" class=\"wp-image-364\" height=\"300\" loading=\"lazy\" sizes=\"(max-width: 500px) 100vw, 500px\" src=\"https://vanphukien.com/wp-content/uploads/2018/11/mat-bich-thep-dac.jpg\" srcset=\"https://vanphukien.com/wp-content/uploads/2018/11/mat-bich-thep-dac.jpg 517w, https://vanphukien.com/wp-content/uploads/2018/11/mat-bich-thep-dac-300x180.jpg 300w\" title=\"Mặt bích thép đặc tiêu chuẩn: JIS, BS, ANSI, DIN\" width=\"500\"/>\n<p class=\"wp-caption-text\" id=\"caption-attachment-364\"><em>Mặt bích thép đặc tiêu chuẩn: JIS, BS, ANSI, DIN (Ảnh: Internet)</em></p></div>\n<h2><strong>Thông số kỹ thuật mặt bích thép</strong></h2>\n<p><strong>Thông số kỹ thuật</strong></p>\n<ul>\n<li>Chất liệu: A106, CT3, SS400, Q235…</li>\n<li>Tiêu chuẩn: JIS 10K, BS PN10, BS PN16, ANSI class150, DIN PN10, DIN PN16… (RF add FF)</li>\n<li>Loại: Hàng đen / Mạ kẽm</li>\n<li>Kích thước: DN15 – DN1200</li></ul>\n<p>Gia công theo yêu cầu các loại bích thép không theo tiêu chuẩn. Chế tạo mặt bích theo thống số và kích thước không có sẵn.</p>\n<h2><strong>Gia công mặt bích thép</strong></h2>\n<p>Với các loại mặt bích thép không theo tiêu chuẩn hoặc các loại mặt bích với kích thước không có sẵn. Chúng tôi nhận gia công theo yêu cầu. Đảm bảo chất lượng, chính xác, giao hàng nhanh chóng.</p>\n<div class=\"wp-caption aligncenter\" id=\"attachment_366\" style=\"width: 510px\"><img alt=\"Gia công mặt bích, bản mã theo yêu cầu\" aria-describedby=\"caption-attachment-366\" class=\"wp-image-366\" height=\"336\" loading=\"lazy\" sizes=\"(max-width: 500px) 100vw, 500px\" src=\"https://vanphukien.com/wp-content/uploads/2018/11/gia-cong-mat-bich-ban-ma.jpg\" srcset=\"https://vanphukien.com/wp-content/uploads/2018/11/gia-cong-mat-bich-ban-ma.jpg 1626w, https://vanphukien.com/wp-content/uploads/2018/11/gia-cong-mat-bich-ban-ma-300x201.jpg 300w, https://vanphukien.com/wp-content/uploads/2018/11/gia-cong-mat-bich-ban-ma-768x516.jpg 768w, https://vanphukien.com/wp-content/uploads/2018/11/gia-cong-mat-bich-ban-ma-1024x688.jpg 1024w, https://vanphukien.com/wp-content/uploads/2018/11/gia-cong-mat-bich-ban-ma-600x403.jpg 600w\" title=\"Gia công mặt bích, bản mã theo yêu cầu\" width=\"500\"/>\n<p class=\"wp-caption-text\" id=\"caption-attachment-366\"><em>Gia công mặt bích, bản mã theo yêu cầu (Ảnh: Internet)</em></p></div>\n<p>Ngoài ra chúng tôi cung cấp các loại bản mã chân cột, bản mã gối cầu… cắt đột lỗ bản mã theo yêu cầu. Gia công nhanh chóng và chính xác, đáp ứng đúng tiến độ giao hàng.</p>\n<p>Chúng tôi chuyên cung cấp các loại mặt bích thép<strong> </strong>tiêu chuẩn JIS, BS, ANSI, DIN, mặt bích thép mạ kẽm và gia công mặt bích phi tiêu chuẩn theo yêu cầu khách hàng.</p>\n', 'Mặt bích thép', 1000.00, 0, 0, 1, 0, 'products/e5621b5c-d201-4c70-ac10-28d31f732779.png', 25, 1, NULL, NULL),
(13, 'Bulon inox', 'bulon-inox', '', '\n<h1>Bulon Inox</h1>\n<p><strong>Bulong inox là loại bu lông được sản xuất từ vật liệu thép không gỉ inox, gồm có Bu lông Inox 201, Bu lông Inox 304 và Bu lông Inox 316. Bu lông inox có khả năng chống ăn mòn hóa học và ăn mòn điện hóa từ môi trường rất tốt.</strong></p>\n<h2>Thông số kỹ thuật của Bulon Inox:</h2>\n<p>- Hình dạng/ Shape: Đầu mũ dạng lục giác, thân ren lửng (DIN 931), thân ren suốt (DIN 933)</p>\n<p>- Kích thước (M) / Diameter: M6 ~ M24</p>\n<p>- Chiều dài (L)/ Length: 16~240 mm</p>\n<p>- Vật liệu/ Material: Stainless steel (thép không gỉ) SUS201, SUS 304</p>\n<p>- Tiêu chuẩn/ Standard: DIN 931, DIN 933, DIN 960, DIN 961, ISO 4014, ISO 4017, ASTM</p>\n<p><img alt=\"bu-long-inox-din933\" height=\"251\" src=\"https://thegioibulongocvit.vn/img/cms/DIN%20933.png\" width=\"984\"/></p>\n<p><img alt=\"bulong-inox-DIN 931\" height=\"273\" src=\"https://thegioibulongocvit.vn/img/cms/DIN%20931.png\" width=\"976\"/></p>\n', 'Bulon inox', 0.00, 0, 0, 1, 0, 'products/74ce5c86-7994-4cc1-9587-6e31d0efd4c5.jpg', 25, 1, NULL, NULL),
(14, 'Phụ kiện thép hàn SCH', 'ph-ki-n-th-p-h-n-sch', '', '\n<h1>Phụ kiên cút thép hàn SCH</h1>\n<p>Các phụ kiện thép hàn dùng cho đường ống bao gồm: cút thép hàn SCH, tê thép hàn SCH, đầu bịt thép hàn SCH,… Các phụ kiện không gỉ và phụ kiện thép carbon là một phần quan trọng của hệ thống đường ống công nghiệp để thay đổi hướng, rẽ nhánh hoặc kết nối cơ khí với hệ thống. Độ dày của phụ kiện hàn được xác định theo kích thước ống danh định với độ dày SCH cụ thể. Kích thước và dung sai phù hợp của BW được xác định theo tiêu chuẩn B16.9 của ASME.</p>\n<ul>\n<li>Kết nối hàn cung cấp kết nối mạnh mẽ hơn</li>\n<li>Cấu trúc kim loại liên tục làm tăng thêm sức mạnh của hệ thống đường ống</li>\n<li>Phụ kiện thép hàn có độ dày SCH phù hợp với độ dày ống, cung cấp dòng chảy liền mạch bên trong đường ống. Một mối hàn tốt và khớp với cút thép hàn SCH 90, côn thu,…phù hợp cung cấp sự chuyển đổi dần dần thông qua lắp ống hàn.</li></ul>\n<p>Tất cả các phụ kiện hàn đều có đầu vát theo tiêu chuẩn ASME B16.25. Điều này giúp tạo ra mối hàn tốt luôn mà không cần bất kỳ sự chuẩn bị thêm nào cần thiết cho việc hàn.</p>\n<p>Phụ kiện cút thép hàn đường ống thường có sẵn bằng thép carbon, thép không gỉ, hợp kim niken, nhôm và vật liệu năng suất cao. Phụ kiện hàn được sản xuất chủ yếu theo các tiêu chuẩn vật liệu A234-WPB, A234-WPC, A420-WPL6, Y-52, Y-60, Y-65, Y-70.</p>\n<p>Công ty Quốc Thái<strong> </strong>là một trong những nhà phân phối lớn nhất về mặt bích và phụ kiện đường ống. Chúng tôi tiếp nhận và xử lý các đơn đặt hàng với số lượng lớn. Hàng hóa nguồn gốc đa dạng.</p>\n', 'Phụ kiện thép hàn SCH', 1000.00, 0, 0, 1, 0, 'products/d51f639a-2169-46fc-adf8-03418e85f526.jpg', 25, 1, NULL, NULL),
(15, 'Phụ kiện ren mạ kẽm', 'ph-ki-n-ren-m-k-m', '', '\n<h1 style=\"margin-top: 0px;\"><strong>Cút ren mạ kẽm</strong></h1>\n<p><b>Quy Cách:</b> DN15 ~ DN100</p>\n<p><b>Áp suất làm việc:</b> 150LBS</p>\n<p><b>Vật Liệu:</b> Gang, gang (CI, DI, vv).</p>\n<p><b>Xuất Xứ:</b> CHINA – THAILAN</p>\n<p><b>Mô tả sản phẩm:</b> Phụ kiện ren mạ kẽm được sản xuất Theo tiêu chuẩn BS EN 10242 BS 143 &amp; 1256 và được mạ nhúng nóng bằng công nghệ tiên tiến nhất hiện nay</p>\n<p><b>Sử dụng:</b> Phụ kiện ren mạ kẽm được sử dụng rộng dãi trong các ngành cơ khí chế tạo máy móc và dùng trong hệ thống cấp thoát nước, hệ thống điện lạnh, hệ thống đường ống phòng cháy chữa cháy, các ngành công nghiệp đường ống.</p>\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\" class=\"table table-bordered text-center\" style=\"width: 100%;\">\n<tbody>\n<tr>\n<td colspan=\"4\" style=\"height: 32px; width: 732px; vertical-align: middle;\">\n<p style=\"text-align: center;\">Cút ren mạ kẽm 90 độ</p></td>\n</tr>\n<tr>\n<td rowspan=\"12\" style=\"height: 32px; width: 48px; vertical-align: middle;\">\n<p style=\"text-align: center;\"><img alt=\"\" src=\"http://skb.vn/upload/images/PK-ONG-THEP/PK-REN-MA-KEM-BSPT/co%20ren%2090.jpg\"/></p></td>\n<td colspan=\"2\" rowspan=\"2\" style=\"height: 32px; width: 464px; vertical-align: middle;\">\n<p style=\"text-align: center;\">Size</p></td>\n<td style=\"height: 32px; width: 220px; vertical-align: middle;\">\n<p style=\"text-align: center;\">Dimensions</p></td>\n</tr>\n<tr>\n<td style=\"height: 32px; width: 220px; vertical-align: middle;\">\n<p style=\"text-align: center;\">(mm.)</p></td>\n</tr>\n<tr>\n<td style=\"height: 32px; width: 212px; vertical-align: middle;\">\n<p style=\"text-align: center;\">Inch</p></td>\n<td style=\"height: 32px; width: 252px; vertical-align: middle;\">\n<p style=\"text-align: center;\">(mm.)</p></td>\n<td style=\"height: 32px; width: 220px; vertical-align: middle;\">\n<p style=\"text-align: center;\">A</p></td>\n</tr>\n<tr>\n<td style=\"height: 32px; width: 212px; vertical-align: middle;\">\n<p style=\"text-align: center;\"> 1/2</p></td>\n<td style=\"height: 32px; width: 252px; vertical-align: middle;\">\n<p style=\"text-align: center;\">15</p></td>\n<td style=\"height: 32px; width: 220px; vertical-align: middle;\">\n<p style=\"text-align: center;\">26.5</p></td>\n</tr>\n<tr>\n<td style=\"height: 32px; width: 212px; vertical-align: middle;\">\n<p style=\"text-align: center;\"> 3/4</p></td>\n<td style=\"height: 32px; width: 252px; vertical-align: middle;\">\n<p style=\"text-align: center;\">20</p></td>\n<td style=\"height: 32px; width: 220px; vertical-align: middle;\">\n<p style=\"text-align: center;\">31</p></td>\n</tr>\n<tr>\n<td style=\"height: 32px; width: 212px; vertical-align: middle;\">\n<p style=\"text-align: center;\">1</p></td>\n<td style=\"height: 32px; width: 252px; vertical-align: middle;\">\n<p style=\"text-align: center;\">25</p></td>\n<td style=\"height: 32px; width: 220px; vertical-align: middle;\">\n<p style=\"text-align: center;\">36.5</p></td>\n</tr>\n<tr>\n<td style=\"height: 32px; width: 212px; vertical-align: middle;\">\n<p style=\"text-align: center;\">1.1/4</p></td>\n<td style=\"height: 32px; width: 252px; vertical-align: middle;\">\n<p style=\"text-align: center;\">32</p></td>\n<td style=\"height: 32px; width: 220px; vertical-align: middle;\">\n<p style=\"text-align: center;\">43.5</p></td>\n</tr>\n<tr>\n<td style=\"height: 32px; width: 212px; vertical-align: middle;\">\n<p style=\"text-align: center;\">1.1/2</p></td>\n<td style=\"height: 32px; width: 252px; vertical-align: middle;\">\n<p style=\"text-align: center;\">40</p></td>\n<td style=\"height: 32px; width: 220px; vertical-align: middle;\">\n<p style=\"text-align: center;\">47.5</p></td>\n</tr>\n<tr>\n<td style=\"height: 32px; width: 212px; vertical-align: middle;\">\n<p style=\"text-align: center;\">2</p></td>\n<td style=\"height: 32px; width: 252px; vertical-align: middle;\">\n<p style=\"text-align: center;\">50</p></td>\n<td style=\"height: 32px; width: 220px; vertical-align: middle;\">\n<p style=\"text-align: center;\">55.5</p></td>\n</tr>\n<tr>\n<td style=\"height: 32px; width: 212px; vertical-align: middle;\">\n<p style=\"text-align: center;\">2.1/2</p></td>\n<td style=\"height: 32px; width: 252px; vertical-align: middle;\">\n<p style=\"text-align: center;\">65</p></td>\n<td style=\"height: 32px; width: 220px; vertical-align: middle;\">\n<p style=\"text-align: center;\">67</p></td>\n</tr>\n<tr>\n<td style=\"height: 32px; width: 212px; vertical-align: middle;\">\n<p style=\"text-align: center;\">3</p></td>\n<td style=\"height: 32px; width: 252px; vertical-align: middle;\">\n<p style=\"text-align: center;\">80</p></td>\n<td style=\"height: 32px; width: 220px; vertical-align: middle;\">\n<p style=\"text-align: center;\">75.5</p></td>\n</tr>\n<tr>\n<td style=\"height: 32px; width: 212px; vertical-align: middle;\">\n<p style=\"text-align: center;\">4</p></td>\n<td style=\"height: 32px; width: 252px; vertical-align: middle;\">\n<p style=\"text-align: center;\">100</p></td>\n<td style=\"height: 32px; width: 220px; vertical-align: middle;\">\n<p style=\"text-align: center;\">94</p></td>\n</tr>\n</tbody></table>\n', 'Phụ kiện ren mạ kẽm', 0.00, 0, 0, 1, 0, 'products/de046de5-300a-4bf9-beb3-f441470d7e22.jpg', 25, 1, NULL, NULL),
(16, 'Mặt bích inox', 'm-t-b-ch-inox', '', '\n<h1 dir=\"ltr\" style=\"text-align: center;\"><span style=\"font-size: 36px;\"><span new=\"\" style=\"font-family: \" times=\"\"><strong><span style=\"color: rgb(255, 0, 0);\">Mặt bích inox không rỉ </span></strong></span></span></h1>\n<p dir=\"ltr\"><span style=\"color: rgb(0, 128, 0);\"><span style=\"font-size: 16px;\"><strong>Mặt bích inox </strong></span></span><span style=\"background-color: transparent; font-size: 13pt;\">là thiết bị</span><strong> </strong><span style=\"background-color: transparent; font-size: 13pt;\">đang được rất nhiều khách hàng trên thị trường tin tưởng lựa chọn để ứng dụng vào thực tế. Công ty Đại Quang Minh Steel sẽ cung cấp một vài thông tin cơ bản về thiết bị trong bài viết dưới đât. Nó sẽ giúp quý khách hàng hiểu rõ hơn về sản phẩm và có sự lựa chọn chính xác nhất.</span></p>\n<h3 dir=\"ltr\" style=\"text-align: justify;\"><em><strong>Mặt bích với thiết bị PCCC là gì?</strong></em></h3>\n<p dir=\"ltr\" style=\"text-align: justify;\"><span style=\"color: rgb(0, 128, 0);\"><span style=\"font-size: 16px;\"><strong>Mặt bích inox </strong></span></span><span style=\"font-size: 13pt;\">l</span><span style=\"background-color: transparent; font-size: 13pt;\">à sản phẩm được ứng dụng rất nhiều trong các đường ống của công trình và đặc biệt là một </span><span style=\"color: rgb(0, 128, 0);\"><span style=\"font-size: 16px;\"><strong>thiết bị PCCC </strong></span></span><span style=\"background-color: transparent; font-size: 13pt;\">rất quan trọng. Sản phẩm được sản xuất từ chất liệu cao cấp như khối thép hay inox không gỉ.</span></p>\n<h3 dir=\"ltr\" style=\"text-align: justify;\"><em><strong>Đặc điểm của mặt bích</strong></em></h3>\n<p dir=\"ltr\" style=\"text-align: justify;\"><span style=\"background-color: transparent; font-size: 13pt;\">- Sản phẩm có áp suất làm việc dao động trong khoảng lớn nên khi ứng dụng vào thực tế sẽ chịu được áp lực rất cao.</span></p>\n<p dir=\"ltr\" style=\"text-align: justify;\"><strong>- <a href=\"https://daiquangminhvina.com/mat-bich-thep\"><span style=\"color: rgb(0, 128, 0);\"><span style=\"font-size: 16px;\">Mặt bích inox </span></span></a></strong><span style=\"font-size: 13pt;\">đ</span><span style=\"background-color: transparent; font-size: 13pt;\">ược sản xuất theo công nghệ hiện đại để đảm bảo sự chính xác đến từng chi tiết.</span></p>\n<p dir=\"ltr\" style=\"text-align: justify;\"><span style=\"background-color: transparent; font-size: 13pt;\">- Kích thước nhỏ gọn nên không gây khó khăn cho việc vận chuyển.</span></p>\n<p dir=\"ltr\" style=\"text-align: justify;\"><span style=\"background-color: transparent; font-size: 13pt;\">- Cấu tạo đơn giản, không có quá nhiều chi tiết phức tạp nên khi lắp đặt vào đường ống sẽ rất nhanh chóng, tiết kiệm thời gian.</span></p>\n<p dir=\"ltr\" style=\"text-align: justify;\"><span style=\"background-color: transparent; font-size: 13pt;\">- Thiết bị có khả năng ứng dụng rộng rãi trong nhiều lĩnh vực của cuộc sống như: đ</span><span style=\"font-size: 13pt;\">ường ống cấp thoát nước sinh hoạt dân dụng hay công nghiệp. Đặc biệt là mặt bích luôn đóng vai trò rất quan trọng trong việc vận hành hệ thống </span><span style=\"font-size: 16px;\">thiết bị PCCC</span><span style=\"font-size: 13pt;\"><span style=\"font-size: 16px;\">.</span> </span></p>\n<p dir=\"ltr\" style=\"text-align: justify;\"> </p>\n<h3 dir=\"ltr\" style=\"text-align: justify;\"><span style=\"color: rgb(0, 128, 0);\"><span style=\"font-size: 22px;\"><strong>3 ưu điểm nổi bật của mặt bích với thiết bị PCCC</strong></span></span></h3>\n<h3 dir=\"ltr\" style=\"text-align: justify;\"><strong><em>Có độ bền cao</em></strong></h3>\n<p dir=\"ltr\" style=\"text-align: justify;\"><span style=\"background-color: transparent; font-size: 13pt;\">Do được sản xuất từ nguồn nguyên liệu cao cấp nên </span><span style=\"color: rgb(0, 128, 0);\"><span style=\"font-size: 16px;\"><strong>mặt bích </strong></span></span><span style=\"background-color: transparent; font-size: 13pt;\">luôn có được độ bền rất vượt trội. Đặc biệt, với khả năng chịu được áp lực lớn nên trong quá trình sử dụng, thiết bị sẽ ít bị bể vỡ hay xảy ra hiện tượng rò rỉ chất lỏng. Điều này sẽ giúp cho hiệu quả hoạt động của hệ thống PCCC được tốt nhất. Với ưu điểm vượt trội này, khách hàng sẽ không tốn nhiều chi phí cho việc bảo dưỡng cũng như thay mới thiết bị.</span></p>\n<p dir=\"ltr\" style=\"text-align: center;\"><a href=\"https://daiquangminhvina.com/mat-bich-thep\"><span style=\"background-color: transparent; font-size: 13pt;\"><img alt=\"MẶT BÍCH THÉP \" src=\"https://lh6.googleusercontent.com/W1TpFIuXemJp3PnRBEMYg5hBDoHv79vgoX7Lzse6OdxMmBWpeM67kFG4UIleZ8hQ9Hs7bvV8qeZ87bDOBQQbJ5i8LdLic9ePRvARL4r0Qcgxmw39m-dqRYQXc8fB_6Gv-g\" style=\"height: 391px; margin-left: 0px; margin-top: 0px; width: 624px;\" title=\"MẶT BÍCH THÉP \"/></span></a></p>\n<h3 dir=\"ltr\" style=\"text-align: justify;\"><strong><em>Dễ dàng tháo lắp</em></strong></h3>\n<p dir=\"ltr\" style=\"text-align: justify;\"><span style=\"background-color: transparent; font-size: 13pt;\">Vì là sản phẩm được sản xuất để ứng dụng trong trường hợp gấp rút nên mặt bích sẽ có kiểu dáng rất đơn giản, dễ dàng tháo lắp. Nó sẽ giúp việc vận hành hệ thống PCCC được nhanh chóng, mang đến kết quả chữa cháy kịp thời và tốt nhất.</span></p>\n<h3 dir=\"ltr\" style=\"text-align: justify;\"><strong><em>Đa dạng kiểu dáng</em></strong></h3>\n<p dir=\"ltr\" style=\"text-align: justify;\"><span style=\"background-color: transparent; font-size: 13pt;\">Hiện nay, trên thị trường, mặt bích đang được sản xuất với 4 loại khác nhau gồm: </span><span style=\"font-size: 13pt;\">Mặt bích thép, mặt bích nhựa, mặt bích đồng và mặt bích inox. Mỗi loại sẽ có những đặc điểm và hiệu quả sử dụng khác nhau. Tùy theo nhu cầu sử dụng của mỗi khách hàng để đưa ra sự lựa chọn dễ dàng và phù hợp nhất. Tuy nhiên, trong hệ thống </span><span style=\"font-size: 16px;\">thiết bị PCCC</span><span style=\"font-size: 13pt;\"><span style=\"font-size: 16px;\"> </span>thì sản phẩm làm từ chất liệu thép vẫn được xem là lựa chọn tối ưu nhất.</span></p>\n<p dir=\"ltr\" style=\"text-align: justify;\"><span style=\"font-size: 13pt;\">Hiện nay, các sản phẩm </span><a href=\"https://daiquangminhvina.com/mat-bich-thep\"><span style=\"color: rgb(0, 128, 0);\"><span style=\"font-size: 16px;\"><strong>Mặt bích inox </strong></span></span></a><span style=\"font-size: 13pt;\">đ</span><span style=\"background-color: transparent; font-size: 13pt;\">ang được Công ty Đại Quang Minh Steel sản xuất trên dây chuyền công nghệ hiện đại, đáp ứng được các tiêu chuẩn kỹ thuật khắt khe nhất. Sản phẩm đã được Cục đo lường chất lượng công nhận. Khách hàng chỉ cần liên hệ đến số Hotline :<span style=\"color: rgb(255, 0, 0);\"> 0919642586</span>  để có được sản phẩm chính hãng với giá tốt nhất thị trường. Chắc chắn, quý khách hàng sẽ có được sự yên tâm tuyệt đối một khi đã đặt niềm tin lựa chọn vào công ty chúng tôi.</span><span style=\"background-color: transparent; font-size: 13pt;\">ĐẠI QUANG MINH cam kết:</span></p>\n<h3 dir=\"ltr\"><span style=\"color: rgb(255, 102, 0);\"><span style=\"font-size: 16px;\"><u><span style=\"font-family: helvetica, arial, sans-serif;\">+ </span><span style=\"font-family: helvetica, arial, sans-serif;\">Nói không với hàng nhái</span><br/>\n<span style=\"font-family: helvetica, arial, sans-serif;\">+ Hàng chuẩn 100% đạt theo tiêu chuẩn quốc tế</span><br/>\n+ Giấy tờ chứng từ đầy đủ<br/>\n<span style=\"font-family: helvetica, arial, sans-serif;\">+ Miễn phí ship nội thành Hà Nội<br/>\n+ Hỗ trợ tài chính<br/>\n+ Mua càng nhiều giá càng rẻ<br/>\n+ Và nhiều ưu đãi lớn</span></u></span></span></h3>\n', 'Mặt bích inox', 0.00, 0, 0, 1, 0, 'products/f4c02720-23c0-471a-8461-c6fc81b21af9.jpg', 25, 1, NULL, NULL);
