(29, 'Đồng hồ nước thải Komax DN100', 'ng-h-n-c-th-i-komax-dn100', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b><i>Thông số kỹ thuật và thông tin sản phẩm</i></b></span></span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\">Đồng hồ nước thải Komax DN100</span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hãng sản xuất : Komax</span></span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chất liệu : thân gang </span></span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kêt nối : Bắt bích</span></span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hiển thị : mặt số hiển thị trực tiếp 99999</span></span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kích thước : dn100 , 4 Inch , phi 114</span></span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kiểu hoạt động : dẫn động từ </span></span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Model sản phẩm : KM</span></span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Lưu lượng trung bình Qn : 60m3\\h</span></span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đơn vị hiển thị nhỏ nhất : 1 m3</span></span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Áp lực làm việc : 0,3 - 16 bar</span></span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nhiệt độ làm việc : 0 - 50 độ C</span></span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hàng hóa được sự Hiệu chuẩn/kiểm định của cơ quan có thẩm quyền đo lường việt nam</span></span></p>\n', 'Đồng hồ nước thải Komax DN100', 50000.00, 0, 0, 1, 0, 'products/417705cd-42fb-46f5-b6f4-3de10129bda6.jpg', 27, 1, NULL, NULL),
