(34, 'Đồng hồ nước sạch Komax DN80', 'ng-h-n-c-s-ch-komax-dn80', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em><strong>Đồng hồ nước sạch Komax DN80 thân gang, mặt bích</strong></em> là dòng sản phẩm phù hợp sử dụng trong cho các nhà máy xí nghiệp công ty cung cấp nước sạch ,nước xả thải vì tính chính xác , ổn định và độ bền .</span></span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Vì sự chính xác và ổn định nên <em><strong>đồng hồ nước sạch komax dn80</strong></em> có thể gắn sau máy bơm , bồn xả hoặc các  vị trí đầu nguồn nước mà không ảnh hưởng đến chất lượng đo đếm thống kê nước</span></span><br/></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Với hoạt động dẫn động từ các bộ phận đếm cách ly chân không với dòng nước nên sự bền và ổn định luôn đạt cao nhất cũng như các điểm tì bánh răng truyền động không bị ăn mòn , bị hoen ố mặt số và kẹt rác rất phù hợp cho việc sử dụng để làm đồng hồ đo lưu lượng nước thải cho các khu xử lý nước thải , nước xả thải và nước đầu bơm .</span></span></p><p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Các chi tiết của đồng hồ được sản xuất tại nền công nghiệp phát triển hàng đầu châu á nên luôn đạt được sự chính xác dù là chi tiết nhỏ nhất, các chất liệu làm ra các chi tiết cũng được đảm bảo sự chống ăn mòn và chống từ tình luôn đạt được chỉ tiêu chất lượng ISO 9002</span></span></p>\n', 'Đồng hồ nước sạch Komax DN80', 1000.00, 0, 0, 1, 0, 'products/d586e0e0-1c65-4b7b-aba1-97b07a97a0c3.jpg', 27, 1, NULL, NULL),
