(39, 'Đồng hồ nước sạch Komax DN65', 'ng-h-n-c-s-ch-komax-dn65', '', '\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật và thông tin sản phẩm</span></span></p>\n<h1><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đồng hồ nước sạch Komax DN65</span></span></h1>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nhiệt độ làm việc: Max 50 độ C</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Áp lực làm việc: 16 Bar</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thân : Gang, đồng, Inox</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Vật liệu phụ: Nhựa, Inox, Jong cao su, vòng đệm...</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chuyển động: Từ tính mặt số khô dễ đọc</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tiêu chuẩn: BS</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hãng sản xuất: Komax</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Cấp độ: B</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thương hiệu Komax Hàn Quốc là lựa chọn thông minh cho Quý Khách hàng với độ bền vượt trội thời gian</span></span></p>\n<p> </p>\n', 'Đồng hồ nước sạch Komax DN65', 0.00, 0, 0, 1, 0, 'products/14d27172-f943-4339-80ab-6898522a9bab.jpg', 27, 1, NULL, NULL),
(40, 'Đồng hồ đo nước sạch DN40 Komax nối ren', 'ng-h-o-n-c-s-ch-dn40-komax-n-i-ren', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông số kỹ thuật và thông tin sản phẩm:</strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hãng sản xuất (manufacturer): Komax</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chất liệu (material): Gang (Cast Iron)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kích cỡ (size): DN40 - phi 49</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chiều dài (length): 245/300 (mm)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chiều rộng (width): 120 (mm)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chiều cao (height): 155 (mm)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Cân nặng (weight): ~ 5.1 (kg)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Cấp (class of measurament): B</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tốc độ (Speed): đa tia</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tốc độ dòng chảy lớn nhất (overload flow-rate): 20 (m<sup>3</sup>/h)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tốc độ trung bình (permanent flow-rate): 10 (m<sup>3</sup>/h)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tốc độ nhỏ nhất (minimum flow-rate): 200 (l/h)</span></span></p>\n', 'Đồng hồ đo nước sạch DN40 Komax nối ren', 0.00, 0, 0, 1, 0, 'products/87fd0630-fbcd-4512-b5eb-32c93e5cc8ee.jpg', 27, 1, NULL, NULL);
