(56, 'Ống Tiền Phong HDPE Gân Sóng 2 Lớp – Phi 800', 'ng-ti-n-phong-hdpe-g-n-s-ng-2-l-p-phi-800', '', '\n<ul>\n<li style=\"text-align: justify;\">Ống và phụ tùng nhựa HDPE 2 lớp Gân Sóng Tiền Phong được sản xuất theo tiêu chuẩn DIN EN 13476-3:2007 và ISO 21138-3:2007.</li>\n<li style=\"text-align: justify;\">Ống HDPE có cấu tạo 2 vách dạng Gân Sóng có khả năng chống chịu được điều kiện khắc nghiệt khi lắp đặt ngoài trời, lắp ngầm, chống tia UV và kháng hóa chất.</li>\n<li style=\"text-align: justify;\">Hiện nay, ống nhựa Tiền Phong HDPE Gân Sóng được sử dụng rộng rãi trong hệ thống thoát nước công nghiệp, dân dụng và bảo vệ dây cáp cho các công trình điện lực, viễn thông,…</li></ul>\n<p style=\"text-align: justify;\"> </p>\n', 'Ống Tiền Phong HDPE Gân Sóng 2 Lớp – Phi 800', 0.00, 0, 0, 1, 0, 'products/083f0269-274e-4040-9011-05e957cc6ddc.jpg', 28, 1, NULL, NULL),
