(58, 'Ống Nhiệt PPR – Nhựa Tiền Phong – Phi 200', 'ng-nhi-t-ppr-nh-a-ti-n-phong-phi-200', '', '\n<ul>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Ống và phụ tùng ống PPR Tiền Phong là lựa chọn tối ưu khi dùng để dẫn nước nóng, lạnh trong dân dụng và công nghiệp.</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Ống nhựa Tiền Phong PP-R có thể chịu được nhiệu độ đến 95ᵒC.</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Ống và phụ tùng PP-R không gây độc hại, không bị đóng cặn, đảm bảo vệ sinh an toàn thực phẩm, độ bền trên 50 năm.</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Ống và phụ tùng PP-R cách âm rất tốt, giữ nhiệt, khối lượng nhẹ hơn hẳn so với ống và phụ tùng kim loại, nên rất dễ thi công lắp đặt.</span></span></li></ul>\n', 'Ống Nhiệt PPR – Nhựa Tiền Phong – Phi 200', 0.00, 0, 0, 1, 0, 'products/85a0cc90-4142-40ef-bdee-80fde9988dbe.jpg', 28, 1, NULL, NULL),
(59, 'Ống thép đen Hòa Phát', 'ng-th-p-en-h-a-ph-t', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Ống thép đen Hòa Phát được sản xuất bằng các loại phôi thép cán mỏng, thép ống đen giữ nguyên được màu sắc ban đầu của sản phẩm và thường được ứng dụng trong nhiều ngành nghề khác nhau.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Ống thép đen Hòa Phát được ứng dụng rộng rãi trong nhiều lĩnh vực của cuộc sống:</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Xây dựng: ống thép đen thường được sử dụng trong việc thiết kế lắp đặt nhà tiền chế, các tòa nhà cao tầng, tháp ăng ten cho đến hệ thống luồn dây cáp, hệ thống PCCC…</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Công nghiệp kỹ thuật: ống thép đen thường được sử dụng trong việc làm khung máy móc thiết bị, khu sườn ô tô, xe máy, xe đạp. Các loại máy móc đòi hỏi cấu trúc chắc chắn.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Trong đời sống hằng ngày: chúng ta có thể dể dàng bắt gặp các sản phẩm được làm từ ống thép đen trong nhà như khung tủ, giường, bàn ghế, cán dao, hàng rào lan can…</span></span></p>\n', 'Ống thép đen Hòa Phát', 0.00, 0, 0, 1, 0, 'products/3fb426a9-14f5-4e25-b7f1-690a0dc73f60.jpg', 28, 1, NULL, NULL),
