(72, 'Khớp nối nhanh Camlock type E inox 304', 'kh-p-n-i-nhanh-camlock-type-e-inox-304', '', '\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kĩ thuật:</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Đường kính:</em> DN15 ~ DN250mm</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Áp suất danh định:</em> 16 ~ 64KG</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Nhiệt độ áp dụng:</em> -40 ~ 180C</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Môi trường áp dụng:</em> nước, dầu, khí và một số chất lỏng ăn mòn.</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Phạm vi ứng dụng:</em> công nghiệp, hóa chất, khí hóa lỏng.</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thiết bị sản xuất phương tiện và tàu thủy, v.v.</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Vật liệu làm kín:</em> NBR, silicone, cao su ethylene-propylene, cao su flo</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Phương pháp kết nối: </em>ren, hàn, mặt bích, kết nối nhanh, loại cờ lê, v.v.</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Tiêu chuẩn ren: </em>NPT / BSPT / BSP / DIN2999</span></span></p>\n', 'Khớp nối nhanh Camlock type E inox 304', 0.00, 0, 0, 1, 0, 'products/619088b5-6059-4797-b785-7bb79da351ea.jpg', 25, 1, NULL, NULL),
