(86, 'Vòi phun cảnh quan ROTOR RPS 75i KRain-Mỹ', 'v-i-phun-c-nh-quan-rotor-rps-75i-krain-m', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Vòi phun cảnh quan Rotor RPS® 75i được thiết kế cho các ứng dụng thương mại và dân dụng. Sự bổ sung mới này cho dòng cánh quạt của K-Rain giữ lại tất cả các tính năng và lợi ích của RPS® 75i và mang lại nhiều hơn nữa.</span></span></p>\n<h1 style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong><a href=\"https://quocthaivn.com/tuoi-canh-quan?page=1\" target=\"_blank\">Vòi phun ROTOR</a> RPS 75i KRain-Mỹ</strong></span></span></h1>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/4/19201567.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Vòi phun cảnh quan ROTOR RPS 75i Krain-Mỹ2\" src=\"https://vietannong.com.vn/_ld/4/s19201567.jpg\" title=\"Vòi phun cảnh quan ROTOR RPS 75i Krain-Mỹ2\"/></a></span></span></p>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông tin kỹ thuật <a href=\"https://quocthaivn.com/tuoi-canh-quan?page=1\" target=\"_blank\">Vòi phun ROTOR</a> RPS 75i KRain-Mỹ</strong></span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã Sản Phẩm:</strong> RPS75i<br/>\n<strong>Thương hiệu/Xuất xứ : </strong>KRain – Mỹ</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông số kỹ thuật:</strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>– Đầu vào:</strong> 3/4 “(27 mm) NPT có ren</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>– Góc phun:</strong> 40 ° – 360 °</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>– Lưu lượng:</strong> .4 – 9.7 GPM ( 0,09 – 2,2m3/h )</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>– Áp suất hoạt động:</strong> 30 – 70 PSI (2,1 – 4,8 bar)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>– Tốc độ phun:</strong> 0,22 – 1,95 in / giờ (6 – 50 mm / giờ)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>– Chiều cao tổng thể của béc (Popped Down):</strong> 7 3/8 “(19,7 cm)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>– Khoảng cách gắn đề xuất:</strong> 17 ‘- 45’ (5,2 – 13,7 m)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>– Bán kính: </strong>13 ‘- 48’ (4 – 14,6 m)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>– Quỹ đạo vòi phun:</strong> 26 °</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>– Quỹ đạo vòi phun góc thấp: </strong>11 °</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>– Bao gồm <a href=\"https://quocthaivn.com/tuoi-canh-quan?page=1\" target=\"_blank\">vòi phun</a>:</strong> 8 tiêu chuẩn, 4 góc thấp</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>– Chiều cao Riser: </strong>4 “(10,2 cm)</span></span></p>\n<p style=\"text-align: justify;\"> </p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em><img align=\"\" alt=\"Vòi phun cảnh quan ROTOR RPS 75i Krain-Mỹ 7\" src=\"https://vietannong.com.vn/_ld/4/68338004.jpg\"/></em></span></span><br/>\n </p>\n<p style=\"text-align: justify;\"> </p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Vòi phun cảnh quan ROTOR RPS 75i Krain-Mỹ1\" src=\"https://vietannong.com.vn/_ld/4/86249352.jpg\" title=\"Vòi phun cảnh quan ROTOR RPS 75i Krain-Mỹ1\"/></span></span><br/>\n </p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/4/V%C3%B2i%20phun%20c%E1%BA%A3nh%20quan%20ROTOR%20RPS%2075i%20Krain-M%E1%BB%B92.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Vòi phun cảnh quan ROTOR RPS 75i Krain-Mỹ4\" src=\"https://vietannong.com.vn/_ld/4/sV%C3%B2i%20phun%20c%E1%BA%A3nh%20quan%20ROTOR%20RPS%2075i%20Krain-M%E1%BB%B92.jpg\"/></a></span></span><br/>\n </p>\n', 'Vòi phun cảnh quan ROTOR RPS 75i KRain-Mỹ', 0.00, 0, 0, 1, 0, 'products/a6896fd1-7dfb-4ebc-ab71-eec056feded5.jpg', 32, 1, NULL, NULL),
(87, 'Bộ lọc lưới inox 27mm cho tưới cảnh quan Krain - Mỹ', 'b-l-c-l-i-inox-27mm-cho-t-i-c-nh-quan-krain-m', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ lọc lưới inox 27mm Krain - Mỹ chống rỉ sét, sử dụng lâu dài và ứng dụng linh hoạt trong các diện tích vừa và nhỏ với khuôn viên cảnh quan tại nhà.</span></span></p>\n<h2 style=\"text-align: justify;\"><strong><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/tuoi-canh-quan?page=1\">Bộ lọc lưới</a> inox 27mm cho cảnh quan Krain - Mỹ</span></span></strong></h2>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ lọc lưới inox 27mm cho cảnh quan Krain - Mỹ a\" src=\"https://vietannong.com.vn/_ld/4/33762856.jpg\"/></span></span></h2>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật của bộ lọc lưới inox 27mm - USA.</span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã hàng: </strong>KP11 - 155<br/>\n<strong>Kích thước gắn ống:</strong> 3/4\" (27mm)<br/>\n<strong>Màu sắc:</strong> Đen<br/>\n<strong>Hình lọc:</strong> Y type<br/>\n<strong>Lưới lọc: </strong>Inox 155m<br/>\n<strong>Lưu lượng:</strong> 1.2 - 1.5m3/h<br/>\n<strong>Áp suất hoạt động: </strong>&lt; 10 bar (atm)<br/>\n<strong>Nhiệt độ hoạt động:</strong> &lt; 57 độ C<br/>\n<strong>Bảo hành:</strong> 2 năm<br/>\n<strong>Xuất xứ:</strong> KRain - Mỹ<br/>\n<strong>Ứng dụng:</strong> Bộ lọc tưới cây 27mm dùng trong <a href=\"https://quocthaivn.com/tuoi-canh-quan?page=1\">hệ thống tưới nhỏ giọt</a>, tưới béc gốc và <a href=\"https://quocthaivn.com/tuoi-canh-quan?page=1\">tưới phun sương</a> cho cảnh quan - sân vườn và các khuôn viên có diện tích nhỏ.</span></span></p>\n<p style=\"text-align: justify;\"> </p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ lọc lưới inox 27mm cho cảnh quan Krain - Mỹ b\" src=\"https://vietannong.com.vn/_ld/4/06016305.jpg\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Tiện ích mở rộng:</strong><br/>\n- Dễ dàng vệ sinh khi lọc bẩn với bàn chải nhỏ<br/>\n- Giảm áp suất không đáng kể (&gt; 0.05 bar)<br/>\n- Inox chống ăn mòn và sử dụng tốt với nhiều hoá chất khác nhau<br/>\n- Bảo hành lâu dài và sử dụng tuyệt vời</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ lọc lưới inox 27mm cho tưới cảnh quan Krain - Mỹ 2\" src=\"https://vietannong.com.vn/_ld/4/99886608.jpg\"/><br/>\n<br/>\n<img align=\"\" alt=\"Bộ lọc lưới inox 27mm cho cảnh quan Krain - Mỹ c\" src=\"https://vietannong.com.vn/_ld/4/06330643.jpg\"/><br/>\n<br/>\n<img align=\"\" alt=\"Bộ lọc lưới inox 27mm cho tưới cảnh quan Krain - Mỹ 9\" src=\"https://vietannong.com.vn/_ld/4/16363947.jpg\"/></span></span></p>\n<h2 style=\"text-align: justify;\"> </h2>\n<center style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a data-fancybox-group=\"ultbx\" href=\"https://vietannong.com.vn/_ld/4/43341734.jpg\" title=\"\"><img align=\"\" alt=\"Bộ lọc lưới inox 27mm cho tưới cảnh quan Krain - Mỹ\" src=\"https://vietannong.com.vn/_ld/4/43341734.jpg\"/></a><a data-fancybox-group=\"ultbx\" href=\"https://vietannong.com.vn/_ld/4/99886608.jpg\" title=\"\"><img align=\"\" alt=\"Bộ lọc lưới inox 27mm cho tưới cảnh quan Krain - Mỹ 2\" src=\"https://vietannong.com.vn/_ld/4/99886608.jpg\"/></a><a data-fancybox-group=\"ultbx\" href=\"https://vietannong.com.vn/_ld/4/03294878.jpg\" target=\"_blank\" title=\"\"><img align=\"\" alt=\"Bộ lọc lưới inox 27mm cho cảnh quan Krain - Mỹ 5\" src=\"https://vietannong.com.vn/_ld/4/03294878.jpg\"/></a><a data-fancybox-group=\"ultbx\" href=\"https://vietannong.com.vn/_ld/4/33762856.jpg\" target=\"_blank\" title=\"\"><img align=\"\" alt=\"Bộ lọc lưới inox 27mm cho cảnh quan Krain - Mỹ a\" src=\"https://vietannong.com.vn/_ld/4/33762856.jpg\"/></a><a data-fancybox-group=\"ultbx\" href=\"https://vietannong.com.vn/_ld/4/06330643.jpg\" target=\"_blank\" title=\"\"><img align=\"\" alt=\"Bộ lọc lưới inox 27mm cho cảnh quan Krain - Mỹ c\" src=\"https://vietannong.com.vn/_ld/4/06016305.jpg\"/></a><a data-fancybox-group=\"ultbx\" href=\"https://vietannong.com.vn/_ld/4/16363947.jpg\" target=\"_blank\" title=\"\"><img align=\"\" alt=\"Bộ lọc lưới inox 27mm cho tưới cảnh quan Krain - Mỹ 9\" src=\"https://vietannong.com.vn/_ld/4/06330643.jpg\"/></a></span></span></center>\n<center style=\"text-align: justify;\"> </center>\n', 'Bộ lọc lưới inox 27mm cho tưới cảnh quan Krain - Mỹ', 0.00, 0, 0, 1, 0, 'products/e8c9ab5e-1f5f-4dbe-af48-c35d42172f31.jpg', 28, 1, NULL, NULL),
(88, 'Thân phun tưới cỏ Pro Seri 7812 KRain - Mỹ', 'th-n-phun-t-i-c-pro-seri-7812-krain-m', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thân phun tưới cỏ Pro Seri 7812 KRain - Mỹ cao 30cm được thiết kế mạnh mẽ và chắc chắn với lò xo bền, phù hợp với nhiều loại cây trồng cảnh quan và nông nghiệp. Bảo hành: 03 năm từ KRain - Mỹ.</span></span></p>\n<h1 style=\"text-align: justify;\"><strong><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/tuoi-canh-quan?page=2\">Thân phun tưới cỏ</a> Pro Seri 7812 KRain - Mỹ</span></span></strong></h1>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/4/92881717.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Thân phun tưới cỏ Pro Seri 7812 KRain - Mỹ2\" src=\"https://vietannong.com.vn/_ld/4/s92881717.jpg\"/></a></span></span></p>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật thân phun tưới cỏ Pro Seri 7812:</span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã hàng:</strong> 7812</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nhãn hiệu:</strong> KRain – USA</span></span></p>\n<ul>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất hoạt động:</strong> 1,4 – 4,8 bar (kg/cm2)</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng:</strong> 0 – 8 psi (0,6 bar) 0,20 GPM (0,76 LPM)</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đầu vào:</strong> Ren trong 21mm</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Chiều cao cơ thể tổng thể:</b></span></span>\n<ul>\n<li><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">K7812– 12 “(30cm)</span></span></li></ul></li></ul>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành:</strong> 3 năm</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kết nối được tất cả với các <a href=\"https://quocthaivn.com/tuoi-canh-quan?page=2\">miệng phun KVF</a> series và của hãng khác.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Có nắp chụp khi không sử dụng.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/4/57743474.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Thân phun tưới cỏ Pro Seri 7812 KRain - Mỹ3\" src=\"https://vietannong.com.vn/_ld/4/s57743474.jpg\"/></a></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kết quả kỹ thuật chính xác của những thử nghiệm thực tế rộng rãi từ các đơn vị thi công trên toàn thế giới, Pro-S ™ được thiết kế với độ bền và hiệu suất tưới vượt trội.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thân phun tưới này dễ dàng nhận biết bởi cấu trúc chắc chắn, thân hình gồ ghề và có nắp chụp, lò xo bên trong mạnh mẽ. Được nghiên cứu để phù hợp với những yêu cầu khó tính nhất.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/4/96299068.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Thân phun tưới cỏ Pro Seri 7812 KRain - Mỹ5\" src=\"https://vietannong.com.vn/_ld/4/s96299068.jpg\"/></a></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng: </strong>Chuyên dùng <a href=\"https://quocthaivn.com/tuoi-canh-quan?page=2\">tưới cảnh quan sân vườn</a>, tưới các công trình cây xanh như con lươn đường, bờ bao kênh, công viên nhỏ và một số ứng dụng trên cây nông nghiệp.</span></span></p>\n', 'Thân phun tưới cỏ Pro Seri 7812 KRain - Mỹ', 0.00, 0, 0, 1, 0, 'products/9df2bb26-a398-4787-86c1-48182c316375.jpg', 32, 1, NULL, NULL),
(89, 'Vòi phun ROTOR MINIPRO ® KRain- Mỹ', 'v-i-phun-rotor-minipro-krain-m', '', '\n<h2 style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/tuoi-canh-quan?page=1\">Vòi phun tưới cỏ</a>  ROTOR MINIPRO ® KRain Krain – Mỹ</span></span></h2>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đặc điểm kỹ thuật vòi phun tưới bãi cỏ diện tích lớn ProSport <a href=\"https://quocthaivn.com/tuoi-canh-quan?page=1\" target=\"_blank\">Krain – Mỹ</a>:</span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Vòi phun ROTOR MINIPRO ® KRain- Mỹ 2\" src=\"https://vietannong.com.vn/_ld/4/87165915.jpg\" title=\"Vòi phun ROTOR MINIPRO ® KRain- Mỹ 2\"/></span></span></p>\n<pre style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thương hiệu/Xuất xứ : </strong>Krain – Mỹ\n\n<strong>Thông số kỹ thuật :</strong> <strong>Đầu vào:</strong> 1/2 “(21 mm) NPT có ren\n\n<strong>– Phạm vi điều chỉnh Arc</strong>: 40 ° – 360 °\n\n<strong>– Phạm vi lưu lượng: </strong>0,8 – 3,3 GPM (3 – 12,5 LPM)\n\n<strong>– Áp suất:</strong> 20 – 70 PSI (1,4 – 4,8 bar)\n\n<strong>– Tốc độ kết tủa:</strong> .26 – .60 in / giờ (6,6 – 15,24 mm / giờ) (Tùy thuộc vào khoảng cách và vòi phun được sử dụng)\n\n<strong>– Chiều cao (Popped Down):</strong> 4 “, 6″, 12 ” (12,2 cm, 15,2 cm, 30,5 cm)\n\n<strong>– Khoảng cách :</strong> 17 ‘- 34’ (5,2 – 10,4 m)\n\n<strong>– Bán kính:</strong> 18 ‘- 33’ (5,5 – 10,1 m)\n\n<strong>– Quỹ đạo <a href=\"https://quocthaivn.com/tuoi-canh-quan?page=1\" target=\"_blank\">vòi phun</a>:</strong> 25 °\n\n<strong>– Chiều cao Riser:</strong> 4 “, 6” hoặc 12 “(12,2 cm, 15,2 cm, 30,5 cm)\n</span></span></pre>\n<pre style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/4/19918462.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Vòi phun ROTOR MINIPRO ® KRain- Mỹ 3\" src=\"https://vietannong.com.vn/_ld/4/s19918462.jpg\" title=\"Vòi phun ROTOR MINIPRO ® KRain- Mỹ 3\"/></a>\n\n<img align=\"\" alt=\"Vòi phun ROTOR MINIPRO ® KRain- Mỹ 4\" src=\"https://vietannong.com.vn/_ld/4/51994522.jpg\" title=\"Vòi phun ROTOR MINIPRO ® KRain- Mỹ 4\"/>\n\n<a href=\"https://vietannong.com.vn/_ld/4/31546118.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Vòi phun ROTOR MINIPRO ® KRain- Mỹ 5\" src=\"https://vietannong.com.vn/_ld/4/s31546118.jpg\" title=\"Vòi phun ROTOR MINIPRO ® KRain- Mỹ 5\"/></a>\n\n</span></span></pre>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong> Chi tiết :</strong></span></span></h2>\n<ul>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đầu vào – NPT luồng NPT</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Phạm vi điều chỉnh Arc – 40 đến 360 độ</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Phạm vi lưu lượng – 0,75 đến 3,3 GPM</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Xếp hạng áp suất – 20 đến 70 PSI</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tốc độ mưa – 0,22 đến 0,41 inch mỗi giờ (Tùy thuộc vào khoảng cách và vòi phun)</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chiều cao tổng thể (Popped Down) – 6 Điên</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Khoảng cách đề xuất – 5,1 đến 8,5m (17 ‘đến 28’)</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bán kính – 5,1 ma 9.0 m ( 17 ‘đến 30’)</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Quỹ đạo vòi phun – 26 độ</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chiều cao Riser – 4, 6, 12, 12</span></span></li></ul>\n', 'Vòi phun ROTOR MINIPRO ® KRain- Mỹ', 0.00, 0, 0, 1, 0, 'products/502507dc-5e05-4288-a568-be5a898a644f.jpg', 32, 1, NULL, NULL);
