(95, 'Máy bơm phun sương HP2000', 'm-y-b-m-phun-s-ng-hp2000', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đặc Điểm: </strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+Máy có kích thước tương đối nhỏ gọn, dễ dàng lắp đặt và sử dụng. </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Động cơ máy trở nên vận hành êm hạn chế việc tạo ra tiếng ồn.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Tốc độ quá trình làm mát cực nhanh hiệu quả, được sử dụng trong mọi không gian lớn nhỏ khác nhau. </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Mức độ thời gian tiêu thụ điện và nước tương đối thấp hơn. </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Quy Cách Ren: Ren trong 17 mm Quy Cách Ống: 8 mm hoặc 10 mm tùy ứng dụng </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Cân nặng: 3.354 g</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng Dụng </strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nguyên Liệu: </strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nước Ứng Dụng Sử Dụng: Sử dụng để cung cấp độ ẩm cho không khí Sử dụng để hấp thụ bụi, lọc bụi cho không khí Sử dụng làm mát cho nhà hàng, quán cafe, quán ăn Làm mát nhà máy, nông trại Sử dụng để tưới lan, tưới cây cảnh hay tưới rau Sử dụng trong hệ thống khí canh</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đơn vị:</strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ Số lượng mua tối thiểu:1 bộ. </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kĩ thuật cuả máy:   HP2000 - 35 béc Điện thế 220V Lưu lượng 2.6 LPM Áp suất 150 PSI Số béc 20 - 50 béc (35 béc là tối ưu nhất) Công suất bơm 100 W</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đến với <a href=\"https://quocthaivn.com/\">Quốc Thái</a> khách hàng sẽ được đội ngũ nhân viên giàu kinh nhiệm, luôn hết mình trong công việc tư vấn,lắp đặt máy bơm....</span></span></p>\n<p segoe=\"\" style=\"text-align: justify;\" ui=\"\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>CÔNG TY TNHH ĐẦU TƯ THƯƠNG MẠI TỔNG HỢP QUỐC THÁI</strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>* Trụ sở chính</strong></span></span></p>\n<p segoe=\"\" style=\"text-align: justify;\" ui=\"\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Địa chỉ : Số 452 Lạc Long Quân - Nhật Tân - Tây Hồ - Hà Nội.<br/>\nĐiện thoại : 024-62620585 Fax : 024-37585153<br/>\nWebsite: www.quocthaivn.com E-mail: quocthai260313@gmail.com</span></span></p>\n<p segoe=\"\" style=\"text-align: justify;\" ui=\"\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>- Cơ sở kinh doanh 01:</strong><br/>\nĐịa chỉ: Số 33b Cổ Dương - Tiên Dương - Đông Anh - Hà Nội.<br/>\nĐiện thoại: 024 37585153 Fax: 024 37585153</span></span></p>\n<p segoe=\"\" style=\"text-align: justify;\" ui=\"\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>- Cơ sở kinh doanh 02:</strong><br/>\nĐịa chỉ: Số (80 + 81) TT9 Khu đô thị Văn Phú - Phú La - Hà Đông - Hà Nội.<br/>\nĐiện thoại : 024-62620585</span></span></p>\n<p segoe=\"\" style=\"text-align: justify;\" ui=\"\"><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Hotline:</strong> 0919642586</span></span></p>\n<p> </p>\n', 'Máy bơm phun sương HP2000', 0.00, 0, 0, 1, 0, 'products/71080f3a-8a71-458a-b719-384a6fb42d96.jpg', 33, 1, NULL, NULL),
