(123, 'Van cầu rắc co 2 đầu ren 27mm Automat - Ấn Độ', 'van-c-u-r-c-co-2-u-ren-27mm-automat-n', '', '\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Van cầu rắc co 2 đầu ren 27mm Automat - Ấn Độ với chất liệu cực kỳ bền bỉ là một phần rất quan trọng trong việc hoàn thiện hệ thống tưới cây và dẫn nước - thiết kế tin xảo với độ bền trên 10 năm.</span></span></p>\n<h1><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/product/van-ren-rac-co-automat\">Van cầu rắc co</a><a href=\"https://quocthaivn.com/vat-tu-khac\"> </a>2 đầu ren 27mm Automat</span></span></h1>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van cầu rắc co một đầu ren 27mm Automat - Ấn Độ 2\" src=\"https://vietannong.com.vn/_ld/4/81309551.jpg\"/></span></span></p>\n<h2><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật van cầu rắc co 27mm cao cấp:</span></span></h2>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Mã hàng: </b>AQ26SU<br/>\n<b>Lưu lượng: </b>0 - 7.5m3/h<br/>\n<b>Áp suất hoạt động: </b>tối đa 16 bar<br/>\n<b>Chất liệu nhựa: </b>uPVC<br/>\n<b>Màu sắc: </b>Cam/Xanh<br/>\n<b>Đường kính gắn ren: </b>27mm<br/>\n<b>Quy cách kết nối:</b> 1 rắc co tháo lắp 1 đầu van<br/>\n<b>Xuất xứ:</b> Automat - India<br/>\n<b>Bảo hành:</b> 18 tháng<br/>\n<b>Ứng dụng: </b> Thường dùng kết nối đóng/mở trên đường ống chính, là một phần rất quan trọng trong việc hoàn thiện <a href=\"https://quocthaivn.com/vat-tu-tuoi-nong-nghiep\">hệ thống tưới nhỏ giọt</a>, <a href=\"https://quocthaivn.com/tuoi-phun-mua\">tưới phun mưa</a> cho cây trồng và đặc biệt rất phổ biến trong lắp ghép bộ trung tâm.</span></span></p>\n<p><span style=\"font-size:16px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van cầu rắc co một đầu ren 27mm Automat - Ấn Độ 3\" src=\"https://vietannong.com.vn/_ld/4/23038215.jpg\"/><br/>\n<br/>\n<img align=\"\" alt=\"Van cầu rắc co một đầu ren 27mm Automat - Ấn Độ 1\" src=\"https://vietannong.com.vn/_ld/4/09561502.jpg\"/></span></span></p>\n', 'Van cầu rắc co 2 đầu ren 27mm Automat - Ấn Độ', 0.00, 0, 0, 1, 0, 'products/972fd249-daba-43a7-92ff-6889570461cb.png', 25, 1, NULL, NULL),
(124, 'Van cầu rắc co hai đầu ren phi 60mm - Automat', 'van-c-u-r-c-co-hai-u-ren-phi-60mm-automat', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Van cầu rắc co hai đầu ren phi 60mm - Automat với chất liệu cực kỳ bền bỉ là một phần rất quan trọng trong việc hoàn thiện hệ thống tưới cây và dẫn nước - được thiết kế với độ bền trên 10 năm trong điều kiện khắc nghiệt.</span></span></p>\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/van-cau-rac-co-hai-dau-ren-49-mm\">Van cầu rắc co</a><a href=\"https://quocthaivn.com/vat-tu-khac\"> </a>hai đầu ren phi 60mm - Automat</span></span></h1>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van cầu rắc co hai đầu ren phi 60mm - Automat\" src=\"https://vietannong.com.vn/_ld/3/72399955.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Mô tả chi tiết vật liệu van khóa ren - rắc co</em></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van cầu rắc co hai đầu ren phi 60mm - Automat\" src=\"https://vietannong.com.vn/_ld/3/52136100.png\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Chú thích cho hình ảnh trên</em></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chi tiết thiết bị:</strong></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">* Tay quay hoạt động theo van cầu.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">* Kết nối: kiểu ren trong</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">* Áp suất tối đa của từng sản phẩm:</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Phi: 1\", 1-1 / 2\" &amp; 2\": 16 Bar / 230Psi</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Phi: 2-1 / 2\" &amp; 3\": 10 bar / 145Psi</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">* Thiết kế ren với rắc co tháo lắp rất dễ dàng khi cài đặt hoặc sửa chữa mà không cần cắt bỏ hệ thống đường ống.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">* Thiết kế thân thiện với người dùng cho phép vận hành trơn tru của tay cầm van.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">* Các vật chất dạng hàng không bị lưu giữ hoặc làm nhám bề mặt bi (cầu)</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">* Không bị rung hoặc rít trong quá trình mở và đóng van.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">* Tháo / lắp ráp van dễ dàng với cờ lê Spanner trên tay cầm.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">* Vòng đệm (roan cao su) TPE đảm bảo không rò rỉ khi hoạt động liên tục hoặc áp suất cao.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">* Chống hóa chất / ăn mòn, ổn định màu dưới tia UV.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/3/82368945.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Van cầu rắc co hai đầu ren phi 60mm - Automat Vệt An Nông\" src=\"https://vietannong.com.vn/_ld/3/s82368945.jpg\"/></a></span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật <a href=\"https://quocthaivn.com/vat-tu-khac\">van cầu rắc co hai đầu ren</a> phi 60mm:</span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã hàng: </strong>AQ - 66DUT</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng:</strong> 0 - 35 m3/giờ</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất hoạt động: </strong>tối đa 16 bar</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu nhựa: </strong>uPVC</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Màu sắc: </strong>Cam/Xanh</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính gắn ren: </strong>60mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Quy cách kết nối:</strong> 2 rắc co tháo lắp 2 đầu van</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Xuất xứ:</strong> Automat - India</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành:</strong> 18 tháng</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng: </strong>Thường dùng kết nối đóng/mở trên đường ống chính, là một phần rất quan trọng trong việc hoàn thiện <a href=\"https://quocthaivn.com/tuoi-nho-giot\">hệ thống tưới nhỏ giọt</a>, tưới phun mưa cho cây trồng và đặc biệt rất phổ biến trong lắp ghép <a href=\"https://quocthaivn.com/vat-tu-tuoi-nong-nghiep\">bộ trung tâm tưới tự động</a>.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van cầu rắc co hai đầu ren phi 60mm - Automat Vệt An Nông 2\" src=\"https://vietannong.com.vn/_ld/3/76331503.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van cầu rắc co hai đầu ren phi 60mm - Automat Vệt An Nông 1\" src=\"https://vietannong.com.vn/_ld/3/69871624.jpg\"/></span></span></p>\n', 'Van cầu rắc co hai đầu ren phi 60mm - Automat', 0.00, 0, 0, 1, 0, 'products/2bbd12f1-da5e-44ce-9dc5-67562e5e0e86.png', 25, 1, NULL, NULL);
