(133, 'Béc phun sương AQ210 Aquamic cao cấp', 'b-c-phun-s-ng-aq210-aquamic-cao-c-p', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Béc phun sương tuới hoa lan Aquamic - AQ210 cao cấp được thiết kế theo tiêu chuẩn công nghệ tốt nhất, đảm bảo yếu tố đều, mịn - thích hợp tuyệt đối cho nhà kính và hoa lan. Đặc biệt các dòng làn Var đột biến (HO, Bảo Duy, Phú Thọ, Mắt Châu...)</span></span></p>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật béc <a href=\"https://quocthaivn.com/tuoi-phun-suong?page=1\">phun sương Aquamic AQ210</a>:</span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bán kính phun:</strong> 0.8 - 1.5m</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng:</strong> 27 - 88 lít/giờ</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất hoạt động:</strong> 2.2 - 4.2 bar (kg/cm2)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất chống nhỏ nước của van áp:</strong> &lt; 0.7 bar</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Tích hợp chân cắm:</strong> Gắn ống PE, LDPE, LLDPE...</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đủ bộ gồm:</strong><br/>\n- Kiểu 1: Chân cắm, dây 6mm, van chống nhỏ giọt, đối trọng và béc phun<br/>\n- Kiểu 2: Chân ren ngoài 21mm + van chống nhỏ giọt + béc phun</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành:</strong> 18 tháng</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Xuất xứ: </strong>Ấn Độ</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Sử dụng nhiều trong hệ thống tưới cây vườn ươm, <a href=\"https://quocthaivn.com/tuoi-phun-suong?page=1\">tưới phun sương</a> hoa lan, (đặc biệt lan phi điệp đột biến), tưới trong nhà kính...</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Béc tưới phun sương hoa lan cao cấp aquamic\" src=\"https://vietannong.com.vn/_ld/2/74872563.jpg\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Béc phun sương tỏa tròn Aquamic tuoi hoa lan - Automat Ấn Độ\" src=\"https://vietannong.com.vn/_ld/2/08268395.jpg\"/></span></span></p>\n', 'Béc phun sương AQ210 Aquamic cao cấp', 1.00, 0, 0, 1, 0, 'products/c856f036-9946-4478-9840-aec7737d50f1.png', 33, 5, NULL, NULL),
(134, 'Bộ tưới gồm các béc phun sương - Tưới hoa lan, làm mát.', 'b-t-i-g-m-c-c-b-c-phun-s-ng-t-i-hoa-lan-l-m-m-t', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tưới phun sương hoa lan, cây treo giàn Tưới phun sương làm mát mái nhà, môi trường Tưới phun sương vườn hoa, cây cảnh Tưới phun sương nông nghiệp</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b><a href=\"https://quocthaivn.com/tuoi-phun-suong?page=2\">Béc phun sương</a> làm mát - Giải pháp tiện ích cho mọi không gian sống</b><br/>\nChúng ta đang sống trong thời kỳ biến đổi khí hậu rõ rệt nhất. Thời tiết mưa nắng thất thường, khí hậu luôn trong tình trang oi bức cực độ.<br/>\nChúng ta luôn có cảm giác khó chịu và cáu gắt khi đi ra đường trong giờ cao điểm, kẹt xe, khói bụi hoặc nắng nóng. <br/>\nVì thế theo xu hướng chung mọi người đã và đang hình thành những mô hình, những thú tiêu khiển và cũng là để đảm bảo sức khỏe, chống chọi sự biến đổi khắc nghiệt của thời tiết. Mọi người dần xây dựng trong nhà mình, trên sân thường, trước ban công, ở sân sau, sân trước những khu vườn nhỏ xanh mướt, trồng đủ loại rau, hoa, củ, quả để tạo bầu không khí mát mẻ, gần gũi thiên nhiên, giảm stress và lại có thực phẩm Tươi Sạch.<br/>\nĐể giúp không gian xanh của mọi người luôn tươi tốt, Việt An Nông sẵn sàng cung cấp mọi giải pháp tốt nhất cho cuộc sống của gia đình mọi người luôn Trong Lành, mặc kệ ngoài kia biến đổi khí hậu hay kẹt xe như thế nào.<br/>\n<b>Các giải pháp mang lại như sau:</b><br/>\n<i><a href=\"https://quocthaivn.com/bi-quyet-chon-bec-tuoi-lan-tu-cac-chuyen-gia-co-kinh-nghiem-trong-lan-lau-nam\"><strong>Tưới phun sương hoa lan</strong></a>, chậu cây treo tường...</i></span></span></p>\n<p style=\"text-align: justify;\"> </p>\n<p style=\"text-align: justify;\"> </p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/1/41721483.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" src=\"https://vietannong.com.vn/_ld/1/s41721483.jpg\"/></a><br/>\n<a href=\"https://vietannong.com.vn/_ld/1/22605583.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" src=\"https://vietannong.com.vn/_ld/1/s22605583.jpg\"/></a></span></span></p>\n<p style=\"text-align: justify;\"> </p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><i>Tưới phun sương làm mát mái nhà</i></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/1/59943287.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" src=\"https://vietannong.com.vn/_ld/1/s59943287.jpg\"/></a></span></span></p>\n<p style=\"text-align: justify;\"><br/>\n<span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><i>Tưới phun sương giảm nhiệt, giảm bụi</i></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"http://4.bp.blogspot.com/-4_A4uw8I1Vg/VV26EWrf1xI/AAAAAAAAAW0/8y-HolfIQxI/s1600/201311121735_he_thong_phun_suong_quan_caf.jpg\" imageanchor=\"1\"><img align=\"\" src=\"https://vietannong.com.vn/_ld/1/66966291.jpg\"/></a></span></span></p>\n<p style=\"text-align: justify;\"><br/>\n<span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><i>Tưới <a href=\"http://www.tuoicanhquansanvuon.com/search/label/T%C6%B0%E1%BB%9Bi-Phun-S%C6%B0%C6%A1ng\">phun sương </a>cho vườn hoa, cây cảnh</i></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"http://2.bp.blogspot.com/-Ttio2OKws2s/VV272eDmukI/AAAAAAAAAXA/wPhdXwAfJ1Y/s1600/s93886969.jpg\" imageanchor=\"1\"><img align=\"\" src=\"https://vietannong.com.vn/_ld/1/77234887.jpg\"/></a></span></span></p>\n<p style=\"text-align: justify;\"><br/>\n<span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Các <a href=\"https://quocthaivn.com/tuoi-phun-suong\">béc tưới phun </a>sương được lựa chọn cung cấp.</b><br/>\n- Béc phun sương bọ Úc<br/>\nBán kính phun: 0.5 - 1.5m<br/>\nLưu lượng: 25 - 40l/h<br/>\nÁp suất hoạt động: 0.8 - 4.2 bar<br/>\nXuất xứ: Úc</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"http://4.bp.blogspot.com/-CGpVRBx-CRg/VV28noyPMWI/AAAAAAAAAXI/GAzXDgzVgQo/s1600/95833678.jpg\" imageanchor=\"1\"><img align=\"\" src=\"https://vietannong.com.vn/_ld/1/10246267.jpg\"/></a></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/1/66448552.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" src=\"https://vietannong.com.vn/_ld/1/s66448552.jpg\"/></a></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- <a href=\"https://vietannong.com.vn/bec-tuoi-phun-suong-bon-huong\">Béc phun sương coolnet</a> - Israel 4 hướng.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bán kính phun: 0.5 - 1.5m<br/>\nLưu lượng: 25 - 40l/h<br/>\nÁp suất hoạt động: 0.8 - 4.2 bar<br/>\nXuất xứ: Israel</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"http://4.bp.blogspot.com/-i_QFGEky_TA/VV2-ewUsq5I/AAAAAAAAAXg/Fjy0mlWVYes/s1600/voi%2Bphun%2Bsuong%2Bcoolnet.jpg\" imageanchor=\"1\"><img align=\"\" src=\"https://vietannong.com.vn/_ld/1/76247098.jpg\"/></a></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/1/16447526.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" src=\"https://vietannong.com.vn/_ld/1/s16447526.jpg\"/></a></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><i>- Béc phun sương 4 hướng - Đài Loan</i></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bán kính phun: 0.5 - 1.5m<br/>\nLưu lượng: 25 - 40l/h<br/>\nÁp suất hoạt động: 0.8 - 4.2 bar<br/>\nXuất xứ: Đài Loan</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"http://2.bp.blogspot.com/-Oj1pYKAunYo/VV2_2y6c-rI/AAAAAAAAAX0/s0jnFjfrA5Y/s1600/phun%2Bsuong%2B4%2Bhuong.jpg\" imageanchor=\"1\"><img align=\"\" src=\"https://vietannong.com.vn/_ld/1/17751619.jpg\"/></a></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><i>- Béc phun sương chống tắt</i></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bán kính phun: 0.5 - 1.5m<br/>\nLưu lượng: 25 - 40l/h<br/>\nÁp suất hoạt động: 0.8 - 4.2 bar<br/>\nXuất xứ: Hàn Quốc</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"http://3.bp.blogspot.com/-hycK7NGkaWo/VV3ARw6DlUI/AAAAAAAAAX8/OfNF85SV2Uw/s1600/phun%2Bsuong%2Bchong%2Btat.jpg\" imageanchor=\"1\"><img align=\"\" src=\"https://vietannong.com.vn/_ld/1/21868225.jpg\"/></a></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/1/25527822.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" src=\"https://vietannong.com.vn/_ld/1/s25527822.jpg\"/></a></span></span></p>\n<p> </p>\n', 'Bộ tưới gồm các béc phun sương - Tưới hoa lan, làm mát.', 0.00, 0, 0, 1, 0, 'products/69fc57d5-bd13-44ed-88d1-dea0b66102bd.png', 33, 1, NULL, NULL),
(135, 'Van giảm áp phi 34 (tưới nhỏ giọt)', 'van-gi-m-p-phi-34-t-i-nh-gi-t', '', '\n<table border=\"0\" cellpadding=\"2\" cellspacing=\"0\" width=\"100%\">\n<tbody>\n<tr>\n<td>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Van giảm áp phi 34 (tưới nhỏ giọt)</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van giảm áp phi 34 (tưới nhỏ giọt)\" src=\"http://shop.vietannong.com.vn/_bd/2/91391129.jpg\"/></span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông số kỹ thuật:</strong></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu: </strong>POM</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính:</strong> 34mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất: </strong>1.75 bar</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Quy cách: </strong>Ren trong - ren ngoài 34mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Màu sắc: </strong>Xanh - Đen</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành:</strong> 06 tháng</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng: </strong>Dùng điều giảm áp lực dòng nước, bảo đảm hệ thống đường ống không bị vỡ đột ngột khi áp lực nước quá mạnh, sử dụng nhiều trong <a href=\"https://quocthaivn.com/bec-tuoi-nho-giot?page=1\">hệ thống tưới nhỏ giọt</a> cây rau màu, cây ăn quả...</span></span></p>\n<p><span style=\"font-size:14px;\