(136, 'Béc tưới phun mưa FCV-2043', 'b-c-t-i-phun-m-a-fcv-2043', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Béc phun tưới nông<br/>\nnghiệp phun mưa tiết kiệm,góc tưới<br/>\n360 độ, có điều chỉnh lưu lượng, thân<br/>\nxoay ,F: 50-100L/H, R:0,5~4,5m,<br/>\ncắm ống 6mm, chất liệu bằng nhựa.</span></span></p>\n', 'Béc tưới phun mưa FCV-2043', 0.00, 0, 0, 1, 0, 'products/61355822-c504-4399-9ffc-3d45bde32e23.png', 35, 1, NULL, NULL),
