(142, 'Dây dẻo đen 5mm (dây 5 ly - thường)', 'd-y-d-o-en-5mm-d-y-5-ly-th-ng', '', '\n<h2><span style=\"font-size:14px;\"><strong>Dây dẻo đen 5mm (dây 5 ly)</strong></span></h2>\n<h2 style=\"text-align: center;\"><img data-thumb=\"original\" original-height=\"386\" original-width=\"450\" src=\"//bizweb.dktcdn.net/100/168/021/products/day-deo-den-5mm.jpg?v=1627724909277\"/></h2>\n<p><span style=\"font-size:14px;\"><strong>Thông số kỹ thuật:</strong></span></p>\n<p><span style=\"font-size:14px;\"><strong>Độ dày: </strong>1.0 - 1.5mm</span></p>\n<p><span style=\"font-size:14px;\">Cực kỳ bền với thời tiết khắc nghiệt.</span></p>\n<p><span style=\"font-size:14px;\">Độ bền sử dụng trên 5 năm.</span></p>\n<p><span style=\"font-size:14px;\"><strong>Ứng dụng tưới. </strong></span></p>\n<p><span style=\"font-size:14px;\">- Lắp <a href=\"https://quocthaivn.com/tuoi-nho-giot\">đầu </a><strong><a href=\"https://quocthaivn.com/tuoi-nho-giot\">tưới nhỏ giọt</a> </strong>cho các cây trồng đa vụ, cây cảnh quan, cây lâm nghiệp</span></p>\n<p><span style=\"font-size:14px;\">- Lắp <a href=\"https://quocthaivn.com/tuoi-nho-giot\">béc </a><strong><a href=\"https://quocthaivn.com/tuoi-nho-giot\">tưới con bọ</a> </strong>nhỏ trong dự án  <strong>tưới</strong> tiết kiệm nước Hồ Tiêu, cà phê,...</span></p>\n<p><span style=\"font-size:14px;\"><b>Quy cách: Một cuộn 33m</b></span></p>\n<p> </p>\n', 'Dây dẻo đen 5mm (dây 5 ly - thường)', 0.00, 0, 0, 1, 0, 'products/5411afea-8cb2-486e-b789-01db6957127f.jpg', 28, 1, NULL, NULL),
(143, 'Bộ điều khiển tưới cây tích hợp van điện phi 34mm Israel', 'b-i-u-khi-n-t-i-c-y-t-ch-h-p-van-i-n-phi-34mm-israel', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bồ điều khiển tưới cây</strong> tích hợp van điện phi 34mm Israel hoàn toàn không thấm nước và có thể hoạt động trong môi trường khắc nghiệt, dễ dàng và thuận tiện tưới cây mọi lúc, ứng dụng trong các lĩnh vực: tưới sân vườn, cây ban công, tưới nông nghiệp,…</span></span></p>\n<h1 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/he-thong-dieu-khien?page=4\" target=\"_blank\">Bộ điều khiển tưới cây</a> tích hợp van điện phi 34mm Israel</span></span></h1>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật bộ điều khiển tưới cây <a href=\"https://quocthaivn.com/he-thong-dieu-khien?page=4\" target=\"_blank\">van điện 34mm</a> Baccara – Israel:</span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã sản phẩm:</strong> G75C – 1</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Hãng sản xuất:</strong> Baccara – Israel</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Năng lượng sử dụng:</strong> PIN Ankaline 9V</span></span></p>\n<ul>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chất lượng PIN đảm bảo sử dụng trên 1 năm</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Sao lưu bộ nhớ khi hết pin</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Các mức cảnh bảo pin yếu</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Màn hình LCD tiết kiệm năng lượng</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tích hợp đi kèm pin</span></span></li></ul>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Số lần bật/tắt (on/off):</strong> 3 lần trên 1 ngày</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thời gian hiển thị:</strong> Tất cả các ngày trong tuần hoặc theo tùy chỉnh</span></span></p>\n<h3 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tiện ích mở rộng của<a href=\"https://quocthaivn.com/he-thong-dieu-khien?page=4\"> bộ hẹn giờ</a> G75C – 1 Baccara:</span></span></h3>\n<ul>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hoạt động trong điều kiện nhiệt độ từ -10 đến 60 độ C</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kết nối được với tất cả Solenoid từ 28mm đường kính trở lên, có thể đặt ngang hoặc dọc bộ điều khiển</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Khoan ốc gắn tường cũng là một lợi thế của thiết bị Baccara này</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Có thể thao rời di chuyển (phụ thuộc vào chiều dài dây điện)</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tương thích với mọi cục Solenoid có điện trở R – 4Ω</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Có thể điều khiển được tất cả các van từ 28mm đường kính trở lên</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đồng hồ đếm thời gian thực</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tính năng hiện thị xem chương trình trực tiếp trên màn hình chính</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nhiều tình năng tùy biến như PIN mặt trời, sạc, khác…</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tiêu chuẩn chất lượng, xuất xứ: CE</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tiêu chuẩn an toàn kỹ thuật, chống nước: IP67, NEMA 4x</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">G75C – 1 điều khiển được 1 van điện từ phi 34mm</span></span></li></ul>\n', 'Bộ điều khiển tưới cây tích hợp van điện phi 34mm Israel', 0.00, 0, 0, 1, 0, 'products/d34583fe-dda1-47b5-a8fa-b846092b224a.jpg', 31, 1, NULL, NULL),
(144, 'Van điện từ 24V proseri 150 phi 34mm của KRain – Mỹ', 'van-i-n-t-24v-proseri-150-phi-34mm-c-a-krain-m', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ van điện từ ProSeries 150 của K-Rain chuyên dùng điều khiển tưới tự động. Van 1 ” (34mm) có thể tháo rời bên ngoài, giúp dễ dàng bảo dưỡng ngoài ra có van tay giúp xả nước dễ dàng khi gặp sự cố với bộ phận Solenoid.</span></span></p>\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Van điện từ 24V proseri 150 phi 34mm của KRain – Mỹ</span></span></h1>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đặc điểm kỹ thuật van điện từ 24V proseri 150 phi 34mm của KRain – Mỹ:</span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã hàng:</strong> VK7101</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thương hiệu:</strong> KRain – Mỹ</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất hoạt động:</strong> 0.7 – 10.5 bar</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất hao hụt:</strong> 0.035 bar</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng:</strong> 1.2 – 7.0 m3/h</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nguồn điện:</strong> 24V – AC</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành:</strong> 02 năm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nhà sản xuất:</strong> KRain – Mỹ</span></span></p>\n', 'Van điện từ 24V proseri 150 phi 34mm của KRain – Mỹ', 0.00, 0, 0, 1, 0, 'products/44bb68b8-29f7-485d-9eec-d5387118793f.jpg', 31, 1, NULL, NULL);
