(163, 'Timer hẹn giờ tưới cây 2 khu vực - CO4002 Úc', 'timer-h-n-gi-t-i-c-y-2-khu-v-c-co4002-c', '', '\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/he-thong-dieu-khien\">Timer hẹn giờ tưới </a>cây 2 khu vực - CO4002</span></span></h1>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Timer hẹn giờ tưới cây 2 khu vực - CO4002 Úc 2\" src=\"https://vietannong.com.vn/_ld/4/66133823.jpg\"/></span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật WHIZ200 Holman - Úc:</span></span></h2>\n<ul>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bật/tắt: 4 lần/1 ngày.</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">2 khu vực tưới riêng biệt cùng chức năng.</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tưới nước theo từng khu vực, nhiều tùy chọn tưới khác nhau.</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Dễ dàng cài đặt lịch tưới khác nhau cho mỗi ngày.</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Có thể chọn được chế độ tưới ngay lập tức.</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Lập trình điện tử linh hoạt và trực quan.</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tưới liên tục các ngày trong tuần và dễ dàng lựa chọn được khoảng thời gian tưới.</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thời gian chạy từ 1 phút cho đến 6 giờ đố, thích ứng được với nguồn nước áp suất thấp.</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kết hợp 2 ron chống ròi rỉ nước tại đầu vào và đầu ra.</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nút bấm sử dụng dễ dàng thuận tiện.</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Màn hình LCD lớn hiển thị rõ ràng.</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Góc nhìn màn hình rộng hơn.</span></span></li></ul>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nhiều lựa chọn để tưới cây: Tất cả các nhu cầu tưới nước cho cây được tổng hợp từ việc bảo trì thảm cỏ đến chăm sóc hoa vườn hoa đầy tinh tế. Bao gồm việc có thể lập kế hoạch để sử dụng vòi xịt, hệ thống nhỏ giọt và…</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Dễ dàng chuyển sang tưới nước thủ công: Cho dù bạn muốn rửa xe, làm sạch vỉa hè hay sử dụng vòi xịt cho các công việc khác, bạn có thể dễ dàng chuyển sang tưới nước thủ công. Không cần điều chỉnh hẹn giờ. Chỉ cần một công tắc đơn giản khi bạn cần sử dụng vòi phun.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Timer hẹn giờ tưới cây 2 khu vực - CO4002 Úc 3\" src=\"https://vietannong.com.vn/_ld/4/60707317.jpg\"/><br/>\n<img align=\"\" alt=\"Timer hẹn giờ tưới cây 2 khu vực - CO4002 Úc 5\" src=\"https://vietannong.com.vn/_ld/4/83776648.jpg\"/></span></span></p>\n', 'Timer hẹn giờ tưới cây 2 khu vực - CO4002 Úc', 0.00, 0, 0, 1, 0, 'products/6e7c0c7a-42d5-4dc0-80eb-c0eed245edd1.png', 31, 1, NULL, NULL),
(164, 'Bộ hẹn giờ tưới cây tự động digital – CO3005 Holman - Úc', 'b-h-n-gi-t-i-c-y-t-ng-digital-co3005-holman-c', 'CO3005', '\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ <a href=\"https://quocthaivn.com/he-thong-dieu-khien\">hẹn giờ tưới cây tự động </a>digital – CO3005 </span></span></h1>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tưới cây tự động digital – CO3005 Holman - Úc 7\" src=\"https://vietannong.com.vn/_ld/3/22181905.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông số kỹ thuật:</strong></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã hàng: CO3005</strong></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất hoạt động từ:</strong> 0.6 – 6 bar</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nhiệt độ ổn định từ:</strong> 3 – 50 độ C</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thời gian hẹn:</strong> Bât/Tắt 4 lần trên 1 ngày</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thương hiệu:</strong> Holman - Úc</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tưới cây tự động digital – CO3005 Holman - Úc 4\" src=\"https://vietannong.com.vn/_ld/3/19736214.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Tiện ích mở rộng của<a href=\"https://quocthaivn.com/he-thong-dieu-khien\"> bộ hẹn giờ tưới cây</a> tự động CO3005:</strong></span></span></p>\n<ul>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kết nối với vòi nước có chuẩn ren 21mm hoặc 27mm.</span></span></li>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tốc độ dòng chảy lên tới 24 lít trên phút tại áp suất 2 bar (kg/cm2)</span></span></li>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Lập trình cực kỳ dễ dàng chỉ với 6 nút bấm và một màn hình LCD lớn.</span></span></li>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thời gian hiển thị: AM/PM. Thời gian tưới nước từ 1 phút đến 12 giờ 59 phút.</span></span></li>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tưới tất cả các ngày trong tuần. </span></span></li>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chương trình giám sát tuổi thọ Pin điện tử giúp biết được lượng Pin còn lại.</span></span></li>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Có năm mức báo lượng pin tiêu thụ là: 4, 3, 2, 1 vạch và sau đó hiển thị cuối.</span></span></li>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tự động khóa van để đảm bảo bộ hẹn giờ không thể mở khi Pin yếu.</span></span></li>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Pin 9V Ankaline, mức tiêu thụ lượng Pin cực kỳ thấp (ít hơn 20 micro amps ở chế độ chờ) đảm bảo tuổi thọ Pin lâu dài.</span></span></li>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Các thao tác bằng tay dễ dàng với các nút Khởi Động và Dừng.</span></span></li>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chế độ tưới khi trời mưa được kích hoạt bằng cách giữ phím OFF trong 3 giây.</span></span></li>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Lưu lượng nước đi qua lớn ở áp suất hoạt động bình thường.</span></span></li>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kết nối vòi nước có áp suất cao dễ làm bung roan cao su chống rò rỉ nước.</span></span></li>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Áp suất hoạt động từ: 0.6 – 6 bar</span></span></li>\n<li data-placeholder=\"Bản dịch\" dir=\"ltr\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nhiệt độ ổn định từ 3 – 50 độ C</span></span></li></ul>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tưới cây tự động digital – CO3005 Holman - Úc\" src=\"https://vietannong.com.vn/_ld/3/10443172.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tưới cây tự động digital – CO3005 Holman - Úc\" src=\"https://vietannong.com.vn/_ld/3/97368850.jpg\"/></span></span></p>\n', 'Bộ hẹn giờ tưới cây tự động digital – CO3005 Holman - Úc', 0.00, 0, 0, 1, 0, 'products/b38d0cfc-f41f-442c-b513-e1bd8efcbfcf.png', 31, 1, NULL, NULL),
(165, 'Bộ hẹn giờ tưới cây qua bluetooth CO3015 Holman - Úc', 'b-h-n-gi-t-i-c-y-qua-bluetooth-co3015-holman-c', '', '\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/he-thong-dieu-khien\">Bộ hẹn giờ tưới cây</a> qua bluetooth CO3015 </span></span></h1>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tưới cây qua bluetooth CO3015 Holman - Úc\" src=\"https://vietannong.com.vn/_ld/3/03308432.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông số kỹ thuật:</strong></span></span></p>\n<ul>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu:</strong> Nhựa</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nguồn pin sử dụng:</strong> Alkaline 9V</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thời gian:</strong> 3 lần bật/tắt trên 1 ngày</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kèm theo ứng dụng test nước ngay lập tức</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Phạm vi kiểm soát bluetooth lên tới 20m</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thương hiệu:</strong> Holman - Úc</span></span></li></ul>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tưới cây qua bluetooth CO3015 Holman - Úc\" src=\"https://vietannong.com.vn/_ld/3/63377596.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Các bước cài đặt và vận hành bộ <a href=\"https://quocthaivn.com/he-thong-dieu-khien\">hẹn giờ tưới cây qua bluetooth</a> CO3015:</strong></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">1.) Tải xuống ứng dụng Holman iWater. Vui lòng truy cập App Store hoặc Google Play và tìm kiếm “Holman Water”. Bạn sẽ có thể tải xuống ứng dụng Holman trực tiếp từ đó.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Lưu ý trên IOS: Bạn cần có tài khoản Apple để có quyền truy cập vào cửa hàng. Ứng dụng Holman là miễn phí cho tất cả.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">2.) Chọn thiết bị Bluetooth được yêu cầu. Nhấn vào tùy chỉnh múi giờ. Sau khi bạn tải ứng dụng Holman, bạn được cung cấp tùy chọn để chọn giữa các thiết bị Bluetooth khác nhau. Chọn bộ hẹn giờ sẵn có và tiến hành cài đặt thời gian tưới như bạn mong muốn.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">3.) Chọn số thứ tự của bộ hẹn giờ cần tưới từ 1 – 8. Mở trang chương trình và cài đặt yêu cầu của bạn chọn 1 hoặc tối đa 8 lần nhấn trên bộ hẹn giờ.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Để Ứng dụng hoạt động chính xác, bạn sẽ cần phải chọn đúng 1 bộ hẹn giờ mà bạn muốn tưới trong 8 bộ (nếu có)</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Còn nếu bạn chỉ có 1 bộ hẹn giờ thì bạn cho núm xoay mặc định về số 1 trên bảng điều khiển.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Sau đó phần còn lại bạn thực hiện trên ứng dụng iWater.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tưới cây qua bluetooth CO3015 Holman - Úc\" src=\"https://vietannong.com.vn/_ld/3/53376306.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tưới cây qua bluetooth CO3015 Holman - Úc\" src=\"https://vietannong.com.vn/_ld/3/18521469.jpg\"/></span></span></p>\n', 'Bộ hẹn giờ tưới cây qua bluetooth CO3015 Holman - Úc', 0.00, 0, 0, 1, 0, 'products/3ace1baa-df42-4638-a86a-7f01b1fe87c3.png', 31, 1, NULL, NULL),
(166, 'Bộ hẹn giờ tưới cây năng lượng mặt trời EVO1001', 'b-h-n-gi-t-i-c-y-n-ng-l-ng-m-t-tr-i-evo1001', '', '\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/he-thong-dieu-khien\">Bộ hẹn giờ tưới cây</a> Pin mặt trời EVO1001</span></span></h1>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tưới cây năng lượng mặt trời EVO1001\" src=\"https://vietannong.com.vn/_ld/3/20514928.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông số kỹ thuật:</strong></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã hàng:</strong> EVO1001</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thời gian hẹn:</strong> 4 lần bật/tắt trên ngày</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất tối đa:</strong> 6.8 bar (kg/cm2)</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thương hiệu:</strong> Holman – Úc</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tưới cây năng lượng mặt trời EVO1001\" src=\"https://vietannong.com.vn/_ld/3/95279120.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Tính năng mở rộng của timer EVO1001:</strong></span></span></p>\n<ul>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Pin năng lượng mặt trời đạt tiêu chuẩn với thời gian lưu PIN dài</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Dễ dàng cài đặt và lập trình tưới</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bảy nút bấm và màn hình lớn, có độ phân giải cao</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Màn hình LCD dễ đọc, thời gian kiểu đồng hồ AM / PM </span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông báo nhấp nháy vào những ngày bộ hẹn giờ kết thúc hoạt động</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Định dạng thời gian 12 hoặc 24 giờ</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ nhớ lưu trữ chương trình lâu dài khi hết PIN (tới 99 ngày)</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tưới tay được ngay khi bấm nút tưới thủ công</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ kết nối vòi nước nhanh chóng và dễ dàng lắp đặt.</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Một nút chọn chế độ nghỉ khi không hoạt động</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tính năng bảo tồn Pin, tự động tắt màn hình hẹn giờ sau khi tưới 15 phút</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đồng hồ đo mức công suất tiêu thụ Pin</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hoạt động bán tự động, tự động hoặc thủ công</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Van tiết lưu lưu lượng cao với DC solenoid cài sẵn bên trong với đầu ren kết nối 3/4” (27mm)</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Dễ dàng kết nối với cảm biến mưa thông qua dây bên ngoài</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Không thấm nước, chất liệu nhựa thân thiện với môi trường.</span></span></li></ul>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tưới cây năng lượng mặt trời EVO1001\" src=\"https://vietannong.com.vn/_ld/3/71139265.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tưới cây năng lượng mặt trời EVO1001\" src=\"https://vietannong.com.vn/_ld/3/90228324.jpg\"/></span></span></p>\n', 'Bộ hẹn giờ tưới cây năng lượng mặt trời EVO1001', 0.00, 0, 0, 1, 0, 'products/2a502edf-82ff-4f3d-b6d1-d60c68516988.png', 31, 1, NULL, NULL),
(167, 'Bộ điều khiển tưới cây qua bluetooth II.RI Baccara – Israel', 'b-i-u-khi-n-t-i-c-y-qua-bluetooth-ii-ri-baccara-israel', '', '\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/he-thong-dieu-khien\">Bộ điều khiển tưới cây</a> qua bluetooth Baccara</span></span></h1>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ điều khiển tưới cây qua bluetooth II.RI Baccara – Israel 1\" src=\"https://vietannong.com.vn/_ld/3/64461824.jpg\"/></span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật bộ điều khiển<a href=\"https://quocthaivn.com/he-thong-dieu-khien\"> van điện từ</a> qua bluetooth II.RI</span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã sản phẩm:</strong> II.RI</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Hãng sản xuất:</strong> Baccara - Israel</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Năng lượng sử dụng:</strong> Pin Lithium</span></span></p>\n<ul>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chất lượng PIN đảm bảo sử dụng trên 3 năm</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Lưu lịch tưới trên Smart phone</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Các mức cảnh bảo pin yếu</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Không màn hình, chỉ 1 nút bấm <a href=\"https://quocthaivn.com/he-thong-dieu-khien\">kết nối bluetooth</a></span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tích hợp đi kèm pin Lithium</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tích hợp đi kèm cục Solenoid</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Điều khiển được tất cả các size van từ 16mm đến 60mm</span></span></li></ul>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ điều khiển tưới cây qua bluetooth II.RI Baccara – Israel 2\" src=\"https://vietannong.com.vn/_ld/3/30760404.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Số lần bật/tắt (on/off):</strong></span></span></p>\n<ul>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Mở được nước ngay, sau khi bật thiết bị để tưới</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đặt lịch tưới trước: 6 lần/ngày (tối đa)</span></span></li></ul>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chế độ tưới chủ động và tùy loại cây trồng:</strong></span></span></p>\n<ul>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tưới hàng tuần (Weekly Plan)</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tưới theo ngày cụ thể ( Interval Days)</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tưới ngày chẵn/lẻ (Even/Odd)</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Cây trồng trên cửa sổ (Herb garden)</span></span></li></ul>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ điều khiển tưới cây qua bluetooth II.RI Baccara – Israel 3\" src=\"https://vietannong.com.vn/_ld/3/58355573.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Tải ứng dụng trên smart phone bằng quét mã QR hoặc truy cập G-play, App Store:</strong></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ điều khiển tưới cây qua bluetooth II.RI Baccara – Israel 5\" src=\"https://vietannong.com.vn/_ld/3/58515422.png\"/></span></span></p>\n<h3><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em><strong>Tiện ích mở rộng của <a href=\"https://i-green.com.vn/danh-muc/bo-hen-gio-tu-dong/\" rel=\"noopener\" target=\"_blank\">bộ hẹn giờ</a><a href=\"https://quocthaivn.com/he-thong-dieu-khien\"> </a>II.RI Baccara:</strong></em></span></span></h3>\n<ul>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hoạt động trong điều kiện nhiệt độ từ -10 đến 60 độ</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Sử dụng tốt nhất với hệ thống lọc đầu dòng nước</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Áp suất nước: 1 – 8 bar (kg/cm2)</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kết hợp với tất cả các van có chuẩn ren Solenoid 3/4″ UNEF</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tự động tắt sau 5 phút khi không có kết nối thiết bị – tiết kiệm PIN</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Báo PIN yếu trên ứng dụng Smart phone (Android/IOS)</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tiêu chuẩn chất lượng, xuất xứ: CE</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tiêu chuẩn an toàn kỹ thuật, chống nước: IP68</span></span></li></ul>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ điều khiển tưới cây qua bluetooth II.RI Baccara – Israel 7\" src=\"https://vietannong.com.vn/_ld/3/89236940.jpg\"/></span></span></p>\n', 'Bộ điều khiển tưới cây qua bluetooth II.RI Baccara – Israel', 0.00, 0, 0, 1, 0, 'products/65f0582f-9830-4e6f-ba56-3c69da891888.png', 31, 1, NULL, NULL),
(168, 'Van cân bằng áp hydraulic bằng đồng phi 60mm Automat', 'van-c-n-b-ng-p-hydraulic-b-ng-ng-phi-60mm-automat', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Van cân bằng áp hydraulic bằng đồng phi 60mm Automat được vận hành dựa trên áp lực được cài đặt tại cục điều khiển (pilot). Chỉ cài mức áp giảm. Duy trì áp đường ống. Nước qua van này được giữ áp lực theo cài đặt mong muốn ban đầu.</span></span></p>\n<h1 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Van cân bằng áp hydraulic bằng đồng phi 60mm</span></span></h1>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van cân bằng áp hydraulic bằng đồng phi 60mm Automat\" src=\"https://vietannong.com.vn/_ld/3/01495557.jpg\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đặc điểm nổi bật của thiết bị:</strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thiết kế đơn giản và mạnh mẽ, chỉ gồm 4 phần liên quan nhau.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thân và nắp chụp của van bằng đồng thau giúp cho độ bền cao hơn và chống ăn mòn.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nắp của van có roan cao su được gia tốt nhất giúp vận hành trơn tru mà không bị biến dạng ở áp suất cao khi xảy ra việc đóng nước bất ngờ.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thời gian tải nước qua van ngắn.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Áp suất bị mất đi rất nhỏ do thiết kế bên trong van rất thoáng.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Lắp van thủy lực đúng theo chiều mũi tên.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tương thích với hầu hết các bộ điều khiển tự động có sẵn trên thị trường</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van cân bằng áp hydraulic bằng đồng phi 60mm Automat 1\" src=\"https://vietannong.com.vn/_ld/3/48732526.jpg\"/></span></span></p>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật van cân bằng áp hydraulic 60mm:</span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã hàng:</strong> AQ334S</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính: </strong>ren trong 60mm</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất hoạt động: </strong>0.6 - 10 bar (kg/cm2)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nhiệt độ chịu đựng: </strong>lên tới 60 độ C</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Kích thước van:</strong> 180x100x119 (LxHxW) mm</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng nước qua van:</strong> 10 - 30m3/h</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu:</strong> Đồng thau</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nhà sản xuất:</strong> Automat - India</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành: </strong>18 tháng</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Giữ cân bằng và duy trì áp suất phù hợp cho <a href=\"https://quocthaivn.com/vat-tu-tuoi-nong-nghiep\">hệ thống tưới tự động nhỏ</a> giọt hay <a href=\"https://quocthaivn.com/vat-tu-tuoi-nong-nghiep\">tưới phun mưa</a> thông qua Hydraulic (thủy lực) trong nhà kính, trang trại ngoài trời và cánh đồng lớn...</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van cân bằng áp hydraulic bằng đồng phi 60mm Automat Vietannong\" src=\"https://vietannong.com.vn/_ld/3/72099595.jpg\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van cân bằng áp hydraulic bằng đồng phi 60mm Automat 2\" src=\"https://vietannong.com.vn/_ld/3/64292484.jpg\"/></span></span></p>\n', 'Van cân bằng áp hydraulic bằng đồng phi 60mm Automat', 0.00, 0, 0, 1, 0, 'products/5fb90d46-2644-4516-a6e0-554fa1e82380.png', 31, 1, NULL, NULL),
(169, 'Bộ hẹn giờ tích hợp van điện từ phi 34 G75C1 - Baccara', 'b-h-n-gi-t-ch-h-p-van-i-n-t-phi-34-g75c1-baccara', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ hẹn giờ tích hợp van điện từ phi 34 G75C - Baccara hoàn toàn không thấm nước và có thể hoạt động trong môi trường khắc nghiệt, dễ dàng và thuận tiện tưới cây mọi lúc, ứng dụng trong các lĩnh vực: tưới sân vườn, cây ban công, tưới nông nghiệp...</span></span></p>\n<h1 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/he-thong-dieu-khien?page=2\">Bộ hẹn giờ </a>tích hợp van điện từ phi 34 G75C1</span></span></h1>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tích hợp van điện từ phi 34 G75C1 Việt An Nông Israel 2\" src=\"https://vietannong.com.vn/_ld/3/67281167.jpg\"/></span></span></p>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật bộ hẹn giờ G75C1 Baccara - Israel:</span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã sản phẩm: </strong>G75C1</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Hãng sản xuất:</strong> Baccara – Israel</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Năng lượng sử dụng:</strong> PIN Ankaline 9V</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Chất lượng PIN đảm bảo sử dụng trên 1 năm</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Sao lưu bộ nhớ khi hết pin</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Các mức cảnh bảo pin yếu</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Màn hình LCD tiết kiệm năng lượng</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Tích hợp đi kèm pin</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Tích hợp đi kèm cục Solenoid</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Điều khiển được van điện từ Baccara 1\" (34mm)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Số lần bật/tắt (on/off): </strong>3 lần trên 1 ngày</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thời gian hiển thị:</strong> Tất cả các ngày trong tuần hoặc theo tùy chỉnh</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng: </strong>Điều khiển mở van điện từ tại nguồn nước trong mọi <a href=\"https://quocthaivn.com/vat-tu-tuoi-nong-nghiep\">hệ thống tưới sân vườn</a>, cảnh quan hoặc nông nghiệp như: tưới béc,<a href=\"https://quocthaivn.com/vat-tu-tuoi-nong-nghiep\"> tưới nhỏ giọt</a>...</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tích hợp van điện từ phi 34 G75C1 Việt An Nông Israel\" src=\"https://vietannong.com.vn/_ld/3/30542703.jpg\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Tiện ích mở rộng của bộ hẹn giờ G75C1 Baccara:</strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Hoạt động trong điều kiện nhiệt độ từ -10 đến 60 độ C</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Kết nối được Solenoid 3/4\" đường kính, có thể đặt ngang hoặc dọc bộ điều khiển</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Khoan ốc gắn tường cũng là một lợi thế của thiết bị Baccara này</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Có thể thao rời di chuyển (phụ thuộc vào chiều dài dây điện)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Tương thích với mọi cục Solenoid có điện trở R – 4Ω</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Có thể điều khiển được tất cả các van từ 28mm đường kính trở lên</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Đồng hồ đếm thời gian thực</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Tính năng hiện thị xem chương trình trực tiếp trên màn hình chính</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Nhiều tình năng tùy biến như PIN mặt trời, sạc, khác…</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Tiêu chuẩn chất lượng, xuất xứ máy móc: CE</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Tiêu chuẩn an toàn kỹ thuật, chống nước: IP67, NEMA 4x</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ G75C1 điều khiển được các <a href=\"https://quocthaivn.com/vat-tu-tuoi-nong-nghiep\">van điện từ phi 34mm</a> của Baccara - Israel</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tích hợp van điện từ phi 34 G75C1 Việt An Nông\" src=\"https://vietannong.com.vn/_ld/3/41642079.jpg\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tích hợp van điện từ phi 34 G75C1 Việt An Nông Israel 1\" src=\"https://vietannong.com.vn/_ld/3/10119695.jpg\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ hẹn giờ tích hợp van điện từ phi 34 G75C1 Việt An Nông Israel 7\" src=\"https://vietannong.com.vn/_ld/3/48925024.jpg\"/></span></span></p>\n', 'Bộ hẹn giờ tích hợp van điện từ phi 34 G75C1 - Baccara', 0.00, 0, 0, 1, 0, 'products/9775e02b-0b7b-4d0e-a4f9-c123d323defc.png', 31, 1, NULL, NULL),
(170, 'Timer hẹn giờ tưới cây 4 khu vực - CO4004 Úc', 'timer-h-n-gi-t-i-c-y-4-khu-v-c-co4004-c', '', '\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/he-thong-dieu-khien\">Timer hẹn giờ tưới</a> cây 4 khu vực - CO4004 Úc</span></span></h1>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật timer CO4004 Whiz400:</span></span></h2>\n<ul>\n<li>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bật/tắt: 4 lần/1 ngày.</span></span></p></li>\n<li>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">4 khu vực tưới riêng biệt cùng chức năng.</span></span></p></li>\n<li>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tưới nước theo từng khu vực, nhiều tùy chọn tưới khác nhau.</span></span></p></li>\n<li>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Dễ dàng cài đặt lịch tưới khác nhau cho mỗi ngày.</span></span></p></li>\n<li>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Có thể chọn được chế độ tưới ngay lập tức.</span></span></p></li>\n<li>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Lập trình điện tử linh hoạt và trực quan.</span></span></p></li>\n<li>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tưới liên tục các ngày trong tuần và dễ dàng lựa chọn được khoảng thời gian tưới.</span></span></p></li>\n<li>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thời gian chạy từ 1 phút cho đến 6 giờ đố, thích ứng được với nguồn nước áp suất thấp.</span></span></p></li>\n<li>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kết hợp 2 ron chống ròi rỉ nước tại đầu vào và đầu ra.</span></span></p></li>\n<li>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nút bấm sử dụng dễ dàng thuận tiện.</span></span></p></li>\n<li>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Màn hình LCD lớn hiển thị rõ ràng.</span></span></p></li>\n<li>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Góc nhìn màn hình rộng hơn.</span></span></p></li></ul>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nhiều lựa chọn để tưới cây: Tất cả các nhu cầu tưới nước cho cây được tổng hợp từ việc bảo trì thảm cỏ đến chăm sóc hoa vườn hoa đầy tinh tế. Bao gồm việc có thể lập kế hoạch để sử dụng vòi xịt, hệ thống nhỏ giọt và…</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Dễ dàng chuyển sang tưới nước thủ công: Cho dù bạn muốn rửa xe, làm sạch vỉa hè hay sử dụng vòi xịt cho các công việc khác, bạn có thể dễ dàng chuyển sang tưới nước thủ công. Không cần điều chỉnh hẹn giờ. Chỉ cần một công tắc đơn giản khi bạn cần sử dụng vòi phun.<br/>\nLập trình 4 khu vực tưới riêng biệt với 16 lần tưới cây khác nhau.</span></span></p>\n', 'Timer hẹn giờ tưới cây 4 khu vực - CO4004 Úc', 0.00, 0, 0, 1, 0, 'products/b1fb5545-c611-4c93-a50f-36c5ce26ee06.jpg', 31, 1, NULL, NULL),
(171, 'Bộ hẹn giờ mở van điện từ G75C - Baccara', 'b-h-n-gi-m-van-i-n-t-g75c-baccara', '', '\n<h1><a href=\"https://quocthaivn.com/he-thong-dieu-khien\">Bộ hẹn giờ</a> mở van điện từ G75C - Baccara</h1>\n<p><img align=\"\" alt=\"Bộ hẹn giờ mở van điện từ Baccara - Israel Việt An Nông 2\" src=\"https://vietannong.com.vn/_ld/3/41878405.jpg\"/></p>\n<h2>Thông số kỹ thuật bộ hẹn giờ mở <a href=\"https://quocthaivn.com/he-thong-dieu-khien\">van điện từ Baccara</a>:</h2>\n<p><strong>Mã sản phẩm: </strong>G75C</p>\n<p><strong>Hãng sản xuất:</strong> Baccara – Israel</p>\n<p><strong>Năng lượng sử dụng:</strong> PIN Ankaline 9V</p>\n<p>- Chất lượng PIN đảm bảo sử dụng trên 1 năm</p>\n<p>- Sao lưu bộ nhớ khi hết pin</p>\n<p>- Các mức cảnh bảo pin yếu</p>\n<p>-- Màn hình LCD tiết kiệm năng lượng</p>\n<p>- Tích hợp đi kèm pin</p>\n<p>- Tích hợp đi kèm cục Solenoid</p>\n<p>- Điều khiển được tất cả các size van và van khác loại</p>\n<p><strong>Số lần bật/tắt (on/off):</strong> 3 lần trên 1 ngày</p>\n<p><strong>Thời gian hiển thị: </strong>Tất cả các ngày trong tuần hoặc theo tùy chỉnh</p>\n<p><strong>Ứng dụng: </strong>Điều khiển mở van điện từ tại nguồn nước trong mọi hệ thống tưới sân vườn, cảnh quan hoặc nông nghiệp như: tưới béc, tưới nhỏ giọt....</p>\n<p><img align=\"\" alt=\"Bộ hẹn giờ mở van điện từ Baccara - Israel Việt An Nông\" src=\"https://vietannong.com.vn/_ld/3/17410865.jpg\"/></p>\n<p><strong>Tiện ích mở rộng của <a href=\"https://quocthaivn.com/he-thong-dieu-khien\">bộ hẹn giờ G75C Baccara</a>:</strong></p>\n<p>+ Hoạt động trong điều kiện nhiệt độ từ -10 đến 60 độ C</p>\n<p>+ Kết nối được với tất cả Solenoid từ 28mm đường kính trở lên, có thể đặt ngang hoặc dọc bộ điều khiển</p>\n<p>+ Khoan ốc gắn tường cũng là một lợi thế của thiết bị Baccara này</p>\n<p>+ Có thể thao rời di chuyển (phụ thuộc vào chiều dài dây điện)</p>\n<p>+ Tương thích với mọi cục Solenoid<a href=\"https://vietannong.com.vn/product/van-dien-tu\"> </a>có điện trở R – 4Ω</p>\n<p>+ Có thể điều khiển được tất cả các van từ 28mm đường kính trở lên</p>\n<p>+ Đồng hồ đếm thời gian thực</p>\n<p>+ Tính năng hiện thị xem chương trình trực tiếp trên màn hình chính</p>\n<p>+ Nhiều tình năng tùy biến như PIN mặt trời, sạc, khác…</p>\n<p>+ Tiêu chuẩn chất lượng, xuất xứ máy móc: CE</p>\n<p>+ Tiêu chuẩn an toàn kỹ thuật, chống nước: IP67, NEMA 4x</p>\n<p>+ G75C điều khiển được tất cả các van điện từ</p>\n<p><img align=\"\" alt=\"Bộ hẹn giờ mở van điện từ Baccara - Israel Việt An Nông 3\" src=\"https://vietannong.com.vn/_ld/3/09558242.jpg\"/></p>\n<p><img align=\"\" alt=\"Bộ hẹn giờ mở van điện từ Baccara - Israel Việt An Nông 1\" src=\"https://vietannong.com.vn/_ld/3/43372536.jpg\"/></p>\n<h3> </h3>\n', 'Bộ hẹn giờ mở van điện từ G75C - Baccara', 0.00, 0, 0, 1, 0, 'products/d1ef0d68-bd9d-4ae4-b26b-39ad227b0831.png', 31, 1, NULL, NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `sku`, `content`, `short_desc`, `price`, `discount`, `quantity`, `status`, `type`, `thumbnail`, `category_id`, `brand_id`, `created_at`, `updated_at`) VALUES
(172, 'Van giảm áp hydraulic bằng đồng phi 60mm Automat', 'van-gi-m-p-hydraulic-b-ng-ng-phi-60mm-automat', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Van giảm áp hydraulic bằng đồng phi 60mm Automat được vận hành dựa trên áp lực được cài đặt tại cục điều khiển (pilot). Có thể cài mức áp tăng hoặc giảm. Điều áp đường ống. Nước qua van này là giảm áp lực theo cài đặt ban đầu</span></span></p>\n<h1 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/he-thong-dieu-khien\">Van giảm áp hydraulic </a>bằng đồng phi 60mm</span></span></h1>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van giảm áp hydraulic bằng đồng phi 60mm Automat 1\" src=\"https://vietannong.com.vn/_ld/3/59872176.jpg\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đặc điểm nổi bật của thiết bị:</strong></span></span></p>\n<ul>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thiết kế đơn giản và mạnh mẽ, chỉ gồm 4 phần liên quan nhau.</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thân và nắp chụp của van bằng đồng thau giúp cho độ bền cao hơn và chống ăn mòn.</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nắp của van có roan cao su được gia tốt nhất giúp vận hành trơn tru mà không bị biến dạng ở áp suất cao khi xảy ra việc đóng nước bất ngờ.</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thời gian tải nước qua van ngắn.</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Áp suất bị mất đi rất nhỏ do thiết kế bên trong van rất thoáng.</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Lắp van thủy lực đúng theo chiều mũi tên.</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tương thích với hầu hết các <a href=\"https://quocthaivn.com/he-thong-dieu-khien\">bộ điều khiển tự động</a> có sẵn trên thị trường</span></span></li></ul>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van giảm áp hydraulic bằng đồng phi 60mm Automat 2\" src=\"https://vietannong.com.vn/_ld/3/83532321.jpg\"/></span></span></p>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật van giảm áp hydraulic phi 60mm:</span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã hàng:</strong> AQ334R</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính:</strong> ren trong 60mm</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất hoạt động:</strong> 0.6 - 10 bar (kg/cm2)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nhiệt độ chịu đựng:</strong> lên tới 60 độ C</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Kích thước van:</strong> 180x100x119 (LxHxW) mm</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng nước qua van: </strong>10 - 30m3/h</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu:</strong> Đồng thau</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nhà sản xuất:</strong> Automat - India</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành: </strong>18 tháng</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Bảo vệ đường ống hoặc tham gia điều khiển áp suất phù hợp cho <a href=\"https://quocthaivn.com/vat-tu-tuoi-nong-nghiep\">hệ thống tưới tự động nhỏ giọt </a>hay <a href=\"https://quocthaivn.com/vat-tu-tuoi-nong-nghiep\">tưới phun mưa</a> thông qua Hydraulic (thủy lực) trong nhà kính, trang trại ngoài trời và cánh đồng lớn...</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van giảm áp hydraulic bằng đồng phi 60mm Automat 3\" src=\"https://vietannong.com.vn/_ld/3/09380778.jpg\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van giảm áp hydraulic bằng đồng phi 60mm Automat 5\" src=\"https://vietannong.com.vn/_ld/3/39618039.jpg\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van giảm áp hydraulic bằng đồng phi 60mm Automat6\" src=\"https://vietannong.com.vn/_ld/3/76932899.jpg\"/></span></span></p>\n', 'Van giảm áp hydraulic bằng đồng phi 60mm Automat', 0.00, 0, 0, 1, 0, 'products/6b74e8d2-35d1-4cad-8f54-afbace22fb94.png', 31, 1, NULL, NULL),
(173, 'Cảm biến độ ẩm đất qua Wifi có solar - Netro', 'c-m-bi-n-m-t-qua-wifi-c-solar-netro', 'Bảng hấp thụ năng lượng mặt trời hiệu quả nhất\nSạc năng lượng mặt trời trong 1 ngày hỗ trợ 2-3 tuần làm việc\nĐèn LED nhiều màu – Chọn màu yêu thích để thắp sáng khu vườn của bạn vào ban đêm\nCảm biến độ ẩm – Độ chính xác cao.\nHoạt động với tất cả các loại đất\nCảm biến ánh sáng mặt trời – Đo một dải phổ rộng từ hồng ngoại đến tia nhìn thấy được\nCảm biến nhiệt độ – Đo nhiệt độ mặt đất Không thấm nước\nĐược làm bằng nhựa bền bỉ và ít bị tác động bởi môi trường\nTích hợp được với bộ điều khiển Netro Sprite và hẹn giờ mở nước Pixie', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Cảm biến độ ẩm đất qua Wifi có solar - Netro công nghệ tối ưu tích hợp bộ điều khiển Sprite và Pixie kiểm soát dữ liệu ẩm tốt nhất cho cây trồng nhà bạn. Chất liệu bền bỉ, kết nối mạnh mẽ, bảo hành 1 năm.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Cảm biến độ ẩm đất qua Wifi có solar - Netro<br/>\n<img alt=\"\" src=\"https://vietannong.com.vn/_ld/4/29322154.jpg\"/><br/>\nThông số kỹ thuật Whisperer Netro cảm biến độ ẩm đất:<br/>\nMã hàng: Whisperer<br/>\n<br/>\nDài x rộng x cao: 21,25 x 6,25 x 32 9 (cm)<br/>\n<br/>\nTrong lượng: 170 gram<br/>\n<br/>\nPin: sạc lại được qua mặt trời<br/>\n<br/>\nNhiệt độ hoạt động: -12 độ – 50 độ C<br/>\n<br/>\nỨng dụng app: IOS (9.0+), Android (5.0+)<br/>\n<br/>\nWifi: 802.11N, 2.4Ghz Us/Japan/Eu<br/>\n<br/>\nBảo hành: 1 năm<br/>\n<br/>\nNhà sản xuất: Netro Home – USA<br/>\n<br/>\n<img alt=\"\" src=\"https://vietannong.com.vn/_ld/4/87442986.jpg\"/><br/>\n<br/>\nBonus:<br/>\n<br/>\nBảng hấp thụ năng lượng mặt trời hiệu quả nhất<br/>\nSạc năng lượng mặt trời trong 1 ngày hỗ trợ 2-3 tuần làm việc<br/>\nĐèn LED nhiều màu – Chọn màu yêu thích để thắp sáng khu vườn của bạn vào ban đêm<br/>\nCảm biến độ ẩm – Độ chính xác cao.<br/>\nHoạt động với tất cả các loại đất<br/>\nCảm biến ánh sáng mặt trời – Đo một dải phổ rộng từ hồng ngoại đến tia nhìn thấy được<br/>\nCảm biến nhiệt độ – Đo nhiệt độ mặt đất Không thấm nước<br/>\nĐược làm bằng nhựa bền bỉ và ít bị tác động bởi môi trường<br/>\nTích hợp được với bộ điều khiển Netro Sprite và hẹn giờ mở nước Pixie<br/>\n<img alt=\"\" src=\"https://vietannong.com.vn/_ld/4/54586245.jpg\"/><br/>\n<img alt=\"\" src=\"https://vietannong.com.vn/_ld/4/60836264.jpg\"/></span></span></p>\n', 'Cảm biến độ ẩm đất qua Wifi có solar - Netro', 0.00, 0, 0, 1, 0, 'products/71604e5c-1437-455d-8cd7-5af76660c826.png', 31, 1, NULL, NULL),
(174, 'Hộp điều khiển tưới cây wifi tự động 6 kênh Netro Spite - Mỹ', 'h-p-i-u-khi-n-t-i-c-y-wifi-t-ng-6-k-nh-netro-spite-m', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hộp điều khiển tưới cây wifi tự động 6 kênh Netro Spite - Mỹ được thiết kế để dễ dàng điều khiển tưới cây sân vườn. Nó giúp tiết kiệm nước. Netro tự lên lịch tưới tự động hoàn toàn. Netro biết cây của bạn cần bao nhiêu nước và cách tốt nhất để tưới nước cho chúng. Bạn hoàn toàn có thể tin tưởng vào Netro và yên tâm rằng khu vườn của bạn được tưới một lượng nước chính xác.</span></span></p>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/he-thong-dieu-khien\">Hộp điều khiển tưới cây</a> wifi 6 kênh Netro Spite</span></span></h2>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Hộp điều khiển tưới cây wifi tự động 6 kênh Netro Spite - Mỹ 1\" src=\"https://vietannong.com.vn/_ld/4/73295625.jpg\"/></span></span></h2>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông tin kỹ thuật hộp điều khiển <a href=\"https://quocthaivn.com/he-thong-dieu-khien\">tưới cây wifi tự động</a> 6 kênh Netro</span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Mã hàng:</b> Spite6</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Hãng sản xuất:</b> Netro Inc, USA</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Hệ điều hành:</b> Netro Cloud (thích hợp Android 5.0+ và IOS 8.3+)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Màu sắc:</b> Trắng</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Điện áp tích hợp: </b>24 Vol</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>PIN dự phòng:</b> CR2</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Adaptor chuyển nguồn:</b> US hay EU Standard.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thiết kế hiện đại, thẩm mỹ cao và gọn nhẹ.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Điều khiển thông qua WIFI (2.4G) dựa trên app Netro (có sẵn tại App Store và Google Play)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Chia khu vực tưới: 6 </b>kênh</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tích hợp tất cả các loại van điện từ phổ biến trên toàn cầu</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Hộp điều khiển tưới cây wifi tự động 6 kênh Netro Spite - Mỹ 7\" src=\"https://vietannong.com.vn/_ld/4/70015732.jpg\"/></span></span></p>\n<h3 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tiện ích mở rộng của<a href=\"https://quocthaivn.com/he-thong-dieu-khien\"> bộ tưới cây tự động</a> Netro Spite:</span></span></h3>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Thời tiết: </b>Nhận thông báo về dữ liệu thời tiết chính xác từng vị trí thông qua trạm quan trắc toàn cầu của Netro (miễn phí 1 năm), hiện thị cụ thể khí hậu trên app Netro, giúp chọn lựa chính xác thời gian và cách tưới cây.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Tiết kiệm nước tối đa tới 50%:</b> Luôn cập nhật độ ẩm của đất để có chế độ tưới nước phù hợp nhất</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Dữ liệu về cấu trúc đất và cây trồng: </b>Cung cấp đầy đủ dữ liệu về đất và cây trồng để lựa chọn hình thức tưới đúng nhất với nhiều loại đất khác nhau và 1000+ loại thực vật có sẵn trong bộ dữ liệu của Netro.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Giải pháp mùa đông:</b> Chuẩn bị đủ lượng nước tưới cần thiết và vô hiệu hóa hệ thống khi xảy ra đóng băng, giá rét.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Hộp điều khiển tưới cây wifi tự động 6 kênh Netro Spite - Mỹ 2\" src=\"https://vietannong.com.vn/_ld/4/80170349.jpg\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Hộp điều khiển tưới cây wifi tự động 6 kênh Netro Spite - Mỹ 3\" src=\"https://vietannong.com.vn/_ld/4/03012701.jpg\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Hộp điều khiển tưới cây wifi tự động 6 kênh Netro Spite - Mỹ 5\" src=\"https://vietannong.com.vn/_ld/4/53587379.jpg\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"hop dieu khien tuoi cay wifi netro 10 khu vuc\" src=\"https://vietannong.com.vn/_ld/4/44465416.jpg\"/></span></span></p>\n', 'Hộp điều khiển tưới cây wifi tự động 6 kênh Netro Spite - Mỹ', 0.00, 0, 0, 1, 0, 'products/06d31ce2-c1d2-4ca1-96a0-d0adcf359320.png', 31, 1, NULL, NULL),
