(179, 'Bộ lọc đĩa phi 90 AQ136T Automat Ấn Độ', 'b-l-c-a-phi-90-aq136t-automat-n', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ lọc đĩa hàng cao cấp phi 90mm, đảm bảo chất lượng. Sản phẩm của Automat - Ấn Độ được bán trên hơn 80 quốc gia. Áp suất bị mất rất thấp. Đĩa lọc bằng nhựa. 120 Mesh/150 micron. Lọc sạch cặn bẩn.</span></span></p>\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ lọc đĩa<a href=\"https://vietannong.com.vn/\"> </a>phi 90 AQ136T Automat Ấn Độ</span></span></h1>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ lọc đĩa phi 90 AQ136T Automat Ấn Độ 1\" src=\"https://vietannong.com.vn/_ld/2/85550352.jpg\"/></span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông số kỹ thuật bộ lọc đĩa 90mm AQ136T cao cấp:</strong></span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã hàng:</strong> AQ136T</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Ống gắn lọc: </b>phi 90mm (3\")</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng nước qua lọc:</strong> 50m3/h</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Vi lọc: </strong>120 mesh - 150 micron.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất mất tại bình lọc:</strong>  0.05 - 0.52 bar</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Kiểu lọc:</strong> Lọc Đĩa </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Màu sắc:</strong> Thân đen - Đĩa lọc màu đỏ.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất chịu đựng: </strong>10 bar</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành:</strong> 18 tháng</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng: </strong>Dùng lọc rác, lọc cặn bẩn, côn trùng trong <a href=\"https://quocthaivn.com/\">hệ thống tưới nhỏ giọt</a> cho khoai lang tưới dưa hấu lọc 60% phèn để chống tắt nghẽn mắt tưới trong hệ thống tự động...</span></span><br/>\n </p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"bộ lọc đĩa phi 90mm Ấn Độ Việt An Nông\" src=\"https://vietannong.com.vn/_ld/2/35921545.jpg\"/></span></span><br/>\n </p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ lọc đĩa phi 90 AQ136T Automat Ấn Độ 2\" src=\"https://vietannong.com.vn/_ld/2/51281972.jpg\"/><br/>\n<br/>\n<a href=\"https://vietannong.com.vn/_ld/2/60521523.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"bộ lọc đĩa phi 90mm Ấn Độ Việt An Nông\" src=\"https://vietannong.com.vn/_ld/2/s60521523.jpg\"/></a></span></span></p>\n<p> </p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/2/47998161.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"bộ lọc đĩa phi 90mm Ấn Độ Việt An Nông\" src=\"https://vietannong.com.vn/_ld/2/s47998161.jpg\"/></a><br/>\n<br/>\n<img align=\"\" alt=\"Bộ lọc đĩa phi 90 AQ136T Automat Ấn Độ 3\" src=\"https://vietannong.com.vn/_ld/2/78501792.jpg\"/><br/>\n<br/>\n<img align=\"\" alt=\"Bộ lọc đĩa phi 90 AQ136T Automat Ấn Độ 5\" src=\"https://vietannong.com.vn/_ld/2/61004981.jpg\"/></span></span></p>\n', 'Bộ lọc đĩa phi 90 AQ136T Automat Ấn Độ', 0.00, 0, 0, 1, 0, 'products/5ff31c70-0f5d-4c79-97f1-810b38a6a481.png', 36, 1, NULL, NULL),
(180, 'Bộ lọc lưới Ấn Độ phi 49 - AQ123YM', 'b-l-c-l-i-n-phi-49-aq123ym', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hệ thống lọc lưới cao cấp đến từ Automat - Ấn Độ với lõi lưới thép không gỉ và lên tới 120mesh. Sản phẩm được đánh giá chất lượng trên hơn 80 quốc gia. Bảo hành 1 năm chính hãng.</span></span></p>\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong><a href=\"https://quocthaivn.com/thiet-bi-loc\">Bộ lọc lưới</a> phi 49<a href=\"https://quocthaivn.com/thiet-bi-loc\"> tưới nhỏ giọt</a> AQ123YM</strong></span></span></h1>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/2/14502157.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Bộ lọc lưới Ấn Độ phi 49 - AQ123YM\" src=\"https://vietannong.com.vn/_ld/2/s14502157.jpg\"/></a></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông số kỹ thuật:</strong></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chân ren gắn ống:</strong> 49mm RN</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng:</strong> 15 - 20 m3/giờ</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưới lọc: </strong>120mesh/150micron</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất hao hụt:</strong> 0.06 - 0.2 bar (kg/cm2)</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Kiểu lọc:</strong> Lọc lưới</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Màu sắc: </strong>Đen,lưới trắng viền xanh.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất chịu đựng:</strong> 12 bar</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Xuất xứ:</strong> Ấn Độ (India)</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành:</strong> 1 năm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Dùng trong lọc rác, cặn bẩn của hệ thống<strong> tưới nhỏ giọt</strong> dùng cho cây ăn quả, cây công nghiệp như tiêu, cà phê, mía, cây lương thực như ngô, sắn...</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/2/89054824.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Bộ lọc lưới Ấn Độ phi 49 - AQ123YM\" src=\"https://vietannong.com.vn/_ld/2/s89054824.jpg\"/></a></span></span></p>\n', 'Bộ lọc lưới Ấn Độ phi 49 - AQ123YM', 0.00, 0, 0, 1, 0, 'products/13b52bdd-05a0-42ce-9ef1-be7ca6ec7f84.png', 36, 1, NULL, NULL);
