(181, 'Bộ lọc đĩa bán tự động Ấn Độ phi 90mm - AQ136T SAD', 'b-l-c-a-b-n-t-ng-n-phi-90mm-aq136t-sad', '', '\n<p><span style=\"color:#000000;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ lọc đĩa bán tự động Ấn Độ phi 90mm - AQ136T SAD không cần tháo lõi lọc khi vệ sinh, dễ dàng làm sạch khi tắc nghẽn. Độ bền cao, áp suất hoạt động tới 8 bar. Bảo hành lên tới 18 tháng</span></span></span></p>\n<h1 style=\"width:1270px; margin-bottom:7px; text-align:start; text-indent:0px; -webkit-text-stroke-width:0px\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><span style=\"box-sizing:border-box\"><span style=\"text-rendering:optimizespeed\"><span style=\"line-height:1.3\"><span style=\"font-weight:700\"><span style=\"font-style:normal\"><span style=\"font-variant-ligatures:normal\"><span style=\"font-variant-caps:normal\"><span style=\"letter-spacing:normal\"><span style=\"orphans:2\"><span style=\"text-transform:none\"><span style=\"white-space:normal\"><span style=\"widows:2\"><span style=\"word-spacing:0px\"><span style=\"background-color:#ffffff\"><span style=\"text-decoration-thickness:initial\"><span style=\"text-decoration-style:initial\"><span style=\"text-decoration-color:initial\"><a href=\"https://vietannong.com.vn/bo_loc_dia_an_do_chu_y_phi_90mm_aq136t\" style=\"box-sizing:border-box; touch-action:manipulation; color:#334862; text-decoration:none\"><span style=\"color:#000000;\">Bộ lọc đĩa</span></a><span style=\"color:#000000;\"> bán tự động 90mm - AQ136T SAD</span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></h1>\n<p style=\"margin-bottom:18px; text-indent:0px; -webkit-text-stroke-width:0px; text-align:center\"><span style=\"color:#000000;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><span style=\"box-sizing:border-box\"><span style=\"font-style:normal\"><span style=\"font-variant-ligatures:normal\"><span style=\"font-variant-caps:normal\"><span style=\"font-weight:400\"><span style=\"letter-spacing:normal\"><span style=\"orphans:2\"><span style=\"text-transform:none\"><span style=\"white-space:normal\"><span style=\"widows:2\"><span style=\"word-spacing:0px\"><span style=\"background-color:#ffffff\"><span style=\"text-decoration-thickness:initial\"><span style=\"text-decoration-style:initial\"><span style=\"text-decoration-color:initial\"><img align=\"\" alt=\"Bộ lọc đĩa bán tự động Automat phi 90mm - AQ136T SAD\" src=\"https://vietannong.com.vn/_ld/3/30238933.jpg\" style=\"box-sizing:border-box; border:0px; max-width:100%; height:auto; display:inline-block; vertical-align:middle; transition:opacity 1s ease 0s; opacity:1; padding:0px\"/></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></p>\n<p style=\"margin-bottom:18px; text-align:start; text-indent:0px; -webkit-text-stroke-width:0px\"><span style=\"color:#000000;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><span style=\"box-sizing:border-box\"><span style=\"font-style:normal\"><span style=\"font-variant-ligatures:normal\"><span style=\"font-variant-caps:normal\"><span style=\"font-weight:400\"><span style=\"letter-spacing:normal\"><span style=\"orphans:2\"><span style=\"text-transform:none\"><span style=\"white-space:normal\"><span style=\"widows:2\"><span style=\"word-spacing:0px\"><span style=\"background-color:#ffffff\"><span style=\"text-decoration-thickness:initial\"><span style=\"text-decoration-style:initial\"><span style=\"text-decoration-color:initial\"><strong style=\"box-sizing:border-box; font-weight:bold\"><span style=\"box-sizing:border-box\"><span style=\"box-sizing:border-box\">Hướng dẫn vệ sinh lọc:</span></span></strong></span></span></span></span></span></span></span></span></span></span></span></span></span></spa