(188, 'Nối thẳng 5mm 1 gờ dùng cho dây dẻo đen 5 li', 'n-i-th-ng-5mm-1-g-d-ng-cho-d-y-d-o-en-5-li', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nối 5mm 1 gờ gắn vào thành ống PVC, HDPE. Hàng Việt Nam</span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Nối thẳng 5mm 1 gờ</b></span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img alt=\"nối 5mm 1 gờ gắn ống cứng upvc\" src=\"https://vietannong.com.vn/noi_5mm_1_go.jpg\"/></span></span></h2>\n<p> </p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chất liệu: Nhựa POM</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tên gọi: Nối thẳng 5mm 1 gờ cho ống PE 5mm kết nối với ống uPVC (ống cứng)..</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Quy cách: 100 cái/1 bịch</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Ứng dụng: Sử dụng trong hệ thống<a href=\"https://quocthaivn.com/phu-kien-tuoi-nho-giot\"> tưới nhỏ giọt,</a> tưới <a href=\"https://quocthaivn.com/phu-kien-tuoi-nho-giot\" target=\"_blank\">béc bọ </a>và tưới tiết kiệm bằng<a href=\"https://quocthaivn.com/phu-kien-tuoi-nho-giot\"> dây pe 6mm</a> được nối từ ống chính</span></span></p>\n', 'Nối thẳng 5mm 1 gờ dùng cho dây dẻo đen 5 li', 0.00, 0, 0, 1, 0, 'products/304e8c8b-1632-4469-b093-ec76fccfa7f8.png', 37, 1, NULL, NULL),
(189, 'Bộ châm dinh dưỡng venturi phi 60', 'b-ch-m-dinh-d-ng-venturi-phi-60', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ châm dinh dưỡng venturi phi 60, lượng hút phân lớn từ 69 - 900 lít phân trên một giờ. Độ bền cao, hoạt động tốt trong môi trường áp suất lớn. Ứng dụng châm phân dinh dưỡng tưới nhỏ giọt.</span></span></p>\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong><a href=\"http://shop.vietannong.com.vn/board/he_thong_tuoi/tuoi_nho_giot/bo_cham_phan_dinh_d_ng_venturi_phi_60mm/2-1-0-120\" target=\"_blank\">Bô châm phân</a><a href=\"https://quocthaivn.com/thiet-bi-cham-phan\"> dinh dưỡng</a> venturi phi 60mm</strong></span></span></h1>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"http://1.bp.blogspot.com/-ECCl7_KfxuI/Vm0eVQq0HII/AAAAAAAAFf0/SiugiKJNsEE/s1600/venturi%2Bphi%2B60_2.jpg\" imageanchor=\"1\"><img alt=\"thiết bị châm phân venturi phi 60\" border=\"0\" height=\"327\" src=\"http://1.bp.blogspot.com/-ECCl7_KfxuI/Vm0eVQq0HII/AAAAAAAAFf0/SiugiKJNsEE/s400/venturi%2Bphi%2B60_2.jpg\" title=\"\" width=\"400\"/></a></span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông số kỹ thuật bộ châm phân:</strong></span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Tên: </strong>Venturi<a href=\"http://vietannong.com.vn/load/bectuoicay/vattutuoitudong/b_cham_phan_dostraton_cong_ngh_piston_france/3-1-0-109\"> </a>phi 60</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu:</strong> Nhựa PP cao cấp</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng hút trộn phân kèm với dòng nước: </strong>69 - 900 lít/giờ</span></span></p