ble>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"http://3.bp.blogspot.com/-v7sWf7FO90w/VnvEHs1645I/AAAAAAAAFlc/Df3ATmOKLIk/s1600/venturi%2Bphi%2B60.jpg\" imageanchor=\"1\"><img align=\"\" alt=\"Bộ châm dinh dưỡng venturi phi 60\" src=\"https://vietannong.com.vn/_ld/1/22909631.jpg\"/></a></span></span></p>\n<h3><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Video hướng dẫn lắp đặt bộ châm phân phi 60:</strong></span></span></h3>\n', 'Bộ châm dinh dưỡng venturi phi 60', 0.00, 0, 0, 1, 0, 'products/03ef110c-6f69-4326-8cde-d6846701b166.png', 38, 1, NULL, NULL),
(190, 'Bơm định lượng dùng châm dinh dưỡng cho nông nghiệp', 'b-m-nh-l-ng-d-ng-ch-m-dinh-d-ng-cho-n-ng-nghi-p', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bơm định lượng dinh dưỡng tương tự Dosatron - Pháp. Với thiết kế thủy lực giúp lực hút mạnh, tỷ lệ chính xác cao. Được ứng dụng nhiều trong thủy sản, chăn nuôi và trang trại rau màu, cây ăn quả.</span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bơm định lượng<a href=\"http://vietannong.com.vn/load/tuoi_nho_giot_gia_re/bo_cham_phan_venturi/b_cham_phan_dostraton_cong_ngh_piston_france/3-1-0-109\"> </a>dùng châm dinh dưỡng cho nông nghiệp</strong></span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bơm định lượng dùng châm dinh dưỡng cho nông nghiệp\" src=\"https://vietannong.com.vn/_ld/2/82186974.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông số kỹ thuật:</strong></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Model: </strong>VAN SFP01</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính gắn ống:</strong> 27mm (3/4\")</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng nước qua ống chính:</strong> 20 - 2500 lít/giờ</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng châm phân:</strong> 0.4 - 4% ( 0.8 - 100 lít/giờ)</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất hoạt động:</strong> 0.2 - 3 bar (kg/cm2)</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nhiệt độ hoạt động:</strong> 4 - 30 độ C.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Độ chính xác:</strong> &gt;95%</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Sử dụng trong<a href=\"https://quocthaivn.com/thiet-bi-cham-phan\"> hệ thống châm dinh dưỡng</a> định lượng chính xác trong chăn nuôi và châm phân trong hệ thống<a href=\"https://quocthaivn.com/thiet-bi-cham-phan\"> tưới tự động</a> cho cây trồng, rau màu, cây ăn quả...</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/2/30430751.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Bơm định lượng dùng châm dinh dưỡng cho nông nghiệp\" src=\"https://vietannong.com.vn/_ld/2/s30430751.jpg\"/></a></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bơm định lượng dùng châm dinh dưỡng cho nông nghiệp\" src=\"https://vietannong.com.vn/_ld/2/31725344.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Mô tả thiết bị bơm định lượng</em></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/2/79773907.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Bơm định lượng dùng châm dinh dưỡng cho nông nghiệp\" src=\"https://vietannong.com.vn/_ld/2/s79773907.jpg\"/></a></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Sơ đồ hướng dẫn lắp đặt</em></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em><a href=\"https://vietannong.com.vn/_ld/2/25729759.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Bơm định lượng dùng châm dinh dưỡng cho nông nghiệp\" src=\"https://vietannong.com.vn/_ld/2/s25729759.jpg\"/></a></em></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Sơ đồ lắp đặt thực tế</em></span></span></p>\n', 'Bơm định lượng dùng châm dinh dưỡng cho nông nghiệp', 0.00, 0, 0, 1, 0, 'products/7f97d1e9-d365-482f-954a-a632f9d4cd89.png', 38, 1, NULL, NULL);
