(192, 'Bộ super venturi hai đầu hút AQ115DS - Automat', 'b-super-venturi-hai-u-h-t-aq115ds-automat', '', '\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ super venturi hai đầu hút AQ115DS - Automat</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ super venturi hai đầu hút AQ115DS - Automat Việt An Nông\" src=\"https://vietannong.com.vn/_ld/3/09654671.jpg\"/></span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Có thể điều chỉnh hút phân bón và dinh dưỡng từ một cổng hoặc cả 2 cổng cùng lúc</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Cung cấp dinh dưỡng và phân bón trực tiếp vào đường ống chính</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Sử dụng thân thiện với nhiều loại phân bón và hóa chất nông nghiệp</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Phân bổ lượng phân bón đồng đều đến từng vị trí cây</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Tiết kiệm nhân công và điện năng nhiều hơn</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Lò xo thiết kế NRV bên ngoài dễ dàng tháo lắp khi vệ sinh.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ super venturi hai đầu hút AQ115DS Automat Việt An Nông\" src=\"https://vietannong.com.vn/_ld/3/91548425.jpg\"/></span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật của bộ super venturi 2 đầu hút:</span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã hàng: </strong>AQ115DS</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính gắn ống:</strong> ren ngoài 60mm (2\")</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính đầu hút của venturi:</strong> ren ngoài 34mm (1\")</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất hoạt động:</strong> 1 - 6 bar (kg/cm2)</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng nước qua:</strong> 6.2 - 14.570m3/h</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng hút phân:</strong> 90 - 1200 lít/giờ (từ áp suất 0.5 - 4 bar)</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành:</strong> 18 tháng</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nhà sản xuất:</strong> Automat - Ấn Độ</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Thường được sử dụng phổ biến trong châm phân và bơm dinh dưỡng cho <a href=\"https://quocthaivn.com/tuoi-nho-giot\">hệ thống tưới nhỏ giọt</a> nhà kính, nhà lưới rau hoa củ quả..., tưới béc gốc trên các loại cây ăn quả như tưới cà phê, tưới sầu riêng và tưới thanh long...</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ super venturi hai đầu hút AQ115DS Việt An Nông\" src=\"https://vietannong.com.vn/_ld/3/44294273.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/3/19131718.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Bộ super venturi hai đầu hút AQ115DS - Automat Vietanong\" src=\"https://vietannong.com.vn/_ld/3/s19131718.jpg\"/></a></span></span></p>\n', 'Bộ super venturi hai đầu hút AQ115DS - Automat', 0.00, 0, 0, 1, 0, 'products/2681011f-e028-4986-8962-c2cef0f69679.png', 38, 1, NULL, NULL),
(193, 'Bộ châm phân venturi phi 34 Aq113 cao cấp - Ấn Độ', 'b-ch-m-ph-n-venturi-phi-34-aq113-cao-c-p-n', 'Mã hàng', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ châm phân venturi phi 34 Aq113 cao cấp - Ấn Độ có bộ điều chỉnh lưu lượng kế chuẩn xác. Sản phẩm thích hợp để tưới nhỏ giọt. Bảo hành 18 tháng</span></span></p>\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/thiet-bi-cham-phan\">Bộ châm phân</a> venturi phi 34 Aq113 cao cấp</span></span></h1>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ châm phân venturi phi 34 Aq113 cao cấp - Ấn Độ\" src=\"https://vietannong.com.vn/_ld/2/61518701.jpg\"/></span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông số kỹ thuật bộ châm phân phi 34 Automat Aq113:</strong></span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã hàng</strong><a href=\"http://vietannong.com.vn/load/bectuoicay/vattutuoitudong/b_cham_phan_dostraton_cong_ngh_piston_france/3-1-0-109\"><strong>:</strong> </a>AQ113RS - 1\" (34mm)</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu:</strong> Nhựa POM cao cấp</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng hút trộn phân kèm với dòng nước:</strong> 50 - 200 lít/giờ</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng nước qua venturi:</strong> 0.75 - 2m3/h</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất bắt đầu hút:</strong> 1 - 4 bar</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính gắn ống:</strong> Ren ngoài phi 34</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Quy cách:</strong> Đủ bộ gồm dây dẫn kèm van, lưu lượng kế, lọc phân, ống chính, rắc co, và các khóa nhánh phi 34 có ren.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Màu sắc:</strong> Đen</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Tỷ lệ hút chính xác:</strong> 95/100</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất hao hụt:</strong> 10% tổng áp suất chung của bơm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nơi sản xuất:</strong> Automat - India</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Ứng dụng: </b>Hút phân, dinh dưỡng hòa theo dòng nước để dẫn tới khu vực cần tưới cho cây trồng. Thông thường đi kèm theo <a href=\"http://vietannong.com.vn/\">hệ thống tưới</a><a href=\"https://quocthaivn.com/tuoi-nho-giot\"> nhỏ giọt</a>, tưới tiết kiệm bù áp. Hút và định lượng chuẩn xác nhất dung dịch trong bệnh viện khi vệ sinh, khi mổ...</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Bộ châm phân venturi phi 34 Aq113 cao cấp - Ấn Độ việt an nông\" src=\"https://vietannong.com.vn/_ld/2/13512255.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Bộ đo lưu lượng phân chuẩn xác</em></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/2/03158198.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Bộ châm phân venturi AQ 113RS - Ấn Độ\" src=\"https://vietannong.com.vn/_ld/2/s03158198.jpg\"/></a></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/2/37095808.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Bộ châm phân venturi AQ 113RS - Ấn Độ\" src=\"https://vietannong.com.vn/_ld/2/s37095808.jpg\"/></a></span></span></p>\n', 'Bộ châm phân venturi phi 34 Aq113 cao cấp - Ấn Độ', 0.00, 0, 0, 1, 0, 'products/116cdd0a-1070-4968-b9d6-8e3195dac709.png', 38, 1, NULL, NULL);
