(196, 'NÚT, ĐẦU BỊT ỐNG LDPE 25MM', 'n-t-u-b-t-ng-ldpe-25mm', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nút bít cuối ống LDPE phi 25 dùng trong hệ thống tưới nhỏ giọt, hệ thống phun gốc cục bộ bằng béc nhỏ. Chất lượng nhựa POM cao cấp.</span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nút bít cuối <a href=\"https://quocthaivn.com/nut-dau-bit-ong-ldpe-16mm\">ống LDPE</a> phi 25</span></span></h2>\n<h2> </h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu:</strong> Nhựa POM</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính:</strong> 25mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Màu sắc:</strong> Đen</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành:</strong> 06 tháng</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Dùng trong việc nối ống 25mm trong hệ thống <a href=\"https://quocthaivn.com/\">tưới nước nhỏ giọt</a>, tưới tiết kiệm nước cho cà phê, hồ tiêu và <a href=\"https://quocthaivn.com/\">tưới thanh long</a></span></span></p>\n', 'NÚT, ĐẦU BỊT ỐNG LDPE 25MM', 0.00, 0, 0, 1, 0, 'products/58b686ce-e2a9-40ba-b041-7e4285fb7d50.png', 37, 1, NULL, NULL),
(197, 'Co, cút 20mm dùng cho ống LDPE EC-0120', 'co-c-t-20mm-d-ng-cho-ng-ldpe-ec-0120', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Co, cút 20mm dùng cho ống LDPE khi lắp đặt hệ thống tưới nhỏ giọt. Chất lượng và giá cả cạnh tranh.</span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Co, cút 20mm dùng cho ống LDPE</b></span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"http://2.bp.blogspot.com/--NkTN-_pgLY/VmAyaZ-IQZI/AAAAAAAAFac/m5UlXys33IQ/s1600/co%2B20mm_4.jpg\" imageanchor=\"1\"><img alt=\"co 20, cút 20mm tưới nhỏ giọt\" src=\"http://2.bp.blogspot.com/--NkTN-_pgLY/VmAyaZ-IQZI/AAAAAAAAFac/m5UlXys33IQ/s400/co%2B20mm_4.jpg\" title=\"\"/></a></span></span></h2>\n<p> </p>\n<p> </p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Dùng trong việc chia nhánh 2 cho ống LDPE 20, PE 20 trong hệ thống<a href=\"http://vietannong.com.vn/\" target=\"_blank\"> </a>tưới tự động.</span></span></p>\n<h2><strong><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật co, cút ống 20mm LDPE:</span></span></strong></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu:</strong> Nhựa POM cao cấp</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Màu sắc: </strong>Đen</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành: </strong>06 tháng</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Dùng trong khu vực dây dẫn PE20 chạy cong trong hệ thống tưới<a href=\"http://vietannong.com.vn/\"> </a>và dẫn nước sinh hoạt.</span></span></p>