(199, 'Van 25mm LPDE điều chỉnh nước', 'van-25mm-lpde-i-u-ch-nh-n-c', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Ứng dụng: Gắn ống LDPE phi 25mm dùng trong điều chỉnh hệ thống tưới nhỏ giọt, dây nhỏ giọt, tưới tiết kiệm vào gốc cây hồ tiêu, cà phê và cây ăn quả...</span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Van 25mm LPDE điều chỉnh nước</strong></span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img alt=\"Van 25mm LPDE điều chỉnh nước\" src=\"https://vietannong.com.vn/tuoinhogiot/vale_25mm_vietannong.jpg\"/></span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông số kỹ thuật:</strong></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu:</strong> Nhựa PP cao cấp</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính gắn ống:</strong> 25mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Quy cách gắn ống:</strong> nối 2 đầu gờ</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Màu sắc cơ bản:</strong> Đen và đỏ</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp sức chịu đựng:</strong> 10 bar (10kg/cm2)</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Gắn ống dây LDPE phi 25mm.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Gắn ống LDPE phi 25 dùng trong điều chỉnh hệ thống tưới nhỏ giọt, dây nhỏ giọt, tưới tiết kiệm vào gốc cây hồ tiêu và cà phê...</span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Hình ảnh lắp đặt thực tế van ldpe 25mm ngoài vườn:</strong></span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong><img alt=\"\" src=\"https://vietannong.com.vn/tuoinhogiot/van_pe_25.jpg\"/></strong></span></span></p>\n<p> </p>\n', 'Van 25mm LPDE điều chỉnh nước', 0.00, 0, 0, 1, 0, 'products/5497f5be-f306-4bc9-a0aa-c52f298f5e91.png', 37, 1, NULL, NULL),
(200, 'Đai siết ống chống rò rỉ nước LDPE 16mm EL-0116', 'ai-si-t-ng-ch-ng-r-r-n-c-ldpe-16mm-el-0116', '', '\n<p><span style=\"font-family:Arial,Helvetica,sans-serif;\"><span style=\"font-size:14px;\">Đai siết ống chống rò rỉ nước LDPE 16mm thường dùng trong hệ thống tưới nhỏ giọt và béc tưới gốc, chồng rò rỉ nước tại khớp nối giữa ống và phụ kiện, ứng dụng khá tốt trong tưới sầu riêng, tưới thanh long và tưới cà phê...</span></span></p>\n<h2><span style=\"font-family:Arial,Helvetica,sans-serif;\"><span style=\"font-size:14px;\"><a href=\"http://shop.vietannong.com.vn/board/he_thong_tuoi/tuoi_nho_giot/dai_siet_ong_chong_ro_ri_nuoc_ldpe_20mm/2-1-0-271\">Đai siết ống</a> chống rò rỉ nước LDPE 16mm</span></span></h2>\n<h2><span style=\"font-family:Arial,Helvetica,sans-serif;\"><span style=\"font-size:14px;\"><img align=\"\" alt=\"Đai siết ống chống rò rỉ nước LDPE 16mm 2\" src=\"https://vietannong.com.vn/_ld/3/54089460.jpg\"/></span></span></h2>\n<h2><span style=\"font-family:Arial,Helvetica,sans-serif;\"><span style=\"font-size:14px;\">Thông số kỹ thuật đai siết ống 16mm LDPE:</span></span></h2>\n<p><span style=\"font-family:Arial,Helvetica,sans-serif;\"><span style=\"font-size:14px;\"><strong>Đường kính:</strong> 16mm</span></span></p>\n<p><span style=\"font-family:Arial,Helvetica,sans-serif;\"><span style=\"font-size:14px;\"><strong>Màu sắc:</strong> Đen</span></span></p>\n<p><span style=\"font-family:Arial,Helvetica,sans-serif;\"><span style=\"font-size:14px;\"><strong>Chất liệu:</strong> Nhựa POM</span></span></p>\n<p><span style=\"font-family:Arial,Helvetica,sans-serif;\"><span style=\"font-size:14px;\"><strong>Cách gắn:</strong> Gắn vào đầu ống LDPE 16mm kết nối với phụ kiện, sau đó siết chặt lại</span></span></p>\n<p><span style=\"font-family:Arial,Helvetica,sans-serif;\"><span style=\"font-size:14px;\"><strong>Ứng dụng:</strong> Thường dùng trong <a href=\"https://quocthaivn.com/phu-kien-tuoi-nho-giot?page=1\">hệ thống tưới nhỏ giọt</a> và<strong> <a href=\"ht