(201, 'Van đa năng dây nhỏ giọt dẹp 16mm MV- 021617', 'van-a-n-ng-d-y-nh-gi-t-d-p-16mm-mv-021617', '', '\n<p>MV-021617 Van đa năng dùng<br/>\ncho ống PE tròn Dn16 hoặc ống<br/>\nPE tròn với ống dẹp Dn16*17.<br/>\nDùng trong tưới nước nông<br/>\nnghiệp,chất liệu bằng nhựa.</p>\n', 'Van đa năng dây nhỏ giọt dẹp 16mm MV- 021617', 0.00, 0, 0, 1, 0, 'products/d04cca84-75b4-41d7-8612-b124be060b25.png', 28, 1, NULL, NULL),
(202, 'Phụ kiện kết thúc dòng chảy TP-0117', 'ph-ki-n-k-t-th-c-d-ng-ch-y-tp-0117', '', '\n<p>TP-0117 Phụ kiện kết thúc dòng chảy<br/>\ncủa ống dẹp Dn17, có móc cắm gim<br/>\nxuống đất. Dùng trong tưới nước<br/>\nnông nghiệp , chất liệu bằng nhựa.</p>\n', 'Phụ kiện kết thúc dòng chảy TP-0117', 0.00, 0, 0, 1, 0, 'products/fecdd163-1a3b-4433-b67b-ae9e9ad16c1d.png', 28, 1, NULL, NULL),
(203, 'Phụ kiện kết nối BC-011617', 'ph-ki-n-k-t-n-i-bc-011617', '', '\n<p>BC-011617 Phụ kiện kết nối giữa<br/>\nống PE tròn với ống dẹp<br/>\nDn17*16. Dùng trong tưới nước<br/>\nnông nghiệp, chất liệu bằng nhựa</p>\n', 'Phụ kiện kết nối BC-011617', 0.00, 0, 0, 1, 0, 'products/d5866296-bb79-4f09-8d44-58669845c003.png', 28, 1, NULL, NULL),
(204, 'Nối nhanh W-3220', 'n-i-nhanh-w-3220', '', '\n<p>W-3220 Van bi 1 đầu ren trong, 1<br/>\nđầu ren ngoài ¾” , đường kính<br/>\ntrong 1cm. Chất liệu bằng nhựa .</p>\n', 'Nối nhanh W-3220', 12100.00, 0, 0, 1, 0, 'products/daacaa47-cfb8-46d6-b6a1-cfc97ac4c2a1.png', 39, 1, NULL, NULL),
(205, 'Nối nhanh W-3290', 'n-i-nhanh-w-3290', '', '\n<p>W-3290 Van bi 1 cửa ren trong<br/>\nD=20mm , 1 cửa ra nối nhanh<br/>\nD=9mm, chất liệu bằng nhựa,<br/>\nđiều kiển bằng tay ,hiệu<br/>\naquamate, mới 100%.</p>\n', 'Nối nhanh W-3290', 15730.00, 0, 0, 1, 0, 'products/02fb4687-72e9-4cb4-805e-da671e1ed3a6.png', 39, 1, NULL, NULL),
(206, 'Nối nhanh W-302-04', 'n-i-nhanh-w-302-04', '', '\n<p>W-302-04 Cút nối Lơ dài thêm:<br/>\nren trong 21mm , ren ngoài<br/>\n21mm, chất liệu bằng nhựa</p>\n', 'Nối nhanh W-302-04', 2750.00, 0, 0, 1, 0, 'products/4d06bab7-68e1-4360-b446-13a46766eecb.png', 39, 1, NULL, NULL),
(207, 'Nối nhanh WT-4120', 'n-i-nhanh-wt-4120', '', '\n<p>WT-4120 Van hẹn giờ bằng tay,<br/>\nloại van 2 cửa, 1 lần đóng hoặc<br/>\nmở trong vòng 2 giờ, cửa vào ren<br/>\ntrong D20mm, cửa ra ren ngoài<br/>\nD20mm, bằng nhựa, dùng trong<br/>\nnông nghiệp, hiệu Aquamate,</p>\n', 'Nối nhanh WT-4120', 121000.00, 0, 0, 1, 0, 'products/9bb61181-1fc3-411f-a55d-eba8ab015091.png', 39, 1, NULL, NULL),
(208, 'Nối nhanh W-3240-10', 'n-i-nhanh-w-3240-10', '', '\n<p>W-3240-10 Cút nối, thay đổi,<br/>\nmở rộng nhanh chóng giữa 2<br/>\nống mềm làm vườn đường kính<br/>\n26mm. chất liệu bằng nhựa.</p>\n', 'Nối nhanh W-3240-10', 14300.00, 0, 0, 1, 0, 'products/c4672375-a871-4e7a-a7fb-394dfd064d49.png', 39, 1, NULL, NULL),
(209, 'Nối nhanh SW-1001', 'n-i-nhanh-sw-1001', '', '\n<p>SW-1001 Phụ kiện kết nối thẳng<br/>\n(Mang sông) 2 đầu ren trong<br/>\n21mm (BSP) , chất liệu bằng<br/>\nnhựa</p>\n', 'Nối nhanh SW-1001', 3300.00, 0, 0, 1, 0, 'products/aa1c6dfa-de1e-49fa-a9a9-8ea7258cdc1c.png', 39, 1, NULL, NULL),
(210, 'Nối nhanh W-301-04', 'n-i-nhanh-w-301-04', '', '\n<p>W-301-04 Cút nối 2 đầu ren ngoài<br/>\n21mm, chất liệu bằng nhựa</p>\n', 'Nối nhanh W-301-04', 2750.00, 0, 0, 1, 0, 'products/cef4de02-6e83-4964-8843-2edcb6cf6933.png', 39, 1, NULL, NULL),
(211, 'Nối nhanh W-3240', 'n-i-nhanh-w-3240', '', '\n<p>W-3240 Cút nối thay đổi, mở<br/>\nrộng nhanh chóng gữa 2 ống mềm<br/>\nlàm vườn, bằng nhựa. đường kính<br/>\n9mm.</p>\n', 'Nối nhanh W-3240', 2750.00, 0, 0, 1, 0, 'products/cef81a37-cd7f-4d4b-96d7-32d2c4f14f83.png', 39, 1, NULL, NULL),
(212, 'Nối nhanh W-302', 'n-i-nhanh-w-302', '', '\n<p>W-302 Cút nối đầu 2 ren ngoài,<br/>\n21mmx27mm bằng nhựa</p>\n', 'Nối nhanh W-302', 3410.00, 0, 0, 1, 0, 'products/06b534da-e44b-4728-8026-ba2be2358fcd.png', 39, 1, NULL, NULL),
(213, 'Nối nhanh W-3090-10', 'n-i-nhanh-w-3090-10', '', '\n<p>W-3090-10 Cút nối, 1 đầu ren<br/>\nngoài 34mm, 1 đầu nối nhanh<br/>\ndương 26mm, chất liệu bằng<br/>\nnhựa.</p>\n', 'Nối nhanh W-3090-10', 13090.00, 0, 0, 1, 0, 'products/9f267808-2a71-4e13-9e61-3df37abc831f.png', 39, 1, NULL, NULL),
(214, 'Nối nhanh W-3085', 'n-i-nhanh-w-3085', '', '\n<p>W-3085 Cút nối chuyển đổi từ ren<br/>\nngoài 3/4” thành ren ngoài 1/2\"<br/>\nBSP , chất liệu bằng nhựa</p>\n', 'Nối nhanh W-3085', 2695.00, 0, 0, 1, 0, 'products/f420f715-cdc0-481c-a74e-b78318b12b4f.png', 39, 1, NULL, NULL),
(215, 'Nối nhanh W-3084-10', 'n-i-nhanh-w-3084-10', '', '\n<p>W-3084-10 Cút nối, 1 đầu nối<br/>\nnhanh 26mm,1 đầu ren trong<br/>\n27mm và 34mm dùng để kết nối<br/>\nvới đầu vòi nước, chất liệu bằng<br/>\nnhựa .</p>\n', 'Nối nhanh W-3084-10', 18150.00, 0, 0, 1, 0, 'products/a60e5d33-8cbd-480f-a283-cf23e4009335.png', 39, 1, NULL, NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `sku`, `content`, `short_desc`, `price`, `discount`, `quantity`, `status`, `type`, `thumbnail`, `category_id`, `brand_id`, `created_at`, `updated_at`) VALUES
(216, 'Nối nhanh W-3090-06', 'n-i-nhanh-w-3090-06', '', '\n<p>W-3090-06 Cút nối, 1 đầu ren<br/>\nngoài 27mm, 1 đầu nối nhanh<br/>\ndương 26mm, chất liệu bằng<br/>\nnhựa.</p>\n', 'Nối nhanh W-3090-06', 11880.00, 0, 0, 1, 0, 'products/b1a87da0-7dcc-4bb2-92dc-d0655a95137a.png', 39, 1, NULL, NULL),
(217, 'Nối nhanh W-3326J', 'n-i-nhanh-w-3326j', '', '\n<p>W-3326J Cút nối một đầu nối<br/>\nnhanh dương, một đầu kết nối với<br/>\nống mềm làm vười 8,5mm. Chất<br/>\nliệu bằng nhựa.</p>\n', 'Nối nhanh W-3326J', 7260.00, 0, 0, 1, 0, 'products/0674b4ff-9a57-4f99-b00c-b7a9c2cf0663.png', 39, 1, NULL, NULL),
(218, 'Nối nhanh W-3393', 'n-i-nhanh-w-3393', '', '\n<p>W-3393 Cút nối, 1 đầu ren<br/>\ntrong 21mm 1 đầu kết nối với<br/>\nống mềm 7.5mm~9.5mm, chất<br/>\nliệu bằng nhựa.</p>\n', 'Nối nhanh W-3393', 7040.00, 0, 0, 1, 0, 'products/b7b61b66-3150-4a5b-b893-5ff31895749a.png', 39, 1, NULL, NULL),
(219, 'Nối nhanh W-3394', 'n-i-nhanh-w-3394', '', '\n<p>W-3394 Cút nối, 1 đầu nối<br/>\nnhanh âm, 1 đầu ren ngoài<br/>\n21mm, chất liệu bằng nhựa</p>\n', 'Nối nhanh W-3394', 7590.00, 0, 0, 1, 0, 'products/120194f9-b048-4fe3-a49f-6e8f98fab90f.png', 39, 1, NULL, NULL),
(220, 'Nối nhanh W-3380', 'n-i-nhanh-w-3380', '', '\n<p>W-3380C Cút nối 1đầu ren ngoài<br/>\n21mm 1 đầu kết nối với ống mềm<br/>\nlàm vườn 14mm, chất liệu bằng<br/>\nnhựa.</p>\n', 'Nối nhanh W-3380', 5500.00, 0, 0, 1, 0, 'products/5fd05ae3-12b2-46a5-b44a-f34431835dfe.png', 28, 1, NULL, NULL),
(221, 'Nối nhanh W-3130-10 (New)', 'n-i-nhanh-w-3130-10-new', '', '\n<p>W-3130-10 Cút nối, 1 đầu nối<br/>\nnhanh âm 26mm, 1 đầu kết nối<br/>\nvới ống mềm làm vườn 25mm,<br/>\nchất liệu bằng nhựa.</p>\n', 'Nối nhanh W-3130-10 (New)', 36300.00, 0, 0, 1, 0, 'products/962bb66e-c713-449c-82a2-48f3c095de22.png', 39, 1, NULL, NULL),
(222, 'Súng tưới MHR-450 Aquamate', 's-ng-t-i-mhr-450-aquamate', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">MHR-450 Bộ súng phun tưới<br/>\nnước nông nghiệp 8 kiểu có ga<br/>\nống và 50m ống phun nước<br/>\n12mm, chất liệu bằng nhựa, điều<br/>\nkhiển bằng tay hiệu Aquamate.</span></span></p>\n', 'Súng tưới MHR-450 Aquamate', 1149500.00, 0, 0, 1, 0, 'products/c3fd4846-e264-4a05-b733-c3fe844b9fd2.jpg', 39, 1, NULL, NULL),
(223, 'Nối nhanh W-3180', 'n-i-nhanh-w-3180', '', '\n<p>W-3180 Cút nối, bằng nhựa, 1<br/>\nđầu nối nhanh âm, 1 đầu kết nối<br/>\nvới ống mềm làm vườn 19mm,<br/>\nhiệu aquamate, mới 100%.</p>\n', 'Nối nhanh W-3180', 10340.00, 0, 0, 1, 0, 'products/71978620-82ee-4bab-8a72-4fe4b208c081.png', 39, 1, NULL, NULL),
(224, 'Súng tưới MHR-430 Aquamate', 's-ng-t-i-mhr-430-aquamate', 'MHR-430', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bọ vòi tưới AquaMate được sử dụng rộng rãi cho gia đình và nhà vườn..</span></span></p>\n<ul>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tên hàng: Bộ phun tưới nước nông nghiệp rulo cuộn AQUAMATE 30 M</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ vòi tưới cây, rửa xe dạng rulo cuộn 30 mét AQUA MATE MHR-430 TAIWAN</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Vòi tưới cao cấp có 8 chế độ tưới khác nhau..</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Mã hàng: MHR-430</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đơn vị tính: Bộ</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thành phần chủ yếu: Nhựa ABS, PP</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Màu sắc: ĐEN, Ống cam</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Định lượng (trọng lượng): 7,3kg</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đóng gói: 01 bộ thùng carton 37x 37x 50 cm</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật: Ren trong 27mm (3/4\')</span></span></li></ul>\n<ul>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Xuất xứ: Đài Loan</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thương hiệu AquaMate</span></span></li></ul>\n', 'Súng tưới MHR-430 Aquamate', 907500.00, 0, 0, 1, 0, 'products/e650728e-d86e-46af-8da0-4ed2a848d6e6.jpg', 39, 1, NULL, NULL),
(225, 'Súng tưới MHR-425  Aquamate', 's-ng-t-i-mhr-425-aquamate', 'MHR-425', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tên hàng: Súng phun tưới nước Aquamate MHR-425, điều chỉnh 8 kiểu, có ga ống và 25m ống phun nước 12mm Mã hàng: MHR-425 </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đơn vị tính: Bộ Thành phần chủ yếu: Nhựa ABS, PP Màu sắc: Đen, Cam Trọng lượng: 5.kg Đóng gói: 1 bộ/thùng Thông số kỹ thuật: Ren trong 21mm (hoặc 27mm) lắp vào đầu ròi nước. </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">HDSD: Lắp đầu ren 21mm hoặc 27mm vào đầu vòi cấp nước. Lắp đầu nối nhanh của đoạn ống ngắn vào đầu ren, đầu còn lại lắp vào đầu nối nhanh của gá ống. Bên trong gá ống còn 1 đầu nối nhanh lắp 1 đầu ống có lò xo chống gập ống vào. 1 đầu còn lại lắp vòi chỉnh 8 kiểu bằng tay. Mở nước và bắt đầu sử dung. Bộ gá ống có bánh xe đẩy nên có thể kéo theo tiện lợi di chuyển mọi lúc mọi nơi. Bộ kết nối nhanh giúp tiết kiệm thời gian, kéo dài đến đâu dùng đến đấy, tay cuộn gọn gàng cất lại nhanh chóng</span></span></p>\n', 'Súng tưới MHR-425  Aquamate', 8470000.00, 0, 0, 1, 0, 'products/73c512f0-2954-4f46-a7d2-4bd2b34d3d6e.jpg', 39, 1, NULL, NULL),
(226, 'Súng tưới MHR-420 Aquamate', 's-ng-t-i-mhr-420-aquamate', 'MHR-420', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tên hàng: Bộ súng phun tưới nước 8 kiểu có gá ống và ống phun nước 12mm</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Mã hàng: MHR-420 </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đơn vị tính: Bộ Thành phần chủ yếu: Nhựa ABS, PP Màu sắc: Đen, Cam Trọng lượng: 5.kg Đóng gói: 1 bộ/thùng Thông số kỹ thuật: Ren trong 21mm (hoặc 27mm) lắp vào đầu ròi nước. </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">HDSD: Lắp đầu ren 21mm hoặc 27mm vào đầu vòi cấp nước. Lắp đầu nối nhanh của đoạn ống ngắn vào đầu ren, đầu còn lại lắp vào đầu nối nhanh của gá ống. Bên trong gá ống còn 1 đầu nối nhanh lắp 1 đầu ống có lò xo chống gập ống vào. 1 đầu còn lại lắp vòi chỉnh 8 kiểu bằng tay. Mở nước và bắt đầu sử dung. Bộ gá ống có bánh xe đẩy nên có thể kéo theo tiện lợi di chuyển mọi lúc mọi nơi. Bộ kết nối nhanh giúp tiết kiệm thời gian, kéo dài đến đâu dùng đến đấy, tay cuộn gọn gàng, cất lại nhanh chóng, gọn gàng, tiết kiệm diện tích lưu trữ.</span></span></p>\n', 'Súng tưới MHR-420 Aquamate', 786500.00, 0, 0, 1, 0, 'products/f7a6e0a1-bc1e-42fd-bb29-047d6dc6fab7.jpg', 39, 1, NULL, NULL),
(227, 'Rulo tay quay Aquamate HR-415', 'rulo-tay-quay-aquamate-hr-415', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Rulo tay quay cuộn dây ống tưới Aquamate Đài Loan HR-415 Bộ Rulo cuộn ống nước mềm làm vườn di động </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Mã SP: HR415</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Thương hiệu: Aquamate - Xuất xứ: Đài Loan GIỚI THIỆU SẢN PHẨM Bộ Rulo cuộn ống mềm làm vườn di động Aquamate</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Mã HR415 hiện tại là mã hàng dần được nhiều người biết đến vì độ tiện dụng của chính nó </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Sản phẩm là loại rulo di động, quay tay, và không dùng điện, không bánh xe, có kèm trục và con lăn, không kèm ống. Với kiểu di động vửa nhỏ vừa gọn như thế này, bạn có thể dễ dàng di chuyển ống mềm làm vườn 1 cách nhanh hơn, gọn gàng hơn. + Khung cuộn được làm từ các nguyên liệu cao cấp. Thân Rulo được làm từ nhựa tổng hợp ABS có tính bền cao khi va chạm và ma sát nhiều lần với cuộn dây.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Khung tay cầm làm từ nhôm cao cấp, làm bộ lô trở nên nhẹ nhàng, hạn chế sự rỉ sét do tiếp xúc nhiều với đất, cát, nước hay sự khắc nghiệt của thời tiết. </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Tay quay nhỏ, gọn, tiện lợi trong quá trình sử dụng. </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Có thể treo lên tường hoặc lên giá khi không sử dụng. Có thể di chuyển nhẹ và gọn trong quá trình làm vườn. Có thể sử dụng cho cuộn ống rửa xe. </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Bộ cuộn cuộn dây có độ dài đến 20m</span></span></p>\n', 'Rulo tay quay Aquamate HR-415', 229900.00, 0, 0, 1, 0, 'products/0108e5d6-66a3-4c46-818b-e7f5f73f2e47.png', 39, 1, NULL, NULL),
(228, 'Van cổng ty nổi Shin Yi', 'van-c-ng-ty-n-i-shin-yi', '', '\n<h2 style=\"text-align: justify;\"><strong><span style=\"font-size:14px;\">Thông số kỹ thuật:</span></strong></h2>\n<ul>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\">Hãng sản xuất: Van Shinyi (Công ty Cổ phần Van Shin Yi)</span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\">Xuất xứ: Việt Nam. (Vốn đầu tư 100% Đài Loan).</span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\">Tiêu chuẩn thiết kế: ISO7259-1988.</span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\">Kích cỡ van cổng ty nổi shinyi: DN50(2″) đến DN300 (12″).</span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\">Áp suất làm việc: 10, 16, 20, 25 Kgf/cm².</span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\">Kết nối mặt bích theo tiêu chuẩn: PN10/16/20/25/JIS10K/ANSI 150-LB.</span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\">Vận hành: Tay quay vô lăng.</span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\">Nhiệt độ làm việc: -10~80ºC.</span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\">Môi trường làm việc: Nước, Nước thải, PCCC, HVAC,…</span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\">Vật liệu: Thân gang cầu cao cấp FCD450, Sơn phủ Eboxy độ dày &gt;=300µm.</span></li></ul>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\">Thông số kích thước của van:</span></h2>\n<table border=\"1\">\n<tbody>\n<tr>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\"><strong>DN – Model</strong></span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\"><strong>Chiều dài L (mm) BS 5163 – 1988.</strong></span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\"><strong>D</strong></span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\"><strong>K</strong></span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\"><strong>n-d</strong></span></td>\n</tr>\n<tr>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">50. RRHX-0050</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">178</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">165</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">125</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">4Φ19</span></td>\n</tr>\n<tr>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">65. RRHX-0065</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">190</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">185</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">145</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">4Φ19</span></td>\n</tr>\n<tr>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">80. RRHX-0080</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">208</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">200</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">160</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">8Φ19</span></td>\n</tr>\n<tr>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">100. RRHX-0100</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">229</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">220</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">200</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">8Φ19</span></td>\n</tr>\n<tr>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">125. RRHX-0125</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">254</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">250</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">210</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">8Φ19</span></td>\n</tr>\n<tr>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">150. RRHX-0150</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">267</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">285</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">240</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">8Φ19</span></td>\n</tr>\n<tr>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">200. RRHX-0200</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">292</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">340</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">295</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">8Φ23/12Φ23</span></td>\n</tr>\n<tr>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">250. RRHX-0250</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">230</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">395/405</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">350/355</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">12Φ23/12Φ28</span></td>\n</tr>\n<tr>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">300. RRHX-0300</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">356</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">445/460</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">400/410</span></td>\n<td style=\"text-align: justify;\"><span style=\"font-size:14px;\">12Φ23/12Φ28</span></td>\n</tr>\n</tbody></table>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\">  </span></p>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\">Cấu tạo :</span></h2>\n<figure id=\"attachment_360\">\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><img alt=\"Cấu tạo Van cổng ty nổi shinyi - vannhapkhau.vn\" height=\"355\" sizes=\"(max-width: 600px) 100vw, 600px\" src=\"https://vannhapkhau.vn/wp-content/uploads/2018/08/C%E1%BA%A5u-t%E1%BA%A1o-Van-c%E1%BB%95ng-ty-n%E1%BB%95i-shinyi-vannhapkhau.vn_.jpeg\" srcset=\"https://vannhapkhau.vn/wp-content/uploads/2018/08/Cấu-tạo-Van-cổng-ty-nổi-shinyi-vannhapkhau.vn_.jpeg 600w, https://vannhapkhau.vn/wp-content/uploads/2018/08/Cấu-tạo-Van-cổng-ty-nổi-shinyi-vannhapkhau.vn_-300x178.jpeg 300w\" width=\"600\"/></span></p>\n<figcaption>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\">Cấu tạo Van cổng ty nổi shinyi</span></p></figcaption>\n</figure>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><strong>    Van cổng ty nổi shinyi</strong> với vật liệu gang  cầu FCD450, lá van hình nêm bằng gang cầu và bọc cao su EPDM và được sơn phủ Eboxy cả mặt trong và ngoài nên hoàn toàn an toàn với nước sạch. Quý khách có thể xem thêm tất cả sản phẩm tại <a href=\"https://quocthaivn.com/van-cong-la-van-boc-cao-su\"><em><strong>Van cổng shinyi</strong></em></a> để lựa chọn sản phẩm phù hợp với dự toán.</span></p>\n', 'Van cổng ty nổi Shin Yi', 1.00, 0, 0, 1, 0, 'products/521f5a38-356c-4c6c-900b-4e9c4ece6db3.png', 40, 7, NULL, NULL),
(229, 'Súng tưới MHR-315 Aquamate', 's-ng-t-i-mhr-315-aquamate', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chất liệu: Nhựa siêu bền , lõi màng lưới bảo vệ chống nổ</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Hướng dẫn sử dụng : Gắn dây có các đầu vòi khác nhau vào vòi nước, mở nguồn nước và sử dụng theo ý muốn</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Màu sắc : Xanh dương - Dây dài : , 15(m)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Vòi phun với 5 chế độ điều chỉnh khách nhaunhưphun mưa to, nhỏ, phun tia ... Có 2 độ dài dây là và 15m các bạn có thể chọn theo nhu cầu sử dụng của mình tại phần tùy chọn màu sắc độ dài ngay cạnh sản phẩm nhé</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đường kính dây: Ngoài 13mm trong 10mm+ Sản phẩm bộ dây vòi xịt cao cấp thương hiệu AQUA MATE được nhập khẩu trực tiếp từ Đài Loanthiết kế gọn gàng đẹp mắt</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tên sản phẩm : Bộ vòi xịt đa năng kèm dây dài 15m -... Xuất xứ: Đài Loan Đặc biệt: có thể sử dụng để rửa xe máy, xe đạp tại nhà....</span></span></p>\n', 'Súng tưới MHR-315 Aquamate', 266200.00, 0, 0, 1, 0, 'products/07205057-4256-426b-a8a3-51b28123b918.jpg', 39, 1, NULL, NULL),
(230, 'Súng tưới MHR-310 Aquamate', 's-ng-t-i-mhr-310-aquamate', '', '\n<p style=\"text-align: justify;\">- Chất liệu: Nhựa siêu bền , lõi màng lưới bảo vệ chống nổ</p>\n<p style=\"text-align: justify;\">- Hướng dẫn sử dụng : Gắn dây có các đầu vòi khác nhau vào vòi nước, mở nguồn nước và sử dụng theo ý muốn</p>\n<p style=\"text-align: justify;\">- Màu sắc : Xanh dương - Dây dài : 10 (m),</p>\n<p style=\"text-align: justify;\">- Vòi phun với 5 chế độ điều chỉnh khách nhaunhưphun mưa to, nhỏ, phun tia ... Có 2 độ dài dây là 10m các bạn có thể chọn theo nhu cầu sử dụng của mình tại phần tùy chọn màu sắc độ dài ngay cạnh sản phẩm nhé</p>\n<p style=\"text-align: justify;\">Đường kính dây: Ngoài 13mm trong 10mm+ Sản phẩm bộ dây vòi xịt cao cấp thương hiệu AQUA MATE được nhập khẩu trực tiếp từ Đài Loanthiết kế gọn gàng đẹp mắt</p>\n<p style=\"text-align: justify;\">Tên sản phẩm : Bộ vòi xịt đa năng kèm dây dài 10m Xuất xứ: Đài Loan Đặc biệt: có thể sử dụng để rửa xe máy, xe đạp tại nhà....</p>\n', 'Súng tưới MHR-310 Aquamate', 215600.00, 0, 0, 1, 0, 'products/60f5c2d9-bc5f-4423-97ef-cba998a6e708.jpg', 39, 1, NULL, NULL),
(231, 'Van xả khí kép-ren Shin Yi', 'van-x-kh-k-p-ren-shin-yi', '', '\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Mô tả sản phẩm:</b><br/>\n<b>Van xả khí kép ren nối ren DN50 SHIN YI ARCT-0050</b><br/>\n<b>Thông số kỹ thuật</b><br/>\n- Mã Hàng : ARCT-0050<br/>\n- Thương hiệu : SHIN YI/ TAIWAN<br/>\n- Xuất xứ : Việt Nam<br/>\n- Kích Thước : DN50<br/>\n- Tiêu Chuẩn Thiết Kế : BS EN 1074-4<br/>\n- Tiêu Chuẩn Mặt Bích/Kết Nối : BSPT/NPT Threaded<br/>\n- Áp Suất Làm Việc : PN10/PN16 JIS 10K/16K ANSI 125-LB<br/>\n- Nhiệt Độ Làm Việc : -10 ~ 80 ºC<br/>\n- Môi Trường Làm Việc : Nước, Nước Thải, Nước Nhiễm Mặn</span></span></h1>\n', 'Van xả khí kép-ren Shin Yi', 1.00, 0, 0, 1, 0, 'products/423c0033-41c9-4aeb-9ff5-dfc47394c6bf.png', 40, 7, NULL, NULL),
(232, 'Trụ tiếp nước PCCC Shin Yi không đế', 'tr-ti-p-n-c-pccc-shin-yi-kh-ng', '', '\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Trụ cứu hỏa ngoài nhà D150 ShinYi </strong></span></span></h1>\n<p>Download Catalogue: </p>\n<h2><a href=\"https://syvalves.com.vn/tru-cuu-hoa\"><font face=\"Arial, Helvetica, sans-serif\"><span style=\"font-size: 14px;\">trucuuhoakhongde.pdf</span></font></a></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Trụ cấp nước PCCC là thiết bị chuyên dùng được lắp đặt dọc theo đường phố, để nhân viên cứu hỏa  lấy nước phục vụ cho mục đích PCCC.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Trụ chữa cháy được chế tạo từ gang cầu với khả năng chịu lực lớn và độ bền sử dụng cao.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Thiết kế chống va đập, khi xẩy ra sự cố thì van vẫn được đóng kín.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Trụ cứu hỏa được sơn Epoxy bao phủ cả bên trong và bên ngoài, chống tia cực tím, không bị gỉ sét và ăn mòn.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Áp suất làm việc: 10 bar.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Ngõ vào: DN150.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Ngõ ra: DN150-2xDN65.</span></span></p>\n', 'Trụ tiếp nước PCCC Shin Yi không đế', 1.00, 0, 0, 1, 0, 'products/49797137-b927-478c-8145-adcb86e9efd9.jpg', 40, 7, NULL, NULL),
(233, 'Súng tưới G12 Aquamate', 's-ng-t-i-g12-aquamate', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">G12 Súng phun tưới nước nông<br/>\nnghiệp, phun lướt gió khuếch tán,<br/>\na/suất: 40kg/cm2, phun rộng đạt<br/>\n5.5L/min, phun thẳng đạt<br/>\n40L/min, k/cách phun 10m</span></span></p>\n', 'Súng tưới G12 Aquamate', 231000.00, 0, 0, 1, 0, 'products/e1f44abd-f923-4954-a944-0d4c8516be95.png', 39, 1, NULL, NULL),
(234, 'Súng tưới W-2160 Aquamate', 's-ng-t-i-w-2160-aquamate', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\">Súng Xịt Tưới Cây, Hoa Cần Phun Dài, Góc Phun Tùy Chỉnh Nhập Khẩu Đài Loan Aqua Mate W2160 </span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\">Chiều dài cần: Điều chỉnh tùy ý. Min: 90cm. Max: 150cm Góc phun điều chỉnh tùy ý Đầu phun có 10 chế độ phun nước và đầu phun có thể xoay 180 độ.</span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\">Tay cầm có nút điều chỉnh lượng nước hoặc khoá tắt hẳn. Chân cắm 3 tầng, thích hợp với ống phi 12 đến phi 19. Quy ước và kích thước khớp nối nhanh Khớp nối 17/25 là khớp có lỗ 17mm và đường kính lỗ ốc xiết là 25mm.</span></p>\n', 'Súng tưới W-2160 Aquamate', 248600.00, 0, 0, 1, 0, 'products/524996ed-7b7c-43e1-8986-f61755b7629a.jpg', 39, 1, NULL, NULL),
(235, 'Súng tưới G09 Aquamate', 's-ng-t-i-g09-aquamate', '', '\n<p>G09 Súng phun tưới nước nông<br/>\nnghiệp, phun lướt gió khuếch tán<br/>\nkép, a/suất: 40kg/cm2, phun rộng<br/>\nđạt 5.5L/min, phun thẳng đạt<br/>\n10L/min, k/cách phun 10m,</p>\n', 'Súng tưới G09 Aquamate', 242000.00, 0, 0, 1, 0, 'products/3154bbe2-f6a4-4a50-8ff9-78760dc0f7c8.png', 39, 1, NULL, NULL),
(236, 'Van bướm động cơ điện Shin Yi', 'van-b-m-ng-c-i-n-shin-yi', '', '\n<h2>Thông số kỹ thuật</h2>\n<h1>Van bướm điện Shin Yi</h1>\n<p>Download Catalogue: </p>\n<p><a href=\"https://syvalves.com.vn/van-buom-dong-co-dien\">vanbuomdongcodien.pdf</a></p>\n<p><strong>Mã Hàng</strong></p>\n<p>EOM</p>\n<p><strong>Kích Thước</strong></p>\n<p>DN50-DN300</p>\n<p><strong>Tiêu Chuẩn Thiết Kế</strong></p>\n<p>BS 5155<br/>\nAPI 609</p>\n<p><strong>Khoảng Cách Giữa 2 Mặt Bích</strong></p>\n<p>BS EN 558-1 TABLE 1 SERIES 20<br/>\nBS 5155<br/>\nISO 5752 Table 1 Series 20<br/>\nASME B16.10<br/>\nAPI 609<br/>\nMounting Flange ISO 5211</p>\n<p><strong>Tiêu Chuẩn Mặt Bích/Kết Nối</strong></p>\n<p>BS EN 1092-2: PN10/PN16 ISO 7005-2: PN10/PN16 JIS B2220: JIS 10K/16K</p>\n<p><strong>Tiêu Chuẩn Thiết Kế</strong></p>\n<p>BS EN 1092-2: PN10/PN16 ISO 7005-2: PN10/PN16 JIS B2220: JIS 10K/16K</p>\n<p> </p>\n<p> </p>\n', 'Van bướm động cơ điện Shin Yi', 1.00, 0, 0, 1, 0, 'products/0343ab8c-871b-4915-b65d-779b1c34b61a.png', 40, 7, NULL, NULL),
(237, 'Súng tưới W-2128 Aquamate', 's-ng-t-i-w-2128-aquamate', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nhập khẩu 100% Đài Loan </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thương hiệu :Aquamate </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kích thước: 70cm </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Trọng lượng: 260 g - Ren trong: 27mm ( 3/4\'\') </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thành phần chủ yếu: Nhôm, nhựa ABS, TPR </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nơi sản xuất: GUI YO Taiwan (Đài Loan) HDSD: Có thể phun 8 kiểu chỉ trong một lần tưới duy nhất. Tùy theo độ tuổi của cây, đặc tính của cây mà bạn tùy chỉnh áp lực tưới cho phù hợp.</span></span></p>\n', 'Súng tưới W-2128 Aquamate', 139150.00, 0, 0, 1, 0, 'products/aa17dcfc-c594-45af-9fbc-ddbd02af4813.png', 39, 1, NULL, NULL),
(238, 'Súng tưới W-4100 Aquamate', 's-ng-t-i-w-4100-aquamate', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hàng nhập khẩu Đài Loan</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thương hiệu: aquamate </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Màu sắc: xanh , đen Béc phun tưới nước nông nghiệp nhiều tia, loại 3 ngả di động. Béc phun nước quay văng tự động.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đầu cấp nước ren trong 27mm.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Lỗ phun D1mm Điều khiển bằng tay</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chất liệu bằng nhựa, dễ dàng di chuyển khi cần thiết, thuận tiện nhất trong tưới cây cỏ,...</span></span></p>\n', 'Súng tưới W-4100 Aquamate', 79200.00, 0, 0, 1, 0, 'products/b9a3a811-c298-4795-b9fe-77dea2f36a2a.png', 39, 1, NULL, NULL),
(239, 'Súng tưới W-9132S Aquamate', 's-ng-t-i-w-9132s-aquamate', 'W-9132S', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tên hàng: Súng phun loại 3 kiểu bằng nhựa, điều khiển đóng mở bằng tay, có bầu chứa dạng nối nhanh.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Mã hàng: W-9132S </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đơn vị tính: Cái </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thành phần chủ yếu: Nhựa PP, PE, kẽm </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Màu sắc: Xanh, trắng Trọng lượng: 540g </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật: Ren trong 27mm (3/4) </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">HDSD: Dùng nước từ máy bơm áp hoặc nguồn nước có áp lực cao, kích hoạt tay cò để mở, thay đầu vòi để chỉnh phun tưới hoặc xịt rửa tùy ý. Đặc biệt có bầu chứa nước để dùng đựng bột \"RỬA XE KHÔNG CHẠM\" dùng phun lên xe rửa trước khi rửa lại bằng nước sạch mà không phải kỳ cọ xe. Có 6 nấc (0-1-2-3-4-50 để điều chỉnh tỉ lệ dung dịch. Được nối nhanh với ống mềm làm vườn.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Cảnh báo an toàn: Tránh xa nguồn nhiệt cao, lửa, không dùng kìm có răng. </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Xuất xứ: Đài Loan</span></span></p>\n', 'Súng tưới W-9132S Aquamate', 399300.00, 0, 0, 1, 0, 'products/8da978c3-30b1-44bb-a689-e841c86a33b0.png', 39, 1, NULL, NULL),
(240, 'Súng tưới W-9302 Aquamate', 's-ng-t-i-w-9302-aquamate', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Lắp ống phi 21 trở xuống.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Có thể điều chỉnh 7 chế độ tưới khác nhau.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Điều chỉnh lượng nước bắng tay bóp, tắt, mở nước ngay trên vòi.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tên hàng: Vòi Tưới nước nông nghiệp, loại 7 kiểu phun, thân bằng kim loại, điều khiển bằng tay .</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thành phần chủ yếu: hợp kim nhôm, đồng, kẽm, nhựa</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật: ren trong 27mm </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">HDSD: </span></span><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Dùng nước từ máy bơm áp hoặc nguồn nước có áp lực cao, kích hoạt tay cò để mở, xoay đầu vòi để chỉnh kiểu phun tùy ý. Kết nối với ống mềm làm vườn.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Cảnh bào an toàn: Tránh va chạm mạnh, không dùng kềm có răng để mở.</span></span></p>\n', 'Súng tưới W-9302 Aquamate', 167200.00, 0, 0, 1, 0, 'products/0c65fc49-24e5-4b90-a373-3b23ef17a734.png', 39, 1, NULL, NULL),
(241, 'Súng tưới W-9301 Aquamate', 's-ng-t-i-w-9301-aquamate', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">HÔNG TIN CHI TIẾT </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Tên sản phẩm: Súng phun tưới nước nông nghiệp, loại 1 tia đầu chỉnh vặn xoắn bằng đồng, thân bằng kim loại, điều khiển bằng tay </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Thương hiệu: Aquamate - Hãng sản xuất: GUIYO INDUSTRICAL CO., LTD - Xuất xứ: Hàng nhập khẩu chính hãng Đài Loan </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Thành phần chủ yếu: Hợp kim nhôm, kẽm, đồng </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Thông số kỹ thuật: Ren trong 27mm (3/4\") </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">GIỚI THIỆU Guiyo được bên đến là hãng sản xuất các thiết bị, phụ kiện làm vườn có chất lượng hàng đầu Đài Loan. Sản phẩm Súng phun tưới nước nông nghiệp loại 1 tia do GUIYO sản xuất chính là giải pháp tốt nhất cho mọi nhà nông. Với chất liệu thân bằng kim loại tạo độ chắc chắn khi thực hiện công việc làm vườn, đầu phun bằng đồng ngăn ngừa sự ăn mòn do sử dụng lâu trong nước kèm các tạp chất có trong nước tưới.</span></span></p>\n', 'Súng tưới W-9301 Aquamate', 179850.00, 0, 0, 1, 0, 'products/1461c7cf-031f-4786-955e-358710528bbc.png', 39, 1, NULL, NULL),
(242, 'Súng tưới W-4090 Aquamate', 's-ng-t-i-w-4090-aquamate', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bép (béc) phun tưới Aquamate W-4090 nhiều tia,phun văng ra nhiều tia chí 3 ngả di động </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thương hiệu: Aquamate</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hàng nhập khẩu mới 100% Đài Loan </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thương hiệu: Aquamate </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Mã sản phẩm : W-4909 Là dòng béc tưới phun nước nhiều tia D=20mm phun văng ra nhiều tia chi 3 ngả di động Chất liệu : thân béc bằng đồng, đế béc bằng kẽm</span></span></p>\n', 'Súng tưới W-4090 Aquamate', 157300.00, 0, 0, 1, 0, 'products/e3d62db0-c9b1-45cf-b508-00b009df27b9.png', 39, 1, NULL, NULL),
(243, 'Súng tưới W-3502 Aquamate', 's-ng-t-i-w-3502-aquamate', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thành phần chủ yếu: Nhựa ABS, POM.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Màu sắc: Xanh, đen. Trọng lượng 348,5g.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật: Ren trong 27mm (3/4).</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">HDSD: Dùng nước từ máy bơm áp hoặc nguồn nước có áp lực cao, kích hoạt tay cò để mở, xoay đầu vòi để chỉnh phun 7 kiểu tùy ý. Đặc biệt có bầu chứa nước để bón chất dinh dưỡng cho cây trồng, phun thuốc trừ sâu organic cho rau xanh hoặc trộn xà bông khi phun rửa xe. Kết nối nhanh với ống mềm làm vườn. </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Cảnh báo an toàn: Tránh xa nguồn nhiệt cao, lửa, không dùng kìm có răng. </span></span></p>\n<p> </p>\n', 'Súng tưới W-3502 Aquamate', 181500.00, 0, 0, 1, 0, 'products/17b2c8e7-0ab8-4570-b353-f86cce40d18f.png', 39, 1, NULL, NULL),
(244, 'Súng tưới BW-N1041', 's-ng-t-i-bw-n1041', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hàng nhập khẩu</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thành phần chủ yếu: Đồng-Nhựa </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Trọng lượng: 75,7gram Thông số Ren trong 27mm ( 3/4\'\'), đuôi ống thiết kế 3 tầng có thể dùng 3 cở ống ống khác nhau: 12.5mm, 16mm, 19mm Vòi điều chỉnh tia nước theo cách vặn xoắn để có tia phun xa, phun gần, chụm, xòe.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Do chất liệu chính là đồng nên rất bền, bền với nắng nóng, mưa gió..</span></span></p>\n', 'Súng tưới BW-N1041', 63250.00, 0, 0, 1, 0, 'products/c5f49d60-6de6-4557-be0f-728b8a91e36c.png', 39, 1, NULL, NULL),
(245, 'Súng tưới W-1110 Aquamate', 's-ng-t-i-w-1110-aquamate', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thành phần chủ yếu: Nhựa Zinc, Brass, ABS.<br/>\nTrọng lượng: 181,4g.<br/>\nThông số kỹ thuật: Ren trong 27mm (3/4).<br/>\nHDSD: Dùng nước từ máy bơm áp hoặc nguồn nước có áp lực cao, kích hoạt tay cò để mở, điều chỉnh ở đầu để chọn loại tia nước mong muốn, ren ngoài để nối thêm phụ kiện gia tăng.<br/>\nCảnh báo an toàn: Tránh xa nguồn nhiệt cao, lửa.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Súng thân sắt, tay cầm chắc chắn. Đầu bằng đồng bền đẹp, dễ sử dụng, điều chỉnh tia to nhỏ. </span></span></p>\n', 'Súng tưới W-1110 Aquamate', 84700.00, 0, 0, 1, 0, 'products/8ec01e23-31a0-43ec-9329-e8c050083693.jpg', 39, 1, NULL, NULL),
(246, 'Súng tưới W-9505 Aquamate', 's-ng-t-i-w-9505-aquamate', 'Hợp kim Nhôm – kẽm – đồng – nhựa.', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tên hàng: Súng phun tưới nước nông nghiệp 8 kiểu thân bằng kim loại. </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Mã hàng: W-9505 Thành phần chủ yếu: Hợp kim Nhôm – kẽm – đồng – nhựa. </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Trọng lượng: 300gr Thông số kĩ thuật: Ren trong 27mm (3/4”) </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Màu sắc : đen , xám , trắng. </span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hướng dẫn sử dụng: Dùng nước từ máy bơm áp hoặc nguồn nước có áp lực cao, kích hoạt tay cò để mở thuận tiện, xoay đầu vòi để chỉnh phun 8 kiểu tùy ý, kết nối với ống mềm làm vườn. Công dụng: Xuất xứ: Đài Loan Nhà sản xuất: Gui Yo Industrial Co.ldt</span></span></p>\n', 'Súng tưới W-9505 Aquamate', 101750.00, 0, 0, 1, 0, 'products/baa82fc5-ef9a-45d9-8db4-47e207bdd8d5.jpg', 39, 1, NULL, NULL),
(247, 'Súng tưới W-9902 Aquamate', 's-ng-t-i-w-9902-aquamate', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tên sản phẩm : Súng phun tưới nước 7 kiểu W-9902</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Kích thước : 12,5mm x 16mm x 19mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Trọng lượng : 215.2 g - Ren trong : 27mm ( 3/4\'\')</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Màu sắc : Xanh lá phối đen</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Thành phần chủ yếu : Nhôm, kẽm đồng, nhựa ABS - HDSD: Có thể phun 7 kiểu chỉ trong một lần tưới duy nhất. Tùy theo độ tuổi của cây, đặc tính của cây mà bạn tùy chỉnh áp lực tưới cho phù hợp.</span></span></p>\n', 'Súng tưới W-9902 Aquamate', 103950.00, 0, 0, 1, 0, 'products/9525d5d9-e4b0-4cc1-a0f5-9a5593111fa9.jpg', 39, 1, NULL, NULL),
(248, 'Súng tưới W-9105 Aquamate', 's-ng-t-i-w-9105-aquamate', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật: Ren trong 27mm (3/4). Tay cầm cao su chống trơn trượt, cầm chắc tay. Nhựa chắc chắn an toàn, kể cả đối với trẻ em. Vòi có 7 tia dễ chỉnh tưới cây to, cây rau mềm cần tia nước nhẹ. Chỉnh phun rửa xe hay rửa sân thoải mái. Thành phần chủ yếu: Nhựa ABS, PP. HDSD: Dùng nước từ máy bơm áp hoặc nguồn nước có áp lực cao, kích hoạt tay cò để mở, xoay đầu vòi để chỉnh phun 7 kiểu tùy ý. Cảnh báo an toàn: Tránh xa nguồn nhiệt cao, lửa, không dùng kìm có răng. Xuất xứ: Đài Loan.</span></span></p>\n', 'Súng tưới W-9105 Aquamate', 66550.00, 0, 0, 1, 0, 'products/1b8f8ed7-931e-4766-84b7-d537f7a22916.png', 39, 1, NULL, NULL),
(249, 'Súng tưới W-9602 Aquamate', 's-ng-t-i-w-9602-aquamate', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thành phần chủ yếu: Nhựa ABS, PP,</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thân ruột bằng kim loại chắc chắn, cán được bọc cao su êm ái, chống trượt</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Trọng lượng: 300gr </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kĩ thuật: Ren trong 27mm (3/4”)</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hướng dẫn sử dụng: Dùng nước từ máy bơm áp hoặc nguồn nước có áp lực cao, dùng ngón tay cái để đóng mở, xoay đầu vòi để chỉnh phun 8 kiểu phun tưới cây, phun sương.. dùng rửa xe, xịt vệ sinh nhà cửa, chuồng trại..., kết nối với ống mềm làm vườn Khóa đóng mở thuận tiện, nhẹ nhàng, không mỏi tay </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Công dụng: Xuất xứ: Đài Loan Nhà sản xuất: Gui Yo Industrial Co.ldt Hàng mới 100%</span></span></p>\n', 'Súng tưới W-9602 Aquamate', 125400.00, 0, 0, 1, 0, 'products/75df56c2-063e-41cb-be1d-d23ae13aa1dd.jpg', 39, 1, NULL, NULL),
(250, 'Súng tưới W-9201 Aquamate', 's-ng-t-i-w-9201-aquamate', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hàng Chính Hãng mới 100% Đài Loan Thương hiệu nổi tiếng Aquamate Sản phẩm thương hiệu nên được sản xuất với độ hoàn thiện cao. Thiết kế bắt mắt. Tăng áp mạnh mẽ Chân cắm 3 tầng. Phù hợp với ống 12-19 Loại 1 tia đầu chỉnh vặn xoắn lỗ phun D6mm bằng nhựa, điều khiển bằng tay</span></span></p>\n', 'Súng tưới W-9201 Aquamate', 57200.00, 0, 0, 1, 0, 'products/b6f5643a-9b8a-4be2-93ce-ce3d3194b5bc.jpg', 39, 1, NULL, NULL),
(251, 'Súng tưới W-9109 Aquamate', 's-ng-t-i-w-9109-aquamate', '', '\n<p>Hàng chính hãng nhập khẩu Đài Loan Thương hiệu : Aquamate Mã sản phẩm: W-9109 Chất liệu: nhựa Mô tả sản phẩm: Súng phun tưới nước nông nghiệp, loại 1 tia đầu ren ngòai lỗ phun D6mm , điều khiển bằng tay.</p>\n', 'Súng tưới W-9109 Aquamate', 25300.00, 0, 0, 1, 0, 'products/bbf538b2-cd58-4502-b002-4eb9525864e5.jpg', 39, 1, NULL, NULL),
(252, 'Súng tưới W3201-10 Aquamate', 's-ng-t-i-w3201-10-aquamate', '', '\n<p>Hàng nhập khẩu : Đài Loan Thành phần chủ yếu: Nhựa ABS, PP Trọng lượng: 110 gram Thông số Ren trong 34mm (1\'\'), đuôi ống thiết kế 3 tầng có thể dùng 3 cở ống ống khác nhau: 18mm,20mm, 25mmmm. Cố định ống bằng đai siết cổ dê Vòi điều chỉnh tia nước theo cách vặn xoắn.Vòi tưới cây tự động tăng áp AQUA MATE W-3201-10 lưu lượng lớn xuất xứ Đài Loan có lưu lượng lớn dùng tưới cho các vườn rộng. Nguồn nước dùng máy bơm hoặc nguồn nước có áp lực cao. Vòi xịt phun nước được làm bằng chất liệu nhựa tổng hợp có độ bền cao, thiết kế tinh xảo, sử dụng dễ dàng, có thể điều chỉnh nhiều kiểu phun nước khác nhau.</p>\n', 'Súng tưới W3201-10 Aquamate', 54450.00, 0, 0, 1, 0, 'products/858428db-7477-4c9d-8cb0-256c295e916a.jpg', 39, 1, NULL, NULL),
(253, 'Súng tưới W-9108J Aquamate', 's-ng-t-i-w-9108j-aquamate', 'Dùng nước từ máy bơm áp hoặc nguồn nước có áp lực cao, kích hoạt tay cò để mở, xoay đầu vòi để chỉnh phun 5 kiểu tùy ý, kết nối nhanh với ống mềm làm vườn.', '\n<p>Súng phun tưới nước nông nghiệp , loại 5 kiểu bằng nhựa điều kiển bằng tay (có nối nhanh, kiểu nhật) Tên hàng: Súng phun tưới nước nông nghiệp, loại 5 kiểu , thân bằng nhựa, điều khiển bằng tay, kết nối nhanh. Mã hàng: W-9108J Thành phần chủ yếu: Nhựa ABS, PP Màu sắc: Trắng, xanh Trọng lượng: 80gr/1sp Thông số kĩ thuật: Ren trong 27mm (3/4”) Hướng dẫn sử dụng: Dùng nước từ máy bơm áp hoặc nguồn nước có áp lực cao, kích hoạt tay cò để mở, xoay đầu vòi để chỉnh phun 5 kiểu tùy ý, kết nối nhanh với ống mềm làm vườn.</p>\n', 'Súng tưới W-9108J Aquamate', 32670.00, 0, 0, 1, 0, 'products/86583196-e90a-498e-8a60-a19b3e7650a6.jpg', 39, 1, NULL, NULL),
(254, 'Súng tưới W-9108 Aquamate', 's-ng-t-i-w-9108-aquamate', 'W-9108', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Mã hàng: <strong>W-9108</strong></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thương hiệu: <strong>Aquamate</strong></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Xuất xứ: <strong>Đài Loan</strong></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông tin sản phẩm</span></span></p>\n<ul>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thành phần chủ yếu: nhựa ABS, PP</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật: Ren trong 27mm (3/4\")</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Định lượng: 82.4 gram</span></span></li></ul>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">*Súng phun tưới nước có 05 chức năng tùy chỉnh tại nòng phun.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">*Tháo lắp vào ống mềm một cách dễ dàng.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">*Rất hữu dụng cho tưới cây cảnh, tưới vườn quả, tưới rau, phun sương tạo độ ẩm hoặc sử dụng để rửa xe rửa sân sàn...</span></span></p>\n', 'Súng tưới W-9108 Aquamate', 30250.00, 0, 0, 1, 0, 'products/7b9bcb2a-c1fa-4068-9f5c-b85a778744f0.png', 39, 1, NULL, NULL),
(255, 'Súng tưới W-3226 Aquamate', 's-ng-t-i-w-3226-aquamate', '', '\n<p>Nhập khẩu 100% Đài Loan Thương hiệu :Aquamate Kích thước: 70cm - Trọng lượng: 260 g - Ren trong: 27mm ( 3/4\'\') - Thành phần chủ yếu: Nhôm, nhựa ABS, TPR - Nơi sản xuất: GUI YO Taiwan (Đài Loan)</p>\n', 'Súng tưới W-3226 Aquamate', 38720.00, 0, 0, 1, 0, 'products/6dcd4109-d7d0-45ec-b88b-855fc161fe02.png', 39, 1, NULL, NULL),
(256, 'Súng tưới W3203 Aquamate', 's-ng-t-i-w3203-aquamate', 'W-3203', '\n<p>Mã hàng: <strong>W-3203</strong></p>\n<p>Thương hiệu: <strong>Aquamate</strong></p>\n<p>Xuất xứ: <strong>Đài Loan</strong></p>\n<p>Chi tiết sản phẩm</p>\n<ul>\n<li>Đầu phun tưới nước nông nghiệp chỉnh vặn xoắn, có đầu kết nối ống mềm làm vườn</li>\n<li>Chất liệu bằng nhựa</li></ul>\n<p> </p>\n', 'Súng tưới W3203 Aquamate', 24200.00, 0, 0, 1, 0, 'products/3201666d-5a53-430b-b918-1c4b8ffb0d80.png', 39, 1, NULL, NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `sku`, `content`, `short_desc`, `price`, `discount`, `quantity`, `status`, `type`, `thumbnail`, `category_id`, `brand_id`, `created_at`, `updated_at`) VALUES
(257, 'Súng tưới W3200 Aquamate', 's-ng-t-i-w3200-aquamate', 'W-3200', '\n<p>Mã hàng: <strong>W-3200</strong></p>\n<p>Thương hiệu: <strong>Aquamate</strong></p>\n<p>Xuất xứ: <strong>Đài Loan</strong></p>\n<p>Chi tiết sản phẩm</p>\n<p>Đầu phun tưới nước nông nghiệp, chỉnh vặn xoắn 1 lỗ phun</p>\n<p>Chất liệu bằng nhựa</p>\n<h2 dir=\"ltr\"><b id=\"docs-internal-guid-13315fad-7fff-2b1b-3a0a-2136189d00eb\">Địa chỉ mua thiết bị tưới tự động uy tín nhất tại HN</b></h2>\n<p dir=\"ltr\"><b id=\"docs-internal-guid-13315fad-7fff-2b1b-3a0a-2136189d00eb\">Tự hào là đơn vị có nhiều năm kinh nghiệm trong ngành vật tư thiết bị, phụ kiện đường uống nước. <a href=\"https://quocthaivn.com/\">Quocthaivn.com</a> luôn là nhà cung cấp chiến lược, đối tác tin cậy của rất nhiều công trình cũng như nhà đầu tư lớn. Luôn mang đến cho các khách hàng những giải pháp tối ưu cùng với đó là cung cấp các sản phẩm với rất nhiều ưu điểm, ưu đãi đi kèm như:</b></p>\n<ul>\n<li aria-level=\"1\" dir=\"ltr\">\n<p dir=\"ltr\" role=\"presentation\"><b id=\"docs-internal-guid-13315fad-7fff-2b1b-3a0a-2136189d00eb\">Mang đến cho khách hàng các sản phẩm với chất lượng tốt nhất.</b></p></li>\n<li aria-level=\"1\" dir=\"ltr\">\n<p dir=\"ltr\" role=\"presentation\"><b id=\"docs-internal-guid-13315fad-7fff-2b1b-3a0a-2136189d00eb\">Cung cấp các sản phẩm vật tư, phụ kiện đường ống nước đa dạng với rất nhiều loại sản phẩm như: van vòi công nghiệp, đường ống nước, thiết bị phòng cháy chữa cháy, đồng hồ đo điện,...</b></p></li>\n<li aria-level=\"1\" dir=\"ltr\">\n<p dir=\"ltr\" role=\"presentation\"><b id=\"docs-internal-guid-13315fad-7fff-2b1b-3a0a-2136189d00eb\">Luôn đáp ứng được đầy đủ những nhu cầu từ phía khách hàng để đảm bảo cung ứng đầy đủ vật tư cho các công trình lớn nhỏ.</b></p></li>\n<li aria-level=\"1\" dir=\"ltr\">\n<p dir=\"ltr\" role=\"presentation\"><b id=\"docs-internal-guid-13315fad-7fff-2b1b-3a0a-2136189d00eb\">Cung cấp các sản phẩm với chất lượng tốt nhất, mang đến cho khách hàng rất nhiều ưu đãi về giá cả cũng như vận chuyển đối với những đơn hàng lớn.</b></p></li></ul>\n<p dir=\"ltr\"><b id=\"docs-internal-guid-13315fad-7fff-2b1b-3a0a-2136189d00eb\">Có rất nhiều khách hàng lần đầu tiên đến với <a href=\"https://quocthaivn.com/\">quocthaivn.com</a> đều cảm thấy hài lòng về chất lượng sản phẩm cũng như những dịch vụ, ưu đãi mà quocthaivn.com mang lại. Bởi vậy, có không ít khách hàng đã trở thành đối tác chiến lược với quocthaivn.com trong nhiều năm qua.</b></p>\n<p dir=\"ltr\"><b id=\"docs-internal-guid-13315fad-7fff-2b1b-3a0a-2136189d00eb\">Nếu như bạn đang có nhu cầu đặt mua các sản phẩm thiết bị đường ống nước hay hệ thống thiết bị tưới tự động thì hãy liên hệ với quocthaivn.com ngay trong hôm nay để được nhận nhiều ưu đãi nhất nhé!</b></p>\n', 'Súng tưới W3200 Aquamate', 20570.00, 0, 0, 1, 0, 'products/a8fb1b55-f691-42d3-95df-6a2d3c2d6e87.png', 39, 1, NULL, NULL),
