(260, 'Bộ chia 3 nhánh ống 16mm nối ren trong 27mm', 'b-chia-3-nh-nh-ng-16mm-n-i-ren-trong-27mm', '', '\n<h2><strong><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Bộ chia 3 nhánh<a href=\"https://quocthaivn.com/day-tuoi-nho-giot\"> ống 16mm </a>nối ren trong 27mm</span></span></strong></h2>\n<h2 style=\"text-align: center;\"><img data-thumb=\"original\" original-height=\"330\" original-width=\"330\" src=\"//bizweb.dktcdn.net/100/168/021/files/2a.png?v=1621073370835\"/></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật chia 3 nhánh ống 16mm ren trong 27mm:</span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã sản phẩm:</strong> CNT2717</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu: </strong>Nhựa POM nguyên sinh</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Quy cách: </strong>ren trong 27mm chia 3 nhánh đuôi chuột 16mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính:</strong> 16mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Màu sắc:</strong> Nâu</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành:</strong> 12 tháng.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Dùng trong việc kết nối ống chính là ống uPVC với đầu nối ren ngoài 27mm sang ống LDPE 16mm, có tác dụng chia nguồn nước từ một thành ba nhánh giống nhau, thường được sử dụng trong các <a href=\"https://quocthaivn.com/day-tuoi-nho-giot\">hệ thống tưới</a>, <a href=\"https://i-green.com.vn/\">tưới cảnh quan</a>, tưới sân thượng ban công, tưới vườn tường, nhà phố…</span></span></p>\n<p style=\"text-align: center;\"><img data-thumb=\"original\" original-height=\"330\" original-width=\"330\" src=\"//bizweb.dktcdn.net/100/168/021/files/1a.png?v=1621073359391\"/></p>\n', 'Bộ chia 3 nhánh ống 16mm nối ren trong 27mm', 0.00, 0, 0, 1, 0, 'products/b4b47e6e-1f5f-4f42-b9de-cf9aaac51f17.png', 37, 1, NULL, NULL),
(261, 'Chữ thập gắn ống LDPE 16mm cao cấp ZM', 'ch-th-p-g-n-ng-ldpe-16mm-cao-c-p-zm', '', '\n<h2><strong><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật chữ thập 16mm ống LDPE:</span></span></strong></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã sản phẩm: </strong>DC17</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu: </strong>Nhựa POM cao cấp</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính:</strong> 16mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Quy cách: </strong>hình dấu cộng với đường kính mỗi đầu là 16mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Màu sắc:</strong> Nâu</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành: </strong>12 tháng</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Dùng trong việc nối các đầu ống LDPE trong <a href=\"https://quocthaivn.com/day-tuoi-nho-giot\">hệ thống tưới </a>nước cho <a href=\"https://quocthaivn.com/day-tuoi-nho-giot\">tưới cảnh quan</a> – sân vườn, biệt thự cao cấp, tưới sân thượng và ban công, vườn tường, nhà phố…</span></span></p>\n<p style=\"text-align: center;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img data-thumb=\"original\" original-height=\"330\" original-width=\"330\" src=\"//bizweb.dktcdn.net/100/168/021/files/b-083733e2-96cf-4861-81df-1e8d2c9fc6a2.png?v=1621073037428\"/></span></span></p>\n<p> </p>\n', 'Chữ thập gắn ống LDPE 16mm cao cấp ZM', 0.00, 0, 0, 1, 0, 'products/c8ee4e0