(267, 'Đầu báo cháy nhiệt Horing Lih kèm đế AHR-871', 'u-b-o-ch-y-nhi-t-horing-lih-k-m-ahr-871', '', '\n<h2><strong><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thiết bị báo cháy HORING AHR-871 (đầu dò nhiệt gia tăng)</span></span></strong></h2>\n<h3><strong><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">1.Ưu điểm của sản phẩm</span></span></strong></h3>\n<ul>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Dễ dàng lắp đặt nhanh chóng</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Cảm biến khói siêu nhạy</span></span></li>\n<li><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Kết nối báo động nhanh </span></span></li></ul>\n<h3><strong><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">2.Thông số kĩ thuật và tính năng</span></span></strong></h3>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>+ Đầu dò nhiệt gia tăng</strong> HORING AHR-871 là thiết bị cảm biến nhiệt  báo trộm- báo cháy có thể hoạt động không giới hạn số lần và không bị ảnh hưởng bởi nhiệt độ phòng, Các bộ phận được mạ vàng để tránh quá trình oxy hóa, Bộ phận cân bằng không khí của thiết bị <a href=\"https://quocthaivn.com/thiet-bi-bao-chay\" target=\"_blank\">báo cháy HORING</a> làm bằng hợp kim để tránh độ ẩm và ổn định các chức năng thông gió. Hợp kim tự nó có thể tản nhiệt (không phải do cháy gây ra) để tránh các báo động sai.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">+ Đầu dò nhiệt gia tăng HORING <a href=\"https://quocthaivn.com/thiet-bi-bao-chay\" target=\"_blank\">AHR-871</a> được cấu tạo hoàn toàn kín và không bị ảnh hưởng bởi độ ẩm, bụi bẩn hoặc côn trùng.</span></span></p>\n<h2><strong><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật</span></span></strong></h2>\n<table border=\"1\" cellspacing=\"1\" dir=\"ltr\">\n<colgroup>\n<col width=\"207\"/>\n<col width=\"210\"/>\n</colgroup>\n<tbody>\n<tr>\n<td data-sheets-value=\'{\"1\":2,\"2\":\"Đầu dò nhiệt độ\"}\'><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đầu dò nhiệt độ</strong></span></span></td>\n<td data-sheets-value=\'{\"1\":2,\"2\":\"loại 2 dây – 3 dây – 4 dây.\"}\'><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">loại 2 dây – 3 dây – 4 dây.</span></span></td>\n</tr>\n<tr>\n<td data-sheets-value=\'{\"1\":2,\"2\":\"Phạm vi điện áp\"}\'><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Phạm vi điện áp</strong></span></span></td>\n<td data-sheets-value=\'{\"1\":2,\"2\":\"12 ~ 30V DC\"}\'><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">12 ~ 30V DC</span></span></td>\n</tr>\n<tr>\n<td data-sheets-value=\'{\"1\":2,\"2\":\"Dòng điện báo động @ 24V DC 470Ω\"}\'><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Dòng điện báo động @ 24V DC 470Ω</strong></span></span></td>\n<td data-sheets-value=\'{\"1\":2,\"2\":\"40mA\"}\'><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">40mA</span></span></td>\n</tr>\n<tr>\n<td data-sheets-value=\'{\"1\":2,\"2\":\"Nhiệt độ báo động\"}\'><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nhiệt độ báo động</strong></span></span></td>\n<td data-sheets-value=\'{\"1\":2,\"2\":\"Theo chuẩn EN54\"}\'><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Theo chuẩn EN54</span></span></td>\n</tr>\n<tr>\n<td data-sheets-value=\'{\"1\":2,\"2\":\"Nhiệt độ môi trường xung quanh\"}\'><span style=\"font-size:14px;\"><