(269, 'Trung tâm báo cháy 4 kênh Horing Lih -  AH-03312-4L', 'trung-t-m-b-o-ch-y-4-k-nh-horing-lih-ah-03312-4l', '', '', 'Trung tâm báo cháy 4 kênh Horing Lih -  AH-03312-4L', 0.00, 0, 0, 1, 0, 'products/c7d09c44-fbb4-4b26-a6a9-c5c24e2d5645.png', 41, 1, NULL, NULL),
(270, 'Đầu báo khói - YSD-22', 'u-b-o-kh-i-ysd-22', '', '\n<h2 style=\"text-align: justify;\"><strong><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông tin chi tiết</span></span></strong></h2>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">– Điện áp làm việc 24VDC<br/>\n– Dòng standby 60uA<br/>\n– Dòng báo cháy 100mA<br/>\n– Nhiệt độ báo cháy 68°C<br/>\n– Nhiệt độ làm việc -10°C ~ 55°C<br/>\n– Chất liệu: Nhựa chống cháy<br/>\n– Kích thước : Đường kính 103 X Cao 48<br/>\n– Màu : Trắng</span></span></h2>\n', 'Đầu báo khói - YSD-22', 0.00, 0, 0, 1, 0, 'products/ad069f9a-daf6-461b-af1e-56f8d969ccac.png', 41, 1, NULL, NULL),
(271, 'Đầu báo nhiệt - YRD-01', 'u-b-o-nhi-t-yrd-01', '', '\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đầu dò nhiệt gia tăng YRD-01 TAIWAN</strong></span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">-       Đầu dò nhiệt cài đặt đơn giản, thuận lợi.<br/>\n-       Chất liệu vỏ bền bỉ, an toàn.<br/>\n-       Điện áp hoạt động: 24VDC/ 420μA.<br/>\n-       Điện áp làm việc: 18VDC ~ 30VDC.<br/>\n-       Nhiệt độ hoạt động: 0°C ~ +50°C<br/>\n-       Hiển thị: Có đèn LED sáng đỏ báo hiệu.<br/>\n-       Độ ẩm tương đối: 95% không ngưng tụ.<br/>\n-       Chất liệu: Nhựa chống cháy.<br/>\n-       Kích thước: 103 x 45 mm.<br/>\n-       Trọng lượng: 158g.<br/>\n-       Màu sắc: Trắng<br/>\n-       Sản xuất tại Taiwan.<br/>\n-       Bảo hàng: 12 tháng.</span></span></p>\n', 'Đầu báo nhiệt - YRD-01', 0.00, 0, 0, 1, 0, 'products/4d81ca5e-cbb7-4da7-93b2-0a0f16c2f0bf.jpg', 41, 1, NULL, NULL),
(272, 'Đèn báo cháy - YIL-01', 'n-b-o-ch-y-yil-01', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đèn báo cháy <strong>YIL-01</strong> một trong những sản phẩm báo cháy, hoạt động khi có sự cố cháy, làm từ vật liệu chống cháy, với khả năng chịu nhiệt cao cùng lớp vỏ đèn được thiết kế để tăng độ sáng cho đèn.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông số kỹ thuật: </strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">-       Màu sắc:  Đỏ</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">-       Điện áp: 24VDC.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">-       Dòng điện khi báo cháy: Tối đa 100μA.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">-       Công suất 3W.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">-       Chất liệu: Nhựa chống cháy.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">-       Trọng lượng: 55g.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">-       Bảo hành: 12 tháng</span></span></p>\n', 'Đèn báo cháy - YIL-01', 0.00, 0, 0, 1, 0, 'products/37c9ca3c-c9f0-4ac8-8ba0-87f3aefe8ace.png', 28, 1, NULL, NULL),
(273, 'Nút ấn báo cháy', 'n-t-n-b-o-ch-y', '', '', 'Nút ấn báo cháy', 0.00, 0, 0, 1, 0, 'products/04ba9408-b714-4bcd-b023-095441bcc609.png', 41, 1, NULL, NULL),
(274, 'Bình chữa cháy MFZ1', 'b-nh-ch-a-ch-y-mfz1', '', '\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>ĐẶC ĐIỂM BÌNH MINI 1KG MFZ1</strong></span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">– Bình chữa cháy MFZ1 có dạng bột, kích thước nhỏ gọn(Ø x H): 9 x 24, dễ sử dụng, thích hợp trang bị trên xe ô tô dưới 3,5 tấn hoặc xe ô tô dưới 10 chỗ.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">– Thân bình hình trụ đứng, được sơn màu đỏ, trên thân có in đặc điểm của bình, cách sử dụng, bảo quản,…</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">– Cụm van được gắn liền với nắp đậy trên miệng bình, có thể tháo cụm van ra nạp lại bột và khí sau khi đã sử dụng.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">– Van khóa là van bóp, được kẹp an toàn trên miệng bình.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">– Vòi phun bằng kim loại, ngắn, nhỏ.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">– Bột chữa cháy trong bình là bột BC, màu trắng, mịn, chữa được các đám cháy loại B,C. Khối lượng bột chữa cháy BC trong bình khoảng 1kg.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">– Khí đẩy trong bình thường là N2, CO2,…khí trơ không cháy, không dẫn điện ở điện áp dưới 50KW và chỉ dùng một lần, muốn sử dụng lần sau thì phải đi nạp lại bình chữa cháy.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">– Đi kèm với bình là một giá đỡ bằng nhựa, thường là màu vàng.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>ƯU ĐIỂM</strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">– Hiệu quả cao với đám cháy xăng, dầu,…</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">– Bột BC trong bình <strong>KHÔNG</strong> bị ẩm, vón cục, bảo quản lâu và an toàn do được đóng kín trong bình.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">– Bột chữa cháy <strong>KHÔNG</strong> độc hại, an toàn với người, gia súc và môi trường xung quanh.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">– Thao tác nạp lại bình nhanh, đơn giản</span></span></p>\n<pre style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Đơn vị <strong>BẢO HỘ</strong> hàng đầu cả nước\n- Sản phẩm được <strong>NHẬP KHẨU</strong> trực tiếp từ nhà sản xuất, CO-CQ đầy đủ.\n- Chúng tôi luôn <strong>KIỂM TRA</strong> trước khi đến tay người tiêu dùng.\n- Bảo hành <strong>6 THÁNG</strong> với bình mini Trung Quốc mới.\n- Tư vấn chi tiết cách sử dụng, bảo quản, kiểm tra sản phẩm cho khách hàng.\n- Giao hàng <strong>MIỄN PHÍ</strong> cho đơn hàng từ 2 triệu.</span></span></pre>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>SỬ DỤNG BÌNH CHỮA CHÁY 1KG NÀY NHƯ THẾ NÀO?</strong></span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">– Xách bình đến gần chỗ xảy ra cháy.<br/>\n– Lắc xóc bình lên xuống 3-4 lần.<br/>\n– Hướng vòi phun vào gốc đám cháy.<br/>\n– Bóp van để bột BC phun vào đám cháy.<br/>\nTùy thuộc vào diện tích và mối nguy hại xung quanh mà nên bố trí <strong>bình chữa cháy MFZ1</strong> sao cho phù hợp nhất. Muốn biết cách bố trí thế nào, hãy gọi ngay đến bộ phận <strong>TƯ VẤN MIỄN PHÍ</strong> của Thiên Bằng. </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Cảm ơn quý khách!</span></span></p>\n', 'Bình chữa cháy MFZ1', 0.00, 0, 0, 1, 0, 'products/87f0d6b0-a340-4767-acdb-f6a18edbdba9.jpg', 41, 1, NULL, NULL),
(275, 'Hộp tổ hợp chuông đèn nút ấn nổi', 'h-p-t-h-p-chu-ng-n-n-t-n-n-i', '', '\n<ul>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nơi đặt đèn báo cháy, chuông và nút nhấn, thích hợp sử dụng cho các công trình, nhà xưởng, tòa nhà cao tầng, văn phòng làm việc, nhà riêng cùng với thiết kế mang tính thẩm mỹ cao, đây là thiết bị nhỏ gọn có thể lắp chìm, lắp nổi.</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Báo động khẩn cấp khi xảy ra sự cố bằng cách bấm vào nút báo cháy để thông báo cho mọi người biết… Khi bấm nút báo cháy, tổ hợp báo động âm thanh kèm theo tín hiệu Đèn LED ánh sáng cực mạnh.</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Ưu điểm của hộp tổ hợp chuông đèn nút ấn 220v:</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Sử dụng trực tiếp nguồn điện gia đình 220v để sử dụng.</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Gọn nhẹ, dễ dàng lắp đặt cho các công trình, văn phòng làm việc &amp; gia đình.</span></span></li>\n<li style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chuông – đèn – nút ấn báo cháy chất lượng cao, chuông kêu to rõ ràng, hoạt động liên tục trong 50h mà không bị giảm hiệu suất, đèn báo cháy sáng cực mạnh để báo vị trí có hỏa hoạn.</span></span></li></ul>\n', 'Hộp tổ hợp chuông đèn nút ấn nổi', 0.00, 0, 0, 1, 0, 'products/42cadf88-5f06-4a4f-a4a7-08e03320c506.png', 41, 1, NULL, NULL),
(276, 'Hộp chữa cháy 500*600*180 (sơn tĩnh điện, không giá)', 'h-p-ch-a-ch-y-500-600-180-s-n-t-nh-i-n-kh-ng-gi', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hộp chữa cháy tĩnh điện có giá hay còn gọi là tủ cứu hỏa, tủ đựng thiết bị PCCC được sử dụng trong công tác phòng cháy chữa cháy. Hộp chữa cháy dùng để chứa, bảo quản các thiết bị chữa cháy như: Cuộn vòi chữa cháy, lăng phun chữa cháy, chăn chiên cứu hỏa, bình chữa cháy,..</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Hộp chữa cháy 600*500*180 (Sơn tĩnh điện) có giá</em></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Xuất xứ: Việt Nam</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Kích thước (cao-rộng-sâu): 600x500x180mm</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Kiểu tủ: Tủ nổi, có giá</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Chất liệu: tôn</span></span></p>\n', 'Hộp chữa cháy 500*600*180 (sơn tĩnh điện, không giá)', 0.00, 0, 0, 1, 0, 'products/737df5c8-3d0b-444c-b467-fd0e420af31c.png', 41, 1, NULL, NULL),
(277, 'Kệ đựng 1 bình chữa cháy', 'k-ng-1-b-nh-ch-a-ch-y', '', '\n<p style=\"text-align: justify;\">Kệ đơn để bình chữa cháy thuộc dòng kệ đặt bình pccc loại nhỏ dùng để đựng một bình chữa cháy cầm tay bất kỳ bên trong giúp bảo vệ bình không bị đổ, cách đất không bị mục đáy và dễ dàng nhìn thấy bình để sử dụng khi phát hiện hỏa hoạn. Kệ đơn PCCC bằng sắt sơn đỏ tĩnh điện có mặt trước khá hẹp nên không có chữ PCCC sơn trắng như kệ đôi.</p>\n', 'Kệ đựng 1 bình chữa cháy', 0.00, 0, 0, 1, 0, 'products/091e1c53-3d1d-4658-8ecd-ed463746dcec.png', 41, 1, NULL, NULL),
(278, 'Hộp chữa cháy 500*600*180 (sơn tĩnh điện, có chân, mái)', 'h-p-ch-a-ch-y-500-600-180-s-n-t-nh-i-n-c-ch-n-m-i', '', '\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hộp chữa cháy sơn tĩnh điện có chân, có mái được trang bị để đặt ở ngoài trời. Hộp dùng để chứa, bảo quản các thiết bị chữa cháy như: Cuộn vòi chữa cháy, lăng phun chữa cháy, chăn chiên cứu hỏa, bình chữa cháy,...</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Hộp chữa cháy 600*500*180 (Sơn tĩnh điện) có chân, có mái</em></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Xuất xứ: Việt Nam</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Kích thước (cao-rộng-sâu): 600x500x180mm</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Kiểu tủ: Tủ nổi, có chân, có mái</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Chất liệu: tôn</span></span></p>\n', 'Hộp chữa cháy 500*600*180 (sơn tĩnh điện, có chân, mái)', 0.00, 0, 0, 1, 0, 'products/ec505459-afdc-49d7-8cef-682c89b42aaa.png', 41, 1, NULL, NULL),
(279, 'Bình chữa cháy Renan mini xe Ôtô – Fire Stop 1000ml', 'b-nh-ch-a-ch-y-renan-mini-xe-t-fire-stop-1000ml', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bình chữa cháy mini Firestop 1000ml</strong> cho xe hơi ô tô hiện tại là mặt hàng bán chạy nhất trên thị thường bình cứu hỏa chuyên dùng cho các phương tiện giao thông nhỏ theo phụ lục từ thông tư 57/2015 của Bộ Công An.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Cách sử dụng sản phẩm bình chữa cháy mini trên ô tô – FIRE STOP</strong><br/>\n– Lắc đều trước khi sử dụng.<br/>\n– Lấy bình ra khỏi giá treo, tháo nắp bảo vệ, nhấn nút để xịt.<br/>\n– Xịt thẳng vào nơi phát sinh ngọn lứa, hiệu quá tối ưu với các đám cháy nhỏ.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Nếu ngọn lửa quá lớn không thể dập tắt bằng bình chữa cháy này thì nhanh chóng gọi người giúp đỡ bằng các phương tiện khác hoặc gọi trung tâm cứu hỏa.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Làm sao để chọn được một<strong> bình chữa cháy</strong><strong> </strong><strong>mini cho ô tô Firestop</strong> đúng tiêu chuẩn chất lượng mà giá cả vẫn tốt nhất. <strong>Giá bán </strong><strong>bình chữa cháy </strong><strong>mini cho ô tô Firestop 1000ml là bao nhiêu tiền?</strong> Hãy liên hệ Vuhoangtelecom để được mua sản phẩm giá tốt, chính hãng.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông tin sản phẩm bình chữa cháy ô tô mini FIRE STOP 1000ml</strong><br/>\n– Được sử dụng để chữa cháy cho ô tô, xe gắn máy hoặc các phương tiện vận chuyển khác.<br/>\n– Mô tả: Bình treo hoặc để nằm trong hộc xe, cốp xe,…<br/>\n– Dung tích: 1000ml<br/>\n– Chất liệu: Bình xịt dạng bọt foam<br/>\n– Chủng loại: Bình dùng một lần<br/>\n– Công nghệ: Italia sản xuất tại Trung Quốc.<br/>\n– Kích thước: 25cm x 6.5cm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Căn cứ quy định Thông tư hướng dẫn của Bộ Công an có hiệu lực kể từ ngày hôm 06/01/2016 thì các phương tiện giao thông cơ giới đường bộ từ 4 chỗ ngồi trở lên, xe rơ-móc hoặc semi rơ-móc chở khách được kéo bởi xe ôtô, máy kéo; xe vận chuyển chất, hàng nguy hiểm về cháy, nổ nằm trong danh mục bắt buộc phải trang bị phương tiện phòng cháy chữa cháy.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Theo quy định các loại xe này phải trang bị một bình bột loại dưới 4kg hoặc bình bọt dưới 5 lít hoặc bình nước với chất phụ gia chữa cháy dưới 5 lít, bình khí CO2 dạng dưới 4kg.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu ý khi sử dụng bình chữa cháy mini cho ô tô Firestop</strong><br/>\n– Tránh xa tầm với của trẻ em.<br/>\n– Không để sản phẩm dưới ánh nắng mặt trời hoặc nơi có nhiệt độ trên 50 độ C.<br/>\n– Không đập dẹp hoặc đốt vỏ chai sau khi sử dụng.</span></span></p>\n', 'Bình chữa cháy Renan mini xe Ôtô – Fire Stop 1000ml', 0.00, 0, 0, 1, 0, 'products/da766e68-e3d4-48f8-a0f3-c6b4c89c8037.jpg', 41, 1, NULL, NULL);
