(312, 'Co, cút 25mm dùng cho ống LDPE', 'co-c-t-25mm-d-ng-cho-ng-ldpe', '', '\n<h1><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Co, cút ống LDPE 25mm</span></span></h1>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/3/71300322.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Co, cút ống LDPE 25mm\" src=\"https://vietannong.com.vn/_ld/3/s71300322.jpg\"/></a></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu: </strong>Nhựa POM</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính:</strong> 25mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Màu sắc:</strong> Đen</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành:</strong> 06 tháng</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng: </strong>Dùng trong việc nối ống 25mm trong hệ thống tưới<a href=\"http://vietannong.com.vn/\"> </a>nước nhỏ giọt, hệ thống béc tưới gốc cây cà phê, hồ tiêu và tưới thanh long...</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/3/02723730.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Co, cút ống LDPE 25mm\" src=\"https://vietannong.com.vn/_ld/3/s02723730.jpg\"/></a></span></span></p>\n', 'Co, cút 25mm dùng cho ống LDPE', 0.00, 0, 0, 1, 0, 'products/5d2853cb-a2e1-44c8-b200-cd1e34030132.jpg', 37, 1, NULL, NULL),
