(323, 'Van khởi thủy dây nhỏ giọt dẹp 16mm BV-011617', 'van-kh-i-th-y-d-y-nh-gi-t-d-p-16mm-bv-011617', '', '\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Van khởi thủy dây nhỏ giọt dẹp 16mm có roan cao su, tiện lợi cho việc lắp đặt và tưới theo luống thích hợp cho mọi địa hình và mọi loại ống cứng như uPVC hay HDPE</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Van khởi thủy dây nhỏ giọt 16mm có roan cao su</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van khởi thủy dây nhỏ giọt dẹp 16mm, roan cao su việt an nông 1\" src=\"https://vietannong.com.vn/_ld/3/74099948.jpg\"/></span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật van khởi khủy nhỏ giọt 16mm:</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu:</strong> Nhựa POM cao cấp</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính gắn ống:</strong> 16mm</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Quy cách gắn ống:</strong> Khoan ống uPVC gắn roan cao su, đầu còn lại xiết chặt với dây nhỏ giọt.</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Màu sắc cơ bản:</strong> Xanh và đen</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp sức chịu đựng:</strong> 10 bar (10kg/cm2)</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Gắn ống dây nhỏ giọt drip cheap phi 16mm.</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Gắn ống dây nhỏ giọt dẹp của Hàn Quốc, Israel.. dùng trong điều chỉnh <a href=\"https://quocthaivn.com/vat-tu-tuoi-nong-nghiep\">hệ thống tưới</a> nhỏ giọt, <a href=\"https://quocthaivn.com/phu-kien-tuoi-nho-giot\">dây nhỏ giọt</a> chuyên tưới rau, hoa màu, dưa lưới...tưới khoai lang và dưa hấu.</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van khởi thủy dây nhỏ giọt dẹp 16mm, roan cao su 2\" src=\"https://vietannong.com.vn/_ld/3/56739720.jpg\"/></span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Van khởi thủy dây nhỏ giọt dẹp 16mm, roan cao su dưa hấu\" src=\"https://vietannong.com.vn/_ld/3/79139097.jpg\"/></span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em>Roan cao su để gắng vào ống cứng và van khởi thủy nhỏ giọt<br/>\n<br/>\n<img align=\"\" alt=\"Van khởi thủy dây nhỏ giọt dẹp 16mm, roan cao su 5\" src=\"https://vietannong.com.vn/_ld/3/19028406.jpg\"/></em></span></span></h2>\n', 'Van khởi thủy dây nhỏ giọt dẹp 16mm BV-011617', 0.00, 0, 0, 1, 0, 'products/ce525ecb-43cd-40a3-a867-1c15dda1a0cc.png', 37, 1, NULL, NULL),
(324, 'Dây tưới nhỏ giọt quấn gốc Hydrogol 12mm', 'd-y-t-i-nh-gi-t-qu-n-g-c-hydrogol-12mm', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Dây tưới nhỏ giọt quấn gốc Hydrogol 12mm, khoảng cách lỗ 20, 30cm, 2, 4 lít/giờ và có thể quấn tròn quanh gốc cây mà không bị gãy - gập. Hạn chế tắt nghẽn so với dây 6mm.</span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><b>Dây <a href=\"https://quocthaivn.com/tuoi-nho-giot\">tưới nhỏ giọt </a>quấn gốc phi 12mm Ấn Độ</b></span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img alt=\"Dây tưới nhỏ giọt quấn gốc Hydrogol 12mm\" src=\"https://vietannong.com.vn/vietannong/day_nho_giot_quan_goc.jpg\"/></span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Thông số kỹ thuật dây nhỏ giọt quấn gốc 12:</strong></span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Tên dây tưới: </strong><b><a href=\"https://quocthaivn.com/tuoi-nho-giot\" target=\"_blank\">Dây nhỏ giọt </a></b>Hydrogol phi 12mm<br/>\n<strong>Đường kính:</strong> 12mm<br/>\n<strong>Quy cách nhỏ giọt:</strong> 30cm có một nhỏ giọt, 2 lít/giờ. <br/>\n<strong>Độ dài:</strong> 500m. <strong>Độ dày:</strong> 1.0mm<br/>\n<strong>Bảo hành:</strong> 01 năm<br/>\n<strong>Ứng dụng:</strong> Dùng trong <a href=\"https://quocthaivn.com/tuoi-nho-giot\">hệ thống nhỏ giọt</a> quấn quanh gốc<strong> </strong><b><strong>tưới</strong> </b>cho cây ăn quả, cây hồ tiêu, cây <b>cà phê</b>, tưới rau màu,<a href=\"https://quocthaivn.com/tuoi-nho-giot\" target=\"_blank\"> <b>dâu tây</b></a>...</span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Một số hình ảnh thực tế đã được lắp đặt về dây nhỏ giọt quấn gốc 12mm:</strong></span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"dây tưới nhỏ giọt quấn gốc tròn 12mm\" src=\"https://vietannong.com.vn/_ld/0/92036785.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"dây tưới nhỏ giọt quấn gốc tròn 12mm\" src=\"https://vietannong.com.vn/_ld/0/58094132.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"dây tưới nhỏ giọt quấn gốc 12mm hydrogol việt an nông\" src=\"https://vietannong.com.vn/_ld/0/66923928.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"dây tưới nhỏ giọt quấn gốc 12mm hydrogol việt an nông 1\" src=\"https://vietannong.com.vn/_ld/0/99639286.jpg\"/></span></span></p>\n<p> </p>\n<p> </p>\n<p> </p>\n<p> </p>\n', 'Dây tưới nhỏ giọt quấn gốc Hydrogol 12mm', 0.00, 0, 0, 1, 0, 'products/24217485-ce51-405a-89eb-83a029410e47.png', 44, 1, NULL, NULL),
(325, 'Ống tưới thẩm thấu Evolution Tape X1 - USA', 'ng-t-i-th-m-th-u-evolution-tape-x1-usa', '', '\n<p>Evolution X1 là thương hiệu lâu đời và danh tiếng 50 năm ở Mỹ. Là nhà sản xuất dây tưới thấm và phụ kiện hàng đầu thế giới. Các sản phẩm có độ bền cao và tính đồng nhất tốt với các trang trại trồng hoa và rau củ quả.</p>\n<h1><strong>Ống tưới thẩm thấu Evolution Tape X1</strong></h1>\n<p><a href=\"https://vietannong.com.vn/_ld/2/33683695.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"day nho giot han quoc 16mm việt an nông\" src=\"https://vietannong.com.vn/_ld/2/s33683695.jpg\"/></a></p>\n<h2>Thông số kỹ thuật tiêu chuẩn ống tưới X1</h2>\n<p><strong>Chất liệu nhựa:</strong> PAE</p>\n<p><strong>Đường kính ngoài:</strong> 16mm</p>\n<p><strong>Khoảng cách lỗ nhỏ giọt:</strong> 20cm</p>\n<p><strong>Lưu lượng:</strong> 1.8 lít/giờ</p>\n<p><strong>Áp suất mở:</strong> 0.6 bar</p>\n<p><strong>Áp suất hoạt động:</strong> 0.6 – 1.1 bar</p>\n<p><strong>Cuộn 1000m</strong></p>\n<p><strong>Bảo hành:</strong> 1 năm</p>\n<p><strong>Made in Israel </strong>theo yêu cầu của NDS Mỹ.</p>\n<p><strong>Ứng dụng:</strong> Trồng hóa và rau màu rất tốt với độ bền lâu dài và tiêu chuẩn ISO quốc tế.</p>\n<p><strong>Mở rộng:</strong></p>\n<ul>\n<li>Chống UV</li>\n<li>Kháng hóa chất</li>\n<li>Dripper được xử lý bằng công nghệ laser</li></ul>\n<p><a href=\"https://vietannong.com.vn/_ld/2/93294730.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"day nho giot han quoc 16mm việt an nông\" src=\"https://vietannong.com.vn/_ld/2/s93294730.jpg\"/></a></p>\n<p><a href=\"https://vietannong.com.vn/_ld/2/49937455.png\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" src=\"https://vietannong.com.vn/_ld/2/s49937455.jpg\"/></a></p>\n<p><em>Quy cách đóng gói hàng hóa chuyên nghiệp</em></p>\n<p><a href=\"https://www.youtube.com/watch?v=qOWZOeGMvAY\"><strong>VIDEO SẢN PHẨM</strong></a></p>\n', 'Ống tưới thẩm thấu Evolution Tape X1 - USA', 0.00, 0, 0, 1, 0, 'products/143db148-6978-4a05-bc38-70db4a77decc.png', 44, 1, NULL, NULL);
