(328, 'Dây nhỏ giọt dẹp 16mm Q160330 Nakyung-Hàn Quốc', 'd-y-nh-gi-t-d-p-16mm-q160330-nakyung-h-n-qu-c', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Namkyung là thương hiệu lâu đời và danh tiếng từ năm 1996 ở Hàn Quốc. Là nhà sản xuất dây nhỏ giọt và phụ kiện nhỏ giọt lớn nhất Hàn Quốc. Các sản phẩm có độ bền cao và tính đồng nhất tốt với giá thành hợp lý túi tiền của bà con nông dân Việt Nam.</span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/day-nho-giot-han-quoc\">Dây nhỏ giọt</a> 16mm Q160330 Hàn Quốc</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/2/00343047.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"dây nhỏ giọt 16mm hàn quốc việt an nông\" src=\"https://vietannong.com.vn/_ld/2/s00343047.jpg\"/></a></span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật dây nhỏ giọt NamKyung:</span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính:</strong> 16mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Độ dày:</strong> 0.3mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng:</strong> 1.8 /2.5 lít/giờ</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất hoạt động:</strong> 0.5 - 1.5 bar</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Khoảng cách lỗ:</strong> 30cm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Độ dài cuộn: </strong>1000m/cuộn</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu nhựa:</strong> Nguyên sinh cao cấp (POM)</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Xuất xứ:</strong> Namkyung - Hàn Quốc</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành:</strong> 1 năm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Chuyên dùng trong <a href=\"http://www.hethongtuoiando.com/\">hệ thống tưới nhỏ giọt</a><a href=\"https://quocthaivn.com/tuoi-nho-giot\"> </a>cho cây rau màu, cây ớt, các loại cây ăn quả, lagim đủ loại và một số loại cây trồng trong nhà kính, các loại cây theo hàng như nha đam, dưa lưới...</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/2/06327452.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"dây nhỏ giọt 16mm hàn quốc việt an nông\" src=\"https://vietannong.com.vn/_ld/2/s06327452.jpg\"/></a></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/2/39106079.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"dây nhỏ giọt 16mm hàn quốc việt an nông\" src=\"https://vietannong.com.vn/_ld/2/s39106079.jpg\"/></a></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"dây nhỏ giọt 16mm hàn quốc việt an nông\" src=\"https://vietannong.com.vn/_ld/2/49081414.jpg\"/></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/2/03603195.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"dây nhỏ giọt 16mm hàn quốc việt an nông\" src=\"https://vietannong.com.vn/_ld/2/s03603195.jpg\"/></a></span></span></p>\n<p><a href=\"https://www.youtube.com/watch?v=bDJO955u6UM\"><span style=\"color:#e74c3c;\"><strong><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">VIDEO SẢN PHẨM</span></span></strong></span></a></p>\n', 'Dây nhỏ giọt dẹp 16mm Q160330 Nakyung-Hàn Quốc', 0.00, 0, 0, 1, 0, 'products/b9d94db9-f077-4732-a0c1-11e106d75802.png', 44, 1, NULL, NULL),
(329, 'Dây nhỏ giọt dẹp 16mm Q160210 Nakyung-Hàn Quốc', 'd-y-nh-gi-t-d-p-16mm-q160210-nakyung-h-n-qu-c', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Dây nhỏ giọt dẹp Nam Kyung - Hàn Quốc,16mm, khoảng cách lỗ 10cm, độ dày 0.2mm là sản phẩm được ưa chuộng nhất hiện nay. Ứng dụng khá phổ biến trên dưa hấu, ớt, bí đỏ và một số loại hoa như hoa hồng, cẩm chướng, cúc...Tiết kiệm nhân công, chi phí và tăng năng suất tối ưu.</span></span></p>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/day-nho-giot-han-quoc\">Dây nhỏ giọt dẹp</a> 16mm - Q160210 - Hàn Quốc</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://vietannong.com.vn/_ld/3/77646164.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"day nho giot han quoc khoang cach lỗ 10cm\" src=\"https://vietannong.com.vn/_ld/3/s77646164.jpg\"/></a></span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật dây nhỏ giọt Nam Kyung 10cm:</span></span></h2>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính:</strong> 16mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Độ dày:</strong> 0.20mm</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Lưu lượng:</strong> <strong>1.8 lít/giờ</strong></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất hoạt động:</strong> 0.5 - 1.5 bar.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Khoảng cách lỗ:</strong> <strong>10cm</strong></span></span></p>\