(330, 'Tê khởi thủy dây nhỏ giọt dẹp 16mm BT-031715R', 't-kh-i-th-y-d-y-nh-gi-t-d-p-16mm-bt-031715r', '', '\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Khởi thủy chữ T cho dây nhỏ giọt 16mm</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Khởi thủy chữ T cho dây nhỏ giọt 16mm\" src=\"https://vietannong.com.vn/_ld/3/39091244.jpg\" title=\"Khởi thủy chữ T cho dây nhỏ giọt 16mm 2\"/></span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu:</strong> Nhựa POM cao cấp</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính gắn ống:</strong> 16mm</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Quy cách gắn ống:</strong> Khoan gắn roan vào ống cứng 2 đầu còn lại xiết chặt với dây nhỏ giọt.</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp sức chịu đựng:</strong> 10 bar (10kg/cm2)</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Khoan ống cứng và gắn với ống dây nhỏ giọt dẹp dùng trong chia nhánh <u><a href=\"https://quocthaivn.com/vat-tu-tuoi-nong-nghiep\">hệ thống tưới</a></u> nhỏ giọt, <u><a href=\"https://quocthaivn.com/tuoi-nho-giot\">dây nhỏ giọt</a> </u>tưới ớt, tưới khoai lang, hoa màu, dưa lưới...</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img align=\"\" alt=\"Khởi thủy chữ T cho dây nhỏ giọt 16mm\" src=\"https://vietannong.com.vn/_ld/3/88097309.jpg\" title=\"Khởi thủy chữ T cho dây nhỏ giọt 16mm 3\"/></span></span><br/>\n </h2>\n<blockquote>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Chia nhánh ống nhỏ giọt dẹp 16mm</span></span></h2></blockquote>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Sản phẩm ống dây nhỏ giọt dẹp 16mm</span></span></h2>\n', 'Tê khởi thủy dây nhỏ giọt dẹp 16mm BT-031715R', 0.00, 0, 0, 1, 0, 'products/af147113-6f61-48f6-892c-b7d272ea733d.png', 37, 1, NULL, NULL),
