(341, 'Ống cứu hỏa trắng – Loại mỏng', 'ng-c-u-h-a-tr-ng-lo-i-m-ng', '', '\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">ỐNG CỨU HỎA TRẮNG- DÙNG TRONG DẪN NƯỚC XẢ, NƯỚC TƯỚI.<br/>\nQuy cách: Ống mỏng – hàng CHT -RT<br/>\nMàu sắc: Màu trắng<br/>\nKích thước: Đa dạng<br/>\n– phi 40, cuộn 20m<br/>\n– phi 50, cuộn 20m<br/>\n– phi 60, cuộn 20m<br/>\n– phi 80, cuộn 20m<br/>\n– phi 100, cuộn 20m<br/>\nỨng dụng: Tải nước môi trường, xả nước, dẫn nước ao tôm, đìa tôm, đầm tôm, vuông tôm, dùng trong cấp thoát nước, tưới cánh đồng mía, tưới cà phê, tưới tự động cây xanh.</span></span></h2>\n', 'Ống cứu hỏa trắng – Loại mỏng', 0.00, 0, 0, 1, 0, 'products/16412465-a076-4e12-9f5f-9b21b977f4a9.png', 28, 1, NULL, NULL),
(342, 'Ống bạt phủ nhựa mềm ĐH- Cứu hỏa – Xanh Cam- Loại tốt', 'ng-b-t-ph-nh-a-m-m-h-c-u-h-a-xanh-cam-lo-i-t-t', '', '\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">ỐNG NHỰA BẠT MỀM CỨU HỎA- DÙNG TRONG DẪN NƯỚC XẢ, NƯỚC TƯỚI..<br/>\nQuy cách: Ống dày Phức Hợp – ĐH<br/>\nMàu sắc: Màu Xanh<br/>\nKích thước: Đa dạng<br/>\n– phi 40, cuộn 50 -100m<br/>\n– phi 50, cuộn 50 -100m<br/>\n– phi 60, cuộn 50 -100m<br/>\n– phi 80, cuộn 50 -100m<br/>\n– phi 100, cuộn 50 -100m<br/>\n– phi 120, cuộn 50 -100m<br/>\n– phi 150, cuộn 50 -100m<br/>\n– phi 200, cuộn 50 -100m<br/>\nỨng dụng: Tải nước môi trường, xả nước, dẫn nước ao tôm, đìa tôm, đầm tôm, vuông tôm, dùng trong cấp thoát nước, tưới tự động cây xanh.</span></span></h2>\n', 'Ống bạt phủ nhựa mềm ĐH- Cứu hỏa – Xanh Cam- Loại tốt', 0.00, 0, 0, 1, 0, 'products/6b86d72a-c268-41e7-b49d-3b220c46a4df.png', 28, 1, NULL, NULL),
(343, 'Ống LDPE phi 16mm dẫn nước tưới vườn cao cấp', 'ng-ldpe-phi-16mm-d-n-n-c-t-i-v-n-cao-c-p', '', '\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Ống LDPE phi 16mm dẫn nước tưới vườn cao cấp thường được dùng làm đường ống chính trong hệ thống tưới nhỏ giọt hoặc phun mưa hạt nhẹ cho vườn rau, khóm hoa, hành làng cỏ và những tiểu cảnh khác…</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/ong-dan-va-phu-kien\" target=\"_blank\">Ống LDPE phi 16mm</a> dẫn nước tưới vườn cao cấp</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Đặc điểm kỹ thuật ống LDPE phi 16mm dẫn nước <a href=\"https://quocthaivn.com/ong-dan-va-phu-kien\" target=\"_blank\">tưới vườn</a> cao cấp:</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Độ dày:</strong> 1.0mm</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Đường kính</strong>: 16mm</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Chất liệu nhựa:</strong> LDPE trơn</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp suất chịu đựng:</strong> 4 bar</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Độ bền:</strong> &gt;15 năm, chôn được dưới đất</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Bảo hành:</strong> 3 năm</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Cuộn:</strong> 200m, cung cấp theo mét/cuộn</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Ứng dụng:</strong> Dùng trong làm đường ống chính, nhánh trong <a href=\"https://i-green.com.vn/san-pham/ong-tuoi-nho-giot-san-vuon-vanogol-16mm/\" rel=\"noopener noreferrer\" target=\"_blank\">tưới nhỏ giọt</a> cho chậu cây, bồn hoa…sử dụng trong <a href=\"https://vietannong.com.vn/product/bec_tuoi_cay/bec_tuoi_rau_hoa/34\" rel=\"noopener noreferrer\" target=\"_blank\">tưới béc phun mưa</a> hạt nhẹ bán kính thấp cho bãi cỏ, hành lan vườn, khóm rau…ngoài ra có thể uốn cong, bẻ thẳng được…</span></span></h2>\n', 'Ống LDPE phi 16mm dẫn nước tưới vườn cao cấp', 0.00, 0, 0, 1, 0, 'products/5921e300-f2e3-4ccc-82d0-49acf25523ed.png', 30, 1, NULL, NULL),
(344, 'Ống dây LDPE phi 5x7mm loại tốt', 'ng-d-y-ldpe-phi-5x7mm-lo-i-t-t', '', '\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Ống dây dẫn nước tưới nhỏ giọt đường kính ngoài 6mm. Nhựa LDPE cao cấp. Chuyên dùng để gắn béc phun mưa cục bộ vào gốc hoặc dùng trong béc tưới nhỏ giọt.</span></span></h2>\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật ống dây LDPE 4×6:<br/>\nChất liệu nhựa: LDPE nguyên sinh 100%<br/>\nĐường kính ngoài: 7mm.<br/>\nĐường kính trong: 5mm.<br/>\nÁp suất: 4 bar<br/>\nMàu sắc: Đen<br/>\nSố mét trên cuộn: 200m/cuộn<br/>\nBảo hành: 3 năm<br/>\nỨng dụng: Dùng dẫn nước trong hệ thống tưới béc tiết kiệm, hệ thống tưới nhỏ giọt quấn quanh gốc, dùng cho cây rau màu, cây ăn quả có múi, gắn béc bù áp tưới thanh long, tưới cây công nghiệp như hồ tiêu</span></span></h2>\n', 'Ống dây LDPE phi 5x7mm loại tốt', 0.00, 0, 0, 1, 0, 'products/11de4fde-8b1b-4141-9c71-b8ea2c1c2260.png', 30, 1, NULL, NULL),
(345, 'Ống cứu hỏa trắng – Loại Dày', 'ng-c-u-h-a-tr-ng-lo-i-d-y', '', '\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">ỐNG CỨU HỎA TRẮNG- DÙNG TRONG DẪN NƯỚC XẢ, PCCC, DẪN NƯỚC TƯỚI.<br/>\nQuy cách: Ống tốt dày – hàng CHT -RD<br/>\nMàu sắc: Ngoài trắng trong đen<br/>\nKích thước: Đa dạng<br/>\n– phi 40, cuộn 20m<br/>\n– phi 50, cuộn 20m<br/>\n– phi 60, cuộn 20m<br/>\n– phi 80, cuộn 20m<br/>\n– phi 100, cuộn 20m<br/>\nỨng dụng: Tải nước PCCC, xả nước môi trường, xả nước, dẫn nước ao tôm, đìa tôm, đầm tôm, vuông tôm, dùng trong cấp thoát nước, tưới cánh đồng mía, tưới cà phê, tưới tự động cây xanh.</span></span></h2>\n', 'Ống cứu hỏa trắng – Loại Dày', 0.00, 0, 0, 1, 0, 'products/f3e60304-6ebd-4160-aba0-ddb6b45f510b.png', 41, 1, NULL, NULL),
(346, 'Ống dẹp cứu hỏa phủ nhựa mềm phi 40mm – Hàn Quốc', 'ng-d-p-c-u-h-a-ph-nh-a-m-m-phi-40mm-h-n-qu-c', 'Thường dùng trong tải nước sinh hoạt, công trình dân dụng, xây dựng, dùng trong hệ thống tưới nhỏ giọt, tưới phun mưa…trong nông nghiệp.', '\n<h2><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Thông số kỹ thuật ống dẹp cứu hỏa phi 40mm Hàn Quốc:<br/>\nMã hàng: Pona40<br/>\nMàu sắc: Xanh da trời/đen/cam<br/>\nChất liệu: Nhựa phủ cao su và dệt<br/>\nĐộ dày: 1.4mm<br/>\nÁp suất: 5 bar<br/>\nBề rộng ống: 40mm (widght)<br/>\nĐường kính tròn: 49mm<br/>\nCuộn dài: 50m<br/>\nNhà sản xuất: Ponaflex Hàn Quốc (Nhà máy tại Việt Nam)<br/>\nỨng dụng: Thường dùng trong tải nước sinh hoạt, công trình dân dụng, xây dựng, dùng trong hệ thống tưới nhỏ giọt, tưới phun mưa…trong nông nghiệp.</span></span></h2>\n', 'Ống dẹp cứu hỏa phủ nhựa mềm phi 40mm – Hàn Quốc', 0.00, 0, 0, 1, 0, 'products/422ba670-fe2b-4818-adce-f0ee339acf0e.png', 28, 1, NULL, NULL),
