(384, 'Béc tưới 8 tia điều chỉnh lưu lượng và bán kính', 'b-c-t-i-8-tia-i-u-ch-nh-l-u-l-ng-v-b-n-k-nh', '', '\n<table border=\"0\" cellpadding=\"2\" cellspacing=\"0\" width=\"100%\">\n<tbody>\n<tr>\n<td>\n<h1>Béc phun 8 tia - Vòi 8 tia</h1>\n<p><strong><img alt=\"béc phun tám tia, vòi 8 tia\" src=\"http://shop.vietannong.com.vn/95049629.jpg\"/></strong></p>\n<p><strong>Thông số kỹ thuật:</strong></p>\n<p><strong>Áp suất hoạt động: </strong>0.7 - 3 bar<br/>\n<strong>Bán kính: </strong> 0.3 - 0.8m<br/>\n<strong>Lưu lượng:</strong> 0 - 70 lít/giờ<br/>\n<strong>Ứng dụng:</strong><a href=\"http://vietannong.com.vn/\"> </a><strong><a href=\"http://vietannong.com.vn/\">Tưới</a> </strong>vào gốc cây<a href=\"https://quocthaivn.com/\"><strong> cà phê</strong></a>, cây hồ tiêu, cây thanh long và các loại cây khác, kể cả cây cảnh quan rất tốt.<br/>\n	Có thể điều chỉnh lưu lượng và bán kính tia nước phun ra của<a href=\"https://quocthaivn.com/\"> béc tưới</a> từ <a href=\"https://quocthaivn.com/tuoi-nho-giot\">nhỏ giọt </a>thành phun tia.</p>\n<p><a href=\"http://shop.vietannong.com.vn/_bd/0/52178431.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Béc phun 8 tia - Vòi 8 tia điều chỉnh lưu lượng\" src=\"http://shop.vietannong.com.vn/_bd/0/s52178431.jpg\"/></a></p>\n<p><em><strong>Vòi 8 tia đang tưới chanh ở Hậu Giang</strong></em></p>\n<p><a href=\"http://shop.vietannong.com.vn/_bd/0/82156770.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"Béc phun 8 tia - Vòi 8 tia điều chỉnh lưu lượng\" src=\"http://shop.vietannong.com.vn/_bd/0/s82156770.jpg\"/></a></p></td>\n</tr>\n</tbody></table>\n', 'Béc tưới 8 tia điều chỉnh lưu lượng và bán kính', 1.00, 0, 0, 1, 0, 'products/2f9d9d98-37fd-4ab8-82f3-39c629e2d231.png', 35, 8, NULL, NULL),
