(386, 'Béc tưới VANCG50 chống côn trùng gắn cây cắm 45cm', 'b-c-t-i-vancg50-ch-ng-c-n-tr-ng-g-n-c-y-c-m-45cm', '', '\n<table border=\"0\" cellpadding=\"2\" cellspacing=\"0\" width=\"100%\">\n<tbody>\n<tr>\n<td>\n<h1><a href=\"https://quocthaivn.com/\">Béc tưới</a> chống côn trùng VANCG50</h1>\n<h2>Thông số kỹ thuật béc chống côn trùng VANCG50:</h2>\n<p><strong>Bộ béc gồm: </strong>Béc phun + cây cắm 50cm</p>\n<p><strong>Chất liệu: </strong>Nhựa POM</p>\n<p><strong>Áp suất: </strong>0.5 - 1.5bar</p>\n<p><strong>Lưu lượng:</strong> 30 - 50 lít/giờ</p>\n<p><strong>Ứng dụng:</strong> <a href=\"https://quocthaivn.com/tuoi-phun-mua\">Tưới tự động</a> cây ăn quả, <a href=\"https://quocthaivn.com/tuoi-phun-mua\">tưới thanh long</a>, tưới cây có múi...chống được côn trùng chui vào, hạt mịn và đều trên 90%</p></td>\n</tr>\n</tbody></table>\n', 'Béc tưới VANCG50 chống côn trùng gắn cây cắm 45cm', 1.00, 0, 0, 1, 0, 'products/f343f4a5-352d-46a5-b3fd-29a56be97050.jpg', 42, 8, NULL, NULL),
