(405, 'Van an toàn Shin Yi', 'van-an-to-n-shin-yi', '', '\n<h2 style=\"text-align: justify;\"><strong><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">1. Van an toàn là gì?</span></span></strong></h2>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/van-an-toan-xa-ap\"><strong>Van an toàn</strong></a> là một thiết bị thủy lực dùng để điều chỉnh áp suất trong ống dẫn hoặc bồn chứa khí hoặc chất lỏng. Van an toàn thuộc nhóm thiết bị điều chỉnh áp suất đầu vào.</span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"> Nhiệm vụ chính của van an toàn là bảo vệ mạch thủy lực khỏi sự tăng áp vượt giá trị định mức (giá trị định mực được cài đặt sẵn). Trong quá trình làm việc, van an toàn luôn ở trạng thái đóng. Khi áp suất đầu vào của van vượt giá trị định mức, van an toàn mở ra cho phép một phần chất lỏng chảy qua van về thùng chứa.</span></span></p>\n<h2 style=\"text-align: justify;\"><strong><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">2. Thông số kỹ thuật</span></span></strong></h2>\n<p>Download Catalogue: </p>\n<p><a href=\"https://www.syvalves.com.vn/van-an-toan-xa-ap\">VanAnToan.pdf</a></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Mã Hàng</strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">H500</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Kích Thước</strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">DN50 - DN600</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Tiêu Chuẩn Thiết Kế</strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">BS 5163-2<br/>\nBS EN 7074-5</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Áp Suất Làm Việc</strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">PN10/PN16 JIS 10K/16K ANSI 125-LB</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Nhiệt Độ Làm Việc</strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">-10 ~ 80 ºC</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong>Môi Trường Làm Việc</strong></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Hệ Thống Nước</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img data-thumb=\"original\" original-height=\"1012\" original-width=\"1120\" src=\"//bizweb.dktcdn.net/100/168/021/files/a.png?v=1618380534393\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img data-thumb=\"original\" original-height=\"1538\" original-width=\"1120\" src=\"//bizweb.dktcdn.net/100/168/021/files/b.png?v=1618380565522\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img data-thumb=\"original\" original-height=\"1445\" original-width=\"1120\" src=\"//bizweb.dktcdn.net/100/168/021/files/c.png?v=1618380924802\"/></span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><img data-thumb=\"original\" original-height=\"1455\" original-width=\"1120\" src=\"//bizweb.dktcdn.net/100/168/021/files/d.png?v=1618380730935\"/></span></span></p>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong> 3. Báo giá ván xả tràn</strong></span></span></h2>\n<h2 style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"https://quocthaivn.com/\"><strong>Công ty Quốc Thái</strong></a> chuyên cung cấp các loại <a href=\"https://quocthaivn.com/thiet-bi-pccc-van-chua-chay\"><strong>van Shin Yi</strong></a>, <a href=\"https://quocthaivn.com/pccc\"><strong>thiết bị phòng cháy chữa cháy</strong></a> nhập khẩu trực tiếp từ Đài Loan, Hàn Quốc, Trung Quốc trên dây truyền thiết bị hiện đại của châu Âu.</span></span></h2>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"> Khi mua van cổng tại <a href=\"https://quocthaivn.com/\"><strong>Quốc Thái</strong></a> quý khách hàng được đảm bảo:</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">-Nhập khẩu chính hãng  chất lượng</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">-Hàng sẵn kho, số lượng lớn</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"> -Đầy đủ chứng từ CO-CQ</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"> -Đổi trả sản phẩm trong vòng 1 tuần</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"> -Tư vấn mua các loại van phù hợp với công trình</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"> -Giao hàng quanh khu vực Hà nội, hỗ trợ vận chuyển giao hàng toàn quốc.</span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"> Xin cảm ơn quý khách hàng đã tin tưởng và chọn lựa <a href=\"https://quocthaivn.com/\"><strong>Quốc Thái</strong></a>, sự hài lòng của quý khách là động lực cho chúng tôi phát triển, hãy liên hệ ngay tới <b>hotline</b>: </span></span><span style=\"font-size:20px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><strong><span style=\"background-color:#e74c3c;\">0919642586</span></strong><b><span style=\"background-color:#e74c3c;\"> </span></b></span></span><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">để được tư vấn chọn mua. </span></span></p>\n<p style=\"text-align: justify;\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Rất hân hạnh được phục vụ quý khách.</span></span></p>\n', 'Van an toàn Shin Yi', 1.00, 0, 0, 1, 0, 'products/4962123c-c491-4da3-a0a3-d2289499ab0c.png', 40, 7, NULL, NULL),
