(422, 'Bảng tiêu lệnh PCCC', 'b-ng-ti-u-l-nh-pccc', '', '\n<p><strong><em>Bộ tiêu lệnh cứu hỏa - BTK - Sản phẩm mang tính chất hướng dẫn và nêu cao tinh thần phòng cháy và cứu hoả, hỗ trợ cứu hoả vào lúc cần thiết.</em></strong></p>\n<p><b>Bảo hành:</b> 12 tháng</p>\n<p><b>Xuất xứ:</b> Việt Nam</p>\n<p><b>Kho hàng:</b> Còn hàng</p>\n<p><br/>\n<b>Giá bán:</b> <b>Liên hệ có giá tốt</b></p>\n<p> </p>\n<table cellpadding=\"0\" cellspacing=\"0.\" width=\"744\">\n<tbody>\n<tr>\n<td>\n<p>Loại thiết bị</p></td>\n<td>Nội Quy Cứu Hoả</td>\n</tr>\n<tr>\n<td>Hãng sản xuất</td>\n<td>BTK</td>\n</tr>\n<tr>\n<td>Đặc điểm</td>\n<td>Sản phẩm mang tính chất hướng dẫn và nêu cao tinh thần phòng cháy và cứu hoả</td>\n</tr>\n<tr>\n<td>Xuất xứ</td>\n<td>\n<p>Vietnam</p></td>\n</tr>\n</tbody></table>\n', 'Bảng tiêu lệnh PCCC', 65000.00, 0, 0, 1, 0, 'products/d3060cea-d352-48b3-83fc-9845df69c448.png', 41, 9, NULL, NULL),
