(426, 'Nối nhanh W-3280', 'n-i-nhanh-w-3280', '', '\n<p>W-3280 Cút nối thay đổi, mở<br/>\nrộng nhanh chóng gữa 3 ống mềm<br/>\nlàm vườn, bằng nhựa, đường kính<br/>\n9mm.</p>\n', 'Nối nhanh W-3280', 6710.00, 0, 0, 1, 0, 'products/df4723c0-53eb-47d5-b307-02dbdf24a9a0.png', 39, 1, NULL, NULL),
(427, 'Bộ điều khiển tưới tự động 9 kênh Pro+ 469 Holman-Úc/Mỹ', 'b-i-u-khi-n-t-i-t-ng-9-k-nh-pro-469-holman-c-m', '', '\n<h1>Bộ điều khiển tưới tự động 9 kênh Pro+ 469 Holman-Úc/Mỹ</h1>\n<p>Bộ điều khiển tưới tự động 9 kênh Pro+ 469 Holman-Úc/Mỹ, phù hợp với những khu vườn nhỏ nhưng có cấu trúc phực tạp với số lần tưới cho mỗi kênh lên tới 12 lần cho mỗi cài đặt. Tiện ích đẳng cấp cùng với giá thành cạnh tranh ở một thương hiệu tốt là những gì Holman mang đến cho quý khách hàng.</p>\n<p>Thông số kỹ thuật Bộ điều khiển tưới tự động 9 kênh Pro+ 469 Holman-Úc/Mỹ</p>\n<p><strong>Mã sản phẩm:</strong> CRS3346 – 9</p>\n<p><strong>Chất liệu sản phẩm: </strong>Nhựa</p>\n<p><strong>Thương hiệu:</strong> Holman – Úc</p>\n<p><strong>Bảo hành:</strong> 1 năm</p>\n<p><strong>Một số đặc điểm nổi bật của hộp điều khiển van điện từ 6 cổng Holman – Úc:</strong></p>\n<p>+ Các mô hình 4, 6 và 9 trạm</p>\n<p>+ Mô hình ngoài trời với một biến áp bao gồm cầu chì và phích cắm</p>\n<p>+ 3 chương trình hoàn toàn độc lập, tối đa 4 lần bắt đầu riêng cho mỗi chương trình, tối đa 12 lần bắt đầu mỗi ngày</p>\n<p>+ Thời gian chạy từ 1 phút đến 12 giờ 59 phút</p>\n<p>+ Nhiều tùy chọn chế độ tưới: theo ngày riêng lẻ, ngày chẵn, ngày lẻ, ngày lẻ trừ ngày 31,..</p>\n<p>+ Tính năng bộ nhớ vĩnh viễn sẽ giữ lại các chương trình tự động trong khi mất điện</p>\n<p>+ Tính năng tiết kiệm nước cho phép điều chỉnh nhanh thời gian tưới nước với mức tăng tư 10% đến 200%</p>\n<p>+ Thao tác thủ công linh hoạt – Hướng dẫn sử dụng tự động, bán tự động và trạm đơn</p>\n<p><strong>Ứng dụng:</strong> Bộ điều khiển tưới tự động 9 cổng CRS3346 được thiết kế để phục vụ cho nhiều ứng dụng trong các tòa nhà dân cư và thương mại, đến nông nghiệp và vườn ươm chuyên nghiệp. nông trại các Farm nông nghiệp.</p>\n<p><a href=\"https://i-green.com.vn/wp-content/uploads/2018/12/hop-dieu-khien-tuoi-cay-6-kenh-tu-dong-holman-uc-pro469-igreen-san-vuon-vietnam-1.jpg\"><img alt=\"hộp điều khiển kênh tưới cây 6 kênh holman úc igreen sân vườn\" height=\"350\" sizes=\"(max-width: 915px) 100vw, 915px\" src=\"https://i-green.com.vn/wp-content/uploads/2018/12/hop-dieu-khien-tuoi-cay-6-kenh-tu-dong-holman-uc-pro469-igreen-san-vuon-vietnam-1.jpg\" srcset=\"https://i-green.com.vn/wp-content/uploads/2018/12/hop-dieu-khien-tuoi-cay-6-kenh-tu-dong-holman-uc-pro469-igreen-san-vuon-vietnam-1.jpg 915w, https://i-green.com.vn/wp-content/uploads/2018/12/hop-dieu-khien-tuoi-cay-6-kenh-tu-dong-holman-uc-pro469-igreen-san-vuon-vietnam-1-150x57.jpg 150w, https://i-green.com.vn/wp-content/uploads/2018/12/hop-dieu-khien-tuoi-cay-6-kenh-tu-dong-holman-uc-pro469-igreen-san-vuon-vietnam-1-300x115.jpg 300w, https://i-green.com.vn/wp-content/uploads/2018/12/hop-dieu-khien-tuoi-cay-6-kenh-tu-dong-holman-uc-pro469-igreen-san-vuon-vietnam-1-768x294.jpg 768w, https://i-green.com.vn/wp-content/uploads/2018/12/hop-dieu-khien-tuoi-cay-6-kenh-tu-dong-holman-uc-pro469-igreen-san-vuon-vietnam-1-555x212.jpg 555w\" width=\"915\"/></a></p>\n', 'Bộ điều khiển tưới tự động 9 kênh Pro+ 469 Holman-Úc/Mỹ', 4080000.00, 0, 0, 1, 0, 'products/010ee959-3cab-4c2f-8c6d-b03e4bbb28c1.jpg', 28, 1, NULL, NULL),
(428, 'Nối nhanh W-3092', 'n-i-nhanh-w-3092', '', '\n<p>W-3092 Cút nối 1 đầu ren ngoài<br/>\n21mm, 1 đầu nối nhanh dương<br/>\n9mm, chất liệu bằng nhựa</p>\n', 'Nối nhanh W-3092', 2750.00, 0, 0, 1, 0, 'products/874579d0-3eaa-4fea-b8d6-d99e942e58a4.png', 39, 1, NULL, NULL),
(429, 'Nối nhanh W-3093', 'n-i-nhanh-w-3093', '', '\n<p>W-3093 Cút nối 1 đầu ren<br/>\nngoài 24mm, 1 đầu nối nhanh<br/>\ndương 9mm, chất liệu bằng<br/>\nnhựa. ( Nối đầu vòi sen vòi<br/>\nLavabo nóng lạnh)</p>\n', 'Nối nhanh W-3093', 3410.00, 0, 0, 1, 0, 'products/6c649862-f2bf-43aa-abb5-b0f7d18df5d0.png', 39, 1, NULL, NULL),
(430, 'Nối nhanh W-3084', 'n-i-nhanh-w-3084', '', '\n<p>W-3084 Cút nối 1 đầu nối nhanh<br/>\n1 đầu ren trong 21mm và 27mm<br/>\ndùng để kết nối với đầu vòi nước,<br/>\nchất liệu bằng nhựa .</p>\n', 'Nối nhanh W-3084', 4510.00, 0, 0, 1, 0, 'products/02bf7e22-c988-425b-9b0f-6effabacdc16.png', 39, 1, NULL, NULL),
(431, 'Nối nhanh W-3084B', 'n-i-nhanh-w-3084b', '', '\n<p>W-3084B Cút nối 1 đầu nối<br/>\nnhanh 1 đầu ren trong 21mm và<br/>\n27mm có gờ, dùng để kết nối với<br/>\nđầu vòi nước, chất liệu bằng nhựa</p>\n', 'Nối nhanh W-3084B', 4510.00, 0, 0, 1, 0, 'products/4434e01e-bdf4-42be-bf93-c6a539a745a3.png', 39, 1, NULL, NULL),
(432, 'Nối nhanh W-3293', 'n-i-nhanh-w-3293', '', '\n<p>W-3293 Van nhiều cửa, 1 cửa vào<br/>\nren trong D25mm, 4 cửa ra độc<br/>\nlập ren ngoài D20mm, bằng nhựa,<br/>\nđ/ khiển bằng tay, dùng trong<br/>\nnông nghiệp.</p>\n', 'Nối nhanh W-3293', 77000.00, 0, 0, 1, 0, 'products/ef9381bd-036c-47f0-ac7b-3ea7489d7a77.png', 39, 1, NULL, NULL),
(433, 'Nối nhanh W-3090', 'n-i-nhanh-w-3090', '', '\n<p>W-3090 Cút nối 1 đầu nối nhanh<br/>\n1 đầu ren ngoài 27mm dùng để<br/>\nkết nối với súng phun tưới và PK<br/>\nchất liệu bằng nhựa .</p>\n', 'Nối nhanh W-3090', 2750.00, 0, 0, 1, 0, 'products/9232ca93-17b6-44bb-bdb2-43779a0caa0e.png', 39, 1, NULL, NULL),
