(436, 'Nối nhanh W-3370', 'n-i-nhanh-w-3370', '', '\n<p>W-3370 Cút chuyển đổi nước từ<br/>\nđầu ra của vòi nước không ren với<br/>\nống mềm 14mm bằng cách xiết cổ<br/>\ndê và nối nhanh, mềm, bằng nhựa,<br/>\nhiệu aquamate, mới 100%.</p>\n', 'Nối nhanh W-3370', 25410.00, 0, 0, 1, 0, 'products/5d2e1067-73ce-4250-ad28-f97f1373328e.jpg', 39, 1, NULL, NULL),
(437, 'Nối nhanh W-3380A1', 'n-i-nhanh-w-3380a1', '', '\n<p>W-3380A1 Cút nối 1đầu ren<br/>\nngoài 34 mm 1 đầu kết nối với<br/>\nống mềm làm vườn 25mm, chất<br/>\nliệu bằng nhựa.</p>\n', 'Nối nhanh W-3380A1', 8800.00, 0, 0, 1, 0, 'products/c85991ce-aded-43cc-9792-e5fe1fbc4db2.jpg', 39, 1, NULL, NULL),
(438, 'Nối nhanh W-3316J', 'n-i-nhanh-w-3316j', '', '\n<p>W-3316J Cút chuyển đổi vòi<br/>\nnước từ đầu ra của vòi nước<br/>\nkhông ren với phần nối nhanh của<br/>\nống mềm làm vườn 14mm, bằng<br/>\nnhựa, hiệu aquamate, mới 100%.</p>\n', 'Nối nhanh W-3316J', 12760.00, 0, 0, 1, 0, 'products/b47ae1e7-fd35-4ddf-9d8f-ab6146f41862.png', 39, 1, NULL, NULL),
(439, 'Nối nhanh W-3360', 'n-i-nhanh-w-3360', '', '\n<p>W-3360 Cút chuyển đổi vòi nước<br/>\nkhông ren trực tiếp với ống mềm<br/>\nlàm vườn 14mm bằng cách xiết<br/>\ncổ dê, bằng nhựa, hiệu aquamate,<br/>\nmới 100%.</p>\n', 'Nối nhanh W-3360', 25410.00, 0, 0, 1, 0, 'products/8d2b365c-2f71-480a-a548-5e699cc63f92.png', 39, 1, NULL, NULL),
