(442, 'Nối nhanh W-3400', 'n-i-nhanh-w-3400', '', '\n<p>W-3400 Cút nối 1 đầu ren trong<br/>\n27mm 1 đầu kết nối với ống mềm<br/>\nlàm vườn 14mm, chất liệu bằng<br/>\nnhựa.</p>\n', 'Nối nhanh W-3400', 0.00, 0, 0, 1, 0, 'products/b14d5d94-7205-41ab-a04d-615894621375.png', 39, 1, NULL, NULL),
(443, 'Nối nhanh W-3170', 'n-i-nhanh-w-3170', '', '\n<p>W-3170 Cút nối 2 đầu kết nối<br/>\nvới ống mềm làm vườn 14mm,<br/>\nchất liệu bằng nhựa. , hiệu<br/>\naquamate, mới 100%.</p>\n', 'Nối nhanh W-3170', 7590.00, 0, 0, 1, 0, 'products/c657d51b-ae67-41ce-bb1b-bb6679c82bb5.png', 39, 1, NULL, NULL),
(444, 'Nối nhanh W-3175', 'n-i-nhanh-w-3175', '', '\n<p>W-3175 Cút nối 2 đầu chuyển bậc<br/>\nnối giữa 2 ống mềm làm vười<br/>\n14mm và 19mm, , hiệu aquamate,<br/>\nmới 100%.</p>\n', 'Nối nhanh W-3175', 8470.00, 0, 0, 1, 0, 'products/3abd5614-1aee-4bc5-9afa-7c21141e6cc4.png', 39, 1, NULL, NULL),
(445, 'Nối nhanh W-3250', 'n-i-nhanh-w-3250', '', '\n<p>W-3250 Cút nối, bằng nhựa, 1<br/>\nđầu nối nhanh âm, 1 đầu kết nối<br/>\nvới ống mềm làm vườn 19mm, ,<br/>\nhiệu aquamate, mới 100%.</p>\n', 'Nối nhanh W-3250', 8800.00, 0, 0, 1, 0, 'products/31d55858-d599-43fe-b679-35a71c453d47.png', 39, 1, NULL, NULL),
(446, 'Nối nhanh W-3160', 'n-i-nhanh-w-3160', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">W-3160 Cút nối bằng nhựa, một<br/>\nđầu nối nhanh có stop, 1 đầu ren<br/>\ntrong 27mm, dùng làm họng nước<br/>\nchờ sẵn, hiệu aquamate, mới<br/>\n100%.</span></span></p>\n', 'Nối nhanh W-3160', 12100.00, 0, 0, 1, 0, 'products/05dd1e28-3a51-4ace-8d86-494e86d0ac86.jpg', 39, 1, NULL, NULL),
(447, 'Nối nhanh W-GH-600S', 'n-i-nhanh-w-gh-600s', '', '\n<p>W-GH-600S bộ Cút nối nhanh ,<br/>\nbằng nhựa, D19mm, dùng kết nối<br/>\ngiữa ống mềm và thiết bị phun<br/>\ntưới nông nghiệp,</p>\n', 'Nối nhanh W-GH-600S', 37400.00, 0, 0, 1, 0, 'products/3678eec4-d268-4448-8718-abbed5b85928.jpg', 39, 1, NULL, NULL),
(448, 'Nối nhanh W-3130', 'n-i-nhanh-w-3130', '', '\n<p>W-3130 Cút nối, bằng nhựa, 1<br/>\nđầu nối nhanh âm, 1 đầu kết nối<br/>\nvới ống mềm làm vườn 14mm,<br/>\nhiệu aquamate, mới 100%.</p>\n', 'Nối nhanh W-3130', 9130.00, 0, 0, 1, 0, 'products/a3abcab5-1189-4dec-9061-c62e96eeaf8b.jpg', 39, 1, NULL, NULL),
(449, 'Nối nhanh W-3140', 'n-i-nhanh-w-3140', '', '\n<p>W-3140 Cút nối, bằng nhựa, 1<br/>\nđầu nối nhanh âm, 1 đầu kết nối<br/>\nvới ống mềm làm vườn 14mm, có<br/>\nSTOP</p>\n', 'Nối nhanh W-3140', 10340.00, 0, 0, 1, 0, 'products/15da2fbc-21e9-4a91-85fd-b3ec73854966.png', 39, 1, NULL, NULL),
(450, 'Nối nhanh W-GH-400S', 'n-i-nhanh-w-gh-400s', '', '\n<p>W-GH-400S bộ Cút nối nhanh ,<br/>\nbằng nhựa, D12mm, dùng kết nối<br/>\ngiữa ống mềm và thiết bị phun<br/>\ntưới nông nghiệp</p>\n', 'Nối nhanh W-GH-400S', 31900.00, 0, 0, 1, 0, 'products/4ba71a15-731d-4ab6-809f-fcdd72319bb9.jpg', 39, 1, NULL, NULL),
(451, 'Van điện từ tự động bằng nhựa chống nước', 'van-i-n-t-t-ng-b-ng-nh-a-ch-ng-n-c', '', '\n<h1>Van điện từ tưới tự động G75 Baccara Israel phi 34mm</h1>\n<p>Mô tả : Bộ van điện từ G75 của Baccara – Israel chuyên dùng điều khiển tưới tự động. Van 1” (34mm) có thể tháo rời bên ngoài, giúp dễ dàng bảo dưỡng ngoài ra có van tay giúp xả nước dễ dàng khi gặp sự cố với bộ phận Solenoid.</p>\n<h2>Đặc điểm kĩ thuật</h2>\n<p>Thương hiệu: Baccara</p>\n<p>Mã sản phẩm : G75 - 1</p>\n<p>Áp suất hoạt động: 0.3 – 10 bar</p>\n<p>Áp suất hao hụt: 0.035 bar</p>\n<p>Lưu lượng: 2.5 – 12 m3/h</p>\n<p>Nguồn điện: 24V – AC</p>\n<p>Bảo hành: 01 năm</p>\n<p>Nhà sản xuất: Baccara – Israel</p>\n<p><img alt=\"van dien tu baccara Israel phi 34mm\" height=\"415\" src=\"http://vietxanhfarm.com/upload/images/van-dien-tu-tuoi-tu-dong-baccara-israel.jpg\" width=\"400\"/></p>\n<h3>Ưu điểm vượt trội của van điện từ G75 Baccara Israel phi 34mm</h3>\n<p>- Van điện từ Baccara dòng G75 là chuyên gia trong lĩnh vực tưới tự động chuyên nghiệp.</p>\n<p>- <a href=\"https://i-green.com.vn/danh-muc/bo-hen-gio-tu-dong/\">Van solenoid</a> được làm từ vật liệu nhựa chống tia UV và thân thiện với môi trường, ứng dụng được trong tất cả các kiểu tưới từ cảnh quan tới nông nghiệp. Áp suất làm việc từ 0.3bar – 10bar. Nguồn điện tiết kiệm 24VAC.</p>\n<p><img alt=\"van dien tu baccara israel phi 34mm\" height=\"415\" src=\"http://vietxanhfarm.com/upload/images/van-dien-tu-tuoi-tu-dong-baccara-israel-2.jpg\" width=\"400\"/></p>\n<p><strong>Một số tính năng quan trọng khác của van điện từ G75 Baccara Israel phi 34mm:</strong></p>\n<ul>\n<li>Chống ăn mòn, hoạt động dưới áp suất lớn, chống tia cực tím</li>\n<li>Kết cấu nhựa PVC chắc chắn cho từng van</li>\n<li>Tháo lắp dễ dàng khi cần</li>\n<li>Tháo rời dễ dàng cục Solenoid</li>\n<li>Hoạt động thủ công khi có sự cố về VAN</li>\n<li>Tiết kiệm tối đa nguồn điện</li>\n<li>Dòng nước đi qua với lưu lượng lớn</li>\n<li>Dễ dàng vệ sinh và làm sạch</li></ul>\n<p><img alt=\"van dien tu baccara israel phi 34mm\" height=\"400\" src=\"http://vietxanhfarm.com/upload/images/van-dien-tuoi-tu-dong-baccara-israel-phi-34mm-igreen-300x300(1).jpg\" width=\"400\"/></p>\n', 'Van điện từ tự động bằng nhựa chống nước', 2150000.00, 0, 0, 1, 0, 'products/2e41cfed-2b6d-45f9-8fe4-dfc3e8f9db6e.png', 31, 10, NULL, NULL),
(452, 'Máy phun thuốc trừ sâu tạo khói cỡ lớn BF-150_Korea', 'm-y-phun-thu-c-tr-s-u-t-o-kh-i-c-l-n-bf-150-korea', '', '\n<h1 itemprop=\"name\">MÁY PHUN THUỐC TẠO KHÓI LOẠI LỚN BF150 HÀN QUỐC</h1>\n<h1 itemprop=\"name\">Máy phun thuốc tạo khói đa năng BF150 là 1 sản phẩm chuyên dụng trong nông nghiệp giúp bà con nông dân tiết kiệm được chi phí khi mua thuốc, thời gian phun nhanh, giảm tác động độc hại cho người phun, máy được thiết kế tự động dễ dàng vận hành, các loại dung môi pha loãng dễ dàng kiếm được. BF150 là sản phẩm cao cấp hợp kim nguyên khối. Nhập khẩu 100% từ Hàn Quốc.<img alt=\"Kết quả hình ảnh cho MÁY PHUN THUỐC TẠO KHÓI LOẠI LỚN BF150 HÀN QUỐC\" src=\"https://s4.nhattao.com/data/attachment-files/2018/08/11019745_may-phun-khoi-mu-nhiet-pk-138am_-_Copy.png\"/></h1>\n<h1 itemprop=\"name\"><strong style=\"font-size: 13px;\">Máy chất lượng hàng đầu đến từ Hàn Quốc</strong></h1>\n<p><a href=\"https://vietannong.com.vn/_ld/3/78414502.jpg\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"máy phun thuốc tạo khói BF150 Hàn Quốc Việt An Nông\" src=\"https://vietannong.com.vn/_ld/3/s78414502.jpg\"/></a></p>\n<p><strong>Thống số kỹ thuật:</strong></p>\n<p><strong>Model:</strong> BF-150</p>\n<p><strong>Kích thước (mm):</strong> 230x1350x340</p>\n<p><strong>Nhiên liệu:</strong> Xăng</p>\n<p><strong>Sạc pin, nguồn:</strong> 12V DC</p>\n<p><strong>Dung tích bình chứa:</strong> 8 lít</p>\n<p><strong>Khối lượng: </strong>9kg</p>\n<p><strong>Hãng sản xuất:</strong> SE Foggers Hàn Quốc</p>\n<p><strong>Bảo hành:</strong> 1 năm</p>\n<p><strong>Dung môi tạo khói: </strong>85.000/1 kg ~ 1 lít</p>\n<p><strong>Tỷ lệ pha:</strong> 1:1 , Nước: Dung môi, thuốc cho vào đầy bình</p>\n<p><strong>Ứng dụng:</strong> Dùng nhiều trong phun thuốc tạo khói cho cây ăn quả, cây công nghiệp như cao su, cà phê, hồ tiêu...tiết kiệm thuốc, rút ngắn thời gian phun và hạn chế gây hại cho người sử dụng.</p>\n<h2><strong>TÍNH NĂNG KỸ THUẬT VỀ MÁY PHUN TAO KHÓI BF-150_HÀN QUỐC.</strong></h2>\n<p><a href=\"https://vietannong.com.vn/_ld/3/71677012.png\" target=\"_blank\" title=\"Click to view in full size...\"><img align=\"\" alt=\"máy phun thuốc tạo khói BF150 Hàn Quốc Việt An Nông\" src=\"https://vietannong.com.vn/_ld/3/s71677012.jpg\"/></a></p>\n<p><img align=\"\" alt=\"$IMAGE3$\" src=\"https://vietannong.com.vn/_ld/3/05726707.jpg\"/></p>\n', 'Máy phun thuốc trừ sâu tạo khói cỡ lớn BF-150_Korea', 14500000.00, 0, 0, 1, 0, 'products/73fe1d82-288a-4626-b135-9cacbc4693c8.jpg', 28, 1, NULL, NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `sku`, `content`, `short_desc`, `price`, `discount`, `quantity`, `status`, `type`, `thumbnail`, `category_id`, `brand_id`, `created_at`, `updated_at`) VALUES
(453, 'Béc tưới nhỏ giọt có van điều chỉnh lưu lượng BB-1H', 'be-c-t-i-nho-gio-t-co-van-i-u-chi-nh-l-u-l-ng-bb-1h', '', '\n<h2>Béc tưới nhỏ giọt bù áp nhiều mức lưu lượng</h2>\n<p>Quocthaivn.com</p>\n<p>Đầu tưới nhỏ giọt bù áp sử dụng tưới các loại cây ăn quả trong các địa hình đồi núi không đông đều hoặc kết hợp với que cắm nhỏ giọt để tưới các loại cây trồng trong chậu, bịch, trong nhà kính…khi độ dài đường ống lớn.</p>\n<p>Tính năng nổi bật:</p>\n<p>1. Béc tưới nhỏ giọt có bù áp.</p>\n<p>2. Nhiều mức lưu lượng tưới nước: 2l/h, 4l/h, 8l/h …</p>\n<p>3. Nhiều loại nối đầu ra: nối trơn, đầu gài, đầu gấp 90 độ.</p>\n<h2>Ứng dụng của béc tưới nhỏ giọt bù áp</h2>\n<p>Đầu tưới nhỏ giọt bù áp ứng dụng tốt nhất cho các vườn cây có địa hình dốc hoặc chiều dài mỗi hàng cây trồng tương đối dài. Khi đó cho dù áp suất nước tưới vẫn luôn đồng đều ở mọi vị trí.</p>\n<p>Đầu tưới bù áp sử dụng kết hợp với que cắm định vị trong nhà kính, trồng cây trong chậu hoặc tưới cảnh quan.</p>\n<p>Có thể sử dụng với các thiết bị chia hai, chia bốn hoặc sử dụng độc lập.</p>\n<p>Đầu tưới có chức năng tự làm sạch và được sản xuất bằng vật liệu cao cấp, có độ bền rất cao.</p>\n<p>Có thể tháo rời để vệ sinh rất tiện lợi.</p>\n<h3>Các loại béc tưới nhỏ giọt bù áp</h3>\n<h4>1 Béc tưới bù áp chia ra theo các mức lưu lượng, quy định bởi màu sắc:</h4>\n<ul>\n<li>Béc bù áp màu vàng : Lưu lượng 2l/h</li>\n<li>Béc nhỏ giọt bù áp màu đen: Lưu lượng tưới 4 lít 1 giờ</li>\n<li>Béc tưới bù áp màu xanh : Lưu lượng nhỏ giọt 8 lít/h</li></ul>\n<h4>2 Béc nhỏ giọt bù áp phân loại theo đầu kết nối</h4>\n<ul>\n<li>Loại 1 đầu gờ , 1 đầu trơn để kết hợp với đầu chia 2, chia 4</li>\n<li>Loại 2 đầu gờ, kết hợp trực tiếp với <a href=\"https://hethongtuoinhogiot.vn/san-pham/que-cam-nho-giot-mui-ten/\">que cắm nhỏ giọt mũi tên </a></li></ul>\n', 'Béc tưới nhỏ giọt có van điều chỉnh lưu lượng BB-1H', 0.00, 0, 0, 1, 0, 'products/f6056513-7778-4ec6-a09f-c87b0cf0d7d2.png', 46, 10, NULL, NULL),
(454, 'Vòi tưới Meganet Israel 650l/h-360 độ', 'v-i-t-i-meganet-israel-650l-h-360', '', '\n<h1>Vòi phun mưa Meganet Israel</h1>\n<p>Vòi phun mưa Meganet Israel có 2 tia quay tròn chuyên dùng để tưới rau, cây nông nghiệp, hoặc để rửa lá cho cây ăn quả, chống sương giá…</p>\n<form action=\"https://agrihitech.vn/san-pham/voi-phun-mua-meganet-israel-ban-kinh-tuoi-8m/\" enctype=\"multipart/form-data\" method=\"post\">\n<h3>Mua vòi phun Meganet chính hãng ở đâu ?</h3>\n<p><strong>Tại Hà Nội, Quốc thái là công ty chuyên bán các loại vòi tưới cây nông nghiệp</strong></p>\n<p>Thiết bị tưới của chúng tôi đã có mặt tại rất nhiều tỉnh thành trên cả nước như: Lào Cai, Yên Bái, Điện Biên, Hòa Bình Lai Châu, Sơn La, Hà Giang, Cao Bằng, Bắc Kạn, Lạng Sơn, Tuyên Quang, Thái Nguyên, Phú Thọ, Bắc Giang, Quảng Ninh, Bắc Ninh, Hà Nam, Hà Nội, Hải Dương, Hưng Yên Hải Phòng, Nam Định, Ninh Bình, Thái Bình, Vĩnh Phúc, Thanh Hoá , Nghệ An, Hà Tĩnh , Quảng Bình, Quảng Trị, Thừa Thiên-Huế.</p>\n<p>Vòi tưới phun mưa Meganet được sản suất tại Israel, đất nước có nền nông nghiệp công nghệ cao tiên tiến nhất trên thế giới. Với những sản phẩm nổi tiếng đã có mặt tại Việt Nam như: <a href=\"https://agrihitech.vn/danh-muc/mang-nha-kinh/\">màng nhà kính Ginegar</a> , <a href=\"https://agrihitech.vn/danh-muc/tuoi-nho-giot/\">thiết bị tưới nhỏ giọt…. netafim, Naandan jain</a></p>\n<h3>Phân biệt vòi phun Meganet chính hãng như thế nào?</h3>\n<p>Vòi phun Meganet cũng như các loại vòi phun khác của Netafim Israel như <a href=\"https://agrihitech.vn/danh-muc/voi-tuoi-phun-mua/\">Gyronet</a>, <a href=\"https://agrihitech.vn/san-pham/voi-tuoi-phun-mua-spinnet-ban-kinh-3m-treo-trong-nha-mang/\">vòi treo Spinnet</a> đều được hãng sản suất dập tên thương hiệu kèm 1 số ký hiệu đặc biệt lên trên đó như lưu lượng nước….</p>\n<p>Tưới phun mưa; béc tưới phun mưa; hệ thống tưới phun mưa;phun sương;tưới phun sương; phun sương làm mát; vòi phun sương; béc phun sương; tuoi nong nghiệp; vòi phun nông nghiệp; vòi phun tưới cây ăn quả; tưới nông nghiệp; cách làm hệ thống tưới phun mưa; bé tưới rau; béc tưới nông nghiệp; vòi phun tưới cây ăn quả; hệ thống tưới nước phun mưa; mô hình hệ thống tưới phun mưa; giá hệ thống tưới phun mưa; chi phí lắp đặt hệ thống tưới phun mưa; thiết kế hệ thống tưới phun mưa; béc tưới nông nghiệp; tưới rau sạch;</p>\n<p>Công nghệ tưới nước đúng cách; béc tươi nông nghiệp; béc tưới dành cho công nông nghiệp và hoa; béc tưới nelson; thiết bị tưới nông nghiệp; các bước thiết kế hệ hống tưới; các loại béc tưới cây hồ tiêu; chi phí lắp đặt dây tưới phun mưa;giá thiết bị tưới phun mưa hiện nay trên thị trường;hệ thống tưới phun mưa cho rau;hệ thống tưới phun mưa cho vườn rau sạch tại nhà; hệ thống tưới phun mưa tự động xoay; hệ thống tưới tự động kiểu phun mưa; hiệu quả mô hình tưới tự động trong nông nghiệp; kỹ thuật tưới phun mưa; thiết kế thi công hệ thống tưới nông nghiệp; tư vấn chọn thiết bị tưới cho vườn rau; tưới nông nghiệp công nghệ cao; tưới nông nghiệp cho vườn cây ăn quả.</p></form>\n', 'Vòi tưới Meganet Israel 650l/h-360 độ', 0.00, 0, 0, 1, 0, 'products/e486253e-1d66-4735-8b66-8d7b49948145.jpg', 42, 10, NULL, NULL),
(455, 'Béc tưới VAN5-34 cánh đập VAN5-34 5 tia RN34', 'b-c-t-i-van5-34-c-nh-p-van5-34-5-tia-rn34', '', '\n<h2><strong><span style=\"font-size:14px;\">1. Giới thiệu Sản phẩm:</span></strong></h2>\n<p><span style=\"font-size:14px;\">Béc tưới cánh đập phi 34 có 5 tia phun nước, lưu lượng tưới lớn, bán kính phun xa, độ đồng đều &gt;95%. Ứng dụng rộng rãi khi tưới mọi loại cây trồng. Đặc biệt cây ăn quả có múi.</span></p>\n<p> </p>\n<p><strong><span style=\"font-size:14px;\">2. Chi tiết sản phẩm</span></strong></p>\n<p><span style=\"font-size:14px;\"><strong>Béc tưới cánh đập 5 tia phun, Đài Loan</strong></span></p>\n<p><span style=\"font-size:14px;\"><strong>Thông số kỹ thuật:</strong></span></p>\n<p><span style=\"font-size:14px;\"><strong>Model: </strong>5 tia cánh đập</span></p>\n<p><span style=\"font-size:14px;\"><strong>Chân ren gắn ống:</strong> 34mm</span></p>\n<p><span style=\"font-size:14px;\"><strong>Bán kính phun:</strong> 12-20m</span></p>\n<p><span style=\"font-size:14px;\"><strong>Lượng nước:</strong> 2-5m3/giờ</span></p>\n<p><span style=\"font-size:14px;\"><strong>Áp lực nước:</strong> 2 - 4 bar (4kg/cm2)</span></p>\n<p><span style=\"font-size:14px;\"><strong>Thời gian sử dụng: </strong>3-5 năm</span></p>\n<p><span style=\"font-size:14px;\"><strong>Máy bơm 2HP: </strong>tưới được  5- 6 cái</span></p>\n<p><span style=\"font-size:14px;\"><strong>Ứng dụng:</strong> Được sử dụng nhiều trong tưới cây ăn quả, hồ tiêu, cà phê và tưới cỏ...</span></p>\n<p><span style=\"font-size:14px;\"><strong>Tia phun nước nhỏ thứ năm trên vòi phun của béc</strong></span></p>\n<p> </p>\n', 'Béc tưới VAN5-34 cánh đập VAN5-34 5 tia RN34', 1.00, 0, 0, 1, 0, 'products/09002123-63d3-49d3-a914-2d80df0e59d0.png', 42, 8, NULL, NULL),
(456, 'Vòi tưới xoay 360 kiểu mới xa và đều', 'v-i-t-i-xoay-360-ki-u-m-i-xa-va-u', '', '\n<p> </p>\n<p><span style=\"font-size:20px;\"><strong>Béc tưới xoay 360 kiểu mới xa và đều</strong></span></p>\n<p>Một sự cải tiến m</p>\n<p>ới của béc tưới mini có thể táo rời các bộ phận, chịu được mài mòn và ma sát cao . Sản phẩm bền gấp nhiều lần so với các sản phẩm thông thường .<br/>\nBéc thường dùng để tưới hoa màu , tưới hoa và cây giống ….</p>\n', 'Vòi tưới xoay 360 kiểu mới xa và đều', 0.00, 0, 0, 1, 0, 'products/4484b61e-c9bf-4b96-873f-82f5fa64f5ca.jpg', 42, 1, NULL, NULL),
(457, 'Béc tưới nhỏ giọt có van điều chỉnh lưu lượng BB-2G', 'be-c-t-i-nho-gio-t-co-van-i-u-chi-nh-l-u-l-ng-bb-2g', '', '\n<h2>Béc tưới nhỏ giọt bù áp nhiều mức lưu lượng</h2>\n<p>Quocthaivn.com</p>\n<p>Đầu tưới nhỏ giọt bù áp sử dụng tưới các loại cây ăn quả trong các địa hình đồi núi không đông đều hoặc kết hợp với que cắm nhỏ giọt để tưới các loại cây trồng trong chậu, bịch, trong nhà kính…khi độ dài đường ống lớn.</p>\n<p>Tính năng nổi bật:</p>\n<p>1. Béc tưới nhỏ giọt có bù áp.</p>\n<p>2. Nhiều mức lưu lượng tưới nước: 2l/h, 4l/h, 8l/h …</p>\n<p>3. Nhiều loại nối đầu ra: nối trơn, đầu gài, đầu gấp 90 độ.</p>\n<h2>Ứng dụng của béc tưới nhỏ giọt bù áp</h2>\n<p>Đầu tưới nhỏ giọt bù áp ứng dụng tốt nhất cho các vườn cây có địa hình dốc hoặc chiều dài mỗi hàng cây trồng tương đối dài. Khi đó cho dù áp suất nước tưới vẫn luôn đồng đều ở mọi vị trí.</p>\n<p>Đầu tưới bù áp sử dụng kết hợp với que cắm định vị trong nhà kính, trồng cây trong chậu hoặc tưới cảnh quan.</p>\n<p>Có thể sử dụng với các thiết bị chia hai, chia bốn hoặc sử dụng độc lập.</p>\n<p>Đầu tưới có chức năng tự làm sạch và được sản xuất bằng vật liệu cao cấp, có độ bền rất cao.</p>\n<p>Có thể tháo rời để vệ sinh rất tiện lợi.</p>\n<h3>Các loại béc tưới nhỏ giọt bù áp</h3>\n<h4>1 Béc tưới bù áp chia ra theo các mức lưu lượng, quy định bởi màu sắc:</h4>\n<ul>\n<li>Béc bù áp màu vàng : Lưu lượng 2l/h</li>\n<li>Béc nhỏ giọt bù áp màu đen: Lưu lượng tưới 4 lít 1 giờ</li>\n<li>Béc tưới bù áp màu xanh : Lưu lượng nhỏ giọt 8 lít/h</li></ul>\n<h4>2 Béc nhỏ giọt bù áp phân loại theo đầu kết nối</h4>\n<ul>\n<li>Loại 1 đầu gờ , 1 đầu trơn để kết hợp với đầu chia 2, chia 4</li>\n<li>Loại 2 đầu gờ, kết hợp trực tiếp với <a href=\"https://hethongtuoinhogiot.vn/san-pham/que-cam-nho-giot-mui-ten/\">que cắm nhỏ giọt mũi tên </a></li></ul>\n', 'Béc tưới nhỏ giọt có van điều chỉnh lưu lượng BB-2G', 0.00, 0, 0, 1, 0, 'products/628901ef-f905-457e-bfa0-a4e41b3737d5.png', 46, 10, NULL, NULL),
(458, 'Béc tưới nhỏ giọt có van điều chỉnh lưu lượng BB-1G', 'be-c-t-i-nho-gio-t-co-van-i-u-chi-nh-l-u-l-ng-bb-1g', '', '\n<h2>Béc tưới nhỏ giọt bù áp nhiều mức lưu lượng</h2>\n<p>Quocthaivn.com</p>\n<p>Đầu tưới nhỏ giọt bù áp sử dụng tưới các loại cây ăn quả trong các địa hình đồi núi không đông đều hoặc kết hợp với que cắm nhỏ giọt để tưới các loại cây trồng trong chậu, bịch, trong nhà kính…khi độ dài đường ống lớn.</p>\n<p>Tính năng nổi bật:</p>\n<p>1. Béc tưới nhỏ giọt có bù áp.</p>\n<p>2. Nhiều mức lưu lượng tưới nước: 2l/h, 4l/h, 8l/h …</p>\n<p>3. Nhiều loại nối đầu ra: nối trơn, đầu gài, đầu gấp 90 độ.</p>\n<h2>Ứng dụng của béc tưới nhỏ giọt bù áp</h2>\n<p>Đầu tưới nhỏ giọt bù áp ứng dụng tốt nhất cho các vườn cây có địa hình dốc hoặc chiều dài mỗi hàng cây trồng tương đối dài. Khi đó cho dù áp suất nước tưới vẫn luôn đồng đều ở mọi vị trí.</p>\n<p>Đầu tưới bù áp sử dụng kết hợp với que cắm định vị trong nhà kính, trồng cây trong chậu hoặc tưới cảnh quan.</p>\n<p>Có thể sử dụng với các thiết bị chia hai, chia bốn hoặc sử dụng độc lập.</p>\n<p>Đầu tưới có chức năng tự làm sạch và được sản xuất bằng vật liệu cao cấp, có độ bền rất cao.</p>\n<p>Có thể tháo rời để vệ sinh rất tiện lợi.</p>\n<h3>Các loại béc tưới nhỏ giọt bù áp</h3>\n<h4>1 Béc tưới bù áp chia ra theo các mức lưu lượng, quy định bởi màu sắc:</h4>\n<ul>\n<li>Béc bù áp màu vàng : Lưu lượng 2l/h</li>\n<li>Béc nhỏ giọt bù áp màu đen: Lưu lượng tưới 4 lít 1 giờ</li>\n<li>Béc tưới bù áp màu xanh : Lưu lượng nhỏ giọt 8 lít/h</li></ul>\n<h4>2 Béc nhỏ giọt bù áp phân loại theo đầu kết nối</h4>\n<ul>\n<li>Loại 1 đầu gờ , 1 đầu trơn để kết hợp với đầu chia 2, chia 4</li>\n<li>Loại 2 đầu gờ, kết hợp trực tiếp với <a href=\"https://hethongtuoinhogiot.vn/san-pham/que-cam-nho-giot-mui-ten/\">que cắm nhỏ giọt mũi tên </a></li></ul>\n', 'Béc tưới nhỏ giọt có van điều chỉnh lưu lượng BB-1G', 0.00, 0, 0, 1, 0, 'products/fb93a3dc-a4c5-4a8b-8ec3-5d9a6e7642c9.jpg', 46, 10, NULL, NULL),
(459, 'Béc bít phun ngang vít nhựa BN-bít PVC', 'be-c-bi-t-phun-ngang-v-t-nh-a-bn-b-t-pvc', '', '\n<p>Béc bít phun ngang phi 21 PVC (màu xám + xanh lá)</p>\n<p>Bán kính tưới 4- 5 m</p>\n<p>Áp lực tưới 0.8 - 1,6 bar</p>\n<p>Lưu lương nước : 80 - 120 lít / h</p>\n<p>Góc tưới 360 độ</p>\n<p>Dùng để tưới vườn rau, sân cỏ v...v...v</p>\n<ul>\n<li><b>Trọng lượng: 10 gram</b></li></ul>\n', 'Béc bít phun ngang vít nhựa BN-bít PVC', 1.00, 0, 0, 1, 0, 'products/7218b7ae-173e-47b6-8021-bb537c306d83.png', 42, 6, NULL, NULL),
(460, 'Béc bít phun cao vít nhựa BC-bít PVC 21', 'be-c-bi-t-phun-cao-v-t-nh-a-bc-b-t-pvc-21', '', '\n<p>Chất liệu : Nhựa pvc Màu sắc: xám, xanh dương Kết nối: Nối ren trong pvc 21mm Xuất xứ: Việt Nam. Bán kính: Tùy chỉnh béc vít phun cao có cấu tạo đơn giản, được thiết kế có thêm khung định hình gồm 3 thanh nhựa đỡ lấy con vít vặn vào, trên nắp có khoét lỗ tròn đường kính 8mm, con vít có tán tròn 7mm, đường kính thân ren 3mm, khi vặn vít còn khe hở xung quanh lỗ cho phép tia nước phun mạnh đi qua. Hoạt đông: tia nước bị xé tơi khi đi qua khung định hình chữ thập, sau đó phun trực diện vào đáy tán vít( có hình phễu) làm tia nước phun ra bị xé mạnh, phun lên cao có hình phễu Có thể điều chỉnh bán kính phun và lượng nước phun ra khi điều chỉnh chiều cao vít so với họng phun, Vặn chặt ép sát vít vào nắp pvc sẽ làm giảm hẳn lượng nước phun và bán kính phun, thích hợp đa dạng cho các loại cây trồng. Béc vít thích hợp sử dụng tưới nông nghiệp cho vườn ươm cây giống, vườn cây ngắn ngày có tán lá rộng, vườn cây ăn trái..v.v.. #béc_tưới #béc_tưới_cây #béc_tưới_phun_mưa #béc_phun_sương #béc_vit_21 #béc_bit_phun-cao_21 #béc_bit #béc_bit_phun_cao</p>\n', 'Béc bít phun cao vít nhựa BC-bít PVC 21', 1.00, 0, 0, 1, 0, 'products/33c43214-2e74-4d17-86db-a22ea0468577.jpg', 42, 6, NULL, NULL),
(461, 'Đầu phun sương 4 hướng xám', 'u-phun-s-ng-4-h-ng-x-m', '', '\n<h2>Béc phun sương 4 hướng gắn T 8mm</h2>\n<ul>\n<li>Béc phun sương chuyên tưới cho lan, tưới làm mát không gian, tưới cây cảnh.</li>\n<li>Chất liệu: Nhựa cao cấp</li>\n<li>Kết nối: ống hơi 8mm</li>\n<li>Lưu lượng: 40 l/h</li>\n<li>Dễ dàng lắp đặt, tháo lắp vệ sinh.</li>\n<li>Áp suất hoạt động: 2.5Bar – 4Bar</li>\n<li>Bộ phun sương gồm 3 thành phần :</li></ul>\n<p>1. Béc phun sương 4 hướng màu xanh</p>\n<p>2. Van chống nhỏ giọt ( khi đạt áp suất 1,5 Bar van sẽ mở thông nước ra béc phun sương, khi ngắt bơm áp suất giảm van sẽ đóng đột ngột giúp ngăn hiện tượng rò rỉ lượng nước còn lại trong ống ra đầu phun).</p>\n<p>3. Tê nối ống hơi 8mm</p>\n', 'Đầu phun sương 4 hướng xám', 1.00, 0, 0, 1, 0, 'products/506bdb50-df3e-470b-a3d9-8583d245a3e2.jpg', 33, 9, NULL, NULL),
(462, 'Béc bít phun cao vít inox BC-vít 21 PVC', 'be-c-bi-t-phun-cao-v-t-inox-bc-v-t-21-pvc', '', '\n<ul>\n<li>\n<p>Màu : Xám</p></li>\n<li>BC-Vít 21 PVC - Béc bít con vít phun cao 21 PVC, dùng được cho ống 16.</li>\n<li>Bán kính tưới: 2 - 3 m.</li>\n<li>Áp lực nước: 0,5 - 1 bar.</li>\n<li>Lưu lượng nước: 150 - 200 lít / h.</li>\n<li>Góc tưới: 360 độ.</li></ul>\n', 'Béc bít phun cao vít inox BC-vít 21 PVC', 1.00, 0, 0, 1, 0, 'products/fe021169-cdce-46b5-89de-9074023e92ce.jpg', 42, 6, NULL, NULL),
(463, 'Béc bít phun ngang vít nhựa B-bít N RN21', 'be-c-bi-t-phun-ngang-v-t-nh-a-b-b-t-n-rn21', '', '\n<h1>Béc bít phun ngang + Nối 21 ( xanh lá) B-Bít N (Bịch 10 cái)</h1>\n', 'Béc bít phun ngang vít nhựa B-bít N RN21', 1.00, 0, 0, 1, 0, 'products/719694ea-10df-4b22-9358-586900083429.png', 42, 6, NULL, NULL),
(464, 'Béc bọ 180 độ tưới gốc BB-1,8 họng 1,8ly', 'be-c-bo-180-t-i-g-c-bb-1-8-h-ng-1-8ly', '', '\n<h2>Béc tưới nhỏ giọt bù áp nhiều mức lưu lượng</h2>\n<p>Quocthaivn.com</p>\n<p>Đầu tưới nhỏ giọt bù áp sử dụng tưới các loại cây ăn quả trong các địa hình đồi núi không đông đều hoặc kết hợp với que cắm nhỏ giọt để tưới các loại cây trồng trong chậu, bịch, trong nhà kính…khi độ dài đường ống lớn.</p>\n<p>Tính năng nổi bật:</p>\n<p>1. Béc tưới nhỏ giọt có bù áp.</p>\n<p>2. Nhiều mức lưu lượng tưới nước: 2l/h, 4l/h, 8l/h …</p>\n<p>3. Nhiều loại nối đầu ra: nối trơn, đầu gài, đầu gấp 90 độ.</p>\n<h2>Ứng dụng của béc tưới nhỏ giọt bù áp</h2>\n<p>Đầu tưới nhỏ giọt bù áp ứng dụng tốt nhất cho các vườn cây có địa hình dốc hoặc chiều dài mỗi hàng cây trồng tương đối dài. Khi đó cho dù áp suất nước tưới vẫn luôn đồng đều ở mọi vị trí.</p>\n<p>Đầu tưới bù áp sử dụng kết hợp với que cắm định vị trong nhà kính, trồng cây trong chậu hoặc tưới cảnh quan.</p>\n<p>Có thể sử dụng với các thiết bị chia hai, chia bốn hoặc sử dụng độc lập.</p>\n<p>Đầu tưới có chức năng tự làm sạch và được sản xuất bằng vật liệu cao cấp, có độ bền rất cao.</p>\n<p>Có thể tháo rời để vệ sinh rất tiện lợi.</p>\n<h3>Các loại béc tưới nhỏ giọt bù áp</h3>\n<h4>1 Béc tưới bù áp chia ra theo các mức lưu lượng, quy định bởi màu sắc:</h4>\n<ul>\n<li>Béc bù áp màu vàng : Lưu lượng 2l/h</li>\n<li>Béc nhỏ giọt bù áp màu đen: Lưu lượng tưới 4 lít 1 giờ</li>\n<li>Béc tưới bù áp màu xanh : Lưu lượng nhỏ giọt 8 lít/h</li></ul>\n<h4>2 Béc nhỏ giọt bù áp phân loại theo đầu kết nối</h4>\n<ul>\n<li>Loại 1 đầu gờ , 1 đầu trơn để kết hợp với đầu chia 2, chia 4</li>\n<li>Loại 2 đầu gờ, kết hợp trực tiếp với <a href=\"https://hethongtuoinhogiot.vn/san-pham/que-cam-nho-giot-mui-ten/\">que cắm nhỏ giọt mũi tên </a></li></ul>\n', 'Béc bọ 180 độ tưới gốc BB-1,8 họng 1,8ly', 1.00, 0, 0, 1, 0, 'products/98f49c3d-4f40-4f83-937e-01c1e1a52ee8.jpg', 45, 6, NULL, NULL),
(465, 'Cây cắm tưới nhỏ giọt gốc', 'c-y-c-m-t-i-nho-gio-t-g-c', '', '\n<h2>Béc tưới nhỏ giọt bù áp nhiều mức lưu lượng</h2>\n<p>Quocthaivn.com</p>\n<p>Đầu tưới nhỏ giọt bù áp sử dụng tưới các loại cây ăn quả trong các địa hình đồi núi không đông đều hoặc kết hợp với que cắm nhỏ giọt để tưới các loại cây trồng trong chậu, bịch, trong nhà kính…khi độ dài đường ống lớn.</p>\n<p>Tính năng nổi bật:</p>\n<p>1. Béc tưới nhỏ giọt có bù áp.</p>\n<p>2. Nhiều mức lưu lượng tưới nước: 2l/h, 4l/h, 8l/h …</p>\n<p>3. Nhiều loại nối đầu ra: nối trơn, đầu gài, đầu gấp 90 độ.</p>\n<h2>Ứng dụng của béc tưới nhỏ giọt bù áp</h2>\n<p>Đầu tưới nhỏ giọt bù áp ứng dụng tốt nhất cho các vườn cây có địa hình dốc hoặc chiều dài mỗi hàng cây trồng tương đối dài. Khi đó cho dù áp suất nước tưới vẫn luôn đồng đều ở mọi vị trí.</p>\n<p>Đầu tưới bù áp sử dụng kết hợp với que cắm định vị trong nhà kính, trồng cây trong chậu hoặc tưới cảnh quan.</p>\n<p>Có thể sử dụng với các thiết bị chia hai, chia bốn hoặc sử dụng độc lập.</p>\n<p>Đầu tưới có chức năng tự làm sạch và được sản xuất bằng vật liệu cao cấp, có độ bền rất cao.</p>\n<p>Có thể tháo rời để vệ sinh rất tiện lợi.</p>\n<h3>Các loại béc tưới nhỏ giọt bù áp</h3>\n<h4>1 Béc tưới bù áp chia ra theo các mức lưu lượng, quy định bởi màu sắc:</h4>\n<ul>\n<li>Béc bù áp màu vàng : Lưu lượng 2l/h</li>\n<li>Béc nhỏ giọt bù áp màu đen: Lưu lượng tưới 4 lít 1 giờ</li>\n<li>Béc tưới bù áp màu xanh : Lưu lượng nhỏ giọt 8 lít/h</li></ul>\n<h4>2 Béc nhỏ giọt bù áp phân loại theo đầu kết nối</h4>\n<ul>\n<li>Loại 1 đầu gờ , 1 đầu trơn để kết hợp với đầu chia 2, chia 4</li>\n<li>Loại 2 đầu gờ, kết hợp trực tiếp với <a href=\"https://hethongtuoinhogiot.vn/san-pham/que-cam-nho-giot-mui-ten/\">que cắm nhỏ giọt mũi tên </a></li></ul>\n', 'Cây cắm tưới nhỏ giọt gốc', 1150.00, 0, 0, 1, 0, 'products/6fe028e2-f689-4ced-8e84-6eff50dbbd99.jpg', 46, 10, NULL, NULL),
