(557, 'BƠM CHÌM TECHRUMI QDX (CÔNG NGHỆ USA)', 'b-m-ch-m-techrumi-qdx-c-ng-ngh-usa', '', '\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><em><strong>Bơm chìm vỏ ionx TECHRUMI QDX 2hp 1.5kw</strong></em></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\"><a href=\"http://quocthaivn.com\">Công Ty TNHH đầu tư và thương mại tổng hợp Quốc Thái</a></span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Bơm chìm thân inox, dây đồng, cánh phíp</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Bơm dùng cho nước sạch và nước thải nhẹ.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Bơm được thiết kế phần đầu gang bằng 2 cái ron bảo vệ cực tốt.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Bơm có dầu bảo vệ phốt, đế bơm được thiết kế lưới bằng inox chống ăn mòn do sử dụng lâu ở dưới nước.</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">- Bơm có phao tự động ngắt chống cạn, có rơ le nhiệt, độ bảo vê IP68.</span></span></p>\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\" width=\"684\">\n<tbody>\n<tr>\n<td>\n<p align=\"center\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Loại bơm</span></span></p></td>\n<td>\n<p align=\"center\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Công suất</span></span></p></td>\n<td>\n<p align=\"center\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Điện áp (V)</span></span></p></td>\n<td>\n<p align=\"center\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Ống xả</span></span></p></td>\n<td>\n<p align=\"center\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Cột áp (m)</span></span></p></td>\n<td>\n<p align=\"center\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Lưu lượng (m3/h)</span></span></p></td>\n</tr>\n<tr>\n<td>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">QDX15-18-1.5FB</span></span></p></td>\n<td colspan=\"1\" rowspan=\"4\">\n<p align=\"center\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">2HP-1.5KW</span></span></p></td>\n<td colspan=\"1\" rowspan=\"4\">\n<p align=\"center\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">220V</span></span></p></td>\n<td colspan=\"1\" rowspan=\"2\">\n<p align=\"center\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">60</span></span></p></td>\n<td>\n<p align=\"center\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">18</span></span></p></td>\n<td>\n<p align=\"center\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">15</span></span></p></td>\n</tr>\n<tr>\n<td><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">QDX15-18-1.5B</span></span></td>\n<td><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">18</span></span></td>\n<td><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">15</span></span></td>\n</tr>\n<tr>\n<td><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">QDX40-9-1.5FB</span></span></td>\n<td colspan=\"1\" rowspan=\"2\"><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">90</span></span></td>\n<td><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">9</span></span></td>\n<td><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">40</span></span></td>\n</tr>\n<tr>\n<td><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">QDX40-9-1.5B</span></span></td>\n<td><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">9</span></span></td>\n<td><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">40</span></span></td>\n</tr>\n</tbody></table>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">ghi chú: chữ F là có phao; chữ B là nước nước sạch</span></span></p>\n<p><span style=\"font-size:14px;\"><span style=\"font-family:Arial,Helvetica,sans-serif;\">Tag: bơm chìm tưới tiêu nông nghiệp, bơm chìm techrumi giá rẻ, bơm chìm giếng đào techrumi, bơm tõm techrumi, bơm chìm vỏ inox có phao chống cạn</span></span></p>\n', 'BƠM CHÌM TECHRUMI QDX (CÔNG NGHỆ USA)', 0.00, 0, 0, 1, 0, 'products/0414247e-de20-4b5b-8f3e-5997e535ce88.png', 29, 1, NULL, NULL);
