(560, 'BƠM CHÌM NƯỚC THẢI CÓ LƯỠI CẮT TECHRUMI SSC(CÔNG NGHỆ USA)', 'b-m-ch-m-n-c-th-i-c-l-i-c-t-techrumi-ssc-c-ng-ngh-usa', '', '\n<p><a href=\"http://quocthaivn.com\">Công Ty TNHH đầu tư và thương mại tổng hợp Quốc Thái</a></p>\n<p>Bơm nước thải có lưỡi cắt thân inox dây đồng chuyên dùng cho bơm nước thải, cắt da và vải, chuyên dùng cho xưởng giày vải và bệnh viện. thiết kế phần đầu gang bằng 2 cái ron, phần dưới gang bằng 2 cái ron bảo vệ cực tốt. Bơm có dầu bảo vệ phốt. Có phao tự ngắt chống cạn.</p>\n', 'BƠM CHÌM NƯỚC THẢI CÓ LƯỠI CẮT TECHRUMI SSC(CÔNG NGHỆ USA)', 0.00, 0, 0, 1, 0, 'products/91d2fa61-8d40-4be3-ae20-6eabbbfc7992.png', 29, 1, NULL, NULL),
(561, 'BƠM CHÌM NƯỚC SẠCH THÂN INOX TECHRUMI QDX(CÔNG NGHỆ USA)', 'b-m-ch-m-n-c-s-ch-th-n-inox-techrumi-qdx-c-ng-ngh-usa', '', '\n<p><a href=\"http://quocthaivn.com\">Công Ty TNHH đầu tư và thương mại tổng hợp Quốc Thái</a></p>\n<p>Bơm chìm thân inox dây đồng, cánh phíp/ gang chuyên dùng cho bơm nước sạch và nước thải nhẹ. thiết kế phần đầu gang bằng 2 cái ron, phần dưới gang bằng 2 cái ron bảo vệ cực tốt. Bơm có dầu bảo vệ phốt. </p>\n', 'BƠM CHÌM NƯỚC SẠCH THÂN INOX TECHRUMI QDX(CÔNG NGHỆ USA)', 0.00, 0, 0, 1, 0, 'products/49c55d39-f01e-4e42-a73e-526b554beddf.png', 29, 1, NULL, NULL),
(562, 'Máy bơm nước Pentax CM 80-160', 'm-y-b-m-n-c-pentax-cm-80-160', '', '\n<p><a href=\"http://quocthaivn.com\">Công Ty TNHH đầu tư và thương mại tổng hợp Quốc Thái</a></p>\n<p>Ứng dụng của máy bơm nước Pentax CM 80-160D</p>\n<p>-Dùng cho các nguồn cung cấp nước</p>\n<p>-Hệ thống ra áp suất, sưởi ấm, làm mát</p>\n<p>-Hệ thống phòng cháy chữa cháy</p>\n<p>-Hệ thống thủy lợi</p>\n<p>-Dùng cho các ứng dụng công nghiệp và nông nghiệp</p>\n<p>Đặc điểm cấu trúc của máy bơm nước Pentax CM 80-160D</p>\n<p>-Thân bơm, khung động cơ: Sắt đúc</p>\n<p>-Cánh quạt: Sắt hoặc đồng tùy theo từng phiên bản</p>\n<p>-Con dấu cơ khí: Gốm-graphite</p>\n<p>-Trục:Thép không gỉ AISI304</p>\n<p>-Động cơ cảm ứng hai cực : 3 pha 230/400V-50Hz</p>\n<p>-Lớp cách điện F</p>\n<p>-Lớp bảo vệ :IP55</p>\n<p>Giới hạn hoạt động của máy bơm nước Pentax CM 80-160D</p>\n<p>-Áp suất tối đa : 10 bar</p>\n<p>-Nhiệt độ chất lỏng bơm : -10 ÷ +90 °C</p>\n<p>Hiệu suất phạm của máy bơm nước Pentax CM 80-160D</p>\n<p>-Lưu lượng Max: 180 m³/h</p>\n<p>-Cột áp Max: 25,4 m</p>\n<h3>Máy bơm nước Pentax CM 80-160</h3>\n<ul id=\"chitiet\"></ul>\n', 'Máy bơm nước Pentax CM 80-160', 0.00, 0, 0, 1, 0, 'products/38ce61e9-d24c-4408-960d-08ad4da3e1f5.png', 29, 1, NULL, NULL),
(563, 'BƠM CHÌM NƯỚC SẠCH THÂN INOX TECHRUMI WQD(CÔNG NGHỆ USA)', 'b-m-ch-m-n-c-s-ch-th-n-inox-techrumi-wqd-c-ng-ngh-usa', '', '\n<p><a href=\"http://quocthaivn.com\">Công Ty TNHH đầu tư và thương mại tổng hợp Quốc Thái</a></p>\n<p>Bơm chìm thân inox dây đồng chuyên dùng bơm nước thải. thiết kế phần đầu gang bằng 2 cái ron, phần dưới gang bằng 2 cái ron bảo vệ cực tốt. Bơm có dầu bảo vệ phốt. Có phao tự ngắt chống cạn.</p>\n', 'BƠM CHÌM NƯỚC SẠCH THÂN INOX TECHRUMI WQD(CÔNG NGHỆ USA)', 0.00, 0, 0, 1, 0, 'products/89ac1011-b19b-4fe1-8f0f-39fe0f4fc422.png', 29, 1, NULL, NULL),
(564, 'Máy bơm nước Pentax CM 65-250A', 'm-y-b-m-n-c-pentax-cm-65-250a', '', '\n<h3><a href=\"http://quocthaivn.com\">Công Ty TNHH đầu tư và thương mại tổng hợp Quốc Thái</a></h3>\n<h3>Máy bơm nước Pentax CM 65-250A</h3>\n<h3>Bảng thông số kỹ thuật chi tiết lưu lượng cột áp của <strong>máy bơm nước Pentax CM 65-250A</strong></h3>\n<p>Bảng thông số chi tiết kích thước của <em>máy bơm nước Pentax CM 65-250A</em></p>\n<p>Biểu đồ thông số hoạt động đường cong thủy lực của máy bơm nước Pentax CM 65-250A</p>\n<p>Mô tả chi tiết máy bơm nước Pentax CM 65-250A</p>\n<p>-Máy bơm nước Pentax CM 65-250A được dùng chuyển tải nước với lưu lượng lớn, cột áp lên tới 90 m</p>\n<p>-Nó được dùng cho các nguồn cung cấp nước, hệ thống ra áp suất, sưởi ấm, làm mát, hệ thống thủy lợi, hệ thống phòng cháy chữa cháy…</p>\n<p>-Thân bơm, khung động cơ: Sắt đúc</p>\n<p>-Cánh quạt: Sắt hoặc đồng tùy theo từng phiên bản</p>\n<p>-Con dấu cơ khí: Gốm-graphite</p>\n<p>-Trục:Thép không gỉ AISI304</p>\n<p>-Động cơ cảm ứng hai cực : 3 pha 230/400V-50Hz</p>\n<p>-Lớp cách điện F</p>\n<p>-Lớp bảo vệ :IP55</p>\n<p>Giới hạn hoạt động của máy bơm nước Pentax CM 65-250A</p>\n<p>-Áp suất tối đa : 10 bar</p>\n<p>-Nhiệt độ chất lỏng bơm : -10 ÷ +90 °C</p>\n<p>-Lưu lượng Max: 2600 l/p</p>\n<p>-Cột áp Max: 90 m</p>\n<h3>Máy bơm nước Pentax CM 65-250</h3>\n', 'Máy bơm nước Pentax CM 65-250A', 0.00, 0, 0, 1, 0, 'products/91070269-65ad-4ef2-9608-ff000e032062.png', 29, 1, NULL, NULL),
