(601, 'Van hút/rọ hút Shin Yi', 'van-h-t-r-h-t-shin-yi', '', '\n<h2 style=\"text-align: center;\">VAN HÚT</h2>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"http://www.syvalves.com.vn/vi/ro-bom/item/download/12_e532c6a8546cdab5113653bc12d1fcb2.html\" title=\"d61d44254608dd06ccdd2ff02982d14d\">VanHut.pdf</a></li></ul>\n<ul>\n<li>Mã sản phẩm:SFVX</li>\n<li>Mô tả sản phẩm:\n<p>SFVX - Van hút  được sử dụng để bảo vệ chống lại dòng chảy ngược khi cắt nguồn điện. Van hoặt động không tạo ra tiếng ồn hay sự va đập của dòng chảy.</p></li></ul>\n<p><strong>Đặt Tính:</strong><br/>\n•    Thân van bằng gang cầu với cơ tính cao tạo ra độ bền cao và trọng lượng thấp.<br/>\n•    Do thiết kế đĩa van bằng cao su  nên tạo cho van đóng hoàn toàn trên mọi áp lực và không cần miếng đệm kín.<br/>\n•    Lưới được chế tạo bằng Inox cứng cáp, cùng với diện tích dòng chảy bằng 3 tới 4 lần diện tích ống.<br/>\n•    Cả trong và ngoài van đều được bao phủ bằng sơn epoxy để chống sự ăn mòn của môi trường.<br/>\n•    Sản xuất theo tiêu chuẩn ISO: 7259-1998.<br/>\n•    Mặt bích được thiết kế theo tiêu chuẩn: GB/T:17241.6 - 1998. ISO: 7005.2-1998, EN: 1092.2-1997.<br/>\n<br/>\n<strong>Lĩnh vực ứng dụng:</strong><br/>\nVan được ứng dụng trong các ngành cấp thoát nước, và công nghiệp …<br/>\n<br/>\n<strong>Thông số kỹ thuật:</strong><br/>\nKích thước: DN50 - DN300 mm<br/>\nÁp suất làm việc: 10, 16, 20 kgf/cm2<br/>\nNhiệt độ làm việc: -100 ~ 800C<br/>\nKết nối : PN10/PN16/JIS10K/ANSI150-LB</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/sfvx_01.jpg\"/></p>\n', 'Van hút/rọ hút Shin Yi', 1.00, 0, 0, 1, 0, 'products/04f2ebb7-dc5e-4bf2-a1c1-7127c244f294.jpg', 40, 7, NULL, NULL),
(602, 'Tủ điều khiển hệ thống bơm bằng Remoter 500m', 'tu-i-u-khi-n-h-th-ng-b-m-b-ng-remoter-500m', '', '', 'Tủ điều khiển hệ thống bơm bằng Remoter 500m', 0.00, 0, 0, 1, 0, 'products/defe0528-832a-44d0-8812-750a1f3acdc2.png', 31, 1, NULL, NULL),
(603, 'Trụ tiếp nước 2 cửa DN100 Shin Yi', 'tr-ti-p-n-c-2-c-a-dn100-shin-yi', '', '\n<h2>TRỤ TIẾP NƯỚC PCCC</h2>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"http://www.syvalves.com.vn/vi/pccc/item/download/22_ba87b9f2160de970203adbfdabce07d0.html\" title=\"fc1da7257992fc36032e11db3df7a664\">TruTiepNuoc.pdf</a></li></ul>\n<ul>\n<li>Mã sản phẩm:FHFA</li>\n<li>Mô tả sản phẩm:\n<p>FHFA - Trụ tiếp nước pccc trên mặt đất là cửa ngõ để kết nối và tiếp nước cho hệ thống pccc trong nha. Thông thường hệ thống không có nước nhưng trong trường hợp khẩn cấp đội pccc sẽ cung cấp nước để phục vụ pccc.</p></li></ul>\n<p><strong>Đặc Tính - Features:</strong></p>\n<ul>\n<li>Thân van được chế tạo từ gang cầu với khả năng chịu lực lớn hơn và độ bền sử dụng cao hơn. Được bao phủ bằng sơn epoxy cả trong lẫn ngoài.</li>\n<li>Sử dụng ngàm bằng nhôm theo tiêu chuẩn của PCCC. Những chi tiết bên trong đều được bao phủ sơn epoxy để chống ăn mòn.</li>\n<li>Thử nước toàn thân của thân van và họng tiếp nước lá 18 kgf/cm3. Thử độ kín của họng tiếp nước là 0.2 kgf/cm3. Để đảm bảo áp lực nước thấp cũng không bị xì.</li>\n<li>Phù hợp với TCVN 5739-1993 và TCVN 6379-1998</li></ul>\n<p><strong>Lĩnh vực ứng dụng:</strong><br/>\nSử dụng cho hệ thống PCCC<br/>\n </p>\n<p><strong>Thông số kỹ thuật:</strong><br/>\nKích thước: DN100 - DN150mm<br/>\nÁp suất làm việc: 1.0 Mpa - 1.6 Mpa<br/>\nNhiệt độ làm việc: -100 ~ 800C<br/>\nKết nối: PN10/PN16/PN20/JIS10K/ANSI150-LB</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/fhfa_01.jpg\"/></p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/fhfa_02.jpg\"/></p>\n', 'Trụ tiếp nước 2 cửa DN100 Shin Yi', 1.00, 0, 0, 1, 0, 'products/5bfffc00-730d-48c8-9b61-eba5d8945604.jpg', 40, 7, NULL, NULL),
(604, 'Trụ tiếp nước PCCC Shin Yi có đế', 'tr-ti-p-n-c-pccc-shin-yi-c', '', '\n<h2>TRỤ CẤP NƯỚC PCCC</h2>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"http://www.syvalves.com.vn/vi/pccc/item/download/23_5062e71e76230152e6b587d638aea664.html\" title=\"c9b002fe1bb0320831a8ae78670fdb6f\">TruCuuHoaPCCC.pdf</a></li></ul>\n<ul>\n<li>Mã sản phẩm:FHDF</li>\n<li>Mô tả sản phẩm:\n<p>FHDF - Trụ cấp nước PCCC là thiết bị chuyên dùng được lắp đặt dọc theo đường phố, để nhân viên cứu hỏa  lấy nước phục vụ cho mục đích PCCC.</p></li></ul>\n<p><strong>Đặt Tính - Features: </strong><br/>\n•    Được chế tạo từ gang cầu với khả năng chịu lực lớn hơn và độ bền sử dụng cao hơn.<br/>\n•    Thiết kế chống va đập, nếu nối trục bị gãy khi có ôtô va chạm mạnh van vẫn được đóng kín.<br/>\n•     Thân trên của trụ được thiết kế quay tự do 3600 nên có thể dẫn hướng trực tiếp dòng chảy đến bất kì vị trí nào.<br/>\n•    Vị trí đóng kín được sơn epoxy và bọc cao su toàn bộ, cho tuổi thọ lá van cao hơn và ngăn chặn hiện tượng gỉ sét thâm nhập.<br/>\n•    Sơn epoxy bao phủ cả bên trong lẩn bên ngoài, chống được tia cực tím, không bị gỉ sét và ăn mòn các chi tiết của trụ.<br/>\n•    Phù hợp với tiêu chuẩn - Meet the following standards TCVN 5739-1993 và TCVN 6379-1998.</p>\n<p><strong>Lĩnh vực ứng dụng </strong><br/>\nSử dụng cho hệ thống PCCC.<br/>\n<br/>\n<strong>Thông số kỹ thuật:</strong><br/>\nKích thước: DN100 - DN150 mm<br/>\nÁp suất làm việc: 1.0 Mpa - 1.6 Mpa<br/>\nNhiệt độ làm việc: -10 ~ 80C<br/>\nMôi trường làm việc: Nước - Water<br/>\nKết nối: PN10 / 16</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/fhd_01.jpg\"/></p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/fhd_02.jpg\"/></p>\n', 'Trụ tiếp nước PCCC Shin Yi có đế', 1.00, 0, 0, 1, 0, 'products/d0603abf-4304-485b-9982-626e31fea62b.png', 40, 7, NULL, NULL),
(605, 'Van vòi đôi Shin Yi', 'van-v-i-i-shin-yi', '', '\n<h2>VAN GÓC PCCC CHỮ Y</h2>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"http://www.syvalves.com.vn/vi/pccc/item/download/24_b62a4ad116045c020a970c8cfc168671.html\" title=\"077ab55046ce80eaf9a3ddea999597ca\">Van góc vòi đôi</a></li></ul>\n<ul>\n<li>Mã sản phẩm:TFH</li>\n<li>Mô tả sản phẩm:\n<p>Van góc PCCC chữ Y là một loại van cứu hỏa chuyên dụng được lắp đặt ngoài nhà. Van được sử dụng để cho nhân viên cứu hỏa tháo nước ra ngoài trong suốt quá trình chữa cháy.</p></li></ul>\n<p><strong>Đặt tính - Features: </strong><br/>\n<br/>\n•    Được chế tạo từ gang cầu với khả năng chịu lực lớn hơn và độ bền sử dụng cao hơn.<br/>\n•    Thiết kế hình dạng chữ Y, cho dòng chảy hiệu quả.<br/>\n•    Đĩa van bằng gang cầu được bao phủ bằng sơn epoxy và bọc cao su ở bề mặt đóng kín nên có tuổi thọ cao và không bị ăn mòn.<br/>\n•    Tay vặn được làm bằng nhựa cao cấp, ngoại quan đẹp, có thể dùng trong trang trí.<br/>\n•    Trục van được chế tạo bằng thép không gỉ, khả năng chịu lực lớn, không bị ăn mòn và bền vững.<br/>\n•    Phù hợp với TCVN 5739-1993 và TCVN 6379-1998.<br/>\n<br/>\n<strong>Lĩnh vực ứng dụng:</strong> <br/>\nSử dụng cho hệ thống PCCC.<br/>\n<br/>\n<strong>Thông số kỹ thuật:</strong><br/>\nKích thước: DN100 mm<br/>\nÁp suất làm việc: 1.0 Mpa - 1.6 Mpa<br/>\nNhiệt độ làm việc: -10 ~ 80C<br/>\nMôi trường làm việc: Nước - Water<br/>\nKết nối: Mặt bích</p>\n', 'Van vòi đôi Shin Yi', 1.00, 0, 0, 1, 0, 'products/ff3219e8-cfd1-4693-b283-c017def5782e.jpg', 40, 7, NULL, NULL);
