(606, 'Van giảm áp Shin Yi', 'van-gi-m-p-shin-yi', '', '\n<h2>VAN GIẢM ÁP</h2>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"http://www.syvalves.com.vn/vi/hydraulic/item/download/29_21a09a1d4109a55af57fc313805279d1.html\" title=\"\">VanGiamAp.pdf</a></li></ul>\n<ul>\n<li>Mã sản phẩm:D200</li>\n<li>Mô tả sản phẩm:\n<p>Dòng van giảm áp được sử dụng để giảm áp lực đường ống và cài đặt sẵn áp lực của hệ thống nước. Tự động điều chỉnh. Van hoạt động trơn tru không gây tiếng ồn.</p></li></ul>\n<p><strong>Đặc tính:</strong><br/>\n<br/>\n•    Van hoạt động trên nguyên tắc thủy lực,điều khiển mực nước chính xác. <br/>\n•    Màng chắn được cấu tạo bằng Nylon và cao su, tạo sự bền vững và chính xác. <br/>\n•    Sử dụng bộ van điều khiển áp lực (Pilot) dễ hoạt động và điều khiển chính xác áp lực.<br/>\n•    Được dẫn hướng bởi trục van trên và dưới. Lắp ráp vào màng chắn van cho tuổi thọ và độ tin cậy cao. <br/>\n•    Cả trong và ngoài van đều được bao phủ bằng sơn epoxy để chống sự ăn mòn của môi trường.<br/>\n•    Sản xuất theo tiêu chuẩn ISO 7259-1998.<br/>\n•    Mặt bích được thiết kế theo tiêu chuẩn:  GB/T17241.61998;ISO7005.2-1998;EN1092.2-1997.</p>\n<p><strong>Lĩnh vực ứng dụng: </strong><br/>\n Van được ứng dụng trong các ngành cấp thoát nước, trong chu trình nước của hệ thống HVAC, hệ thống PCCC.<br/>\n<br/>\n<strong>Thông số kỹ thuật:</strong><br/>\nKích thước: DN50-DN200 mm                      <br/>\nÁp suất làm việc: 10,16 kgf/cm2          <br/>\nNhiệt độ làm việc: -10C ~ 80C<br/>\nMôi trường làm việc: Nước, nước thải.                                <br/>\nKết nối: PN10/PN16/JIS 10K/ANSI 150- LB</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/d200_01.jpg\"/></p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/d200_02.jpg\"/></p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/d200_03.jpg\"/></p>\n', 'Van giảm áp Shin Yi', 1.00, 0, 0, 1, 0, 'products/48542aa3-610a-4482-a175-d33c6f8495ca.jpg', 40, 7, NULL, NULL),
(607, 'Van xả khí đơn/ren Shin Yi', 'van-x-kh-n-ren-shin-yi', '', '\n<h2>VAN XẢ KHÍ</h2>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"http://www.syvalves.com.vn/vi/van-xa-khi/item/download/11_3f8474bd2552b8d36f5ea7351290e8e6.html\" title=\"184b7cb84d7b456c96a0bdfbbeaa5f14\">VanXaKhi.pdf</a></li></ul>\n<ul>\n<li>Mã sản phẩm:ARVX</li>\n<li>Mô tả sản phẩm:\n<p>ARVX - Do trong ống cấp nước luôn có khoảng 2% lượng khí được tạo ra khi nước chảy. Do đó van xả khí  được sử dụng để xả lượng khí trong hệ thống ống. Tạo dòng chảy lớn nhất trong ống.</p></li></ul>\n<p><strong>Đặc Tính:</strong><br/>\n<br/>\n•    Tự họat động chính xác bởi sự lên xuống của hệ thống  phao Inox.<br/>\n•    Thân van và nắp van được chế tạo chắc chắn sử dụng lâu dài.<br/>\n•    Chốt cao su đóng mở được thiết kế bằng cao su đặc biệt bảo đảm sử dụng lâu dài. Không phải bảo trì và hoạt động tự do.<br/>\n•    Thân và nắp Van được bao phủ bởi sơn epoxy chống ăn mòn.<br/>\n•    Thiết kế Oring trên nắp van đảm bảo kín giữa thân và nắp.<br/>\n<br/>\n<strong>Lĩnh vực ứng dụng:</strong><br/>\nSử dụng cho hệ thống nước, PCCC.<br/>\n<br/>\n<br/>\n<strong>Thông số kỹ thuật:</strong><br/>\nKích thước: DN20-DN100 mm                     <br/>\nÁp suất làm việc: 10, 16 kgf/cm2         <br/>\nNhiệt độ làm việc: -100 ~ 800C<br/>\nMôi trường sử dụng: Nước, nước thải<br/>\nKết nối: Ren, mặt bích</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/arvx_01.jpg\"/></p>\n', 'Van xả khí đơn/ren Shin Yi', 1.00, 0, 0, 1, 0, 'products/2cb7fc5a-e295-4d22-8b61-b8864e89be82.jpg', 40, 7, NULL, NULL),
(608, 'Van Y lọc Shin Yi', 'van-y-l-c-shin-yi', '', '\n<h2>VAN Y LỌC</h2>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"http://www.syvalves.com.vn/vi/y-loc/item/download/10_77f216b6d2039874c169c85bf41e4aff.html\" title=\"9caa2793658f3cc387f216157300b1ce\">VanYLoc.pdf</a></li></ul>\n<ul>\n<li>Mã sản phẩm:YSTX</li>\n<li>Mô tả sản phẩm:\n<p>YSTX - Van Y lọc được sử dụng cho hệ thống nước, dùng để lọc những mảnh vỡ và rác. Ứng dụng phổ biến trong công nghiệp.</p></li></ul>\n<p><strong>Đặc tính:</strong><br/>\n<br/>\n•    Thân van bằng gang cầu với cơ tính cao tạo ra độ bền cao và trọng lượng thấp.<br/>\n•    Thiết kế dẫn dòng chảy tiên tiến cho phép hạn chế tối đa tổn thất áp lực đầu nguồn.<br/>\n•    Van được bao phủ bởi sơn epoxy chống ăn mòn.<br/>\n•    Đai ốc bên ngoài nên khi mở nắp van không phải tháo thân van ra khỏi hệ thống.<br/>\n•    Sản xuất theo tiêu chuẩn: ISO 7259-1998.<br/>\n•    Mặt bích được thiết kế theo tiêu chuẩn: GB/T:17241.6 - 1998. ISO: 7005.2-1998, EN: 1092.2-1997.<br/>\n<br/>\n<strong>Lĩnh vực ứng dụng:</strong><br/>\nVan được ứng dụng trong các ngành cấp thoát nước, và công nghiệp.<br/>\n<br/>\n<strong>Thông số kỹ thuật:</strong><br/>\nKích thước: DN50 - DN300 mm<br/>\nÁp suất làm việc: 10,16,20 kgf/cm2<br/>\nNhiệt độ làm việc: -100 ~ 800C<br/>\nKết nối: PN10/PN16/PN20/JIS 10K/ANSI 150-LB</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/ystx_01.jpg\"/></p>\n', 'Van Y lọc Shin Yi', 1.00, 0, 0, 1, 0, 'products/27676352-90ba-41d3-bf65-5ddb1d62f282.jpg', 40, 7, NULL, NULL),
(609, 'Van một chiều lá lật Shin Yi', 'van-m-t-chi-u-l-l-t-shin-yi', '', '\n<h2>VAN MỘT CHIỀU LÁ LẬT</h2>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"http://www.syvalves.com.vn/vi/van-mot-chieu/item/download/7_3be4a950e49cbac48040a303e7b12ddd.html\" title=\"ffee2447b152494b43d9816faaea83c8\">VanMotChieuLaLat.pdf</a></li></ul>\n<ul>\n<li>Mã sản phẩm:RDCV</li>\n<li>Mô tả sản phẩm:\n<p>RDCV - Van Một chiều lá lật  được sử dụng để bảo vệ chống lại dòng chảy ngược. Lá van nghiêng 45o nên van đóng rất nhanh. Giảm tối thiểu sự va đập của nước.</p></li></ul>\n<p><strong>Đặc Tính:</strong><br/>\n<br/>\n•    Lá van bọc toàn bộ bằng cao su NBR. Nên van đóng kín và chống sự ăn mòn.<br/>\n•    Van được bao phủ bởi sơn epoxy chống ăn mòn.<br/>\n•    Thiết kế đơn giản, nắp van cho phép vệ sinh, thay thế và bảo trì dễ dàng.<br/>\n•    Mặt bích được thiết kế theo tiêu chuẩn :<br/>\nGB/T17241.6-1998;ISO7005.2-1998;EN1092.2-199.<br/>\n<br/>\n<strong>Lĩnh vực ứng dụng:</strong><br/>\nVan được ứng dụng trong các ngành cấp thoát nước, trong chu trình nước của hệ thống HVAC, hệ thống PCCC.<br/>\n<br/>\nThông số kỹ thuật:<br/>\nKích thước: DN50-DN300 mm<br/>\nÁp suất làm việc: 10,16,20 kgf/cm2<br/>\nNhiệt độ làm việc: -100 ~ 800C<br/>\nMôi trường làm việc: Nước, nước thải<br/>\nKết nối: PN10,16,20, ANSI 150LB</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/rdcv_01.jpg\"/></p>\n', 'Van một chiều lá lật Shin Yi', 1.00, 0, 0, 1, 0, 'products/9c5b63e2-33b5-453a-8a47-275bd9cf7651.jpg', 40, 7, NULL, NULL),
(610, 'Van phao cơ Shin Yi', 'van-phao-c-shin-yi', '', '\n<h1>Van phao cơ Shin Yi</h1>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"http://www.syvalves.com.vn/vi/hydraulic/item/download/26_aff1274d8fe01ebaf23f18a48e7b9489.html\" title=\"\">VanPhao.pdf</a></li></ul>\n<ul>\n<li>Mã sản phẩm:H100</li>\n<li>Mô tả sản phẩm:\n<p>H100 - Van phao cơ Shin Yi là loại van điều khiển mực nước nhờ sự lên xuống của phao theo mực nước . Do đó van sẽ kiểm soát  chính xác mực nước trong bồn chứa, bể nước.</p></li></ul>\n<p><strong>Đặc Tính - Features:</strong><br/>\n<br/>\n•    Van hoạt động trên nguyên tắc thủy lực, điều khiển mực nước chính xác.<br/>\n•     Màng chắn được cấu tạo bằng Nylon và cao su, tạo sự bền vững và chính xác.<br/>\n•    Bộ phao điều khiển với đặc tính hoạt động dễ dàng và điều khiển chính xác mực nước.<br/>\n•    Được dẫn hướng bởi trục van trên và dưới. Lắp ráp vào màng chắn cho tuổi thọ và độ tin cậy cao.<br/>\n•    Cả trong và ngoài van đều được bao phủ bằng sơn epoxy để chống sự ăn mòn của môi trường.<br/>\n•    Kích thước giữa hai mặt bích theo tiêu chuẩn: GB1221-1989 ISO5752-1982,Table1, Series3;BS5163-1986.<br/>\n•    Mặt bích được thiết kế theo tiêu chuẩn: GB/T17241.6-1998;ISO7005.2-1998;EN1092.2-1997.</p>\n<p> </p>\n<p><strong>Lĩnh vực ứng dụng - Field Services:</strong> <br/>\nVan được ứng dụng trong các ngành cấp thoát nước, trong chu trình nước của hệ thống HVAC, hệ thống PCCC.<br/>\n<br/>\n<strong>Thông số kỹ thuật - Technical Data:</strong><br/>\nKích thước: DN50-DN200 mm                      <br/>\nÁp suất làm việc: 10,16 kgf/cm2          <br/>\nNhiệt độ làm việc: -10 ~ 80C<br/>\nMôi trường làm việc: Nước, nước thải.                                <br/>\nKết nối: PN10/PN16/JIS 10K/ANSI 150- LB</p>\n', 'Van phao cơ Shin Yi', 1.00, 0, 0, 1, 0, 'products/b5c1646a-046e-44a4-b949-6555eed7d06d.jpg', 40, 7, NULL, NULL),
(611, 'Van một chiều lò xo Shin Yi', 'van-m-t-chi-u-l-xo-shin-yi', '', '\n<h2>VAN MỘT CHIỀU LÒ XOod</h2>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"http://www.syvalves.com.vn/vi/van-mot-chieu/item/download/2_b29d9a03a5e41995432592bf9b6f4b78.html\" title=\"\">Download Catalogue</a></li></ul>\n<ul>\n<li>Mã sản phẩm:SCVX</li>\n<li>Mô tả sản phẩm:\n<p>SCVX - Van một chiều lò xo  được sử dụng để bảo vệ chống lại dòng chảy ngược khi cắt nguồn điện. Van hoạt động không tạo ra tiếng ồn hay sự va đập của dòng chảy.</p></li></ul>\n<p><strong>Đặc Tính:</strong></p>\n<p>•    Thân van bằng gang cầu với cơ tính cao tạo ra độ bền cao và trọng lượng thấp.<br/>\n•    Thiết kế dẫn dòng chảy tiên tiến cho phép hạn chế tối đa tổn thất áp lực đầu nguồn.<br/>\n•    Van được bao phủ bởi sơn epoxy chống ăn mòn.<br/>\n•    Bạc nhựa chịu lực dẫn hướng nên dễ dàng tháo lắp và ít chi tiết.<br/>\n•    Lò xo bằng thép không gỉ và được bảo vệ bởi lõi dẫn hướng trong khi van hoạt động.<br/>\n•    Mặt bích được thiết kế theo tiêu chuẩn:<br/>\nGB/T17241.6 - 1998<br/>\nISO7005.2 - 1998;<br/>\nEN1092.2 - 199.<br/>\n<br/>\n<strong>Lĩnh vực ứng dụng:</strong><br/>\nVan được ứng dụng trong các ngành cấp thoát nước, trong chu trình nước của hệ thống HVAC, hệ thống PCCC…<br/>\n<br/>\nThông số kỹ thuật - Technical Data:<br/>\nKích thước: DN50 - DN300 mm<br/>\nÁp suất làm việc: 10, 16, 20 kgf/cm2<br/>\n175 PSI - Grooved; 232 PSI/290 PSI flange valve.<br/>\nNhiệt độ làm việc: -100 ~ 800C<br/>\nMôi trường làm việc: Nước, nước thải.<br/>\nKết nối: PN10, 16, 20, JIS 10K, ANSI 150-LB</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/scvx_01.jpg\"/></p>\n', 'Van một chiều lò xo Shin Yi', 1.00, 0, 0, 1, 0, 'products/f0cf6d59-9105-4be7-a536-4b5352260b64.png', 40, 7, NULL, NULL),
(612, 'Van bướm tín hiệu Shin Yi', 'van-b-m-t-n-hi-u-shin-yi', '', '\n<h2>VAN BƯỚM TÍN HIỆU</h2>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"http://www.syvalves.com.vn/vi/van-buom/item/download/9_9c1c0409f1624200c533b42985edba6f.html\" title=\"\">VanBuomTinHieu.pdf</a></li></ul>\n<ul>\n<li>Mã sản phẩm:WBSS</li>\n<li>Mô tả sản phẩm:\n<p>WBSR - Van bướm tín hiệu là loại van bướm kiểu đĩa đệm có gắn thêm hộp tín hiệu điện. Hộp tín hiệu sẽ cung cấp tín hiệu tới phòng điều khiển để thông báo tình trạng của van đóng hay mở.</p></li></ul>\n<p><strong>Đặc Tính:</strong><br/>\n<br/>\n•    Van được thiết kế theo kiểu lệch tâm cho lực vặn thấp.<br/>\n•    Đĩa van bọc cao su NBR/EDPM.<br/>\n•    Cạnh của đĩa van bọc cao su nên hoạt động êm, ít tạo bọt và tuổi thọ cao.<br/>\n•    Thân van được bao phủ bởi sơn Eposy chống ăn mòn.<br/>\n•    Đóng mở theo hai chiều nhẹ nhàng.<br/>\n•    Hai vòng làm kín ở ty trên giúp van luôn luôn kín trong suốt quá trình hoạt động.<br/>\n•    Sản xuất theo tiêu chuẩn: ISO 5752 &amp; ISO 5208.<br/>\n<br/>\n<strong>Lĩnh vực ứng dụng:</strong><br/>\nVan được ứng dụng trong các ngành cấp thoát nước, trong chu trình nước của hệ thống HVAC, hệ thống PCCC…<br/>\n<br/>\n<strong>Thông số kỹ thuật:</strong><br/>\nKích thước: DN50-DN300 mm<br/>\nÁp suất làm việc: 10, 16, 20 kgf/cm2<br/>\nNhiệt độ làm việc: -10C ~ 80C<br/>\nMôi trường sử dụng: Nước, nước thải<br/>\nKết nối : PN10/PN16/JIS 10K/ANSI 150-LB</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/wbsr_01.jpg\"/></p>\n', 'Van bướm tín hiệu Shin Yi', 1.00, 0, 0, 1, 0, 'products/85e031c1-d388-4af4-9007-a285b1236a57.jpg', 40, 7, NULL, NULL),
(613, 'Van bướm tay gạt lá cao su Shin Yi', 'van-b-m-tay-g-t-l-cao-su-shin-yi', '', '\n<h2>VAN BƯỚM LÁ VAN BỌC CAO SU</h2>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"http://www.syvalves.com.vn/vi/van-buom/item/download/18_2037ba4a960dfb615e1a623badfc2de6.html\" title=\"\">VanBuom.pdf</a></li></ul>\n<ul>\n<li>Mã sản phẩm:WB</li>\n<li>Mô tả sản phẩm:\n<p>WB - Van bướm kiểu đĩa đệm là loại van bướm đóng  kín nhờ sự đàn hồi của đĩa van bọc cao su EPDM/NBR. Van được sử dụng trong hệ thống nước cấp, nước thải, PCCC và các hệ thống khác.</p></li></ul>\n<p><strong>Đặc tính - Features:</strong><br/>\n<br/>\n•    Van được thiết kế theo kiểu lệch tâm cho lực vặn thấp.<br/>\n•    Đĩa van bọc cao su NBR/EPDM<br/>\n•    Cạnh của đĩa van bọc cao su nên hoạt động êm, ít tạo bọt và tuổi thọ cao.<br/>\n•    Thân van được bao phủ bởi sơn epoxy chống ăn mòn.<br/>\n•    Đóng mở theo hai chiều nhẹ nhàng.<br/>\n•    Hai vòng làm kín ở ty trên giúp van luôn luôn kín trong suốt quá trình hoạt động.<br/>\n•    Sản xuất theo tiêu chuẩn: ISO 5752 &amp; ISO 5208<br/>\n<br/>\n<strong>Lĩnh vực ứng dụng:</strong><br/>\nVan được ứng dụng trong các ngành cấp thoát nước,trong chu trình nước của hệ thống HVAC, hệ thống PCCC…<br/>\n<br/>\n<strong>Thông số kỹ thuật:</strong><br/>\nKích thước: DN50-DN300 mm<br/>\nÁp suất làm việc: 10, 16 kgf/cm2<br/>\nNhiệt độ làm việc: -10 ~ 80C<br/>\nMôi trường sử dụng: Nước, nước thải<br/>\nKết nối: PN10/PN16</p>\n', 'Van bướm tay gạt lá cao su Shin Yi', 1.00, 0, 0, 1, 0, 'products/40944efe-9dff-4dab-a0ba-a15a7540434c.png', 40, 7, NULL, NULL),
(614, 'Van bướm tay gạt lá inox Shin Yi', 'van-b-m-tay-g-t-l-inox-shin-yi', '', '\n<h2>VAN BƯỚM LÁ VAN INOX</h2>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"http://www.syvalves.com.vn/vi/van-buom/item/download/17_93e234ed8da2d5f333de474561557c2f.html\" title=\"\">Van-Buom-Inox.pdf</a></li></ul>\n<ul>\n<li>Mã sản phẩm:WBLS</li>\n<li>Mô tả sản phẩm:\n<p>WBLS - Van bướm kiểu đĩa Inox là loại van bướm đóng kín nhờ sự đàn hồi của vòng đệm cao su được đúc sẵn trong thân van. Van được sử dụng trong hệ thống nước cấp, nước thải, PCCC và các hệ thống khác</p></li></ul>\n<p><strong>Đặc Tính:</strong><br/>\n•    Van được thiết kế theo kiểu đối xứng tâm nên cho lực vặn thấp<br/>\n•    Đĩa van được làm bằng Inox nên van sử dụng được trong môi trường hóa chất.<br/>\n•    Vòng đệm cao su được đúc sẵn trong thân van nên đảm bảo chắc chắn và tuổi thọ cao.<br/>\n•    Thân van được bao phủ bởi sơn Eposy chống ăn mòn.<br/>\n•    Đóng mở theo hai chiều nhẹ nhàng.<br/>\n•    Sản xuất theo tiêu chuẩn: ISO 5752 &amp; ISO 5208.</p>\n<p><strong>Lĩnh vực ứng dụng:</strong><br/>\nVan được ứng dụng trong các ngành cấp thoát nước, trong chu trình nước của hệ thống HVAC, hệ thống PCCC…<br/>\n<strong>Thông số kỹ thuật:</strong><br/>\nKích thước: DN50-DN150 mm<br/>\nÁp suất làm việc: 10, 16 kgf/cm2<br/>\nNhiệt độ làm việc: -10C ~ 80C<br/>\nMôi trường sử dụng: Nước, nước thải<br/>\nKết nối: PN10/PN16</p>\n', 'Van bướm tay gạt lá inox Shin Yi', 1.00, 0, 0, 1, 0, 'products/75aa55d1-067a-4387-b9b7-026a78c48287.png', 40, 7, NULL, NULL),
(615, 'Van cổng UL/FM Shin Yi', 'van-c-ng-ul-fm-shin-yi', '', '\n<h2>VAN CỔNG FM LÁ VAN BỌC CAO SU</h2>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"https://syvalves.com.vn/van-cong-fm-ul-noi-cum\">VanCongFM.pdf</a></li></ul>\n<ul>\n<li>Mã sản phẩm:FM</li>\n<li>Mô tả sản phẩm:\n<p>FM-Van cổng FM là một loại van được làm kín bằng lá van bọc cao su với đai ốc cố định trên lá van. Van hoạt động nhẹ không bị kẹt và bị ăn mòn hóa học.</p></li></ul>\n<p><strong>Đặc Tính - Features:</strong><br/>\n<br/>\n•    Van được thiết kế tiên tiến. Tiết kiệm lực và dễ dàng bảo trì.<br/>\n•    Thân và nắp van được chế tạo từ gang cầu cao cấp. <br/>\n•     Thân van được thiết kế phẳng để tránh bị kẹt. <br/>\n•    Lá van bên trong được chế tạo bằng gang cầu bên ngoài bọc cao su chất lượng cao.<br/>\n•    Ty van cứng cáp, lá van thiết kế hiện đại  nên van đóng mở nhẹ, Tiết kiệm lực. <br/>\n•    Thân van được đúc chính xác có thể làm việc dưới áp lực cao.<br/>\n </p>\n<p><strong>Lĩnh vực ứng dụng - Field Services:</strong><br/>\nVan được ứng dụng trong hệ thống PCCC…<br/>\n<br/>\n<br/>\n<strong>Thông số kỹ thuật - Technical Data:</strong><br/>\nKích thước: DN50-DN300 mm.<br/>\nÁp suất làm việc: 10, 16, 20 kgf/cm2 175 PSI-Grooved; 232 PSI/ 290 PSI flange valve.<br/>\nNhiệt độ làm việc: -10 ~ 80<br/>\nMôi trường làm việc: Nước.</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/fm_01.jpg\"/></p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/fm_02.jpg\"/></p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/fm_03.jpg\"/></p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/fm_04.jpg\"/></p>\n', 'Van cổng UL/FM Shin Yi', 1.00, 0, 0, 1, 0, 'products/5a26d4a5-622e-4a08-8267-fbeca0193ec1.jpg', 40, 7, NULL, NULL),
(616, 'Van cổng ty nổi FM Shin Yi', 'van-c-ng-ty-n-i-fm-shin-yi', '', '\n<h2>Thông số kỹ thuật</h2>\n<p><strong>Mã Hàng - </strong>Product Code: RRHX</p>\n<p><strong>Kích Thước - </strong>Size Range: DN50 - DN1200</p>\n<p><strong>Tiêu Chuẩn Thiết Kế</strong>: BS 5163-1 <br/>\nDesign Standard : ISO7259;  AWWA C509; BS EN 1074-1</p>\n<p><strong>Khoảng Cách Giữa 2 Mặt Bích</strong></p>\n<p>BS EN 558-1 TABLE 1 SERIES 3 <br/>\nFace To Face Standard: ISO 5752 TABLE 1 SERIES 3, ASME B16.10</p>\n<p><strong>Tiêu Chuẩn Mặt Bích/Kết Nối</strong></p>\n<p>BS EN 1092-2|ISO 7005-2: PN10/16/20/25 <br/>\nConnection/Flange Standard: JIS B2220: JIS 10K/16K/20K, ASME B16.42: ANSI 150LB</p>\n<ul>\n<li>\n<p><a href=\"http://www.facebook.com/sharer.php?u=http://www.syvalves.com.vn/van-cong-ty-noi\" onclick=\"window.open(\'http://www.facebook.com/sharer.php?u=http://www.syvalves.com.vn/van-cong-ty-noi\',\'Facebook\',\'width=600,height=300,left=\'+(screen.availWidth/2-300)+\',top=\'+(screen.availHeight/2-150)+\'\'); return false;\"><i></i> </a><b><a data-target=\"#chiTietModel\" data-toggle=\"modal\" href=\"http://www.syvalves.com.vn/van-cong-ty-noi#\">XEM CHI TIẾT</a> - </b><a href=\"http://www.syvalves.com.vn/images/catalogues/RRRV.pdf\" target=\"_blank\"><b>DOWNLOAD CATALOG</b></a></p></li></ul>\n<article>\n<p>Van Cổng là loại van được dùng phổ biến trong các hệ thống đường ống công nghiệp, chủ yếu cho chất lỏng có dòng chảy thẳng. Loại van này không nên sử dụng để điều tiết dòng chảy, trừ khi chúng được thiết kế đặc biệt cho mục đích đó. Van cửa hoạt động đóng, mở bằng cách nâng hạ lá van ra khỏi đường đi của chất lỏng.</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/stories/virtuemart/product/van-cong-ty-noi-1-min.jpg\"/></p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/stories/virtuemart/product/IMG_2320.jpg\"/></p>\n<p><strong>Cấu tạo và nguyên lý hoạt động của van cổng:</strong><br/>\n– Van kết nối với đường ống bằng mặt bích ở cả hai đầu, hoặc nối cùm đối với ống HDPE. Van và đường ống được nối với nhau bằng các bulông. Gioăng đệm được chèn vào giữa hai mặt bích của van và đường ống để mối kết nối có được độ kín cao. </p>\n<p>– Thân van được đúc từ Gang Cầu FCD450, phủ cả 2 mặt bằng sơn Epoxy với độ dầy &gt;=300 μm.</p>\n<p>– Trong nắp van ở phía trên có khoảng không để chứa lá van khi mở van, bên ngoài các lỗ bulông được làm chìm vào trong thân và đổ keo hoặc sáp nến ngăn cát bụi, nước và không khí ẩm làm kẹt và rỉ sét bulông.</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/stories/virtuemart/product/IMG_2309.jpg\"/>– Lá van có hình nêm, làm bằng Gang Cầu, bên ngoài bọc 1 lớp cao su EPDM an toàn với nguồn nước sạch.</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/stories/virtuemart/product/IMG_2315.jpg\"/>– Lá van được gắn cố định với 1 đầu của ty van bằng thanh chốt (pin), đầu phía trên của ty van được nối với tay quay bằng lỗ ren, phía trên nắp van vị trí ty van đi qua có nắp bịt kín, nắp này có chức năng làm kín không cho vật chất rò rỉ ra ngoài. Khi vặn tay quay thì ty van sẽ chuyển động lên xuống để đóng hay mở van. Nên chúng ta gọi đây là loại Van Cổng Ty Nổi. Khi quan sát vị trí của ty van ta có thể nhận biết được van đang ở vị trí đóng hay mở do khi lá van ở trạng thái mở, ty van lồi thẳng lên khỏi tay quay.</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/stories/virtuemart/product/van-cong-ty-noi-3-min.jpg\"/></p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/stories/virtuemart/product/IMG_2334.jpg\"/><em><strong>Ưu điểm của van cửa:</strong></em><br/>\nThiết kế hiện đại , dễ tháo lắp, dễ bảo trì<br/>\nThân van được thiết kế chuẩn tránh bị kẹt<br/>\nTrong và ngoài van được phủ lớp Epoxy tránh sự ăn mòn từ bên ngoài môi trường<br/>\nLá van được bọc cao su cao cấp đáp ứng các tiêu chuẩn an toàn cho nước uống.</p></article>\n', 'Van cổng ty nổi FM Shin Yi', 1.00, 0, 0, 1, 0, 'products/19d40cd1-84d6-4682-85ad-44850802e067.png', 40, 7, NULL, NULL),
(617, 'Ống LDPE nhựa dẻo phi 4/6mm', 'ng-ldpe-nh-a-d-o-phi-4-6mm', '', '\n<p>Ống dây dẫn nước tưới nhỏ giọt béc tưới 8 tia đường kính 6mm. Nhựa LDPE cao cấp nguyên sinh</p>\n<p><span style=\"font-size:16px;\">Chi tiết sản phẩm</span></p>\n<p><strong><a href=\"http://vietannong.com.vn/load/ong_dan_nuoc_tuoi/ong_day_pe_ldpe/13\">Ống LDPE</a> dẻo phi 6mm VAN PIPE DRIP</strong></p>\n<p><img alt=\"Ống dây LDPE phi 6mm VAN PIPE DRIP\" src=\"http://shop.vietannong.com.vn/ldpe_phi_6mm.jpg\"/></p>\n<p><strong>Chất liệu nhựa:</strong> LDPE nguyên sinh 100%</p>\n<p><strong>Đường kính ngoài:</strong> 6mm.</p>\n<p><strong>Đường kính trong</strong>: 4 - 5mm.</p>\n<p><strong>Áp suất:</strong> 4 bar</p>\n<p><strong>Màu sắc:</strong> Đen</p>\n<p><strong>Số mét trên cuộn:</strong> 1000m/cuộn</p>\n<p><strong>Ứng dụng:</strong> Dùng dẫn nước trong hệ thống <a href=\"http://vietannong.com.vn/load/tuoi_nho_giot/day_tuoi_nho_giot/day_nho_giot_phi_16mm_drip_cheap_re_nhat_viet_nam/20-1-0-139\">tưới béc tiết kiệm</a>, hệ thống<a href=\"http://vietannong.com.vn/load/tuoi_nho_giot/day_tuoi_nho_giot/20\"> tưới nhỏ giọt</a> quấn quanh gốc, dùng cho cây rau màu, cây ăn quả có múi, cây công nghiệp như hồ tiêu...</p>\n<p><img alt=\"Ống dây LDPE phi 6mm VAN PIPE DRIP\" src=\"http://shop.vietannong.com.vn/ldpe_phi_6mm_1.jpg\"/></p>\n', 'Ống LDPE nhựa dẻo phi 4/6mm', 0.00, 0, 0, 1, 0, 'products/d51ef05f-bef6-4e13-b1a5-6fb3518cb085.png', 30, 13, NULL, NULL),
(618, 'Van cổng tín hiệu Shin Yi', 'van-c-ng-t-n-hi-u-shin-yi', '', '\n<h2>VAN CỔNG TÍN HIỆU</h2>\n<p>Download Catalogue: </p>\n<ul>\n<li><a href=\"http://www.syvalves.com.vn/vi/van-cong-fm/item/download/21_ac316fb9b218cf08c1e710ba402f8adc.html\" title=\"\">VanCongTinHieu.pdf</a></li></ul>\n<ul>\n<li>Mã sản phẩm:RRSX</li>\n<li>Mô tả sản phẩm:\n<p>RRSX - Van cổng tín hiệu điện được sử dụng cho hệ thống phun nước tự động trong hệ thống PCCC. Thông báo tình trạng của van đóng hoặc mở trên bảng điều khiển.</p></li></ul>\n<p><strong>Đăc Tính - Features:</strong><br/>\n<br/>\n•    Thân và nắp van được chế tạo từ gang cầu cao cấp, trọng lượng van nhẹ hơn 20-30% so với van được chế tạo từ gang xám.<br/>\n•    Thân van được thiết kế phẳng để tránh bị kẹt. Lá van được bọc cao su cao cấp đáp ứng các tiêu chuẩn an toàn cho nước uống.<br/>\n•    Cả trong và ngoài van đều được bao phủ bằng sơn epoxy để chống sự ăn mòn của môi trường.<br/>\n•    Công tắc giám sát lấy tín hiệu từ lõi nam châm cung cấp tín hiệu chính xác. <br/>\n•    Sản xuất theo tiêu chuẩn ISO 7259-1998.<br/>\n•    Kích thước giữa hai mặt bích theo tiêu chuẩn<br/>\n•    Mặt bích được thiết kế theo tiêu chuẩn:<br/>\nGB/T17241.6-1998;ISO7005.2-1998;EN1092.2-1997.</p>\n<p><strong>Lĩnh vực ứng dụng - Field Services:</strong><br/>\nVan được ứng dụng hệ thống PCCC…<br/>\n </p>\n<p><strong>Thông số kỹ thuật  - Technical Data:</strong><br/>\nKích thước: DN50 - DN300 mm<br/>\nÁp suất làm việc: 10, 16, 20, 25 Kgf/cm2<br/>\nNhiệt độ làm việc : -100 ~ 800C<br/>\nKết nối theo tiêu chuẩn mặt bích:<br/>\nPN10 / PN16 / PN20 / JIS 10K / ANSI 150-LB</p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/rrsx_01.jpg\"/></p>\n<p><img alt=\"\" src=\"http://www.syvalves.com.vn/images/mota/rrsx_02.jpg\"/></p>\n', 'Van cổng tín hiệu Shin Yi', 1.00, 0, 0, 1, 0, 'products/8c2f502e-fa84-4a53-9ff0-79f89a63a3ff.jpg', 40, 7, NULL, NULL),
(619, 'Dây PE 10mm dùng dẫn nước trong hệ thống tưới, béc có đuôi 10mm', 'd-y-pe-10mm-du-ng-d-n-n-c-trong-h-th-ng-t-i-be-c-co-u-i-10mm', '', '\n<h1><strong><a href=\"http://vietannong.com.vn/load/bectuoicay/day_pe/22\">Dây PE </a>10mm</strong></h1>\n<p><strong>Đường kính: </strong>10mm</p>\n<p><strong>Độ dài cuộn:</strong> 35m</p>\n<p><strong>Áp suất hoạt động:</strong> 2 - 4 bar</p>\n<p><strong>Cuộn:</strong> 2kg, Bán theo kg.</p>\n<p><strong>Ứng dụng:</strong> Sử dụng trong <a href=\"http://vietannong.com.vn/\">hệ thống tưới</a><a href=\"http://vietannong.com.vn/\"> tự động </a>sân vườn nhỏ, <a href=\"http://vietannong.com.vn/\">hệ thống</a><a href=\"http://vietannong.com.vn/\"> tưới nhỏ giọt</a> cho cây rau màu, hoa quả, tiết kiệm chi phí cho hệ thống tưới chảy tràn.</p>\n', 'Dây PE 10mm dùng dẫn nước trong hệ thống tưới, béc có đuôi 10mm', 0.00, 0, 0, 1, 0, 'products/fecdf776-c443-460b-96d3-130eb4c279f4.jpg', 28, 1, NULL, NULL),
(620, 'Ống LDPE nhựa dẻo phi 12mm', 'ng-ldpe-nh-a-d-o-phi-12mm', '', '\n<h2>Dây LDPE dẻo phi 12mm. Chuyên dùng làm ống dẫn nước cho hệ thống tưới nhỏ giọt, tưới tiết kiệm và quấn gốc thanh long, hồ tiêu tưới béc bọ...</h2>\n<h2>Chi tiết sản phẩm</h2>\n<p><strong><a href=\"http://vietannong.com.vn/load/ong_dan_nuoc_tuoi/ong_day_pe_ldpe/day_d_o_ldpe_phi_25mm_nh_a_nguyen_sinh_cao_c_p/13-1-0-209\">Dây LDPE </a> dẻo phi 12mm, nhựa nguyên sinh cao cấp</strong></p>\n<p><img alt=\"Dây dẻo LDPE phi 12mm, nhựa nguyên sinh cao cấp\" src=\"http://vietannong.com.vn/vietannong/ldpe_phi_12.jpg\"/></p>\n<p><strong>Quy cách:</strong></p>\n<p><strong>Độ dày:</strong> 1.0mm</p>\n<p><strong>Đường kính:</strong> 12mm</p>\n<p><strong>Chất liệu: </strong>LDPE</p>\n<p><strong>Áp suất chịu đựng:</strong> 4 bar</p>\n<p><strong>Độ bền:</strong> &gt;5 năm, chôn được dưới đất</p>\n<p><strong>Cuộn:</strong> 200m, cung cấp theo cuộn.</p>\n<p><strong>Ứng dụng:</strong> Dùng trong dẫn nước <a href=\"http://vietannong.com.vn/load/tuoi_nho_giot/4\">tưới nhỏ giọt</a>, hệ thống tưới tiết kiệm hồ tiêu, cà phê, tưới cây đa vụ, hoa cảnh, quấn gốc tưới tiết kiệm cây thanh long...</p>\n<p><img alt=\"Dây dẻo LDPE phi 12mm, nhựa nguyên sinh cao cấp\" src=\"http://vietannong.com.vn/vietannong/LDPE_12mm_thanh_long.png\"/></p>\n<p><img alt=\"Dây dẻo LDPE phi 12mm, nhựa nguyên sinh cao cấp\" src=\"http://vietannong.com.vn/vietannong/Ldpe_12mm_thanh_long.jpg\"/></p>\n', 'Ống LDPE nhựa dẻo phi 12mm', 0.00, 0, 0, 1, 0, 'products/60b18469-1a29-4cdf-bc4d-89bc3f744cfa.png', 30, 13, NULL, NULL),
(621, 'Ống LDPE Nhựa dẻo phi 20mm', 'ng-ldpe-nh-a-d-o-phi-20mm', '', '\n<div class=\"woocommerce-tabs\" style=\"text-align:start; -webkit-text-stroke-width:0px\">\n<div class=\"baivietlienquan\" style=\"margin-top:30px\">\n<div class=\"same1\" style=\"padding:20px\">\n<div class=\"panel entry-content\" id=\"tab-description\" style=\"border:1px solid transparent; margin-bottom:20px; border-radius:4px\">\n<p style=\"margin:0px 0px 15px\">Dây LDPE dẻo phi 20mm. Chuyên dùng làm ống xương cá cho hệ thống tưới nhỏ giọt, tưới tiết kiệm và mini sprinklers...</p>\n<p style=\"margin:0px 0px 15px\"><span style=\"font-size:13px\"><span style=\"box-sizing:border-box\"><span style=\"color:#333333\"><span style=\'font-family:arial, \"time new roman\"\'><span style=\"font-style:normal\"><span style=\"font-variant-ligatures:normal\"><span style=\"font-variant-caps:normal\"><span style=\"font-weight:normal\"><span style=\"letter-spacing:normal\"><span style=\"orphans:2\"><span style=\"text-transform:none\"><span style=\"white-space:normal\"><span style=\"widows:2\"><span style=\"word-spacing:0px\"><span style=\"background-color:#ffffff\"><span style=\"text-decoration-style:initial\"><span style=\"text-decoration-color:initial\"><span style=\"box-sizing:border-box\"><span style=\"box-sizing:border-box\"><span style=\"box-sizing:border-box\"><span style=\"background-color:#ffffff\"><span style=\"box-shadow:rgba(0, 0, 0, 0.05) 0px 1px 1px\"><span style=\"overflow:hidden\"><span style=\"display:block\"><span style=\"box-sizing:border-box\"><span style=\"font-size:14px\"><span style=\"box-sizing:border-box\"><span style=\"box-sizing:border-box\"><span style=\"font-family:arial, helvetica, sans-serif\"><strong style=\"box-sizing:border-box; font-weight:bold\">Dây LDPE dẻo phi 20mm</strong></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span></span>