(622, 'Ống LDPE nhựa dẻo phi 25mm', 'ng-ldpe-nh-a-d-o-phi-25mm', '', '\n<p>Dây LDPE dẻo phi 25mm. Chuyên dùng làm ống dẫn nước cho hệ thống tưới nhỏ giọt, tưới tiết kiệm và tưới béc nhí...</p>\n<p><span style=\"font-size:16px;\"><strong>Chi tiết sản phẩm</strong></span></p>\n<p><strong><a href=\"http://vietannong.com.vn/load/ong_dan_nuoc_tuoi/ong_day_pe_ldpe/day_ldpe_phi_20_nhua_nguyen_sinh_cao_cap/13-1-0-78\">Dây LDPE</a> dẻo phi 25mm nhựa nguyên sinh</strong></p>\n<p><img data-thumb=\"original\" original-height=\"600\" original-width=\"600\" src=\"//bizweb.dktcdn.net/100/168/021/products/anh-ong-nhua-deo.jpg?v=1627725101777\"/></p>\n<p><strong>Quy cách:</strong></p>\n<p><strong>Độ dày:</strong> 1.4mm</p>\n<p><strong>Đường kính:</strong> 25mm</p>\n<p><strong>Chất liệu: </strong>LDPE</p>\n<p><strong>Áp suất chịu đựng:</strong> 4 bar</p>\n<p><strong>Độ bền:</strong> &gt;5 năm, chôn được dưới đất</p>\n<p><strong>Cuộn:</strong> 200m, cung cấp theo cuộn.</p>\n<p><strong>Ứng dụng:</strong> Dùng trong dẫn nước <a href=\"http://vietannong.com.vn/load/tuoi_nho_giot/4\">tưới nhỏ giọt</a>, hệ thống tưới tiết kiệm hồ tiêu, cà phê, tưới cây đa vụ, hoa cảnh...</p>\n', 'Ống LDPE nhựa dẻo phi 25mm', 0.00, 0, 0, 1, 0, 'products/d45bd2ed-f3ef-4fb3-b42b-08c07e1c3096.jpg', 30, 13, NULL, NULL),
(623, 'Ống LDPE nhựa dẻo phi 16mm', 'ng-ldpe-nh-a-d-o-phi-16mm', '', '\n<p>Dây LDPE dẻo phi 16mm. Chuyên dùng làm ống xương cá cho hệ thống tưới nhỏ giọt, tưới tiết kiệm và mini sprinklers...</p>\n<p><strong>Dây LDPE dẻo phi 16mm - Chất liệu nguyên sinh cao cấp.</strong></p>\n<p><img alt=\"ống ldpe 16mm dẫn nước tưới nhỏ giọt\" src=\"http://vietannong.com.vn/day_ldpe_phi_16mm.jpg\"/></p>\n<p><strong>Thông số kỹ thuật:</strong></p>\n<p><strong>Độ dày</strong>: 1.2mm</p>\n<p><strong>Đường kính</strong>: 16mm</p>\n<p><strong>Chất liệu:</strong> LDPE</p>\n<p><strong>Áp suất chịu đựng:</strong> 4 bar</p>\n<p><strong>Độ bền:</strong> &gt;5 năm, chôn được dưới đất</p>\n<p><strong>Cuộn:</strong> 200m, cung cấp theo cuộn.</p>\n<p><strong>Ứng dụng: </strong>Dùng trong hệ thống <a href=\"http://vietannong.com.vn/\">tưới nhỏ giọt</a> tưới cà chua, cắm vòi nhỏ giọt, dẫn nước sinh hoạt...hệ thống<a href=\"http://vietannong.com.vn/\"> tưới tự động</a> cây công nghiệp, tưới cây ăn quả.</p>\n<p><img alt=\"ống ldpe 16mm dẫn nước tưới nhỏ giọt\" src=\"http://vietannong.com.vn/dan_pe_16mm.jpg\"/></p>\n', 'Ống LDPE nhựa dẻo phi 16mm', 0.00, 0, 0, 1, 0, 'products/931fb94c-a41c-4749-b55b-c1d1f4228602.jpg', 30, 1, NULL, NULL);
