(642, 'Bộ nối nhanh ống mềm các loại', 'b-n-i-nhanh-ng-m-m-ca-c-loa-i', '', '\n<p><img data-thumb=\"original\" original-height=\"2719\" original-width=\"2432\" src=\"//bizweb.dktcdn.net/100/168/021/files/image-5.jpg?v=1496139532975\"/></p>\n', 'Bộ nối nhanh ống mềm các loại', 0.00, 0, 0, 1, 0, 'products/d20ee865-81b7-4a1a-9019-a5d5e4eb50f4.jpg', 28, 1, NULL, NULL),
(643, 'Béc bọ chống côn trùng tưới gốc', 'b-c-b-ch-ng-c-n-tr-ng-t-i-g-c', '', '\n<h1><strong><a href=\"http://vietannong.com.vn/\">BÉC TƯỚI</a> GỐC CHỐNG CÔN TRÙNG</strong></h1>\n<p><img alt=\"Béc tưới gốc chống côn trùng Việt An Nông\" src=\"http://vietannong.com.vn/tuoitudong/bec_phun_goc_chong_con_trung_1.jpg\"/></p>\n<p><strong>Thông số kỹ thuật:</strong></p>\n<p><strong>Bán kính phun:</strong> 1.1 - 1.2m</p>\n<p><strong>Lưu lượng:</strong> 53 - 82 lít/giờ</p>\n<p><strong>Áp suất hoạt động:</strong> 1.5 - 3.0 bar</p>\n<p><strong>Chân béc gắn ống: </strong>5mm có gờ.</p>\n<p><strong>Thời gian sử dụng:</strong> &gt;3 năm</p>\n<p><strong>Xuất xứ:</strong> Trung Quốc</p>\n<p><strong>Ứng dụng:</strong> Thường sử dụng nhiều trong <a href=\"http://vietannong.com.vn/\" target=\"_blank\">hệ thống tưới</a> gốc tiết kiệm nước cho cây hồ tiêu, cà phê, cây ăn quả có múi...</p>\n<p><img alt=\"Béc tưới gốc chống côn trùng Việt An Nông\" src=\"http://vietannong.com.vn/tuoitudong/bec_phun_goc_chong_con_trung.jpg\"/></p>\n', 'Béc bọ chống côn trùng tưới gốc', 1.00, 0, 0, 1, 0, 'products/dc2b0d8e-8ab0-473f-a380-21643fed2c8f.jpg', 45, 8, NULL, NULL),
(644, 'Van điện từ tự động UNID 21-27-34-42-48-60 điện áp 220/24V', 'van-i-n-t-t-ng-unid-21-27-34-42-48-60-i-n-a-p-220-24v', '', '\n<h2><strong>I. Tìm hiểu về van điện từ</strong></h2>\n<h2><strong>1. Định nghĩa:</strong></h2>\n<p><strong>Van điện từ</strong> là một thiết bị cơ điện được sử dụng để kiểm soát dòng chảy chất lỏng hoặc khí. <strong>Van điện từ</strong> hay còn gọi là Solenid valve được điều khiển bởi dòng điện 220V hoặc 24V được điều hành thông qua một cuộn dây. Khi cuộn dây được cấp điện, một từ trường được tạo ra, tạo thành lực tác động lên pít tông bên trong các cuộn dây sẽ làm pít tông di chuyển. Tùy thuộc vào thiết kế của van, pít tông tác động hoặc sẽ mở hoặc đóng van. Khi dòng điện được ngắt từ các cuộn dây, các van sẽ trở về trạng thái của nó lúc ban đầu</p>\n<h3><strong>2. Cấu tạo của <em>Van điện từ</em>:</strong></h3>\n<p>Để hiểu rõ cấu tạo của nó xin mời quý khách hàng xem bản vẽ kỹ thuật của van điện từ như hình dưới đây:</p>\n<p><img alt=\"\" src=\"http://vanhanquoc.vn/uploads/files/Van%20%C4%91i%E1%BB%87n%20t%E1%BB%AB/11.jpg\"/></p>\n<p>Cấu tạo VĐT:</p>\n<p>                  1. Thân van: bằng đồng hoặc inox, nhựa</p>\n<p>                 2. Lưu chất: Chất lỏng (nước, dầu) hoặc khí ( khí nén, gas, v,v)</p>\n<p>                 3. Trục ống rỗng  - Lúc chưa có lưu chất qua</p>\n<p>                 4. Vỏ ngoài cuộn hút ( Dùng để bảo vệ cuộn điện)</p>\n<p>                 5. Cuộn từ - cuôn coil ( Cuộn từ này sẽ sinh tư tạo ra lực hút)</p>\n<p>                 6. Dây điện ( có thể dùng điện áp 220V, 24V, 110V)</p>\n<p>                 7. Trục van làm kín ( trạng thái bình thường lò xo 8 sẽ tác động ép kín, giúp van ở trạng thái thường đóng)</p>\n<p>                  8. Lò xo</p>\n<p>                 9. Khe hở lưu chất đi qua khi mở van</p>\n<p>       Về cơ bản 1 van điện từ sẽ cấu tạo như trên tuy nhiên do một số yêu cầu kỹ thuật đặc biệt như môi trường làm việc, nhiệt độ, áp lực, lưu chất đi qua, vật liệu chế tạo mà một số loại van điện từ sẽ được thiết kế đặc biệt sẽ khác hơn so với hình vẽ trên.</p>\n<h3><strong>3. Nguyên lý hoạt động của <em>Van điện từ</em>:</strong></h3>\n<p>    Có 2 dạng van điện từ cơ bản là <em>van điện từ</em> thường đóng và van điện từ thường mở, Ở bài viết này chúng tôi sẽ giới thiệu sơ qua cho khách hàng về nguyên lý hoạt động của van diện từ thường đóng:</p>\n<p>- Ban đầu van ở trạng thái luôn luôn đóng khi chúng ta chưa cấp điện cho van, khi đó dòng lưu chất di chuyển trên đường ống gặp van sẽ ngưng chuyển động vì van ở trạng thái đóng.</p>\n<p>- Tiếp theo chúng ta cấp điện cho van ( Có thể dùng điện áp 220V xoay chiều hoặc điện áp 24V ). Khi đó cuộn từ - cuộn coil sẽ sinh từ tạo ra một lực hút nhất định, lực hút này sẽ hút trục van có đĩa đệm và gioăng làm kín lên phía trên.</p>\n<p>- Với lực hút của cuộn coil - cuộn dây từ sẽ thắng lực đẩy của lò xo thì đĩa đệm và gioăng làm kín với thân van sẽ tạo thành một khe hở nhất định và khi đó lưu chất sẽ lọt qua van và khi lò xo được nén tối đa van điện từ sẽ mở hoàn toàn tạo ra hiện tượng mở van</p>\n<p>- Khi chúng ta ngừng cấp điện cho van thì không còn lực hút nào nữa thì lò xo sẽ giãn nở một cách tự nhiên ép đĩa đệm và gioăng làm kín vào thân van giúp va trở về trạng thái đóng ban đầu.</p>\n<p>  Như vậy khi nào cần mở van thì chúng ta cấp điện và khi nào cần đóng van chúng ta ngừng cấp điện cho nó. Vì cuộn từ gần như sinh từ ngay lập tức nên van điện từ thường đóng mở rất nhanh có thể nói là đóng mở ngay tức thì.</p>\n<p>  Từ đây chúng ta có thể thấy nguyên lý hoạt động của van điện từ thường mở cũng sẽ tương tự như van điện từ thường đóng</p>\n<p>Để hiểu rõ hơn nữa cũng như trực quan hơn mời quý khách hàng xem video mô tả hoạt động của chúng tôi dưới đây:</p>\n<h3><iframe frameborder=\"0\" height=\"420\" src=\"https://www.youtube.com/embed/GttgRmZf6AM\" width=\"520\"></iframe></h3>\n<h3><strong>4. Ứng dụng của <em>Van điện từ</em> và tầm quan trọng của nó</strong></h3>\n<p>    Với sự phát triển không ngừng của công nghệ, cũng như ngành tự động hóa sản xuất nói chung và tiêu dùng nói riêng. Việc đóng mở cho thiết bị đường ống cũng được tự động hóa và trở nên cấp thiết. Van điện từ (solenoid valve) đã được nghiên cứu và sản xuất từ rất lâu, hiện nay dòng van này trở nên thông dụng hơn ở thị trường nươc nhà.</p>\n<p>    Để đáp ứng nhu cầu ngày một lớn của thị trường, nay công ty chúng tôi đã và đang nhập khẩu rất nhiều loại van điện từ kịp thời phục vụ nhu cầu của đa dạng quý khách hàng.</p>\n<p>   Chúng tôi đã và đang có sẵn trong kho các dòng van điện từ:</p>\n<p>- Van điện từ nước ( 0-80 độ C)</p>\n<p>- Van điện từ dùng cho hơi nước (0-180 độ C)</p>\n<p>- Van điện từ dùng cho hệ thống khí nén, dầu, gas</p>\n<h2><strong>II. Phân loại <em>Van điện từ</em>:</strong></h2>\n<p>  Van điện từ được phân loại cụ thể dựa vào các yếu tố sau:</p>\n<p>- Phân loại theo chức năng: van điện từ thường mở, van điện từ thường đóng</p>\n<p>- Phân loại theo vật liệu chế tạo van: van điện từ đồng, van điện từ nhựa, van điện từ inox</p>\n<p>- Phân loại theo điện áp: van điện từ 220V, van điện từ 24V, van điện từ 110V</p>\n<p>- Phân loại theo Kiểu lắp: van điện từ lắp ren, van điện từ rắc co, van điện từ lắp bích, van điện từ mặt bích</p>\n<p>- Phân loại theo xuất sứ: Van điện từ Hàn Quốc, van điện từ Đài Loan, van điện từ Nhật, van điện từ Italy</p>\n<p>- Phân loại theo nhãn hiệu: Van điện từ UniD, van điện từ TPC, van điện từ Round Star...</p>\n<h2><strong>III. Ưu điểm và nhược điểm của <em>Van điện từ</em>:</strong></h2>\n<h3>1. Ưu điểm:</h3>\n<p>- Van điện từ là một trong những loại van thông dụng, dân dụng, phổ biến nhất hiện nay. Chính vì thế mà ứng dụng của nó vô cùng rộng rãi: trong dân dụng, công nghiệp</p>\n<p>- Thiết kế nhỏ gọn, bền vững</p>\n<p>- Vật liệu đa dạng: đồng, inox, nhựa do đó phù hợp với nhiều môi trường khác nhau</p>\n<p>- Thời gian đóng mở diễn ra rất nhanh gần như là tức thì chưa tới 1s</p>\n<p>- Đa dạng điện áp: 220V, 24V, 12V, 110V</p>\n<p>- Có cả kiểu lắp ren và mặt bích</p>\n<p>- Giá thành tương đối rẻ</p>\n<p>- Hàng có sẵn rất nhiều</p>\n<p>2. Nhược điểm:</p>\n<p>- Độ bền không quá cao so với dòng van điều khiển bằng mô tơ/ động cơ điện</p>\n<p>- Lưu chất đi qua van bị ảnh hưởng lưu lượng. Lưu lượng trước van lúc nào cũng lớn hơn lưu lượng đường sau van.</p>\n<p>Trên đây chúng tôi đã cung cấp cho Quý khách những thông tin cơ bản về <em><strong>Van điện từ</strong></em>. Mọi thắc mắc Quý khách vui lòng liên hệ trực tiếp với chúng tôi theo thông tin bên dưới để được hỗ trợ tốt nhất!</p>\n', 'Van điện từ tự động UNID 21-27-34-42-48-60 điện áp 220/24V', 0.00, 0, 0, 1, 0, 'products/92294df9-a331-4867-be11-b1d47642302e.png', 31, 1, NULL, NULL),
(645, 'Bộ timer điều khiển tưới tự động claber 8428 dùng pin AAA Italia', 'b-timer-i-u-khi-n-t-i-t-ng-claber-8428-du-ng-pin-aaa-italia', '', '\n<p data-mce-style=\"text-align: justify;\">Mỗi khi đi làm về bạn thường cảm thấy mệt mỏi nên quên đi nhiệm vụ tưới cây và thường bỏ mặc chúng.<br/>\nNhững lần đi công tác hay đi chơi xa bạn thường lo lắng vì cây ở nhà không ai tưới, chăm sóc.<br/>\nBạn muốn lắp đặt một hệ thống tưới nhưng bạn lo ngại chi phí sẽ rất tốn kém và cách sử dụng phức tạp.<br/>\nHiểu được những suy nghĩ và lo lắng mà bạn đang phải đối mặt hàng ngày nên hôm nay chúng tôi xin giới thiệu đến bạn <b>bộ timer điều khiển tưới tự động claber 8428</b>.</p>\n<p data-mce-style=\"text-align: center;\"><img data-mce-src=\"//file.hstatic.net/1000120140/file/timer_20claber_208428_20ung_20dung.jpg\" src=\"http://file.hstatic.net/1000120140/file/timer_20claber_208428_20ung_20dung.jpg\"/><br/>\n<em>Sử dụng bộ Timer Claber 8428 - Tưới tự động cho hoa và rau mỗi ngày</em></p>\n<h2><b>Timer claber 8428 có những tính năng gì?</b></h2>\n<p data-mce-style=\"text-align: justify;\">- Bộ timer điều khiển tưới tự động claber 8428<b> </b>dùng để hẹn giờ mở nước tự động cho hệ thống tưới.<br/>\n- Cây nhà bạn sẽ được chăm sóc hoàn toàn tự động theo lịch đã hẹn sẵn. <br/>\n- Sản phẩm sẽ hẹn giờ theo thời gian thực tế và tự lặp lại hàng ngày theo thời gian bạn đã chọn.<br/>\n- Có thể hẹn giờ tưới cho tất cả các ngày trong tuần. <br/>\n- Cách cài đặt và xử dụng đơn giản, hoạt động chính xác và bền bỉ. Các chương trình hoạt động đơn giản, 8428 mang đến sự tin cậy, tiết kiệm và rất phù hợp cho các hộ gia đình.</p>\n<h2><b>Cách lắp đặt và hoạt động của timer 8428 như thế nào?</b></h2>\n<h3><b><i>Cách lắp đặt timer </i></b></h3>\n<p data-mce-style=\"text-align: justify;\"><b>Bước 1: </b>Kết nối 1 đầu của timer với vòi nước romine bằng cách vặn thật chặt. (Hình 1 và 2).<br/>\n<b>Bước 2: </b>Kết nối đầu còn lại của timer với ống phi 16. (Hình 3)<br/>\n<strong>Bước 3</strong>: Lắp đặt pin vào hệ thống tưới, bằng cách ấn vào 2 nút bên hông, có thể bỏ qua bước này vì thông thường Maka sẽ lắp pin sẵn trước khi khách hàng mua về. (Hình 4,5 và 6).<br/>\n<b>Bước 4: </b>Cài đặt chế độ hẹn giờ trên timer theo thời gian thật mà bạn muốn tưới cho vườn cây nhà mình. (Hình 7).</p>\n<p><img data-mce-src=\"//file.hstatic.net/1000120140/file/timer_20claber_20huong_20dan_201_00bdc448c4a4436ba3fe43d628a75425.jpg\" data-mce-style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"http://file.hstatic.net/1000120140/file/timer_20claber_20huong_20dan_201_00bdc448c4a4436ba3fe43d628a75425.jpg\"/></p>\n<p data-mce-style=\"text-align: center;\"><em>Hướng dẫn lắp đặt bộ timer điều khiển tưới tự động Claber 8428. (Ảnh 1)</em></p>\n<p> </p>\n<p data-mce-style=\"text-align: center;\"><img data-mce-src=\"//file.hstatic.net/1000120140/file/timer_20claber_20huong_20dan_202_f39f7c9c4dde42b5a435cb82dec96839.jpg\" src=\"http://file.hstatic.net/1000120140/file/timer_20claber_20huong_20dan_202_f39f7c9c4dde42b5a435cb82dec96839.jpg\"/><br/>\n<em>Hướng dẫn lắp đặt bộ timer điều khiển tưới tự động Claber 8428. (Ảnh 2)</em></p>\n<p data-mce-style=\"text-align: center;\"><img data-mce-src=\"//file.hstatic.net/1000120140/file/timer_20claber_20huong_20dan_203.jpg\" src=\"http://file.hstatic.net/1000120140/file/timer_20claber_20huong_20dan_203.jpg\"/><br/>\n<em>Hướng dẫn lắp đặt bộ timer điều khiển tưới tự động Claber 8428. (Ảnh 3)</em><br/>\n </p>\n<h3><b><i>Chế độ hoạt động</i></b></h3>\n<p>- Khi đến thời gian mà bạn cài đặt sẵn thì timer sẽ tự động kích van điện để mở nước cho hệ thống tưới. Khi đến thời gian tắt thì timer sẽ ngắt van điện và ngừng cung cấp nước cho hệ thống.<br/>\n- Bạn có thể hẹn giờ tưới vào tất cả các giờ trong ngày và tất cả các ngày trong tuần.<br/>\n- Hẹn giờ ngày có thể tưới từ 1 đến 2 lần. Thời gian tưới tối thiểu là 1 phút.</p>\n<h2><b>Ưu điểm của timer 8428 là gì?</b></h2>\n<p data-mce-style=\"text-align: justify;\">Bộ timer điều khiển tưới tự động claber 8428 được thiết kế hiện đại, không cần phải dùng nguồn điện, dùng hoàn toàn bằng pin.<br/>\nCách lắp đặt đơn giản, sử dụng dễ dàng.<br/>\nBạn có thể dùng để hẹn giờ điều khiển tưới tự động cho tường cây, vườn đứng, tưới rau, cây cảnh… Vườn cây nhà bạn sẽ luôn được cung cấp đủ nước ngay khi bạn vắng nhà.</p>\n<p data-mce-style=\"text-align: justify;\">Tưới tự động sẽ chưa thực sự tiết kiệm và hiệu quả triệt để nếu không có một hệ thống điều khiển tự động. Hệ thống điều khiển luôn giúp cung cấp nước đúng lưu lượng, đúng thời điểm, giúp tăng cường tối đa hiệu quả cây trồng, tiết kiệm điện, nước và thời gian. Với một bộ timer claber 8428, chắc chắn sẽ giúp bạn có một mảnh vườn ưng ý nhất.</p>\n<p data-mce-style=\"text-align: center;\"><img data-mce-src=\"//file.hstatic.net/1000120140/file/timer_20claber_208425_20san_20pham.jpg\" src=\"http://file.hstatic.net/1000120140/file/timer_20claber_208425_20san_20pham.jpg\"/><br/>\n<em>Ứng dụng của Timer claber 8428 trong việc tưới hoa ban công tự động</em></p>\n<h2><b>Thông số kỹ thuật</b></h2>\n<p>- Điện áp: Pin 9V DC.<br/>\n- Đường kính ống phi 27 (3/4 inch).<br/>\n- Áp suất hoạt động thấp: 0.2 bar – 12 bar.</p>\n<p>Tất cả các sản phẩm của Maka được nhập khẩu từ các thương hiệu nổi tiếng như: Claber (Ý), Mỹ… <br/>\nĐổi mới sản phẩm trong vòng 14 ngày.<br/>\nSản phẩm được bảo hành 1 đổi 1 trong 12 tháng.<br/>\nGiao hàng tận nơi.<br/>\nThanh toán khi nhận hàng.</p>\n<p data-mce-style=\"text-align: justify;\">Sử dụng bộ timer tưới tự động claber 8428 giúp tiết kiệm hơn 50% thời gian chăm sóc cây. Hãy liên hệ với chúng tôi để được hỗ trợ và mua hàng ngay hôm nay.</p>\n', 'Bộ timer điều khiển tưới tự động claber 8428 dùng pin AAA Italia', 0.00, 0, 0, 1, 0, 'products/376ef4f9-c813-400a-96ec-364942a6fb15.png', 31, 1, NULL, NULL),
(646, 'Bộ hẹn giờ  tự động KG316 - 220v/25A', 'b-h-n-gi-t-ng-kg316-220v-25a', '', '\n<p><strong>Mô tả</strong></p>\n<p>Bộ hẹn giờ KG316T có khả năng hẹn giờ đến 17 lần On và 17 lần Off vào các thời gian khác nhau. Đặc điểm nổi bật của sản phẩm là có khả năng đóng cắt dòng điện lớn (lên tới 25A), có thể đóng các được các tải lớn như đèn cao áp, bơm nước, bình nóng lạnh, điều hòa.....Máy bơm công suất lớn hơn 300W phải dùng qua bộ khởi động từ để đảm bảo độ bền của thiết bị.</p>\n<h2><strong>THÔNG SỐ SẢN PHẨM</strong><br/>\n- Điện áp hoạt động: 220VAC.<br/>\n- Dòng tải: 25A.<br/>\n- Thời gian nhỏ nhất có thể cài đặt: 1 phút.<br/>\n- Pin chờ: 100 ngày (tự động sạc lại khi bị mất nguồn).<br/>\n- Kích thước: (Rộng x cao x sâu) : 55x98x45 mm</h2>\n', 'Bộ hẹn giờ  tự động KG316 - 220v/25A', 0.00, 0, 0, 1, 0, 'products/66bb4001-ab76-4ff2-aa78-fc903a7b29eb.png', 31, 1, NULL, NULL),
(647, 'MÁY BƠM HÚT GIẾNG SÂU ABC 2HP', 'm-y-b-m-h-t-gi-ng-s-u-abc-2hp', '', '\n<p><a href=\"http://quocthaivn.com\">Công Ty TNHH đầu tư và thương mại tổng hợp Quốc Thái</a></p>\n<p>MÁY BƠM HÚT GIẾNG SÂU ABC 2HP</p>\n<p><big><b>Bơm hút giếng sâu – ABC với hai đầu bơm nước thích hợp dùng để hút giếng khoan ở các tầng sâu ( tầng 2, 3 ) mà bơm một đầu không thể thực hiện được, ngoài ra máy còn đẩy cao rất tốt.</b><span style=\"font-size: 13px;\"> </span></big><b><big>Bơm hút giếng sâu ABC được thiết kế với 2 đầu bơm nước, có áp suất nước rất lớn, dùng để hút giếng khoan ở tầng sâu, nơi mà các loại bơm một đầu không thể sử dụng được.<br/>\nThích hợp dùng cho các tòa nhà cao tầng, chung cư, căn hộ gia đình</big></b></p>\n', 'MÁY BƠM HÚT GIẾNG SÂU ABC 2HP', 0.00, 0, 0, 1, 0, 'products/cd3c8511-d324-4213-86c8-ac66124d5599.jpg', 28, 1, NULL, NULL),
(648, 'Máy cắt rãnh tường 5 lưỡi CaoWang ZR3928', 'm-y-c-t-r-nh-t-ng-5-l-i-caowang-zr3928', '', '\n<h2>Máy cắt rãnh tường 5 lưỡi Caowang ZR3928 là phiên bản kế nhiệm của model Caowang ZR3836 thừa hưởng mọi ưu điểm về tuổi thọ, độ bền và khả năng cắt chính xác, lại được trang bị thêm nhiều tính năng mới giúp dễ căn chỉnh khi làm việc như: Có Livo cân bằng máy.</h2>\n<h3> Máy cắt rãnh tường 5 lưỡi Caowang ZR3928 có tính năng khởi động mềm, khởi động dần tới tốc độ tối đa trong 2 giây nên không tổn hại tới hệ thống bánh răng truyền động, không sụt điện lưới, an toàn tuyệt đối cho người sử dụng.</h3>\n<h4><strong>Giá rãnh tường 5 lưỡi CaoWang trên đã bao gồm phí vận chuyển trong nội thành HN, ngoại thành và các khu vực khác vui lòng liên hệ để biết thêm chi tiết. Giá máy cắt rãnh tường trên đồng thời bao gồm các phụ kiện đi kèm như: Ổ cắm 3 chân chống giật, máy bơm nước mini, bộ lưỡi lắp sẵn (5 lưỡi), ti-o dẫn nước, cờ lê, lục lăng mở ốc, long đen đệm, chổi than sơ cua...</strong></h4>\n<p>Quý khách hàng lưu ý: Hiện nay trên thị trường đã xuất hiện máy giả và chiêu trò nhằm nâng giá (thực chất là móc túi khách hàng) và làm nhiễu loạn thị trường như: Cùng 1 mã hàng ZR3928 hoặc ZR3836 họ đặt in nhiều logo và mã máy khác nhau, với nhiều mức giá khác nhau rồi sau đó tư vấn cho khách lấy mã máy đắt nhất. Chúng tôi xin khẳng định Máy cắt rãnh tường đi đường điện nước của Caowang chỉ có 2 mã là: ZR3928 và ZR3836 nên quý khách hàng lưu ý và lựa chọn chính xác.</p>\n<p>Máy cắt rãnh tường 5 lưỡi Caowang ZR3928</p>\n<p>Video sử dụng máy</p>\n<p>Thông số kỹ thuật:</p>\n<p>Điện áp: 220V/50Hz</p>\n<p>Công suất: 4800W</p>\n<p>Tốc độ không tải: 7000 V/P</p>\n<p>Đường kính đĩa: 125mm</p>\n<p>Kích thước rãnh khoan lớn nhất: Rộng 30mm, sâu 40mm</p>\n<p>Khối lượng tịnh: 6 kg</p>\n<p>Bảo hành: 6 tháng</p>\n<p>Xuất xứ: Trung quốc</p>\n', 'Máy cắt rãnh tường 5 lưỡi CaoWang ZR3928', 0.00, 0, 0, 1, 0, 'products/1c0f54cc-495f-41b3-afd0-097b8d58db1a.gif', 25, 10, NULL, NULL),
(649, 'ĐỒNG HỒ ĐO ÁP HT320 LOẠI TỐT CÓ DẦU LỎNG', 'ng-h-o-p-ht320-lo-i-t-t-co-d-u-lo-ng', '', '\n<h2><strong><a href=\"http://www.hethongtuoiando.com/san-pham/dong-ho-do-ap-uot-ht320-1946.html\">ĐỒNG HỒ ĐO ÁP </a>HT320 LOẠI TỐT</strong></h2>\n<p><img alt=\"Đồng hồ đo áp HT320 loại tốt\" src=\"http://vietannong.com.vn/tuoitudong/dong_ho_do_ap_an_do.jpg\"/></p>\n<p><strong>Thông số kỹ thuật:</strong></p>\n<p><strong>Mã hàng: </strong><strong>HT320</strong></p>\n<p><strong>Chất liệu:</strong> Kim loại</p>\n<p><strong>Kiểu đồng hồ:</strong><strong> </strong> Ướt (Có chất lỏng trong mặt đồng hồ)</p>\n<p><strong>Chân ren đầu vào:</strong> 12mm (1/4\")</p>\n<p><strong>Sai số cho phép</strong>: + (-) 2%</p>\n<p><strong>Nhiệt độ môi trường hoạt động:</strong> - 20 đến +60 độ.</p>\n<p><strong>Dải áp suất đo được: </strong>1 - 7 bar (kg/cm2)</p>\n<p><strong>Đường kính ống chính cho phép gắn đồng hồ: </strong>60mm</p>\n<p><strong>Xuất xứ:</strong> Automat - Ấn Độ</p>\n<p><strong>Bảo hành:</strong> 18 tháng</p>\n<p><strong>Ứng dụng:</strong> Thường sử dụng đo áp suất đầu vào của hệ thống <a href=\"http://vietannong.com.vn/load/tuoi_nho_giot_han_quoc/day_tuoi_nho_giot/52\">tưới nhỏ giọt</a> hoặc tưới phun mưa cho cây trồng.</p>\n<p><img alt=\"Đồng hồ đo áp AQ320 loại tốt\" src=\"http://vietannong.com.vn/vietannong/dong_ho_do_ap_1.jpg\"/>A</p>\n', 'ĐỒNG HỒ ĐO ÁP HT320 LOẠI TỐT CÓ DẦU LỎNG', 0.00, 0, 0, 1, 0, 'products/8adf75cd-c9a6-464b-a798-f95bca021986.png', 28, 1, NULL, NULL),
(650, 'ĐỒNG HỒ ĐO ÁP AUTOMAT HT305', 'ng-h-o-p-automat-ht305', '', '\n<h2><strong>ĐỒNG HỒ ĐO ÁP AUTOMAT HT305</strong></h2>\n<h2><img alt=\"Đồng hồ đo áp thường HT305 Việt An Nông\" src=\"http://vietannong.com.vn/tuoitudong/he_thong_tuoi_an_do_7.jpg\"/></h2>\n<p><strong>Thông số kỹ thuật:</strong></p>\n<p><strong>Mã hàng:</strong> HT305</p>\n<p><strong>Chất liệu:</strong> Nhựa</p>\n<p><strong>Kiểu đồng hồ:</strong> Khô (không có chất lỏng trong mặt đồng hồ)</p>\n<p><strong>Chân ren đầu vào:</strong> 12mm (1/4\")</p>\n<p><strong>Sai số cho phép</strong>: + (-) 2%</p>\n<p><strong>Nhiệt độ môi trường hoạt động:</strong> - 20 đến +60 độ.</p>\n<p><strong>Dải áp suất đo được: </strong>1 - 7 bar (kg/cm2)</p>\n<p><strong>Đường kính ống chính cho phép gắn đồng hồ: </strong>60mm</p>\n<p><strong>Xuất xứ:</strong> Ấn Độ</p>\n<p><strong>Bảo hành:</strong> 1 năm</p>\n<p><strong>Ứng dụng: </strong>Dùng đo áp suất trong hệ thống<a href=\"http://vietannong.com.vn/load/\"> tưới nhỏ giọt</a>, hệ thống tưới phun mưa,<a href=\"http://vietannong.com.vn/load/sung_tuoi_cay/sung_tuoi_cay_nodolini_y/16\">súng tưới cây</a>...</p>\n<p><img alt=\"Đồng hồ đo áp ATMA HT305 - Ấn Độ\" src=\"http://vietannong.com.vn/vietannong/dong_ho_do_ap_1.jpg\"/></p>\n', 'ĐỒNG HỒ ĐO ÁP AUTOMAT HT305', 0.00, 0, 0, 1, 0, 'products/b895650e-7d4b-4a3c-982b-85033814305a.png', 28, 1, NULL, NULL);
