(689, 'Bộ lọc đĩa tưới nhỏ giọt phi 49mm', 'b-l-c-a-t-i-nh-gi-t-phi-49mm', '', '\n<p><span style=\'font-family: arial, \"time new roman\";\'>Tiếp nối công nghệ của lọc 60mm, lọc đĩa phi 49 có kết câu, kiểu lọc và chất lượng tương tự với chân ren nhỏ hơn phù hợp với máy bơm công suất nhỏ, khu vực tưới có diện tích vừa phải.</span></p>\n', 'Bộ lọc đĩa tưới nhỏ giọt phi 49mm', 0.00, 0, 0, 1, 0, 'products/03755c8f-c5b7-4f55-a828-db5852c61f59.jpg', 36, 1, NULL, NULL);
