(716, 'Béc tưới tỏa tròn đuôi 5ly VAN 250L', 'b-c-t-i-t-a-tr-n-u-i-5ly-van-250l', '', '\n<p><span style=\'font-family: arial, \"time new roman\";\'>Béc bướm phun tưới theo kiểu tỏa tròn cho cây rau hoa, cây công nghiệp, cây ăn quả. Nhựa cao cấp POM. Sản xuất theo công nghệ hiện đại trên thế giới.</span></p>\n<p><strong><a href=\"http://vietannong.com.vn/load/bec_tuoi_cay/bec_phun_toa_tron/bec_buom_toa_tron_phun_tuoi_rau_van0334/34-1-0-188\">Béc tưới cây</a> tỏa tròn kiểu bướm VAN 250L</strong></p>\n<p><img alt=\"Béc tưới cây tỏa tròn kiểu bướm VAN 250L\" src=\"http://vietannong.com.vn/vietannong/bec_buom_1.jpg\"/></p>\n<p><strong><font face=\"arial, helvetica, sans-serif\">Thông số kỹ thuật:</font></strong></p>\n<p><strong>Bán kính phun:</strong> 3 - 4m</p>\n<p><strong>Áp suất:</strong> 1.7 - 4.25 bar</p>\n<p><strong>Hình vòng quay:</strong> Xòe tròn xung quanh</p>\n<p><strong>Lưu lượng</strong>: 200 - 250l/h</p>\n<p><strong>Độ phủ:</strong> 90%</p>\n<p><strong>Sử dụng:</strong> 3 - 5 năm</p>\n<p><strong>Chân ren gắn béc:</strong> phi 21mm</p>\n<p><strong>Ứng dụng:</strong> Hệ thống <a href=\"http://vietannong.com.vn/load/bec_tuoi_cay/31\">béc tưới rau</a>, tưới hoa màu, tưới cây ăn quả...</p>\n<p><img alt=\"Béc tưới cây tỏa tròn kiểu bướm VAN 250L\" src=\"http://vietannong.com.vn/vietannong/bec_buom_2.jpg\"/></p>\n', 'Béc tưới tỏa tròn đuôi 5ly VAN 250L', 1.00, 0, 0, 1, 0, 'products/6e4a0cd3-15f1-4d0e-b089-1d7c77c5d798.jpg', 42, 8, NULL, NULL),
(717, 'Béc tưới chỉnh góc VAN0410 cao cấp 2 tia RN34', 'b-c-t-i-ch-nh-g-c-van0410-cao-c-p-2-tia-rn34', '', '\n<p><strong><a href=\"http://vietannong.com.vn/\">Béc tưới cây </a>có chỉnh góc phi 34 - VAN0410</strong></p>\n<p><img alt=\"Béc tưới cây có chỉnh góc phi 34 - VAN0410\" src=\"http://vietannong.com.vn/bec_chinh_goc_phi_34.jpg\"/></p>\n<p><strong>Thông số kỹ thuật:</strong></p>\n<p><strong>Bán kính phun:</strong> 14 - 22m<br/>\n<strong>Lưu lượng:</strong> 2 - 5m3/giờ<br/>\n<strong>Áp lực nước:</strong> 2 - 4 bar<br/>\n<strong>Đầu nối: </strong>răng trong 34</p>\n<p><strong>Chỉnh góc phun:</strong> từ 0 - 360 độ<br/>\n<strong>Thời gian sử dụng:</strong> 3 - 5 năm</p>\n<p><strong>Ứng dụng: </strong>Tưới cà phê,<a href=\"http://vietannong.com.vn/blog/tuoi_cay_ho_tieu_buon_ho/2015-01-04-10\"> tưới hồ tiêu</a>, tưới cây ăn quả có múi, tưới thanh long, tưới rau...</p>\n<p><img alt=\"Béc tưới cây có chỉnh góc phi 34 - VAN0410\" src=\"http://vietannong.com.vn/mua_tuoi_ca_phe.jpg\"/></p>\n<p> </p>\n', 'Béc tưới chỉnh góc VAN0410 cao cấp 2 tia RN34', 1.00, 0, 0, 1, 0, 'products/8ea9bca8-989e-4a25-9710-d0752e310e4d.jpg', 43, 8, NULL, NULL),
(718, 'Béc tưới AQ30M cánh đập bằng đồng nguyên chất RN34', 'b-c-t-i-aq30m-c-nh-p-b-ng-ng-nguy-n-ch-t-rn34', 'Mã hàng', '\n<p><span style=\'font-family: arial, \"time new roman\";\'>Với cấu tạo từ đồng nguyên sinh 100%, các dòng béc tưới AQ cánh đập bằng đồng luôn mang lại cho quý khách sự an tâm về độ bền cũng như chất lượng phun tuyệt vời.</span></p>\n<h2><strong><a href=\"http://www.hethongtuoiando.com/san-pham/bec-tuoi-canh-dap/bec-canh-dap-bang-dong-314/\">BÉC PHUN CÁNH ĐẬP</a> AQ30M BẰNG ĐỒNG NGUYÊN CHẤT</strong></h2>\n<p><img alt=\"Béc phun cánh đập ATMA30M bằng đồng nguyên chất ấn độ\" src=\"http://vietannong.com.vn/vietannong/bec_dong_34.jpg\"/></p>\n<p> </p>\n<p><strong>Thông số kỹ thuật:</strong></p>\n<p><strong>Mã hàng</strong>: ATMA30M - 1\" (chân ren 34mm)</p>\n<p><strong>Bảo hành:</strong> 01 năm</p>\n<p><strong>Họng phun thay thế:</strong> không có</p>\n<p><strong>Bán kính phun:</strong> 17.25 -  22.25m</p>\n<p><font><strong>Áp suất:</strong> 2.5 - 5 bar (kg/cm2)</font></p>\n<p><font><strong>Lưu lượng:</strong> 3.6 - 10m3/h</font></p>\n<p><font><strong>Độ phủ đồng đều:</strong> &gt;90%</font></p>\n<p><font><strong>Hình thức phun:</strong> xoay tròn 360 độ</font></p>\n<p><font><b>Xuất xứ:</b> Ấn Độ (India)</font></p>\n<p><font><strong>Ứng dụng:</strong> Sử dụng trong <a href=\"http://vietannong.com.vn/load/sung_tuoi_cay/sung_tuoi_cay_nodolini_y/16\">tưới cà phê</a>, tưới cây ăn quả các loại, cánh đồng cỏ, bắp và ứng dụng trong tưới cảnh quan sân vườn...</font></p>\n<p><img alt=\"Béc phun cánh đập ATMA30M bằng đồng nguyên chất ấn độ\" src=\"http://vietannong.com.vn/vietannong/bec_dong_34_1.jpg\"/></p>\n<p><img alt=\"Béc phun cánh đập ATMA30M bằng đồng nguyên chất ấn độ\" src=\"http://vietannong.com.vn/vietannong/bec_dong_34_2.jpg\"/></p>\n', 'Béc tưới AQ30M cánh đập bằng đồng nguyên chất RN34', 980000.00, 0, 0, 1, 0, 'products/e135d38b-fedc-4e81-b960-490ca5a50cae.png', 42, 15, NULL, NULL),
(719, 'Béc tưới VANBR27 cánh đập 2 tia hợp kim đồng thau RN27', 'b-c-t-i-vanbr27-c-nh-p-2-tia-h-p-kim-ng-thau-rn27', '', '\n<p><strong><a href=\"http://vietannong.com.vn/\">Béc tưới </a>cây cánh đập 27 bằng hợp kim Kẽm - <a href=\"http://vietannong.com.vn/\">Đồng</a>. [Brass Impact Sprinkler]</strong></p>\n<p> </p>\n<p><img alt=\"Béc tưới cây hợp kim thau 27 - VANBR27\" src=\"http://vietannong.com.vn/vietannong/bec_dong_phi_27.jpg\"/></p>\n<p><strong>Thông số kỹ thuật:</strong></p>\n<p><strong>Model:</strong> BR - 27 AF</p>\n<p><strong>Bán kính phun: </strong>10.7 - 15.5m</p>\n<p><strong>Lưu lượng:</strong> 1.2 - 2m3/h</p>\n<p><strong>Áp suất</strong>: 2.25 - 4.0 bar</p>\n<p><strong>Độ bền:</strong> &gt;7 năm</p>\n<p><strong>Bảo hành:</strong> 06 tháng</p>\n<p><strong>Độ phủ:</strong> &gt;89%</p>\n<p><strong>Ứng dụng:</strong> <a href=\"http://vietannong.com.vn/\">Tưới</a> cây công nghiệp mía, cà phê, cao su, <a href=\"http://vietannong.com.vn/\">hồ tiêu</a>, Tưới tự động trong <a href=\"http://vietannong.com.vn/\">hệ thống phun</a> cho cây ăn quả, rau,...</p>\n<p><img alt=\"Béc tưới cây hợp kim thau 27 - VANBR27\" src=\"http://vietannong.com.vn/vietannong/bec_dong_phi_27_1.jpg\"/></p>\n', 'Béc tưới VANBR27 cánh đập 2 tia hợp kim đồng thau RN27', 1.00, 0, 0, 1, 0, 'products/39d28e31-ba5c-4963-bdb8-2fdd2d2ed6af.jpg', 42, 8, NULL, NULL);
INSERT INTO `products` (`id`, `name`, `slug`, `sku`, `content`, `short_desc`, `price`, `discount`, `quantity`, `status`, `type`, `thumbnail`, `category_id`, `brand_id`, `created_at`, `updated_at`) VALUES
(720, 'Béc tưới LF2400 - Rainbird - Mỹ', 'b-c-t-i-lf2400-rainbird-m', '', '\n<p>Dòng béc LF2400 đã chứng tỏ được sự thành công vượt bậc trong hệ thống tưới tự động nông nghiệp trên thế giới về độ phủ trên 92%...</p>\n<p><img alt=\"béc tưới cỏ lf2400 của mỹ bảo hành 5 năm\" src=\"http://vietannong.com.vn/bec_lf2400_tuoi_co.jpg\"/></p>\n<p>Hãng sản xuất: Rainbird - Mỹ<br/>\nBán kính phun: 11.7 - 15.2m<br/>\nLưu lượng: 1.5m3/h<br/>\nÁp suất: 1.7 - 4.2 kg/cm2<br/>\nTốc độ vòng quay: 15s/vòng<br/>\nĐộ phủ: 93%<br/>\nỨng dụng: <a href=\"http://www.vietannong.com.vn/\"><strong>Tưới cây ăn quả</strong></a>, cây công nghiệp, tưới rau, <strong><a href=\"http://www.vietannong.com.vn/\">tưới cỏ</a>,</strong>...<br/>\nMáy bơm: 2HP tưới 1 lúc  8 - 10 béc.<br/>\nĐơn giá: <b>Liên hệ - 0934 191 445</b><br/>\nBảo hành: 05 năm, theo đúng luật của Rainbird - Mỹ</p>\n<p><img alt=\"béc tưới cây lf2400 bền nhất\" src=\"http://vietannong.com.vn/bec_tuoi_Lf2400.jpg\"/></p>\n<p><strong><em>Béc tưới LF2400 của Rainbird bảo hành 05 năm</em></strong></p>\n<p>Một loạt các béc phun với họng phun lớn và góc phun đa dạng từ 15, 24 độ tạo nên sự linh hoạt khi tưới. Sự linh hoạt này giúp chúng ta điều khiển được độ cao của béc để phù hợp với địa hình, cây trồng và sự thấm bề mặt.</p>\n<table align=\"center\" cellpadding=\"0\" cellspacing=\"0\">\n<tbody>\n<tr>\n<td><a href=\"http://3.bp.blogspot.com/-xSCbm-lEp0U/VCWj_AKx-uI/AAAAAAAADks/GUlr2ZocVMo/s1600/tuoi%2Bchuoi%2B1.jpg\" imageanchor=\"1\"><img alt=\"Béc tưới tự động LF2400 Rainbird tưới cây chuối\" border=\"0\" height=\"240\" src=\"http://3.bp.blogspot.com/-xSCbm-lEp0U/VCWj_AKx-uI/AAAAAAAADks/GUlr2ZocVMo/s1600/tuoi%2Bchuoi%2B1.jpg\" title=\"\" width=\"320\"/></a></td>\n</tr>\n<tr>\n<td><i><b><a href=\"http://www.vietannong.com.vn/\">Béc LF2400 Rainbird t</a>ưới cây chuối</b></i></td>\n</tr>\n</tbody></table>\n<p>Thiết kế <a href=\"http://muabectuoi.blogspot.com/2014/05/bec-tuoi-lf2400.html\" rel=\"nofollow\" target=\"_blank\">béc tưới LF2400</a> đã được cấp bằng sáng chế và bản quyền về độ bền tuyệt vời và sự thích nghi với nhiều điều kiện của nước kể cả nước thải, bẩn.<br/>\nDòng LF đã chứng tỏ được sự thành công vượt bậc trong hệ thống<a href=\"http://tuoitudongnongnghiep.blogspot.com/\" rel=\"nofollow\" target=\"_blank\"> tưới tự động </a>nông nghiệp trên thế giới về độ phủ trên 92%, tạo lượng bụi sương cần thiết cho cây trồng, đặc biệt các loại cây ăn quả.<br/>\nNếu năng suất tối đa và chất lượng của cây trồng rất quan trọng với bạn , hãy thử <a href=\"http://tuoitudongnongnghiep.blogspot.com/search/label/B%C3%A9c%20T%C6%B0%E1%BB%9Bi%20RainBird%20-%20USA\" rel=\"nofollow\" target=\"_blank\">béc tưới phun mưa </a>LF 2400 từ Rain Bird , công ty đã được thiết lập các tiêu chuẩn cho tưới nông nghiệp từ năm 1933 .</p>\n<p><img alt=\"béc tưới lf2400 tưới cây ăn quả đồng đều\" src=\"http://vietannong.com.vn/bec_tuoi_lf2400.jpg\"/></p>\n<p><strong><em>Thí nghiệm đảm bảo lượng nước ở mọi vị trí tưới là như nhau</em></strong></p>\n', 'Béc tưới LF2400 - Rainbird - Mỹ', 1.00, 0, 0, 1, 0, 'products/6336084e-5871-4c2a-8913-60d64dcccfe8.jpg', 42, 1, NULL, NULL);
